-- Poems batch 401
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('song-ci-172','风入松','万俟绍之','宋','宋词','song-ci','风入松','[]','一春心事与谁同。',88,'宋词/ci.song.16000.json','["一春心事与谁同。", "绿聚眉峰。", "小楼彻夜听鸣雨，想西园、锦绣成空。", "栏漾金鱼池水，钩闲紫燕帘风。", "年时忻折海棠红。", "来比芳容。", "如今玉减香销似，怕轻寒、懒出房栊。", "尘满谢娘吟卷，从教飞絮濛濛。"]'),
('song-ci-173','贺新郎','万俟绍之','宋','宋词','song-ci','贺新郎','[]','决眦入飞鸟。',142,'宋词/ci.song.16000.json','["决眦入飞鸟。", "正江南、梅雨初晴，乱山浮晓。", "凤去台空箫声断，惟有疏林鸦噪。", "但空锁、吴时花草。", "指点中原青山外，奈征尘、迷望愁云绕。", "佳丽地，谩凝眺。", "清风助我舒长啸。", "问其中、虚帘曲槛，阅人多少。", "风景不殊江山在，况是英雄未老。", "且拚与、尊前一笑。", "欲说前朝兴亡事，唤谪仙、来共传清醥。", "归路晚，月明照。"]'),
('song-ci-174','江神子・江城子','万俟绍之','宋','宋词','song-ci','江神子・江城子','[]','十年心事上眉端。',86,'宋词/ci.song.16000.json','["十年心事上眉端。", "梦惊残。", "琐窗寒。", "云絮随风，千里度关山。", "琴里知音无觅处，妆粉淡，钏金宽。", "瑶箱吟卷懒重看。", "忆前欢。", "泪偷弹。", "我已相将，飞棹过长安。", "为说崔徽憔悴损，须觅取，锦笺还。"]'),
('song-ci-175','水龙吟','丁宥','宋','宋词','song-ci','水龙吟','[]','雁风吹裂云痕，小楼一线斜阳影。',126,'宋词/ci.song.16000.json','["雁风吹裂云痕，小楼一线斜阳影。", "残蝉抱柳，寒蛩入户，凄音忍听。", "愁不禁秋，梦还惊客，青灯孤枕。", "未更深，早是梧桐泫露，那更度、兰宵永。", "空叹银屏金井。", "醉乡醒、温柔乡冷。", "征尘倦扑，闲花谩舞，何心管领。", "葱指冰弦，蕙怀春锦，楚梅风韵。", "怅芙蓉城杳，蓝云依黯，锁巫峰暝。"]'),
('song-ci-176','法曲献仙音','丁宥','宋','宋词','song-ci','法曲献仙音','[]','蝉碧句花，雁红攒月。',10,'宋词/ci.song.16000.json','["蝉碧句花，雁红攒月。"]'),
('song-ci-177','失调名','丁宥','宋','宋词','song-ci','失调名','[]','疏绮笼寒，浅云栖月。',10,'宋词/ci.song.16000.json','["疏绮笼寒，浅云栖月。"]'),
('song-ci-178','六么令','丁宥','宋','宋词','song-ci','六么令','[]','清阴一架，颗颗蒲萄醉花碧。',13,'宋词/ci.song.16000.json','["清阴一架，颗颗蒲萄醉花碧。"]'),
('song-ci-179','瑞鹤仙','周氏','宋','宋词','song-ci','瑞鹤仙','[]','画楼帘卷翠。',127,'宋词/ci.song.16000.json','["画楼帘卷翠。", "正柳约东风，摇荡春霁。", "缃桃雨才洗。", "似妆临宝镜。", "脂凝铅水。", "云偏髻子。", "坠钗梁、羞看燕垒。", "最堪怜，锦绣香中，早有片红飘砌。", "闲记。", "琴弹古调，曲按清商，旧年时事。", "屏山画里。", "江南信，梦中寄。", "感春浓怀抱，午酲初解，浅酌依然又醉。", "傍阑干、犹怯馀寒，倦和袖倚。"]'),
('song-ci-180','水龙吟','潘牥','宋','宋词','song-ci','水龙吟','[]','（上缺）玉带悬鱼，黄金铸印，侯封万户。',35,'宋词/ci.song.16000.json','["（上缺）玉带悬鱼，黄金铸印，侯封万户。", "待从头，缴纳君王，觅取爱卿归去。"]'),
('song-ci-181','南乡子','潘牥','宋','宋词','song-ci','南乡子','[]','生怕倚阑干。',66,'宋词/ci.song.16000.json','["生怕倚阑干。", "阁下溪声阁外山。", "惟有旧时山共水，依然。", "暮雨朝云去不远。", "应是蹑飞鸾。", "月下时时整佩环。", "月又渐低霜又下，更阑。", "折得梅花独自看。"]'),
('song-ci-182','乌夜啼','潘牥','宋','宋词','song-ci','乌夜啼','[]','无端小雪廉纤。',45,'宋词/ci.song.16000.json','["无端小雪廉纤。", "入平檐。", "金鸭旋添龙饼，莫开帘。", "寻梅约。", "开还落。", "可曾忺。", "合作一年春恨，上眉尖。"]'),
('song-ci-183','满江红','潘牥','宋','宋词','song-ci','满江红','[]','筑室依崖，春风送、一帘山色。',115,'宋词/ci.song.16000.json','["筑室依崖，春风送、一帘山色。", "沙岛外，渔樵而已，别无闲客。", "醉后和友眠犊背，醒来瀹茗寻泉脉。", "把心情、分付陇头云，溪边石。", "身未老，头先白。", "人不见，山空碧。", "约钓竿共把，自惭钩直。", "相蜀吞吴成底事，何如只抱隆中膝。", "漫长歌、歌罢悄无言，看青壁。"]'),
('song-ci-184','洞仙歌','潘牥','宋','宋词','song-ci','洞仙歌','[]','雕檐绮户，倚晴空如画。',106,'宋词/ci.song.16000.json','["雕檐绮户，倚晴空如画。", "曾是吴王旧台榭。", "自浣纱去后，落日平芜，行云断，几见花开花谢。", "凄凉阑干外，一簇江山，多少图王共争霸。", "莫闲愁、金杯潋滟，对酒当歌，欢娱地、梦中兴亡休话。", "渐倚遍、西风晚潮生，明月里、鹭鹚背人飞下。"]'),
('song-ci-185','霜天晓角','赵希��','宋','宋词','song-ci','霜天晓角','[]','姮娥戏剧。',53,'宋词/ci.song.16000.json','["姮娥戏剧。", "手种长生粒。", "宝干婆娑千古，飘芳吹满虚碧。", "韵色。", "檀露滴。", "人间秋第一。", "金粟如来境界，谁移在、小亭侧。"]'),
('song-ci-186','秋蕊香','赵希□','宋','宋词','song-ci','秋蕊香','[]','髻稳冠宜翡翠。',56,'宋词/ci.song.16000.json','["髻稳冠宜翡翠。", "压鬓彩丝金蕊。", "远山碧浅蘸秋水。", "香暖榴裙衬地。", "亭亭二八馀年纪。", "恼春意。", "玉云凝重步尘细。", "独立花阴宝砌。"]'),
('song-ci-187','摸鱼儿','孙吴会','宋','宋词','song-ci','摸鱼儿','["\u957f\u6c5f"]','八窗空、展宽秋影，长江流入尊俎。',140,'宋词/ci.song.16000.json','["八窗空、展宽秋影，长江流入尊俎。", "天围绀碧低群岫，斜日去鸿堪数。", "沈别浦。", "但目断、烟芜莽苍连平楚。", "晨钟暮鼓。", "算触景多愁，关人底事，倚槛听鸣橹。", "英雄恨，赢得名存北府。", "寄奴今寄何所。", "西风依旧潮来去，山海颉颃吞吐。", "霜月古。", "直耐冷、相随燕我瑶芝圃。", "掀髯起舞。", "看羱伏苍苔，龙吟翠葆，天籁奏韶舞。"]'),
('song-ci-188','临江仙','赵溍','宋','宋词','song-ci','临江仙','[]','堤曲朱墙近远，山明碧瓦高低。',68,'宋词/ci.song.16000.json','["堤曲朱墙近远，山明碧瓦高低。", "好风二十四花期。", "骄骢穿柳去，文艗挟春飞。", "箫鼓晴雷殷殷，笑歌香雾霏霏，闲情不受酒禁持。", "断肠无立处，斜日欲归时。"]'),
('song-ci-189','吴山青・长相思','赵溍','宋','宋词','song-ci','吴山青・长相思','["\u6d1e\u5ead\u6e56"]','金璞明。',44,'宋词/ci.song.16000.json','["金璞明。", "玉璞明。", "小小杯柈翠袖擎。", "满将春色盛。", "仙佩鸣。", "玉佩鸣。", "雪月花中过洞庭。", "此时人独清。"]'),
('song-ci-190','庆宫春・高阳台','刘澜','宋','宋词','song-ci','庆宫春・高阳台','[]','春翦绿波，日明金渚，镜光尽浸寒碧。',126,'宋词/ci.song.16000.json','["春翦绿波，日明金渚，镜光尽浸寒碧。", "喜溢双蛾，迎风一笑，两情依旧脉脉。", "那时同醉，锦袍湿、乌纱敧侧。", "英雄何在，满目青山，飞下孤白。", "片帆谁上天门，我亦明朝，是天门客。", "平生高兴，青莲一叶，从此飘然八极。", "矶头绿树，见白马、书生破敌。", "百年前事，欲问东风，酒醒长笛。"]'),
('song-ci-191','瑞鹤仙','刘澜','宋','宋词','song-ci','瑞鹤仙','[]','向阳看未足。',127,'宋词/ci.song.16000.json','["向阳看未足。", "更露立阑干，日高人独。", "江空佩鸣玉。", "问烟鬟霞脸，为谁膏沐。", "情闲景淑。", "嫁东风、无媒自卜。", "凤台高，贪伴吹笙，惊下九天霜鸪。", "红蹙。", "花开不到，杜老溪庄，已公茅屋。", "山城水国。", "欢易断，梦难续。", "记年时马上，人酣花醉，乐奏开元旧曲。", "夜归来，驾锦漫天，绛纱万烛。"]'),
('song-ci-192','齐天乐','刘澜','宋','宋词','song-ci','齐天乐','[]','玉钗分向金华后，回头路迷仙苑。',123,'宋词/ci.song.16000.json','["玉钗分向金华后，回头路迷仙苑。", "落翠惊风，流红逐水，谁信人间重见。", "花深半面。", "尚歌得新词，柳家三变。", "绿叶阴阴，可怜不似那时看。", "刘郎今度更老，雅怀都不到，书带题扇。", "花信风高，苕溪月冷，明日云帆天远。", "尘缘较短。", "怪一梦轻回，酒阑歌散。", "别鹤惊心，感时花泪溅。"]'),
('song-ci-193','买陂塘・摸鱼儿','刘澜','宋','宋词','song-ci','买陂塘・摸鱼儿','["\u897f\u6e56"]','御风来、翠乡深处，连天云锦平远。',140,'宋词/ci.song.16000.json','["御风来、翠乡深处，连天云锦平远。", "卧游已动蓬舟兴，那在芙蓉城畔。", "巾懒岸。", "任压顶嵯峨，满鬓丝零乱。", "飞吟水殿。", "载十丈青青，随波弄粉，菰雨泪如霰。", "斜阳外，也有新妆半面。", "无言应对花怨。", "西湖千顷腥尘暗。", "更忆鉴湖一片。", "何日见。", "试折藕占丝，丝与肠俱断。", "遐征渐倦。", "当颍尾湖头，绿波彩笔，相伴老坡健。"]'),
('song-ci-194','水调歌头','魏庭玉','宋','宋词','song-ci','水调歌头','[]','璧月挂银汉，冷浸一江秋。',114,'宋词/ci.song.16000.json','["璧月挂银汉，冷浸一江秋。", "天公付我清赏，仙籍桂香浮。", "极目江山如画，际晚云烟凝紫，秋色豁羁愁。", "领看上雄观，波影动帘钩。", "雁排空，渔唱晚，楚天幽。", "湖阴一曲千载，成败倩谁筹。", "试问谪仙何处，唤起于湖同醉，小为作遨头。", "老子欲起舞，摆脱利名休。"]'),
('song-ci-195','贺新凉・贺新郎','魏庭玉','宋','宋词','song-ci','贺新凉・贺新郎','[]','暮雨初收霁。',142,'宋词/ci.song.16000.json','["暮雨初收霁。", "凭阑干、一江新绿，远山凝翠。", "漠漠春阴添客思，怅望天涯无际。", "又猛省、平生行止。", "楚尾吴头多少恨，付吟边、醉里消磨矣。", "浮世事，只如此。", "阳关三叠徒劳耳。", "也何须、琵琶江上，掩青衫泪。", "一斗百篇乘逸兴，要借青天为纸。", "儿辈诧、龙蛇飞起。", "今夜月明呼酒处，待明朝、酒醒帆千里。", "且为我，唱新制。"]'),
('song-ci-196','晴偏好','李霜涯','宋','宋词','song-ci','晴偏好','[]','平湖百顷生芳草。',28,'宋词/ci.song.16000.json','["平湖百顷生芳草。", "芙蓉不照红颠倒。", "东坡道。", "波光潋滟晴偏好。"]'),
('song-ci-197','渔父词・渔父','王谌','宋','宋词','song-ci','渔父词・渔父','[]','兰芷流来水亦香。',32,'宋词/ci.song.16000.json','["兰芷流来水亦香。", "满汀鸥鹭动斜阳。", "声诶乃，间鸣榔。", "侬家只合岸西旁。"]'),
('song-ci-198','渔父词・渔父','王谌','宋','宋词','song-ci','渔父词・渔父','[]','翁妪齐眉妇亦贤。',32,'宋词/ci.song.16000.json','["翁妪齐眉妇亦贤。", "小姑颜貌正笄年。", "头发乱，髻鬟偏。", "爱把花枝立舵前。"]'),
('song-ci-199','渔父词・渔父','王谌','宋','宋词','song-ci','渔父词・渔父','[]','湘妃泪染竹痕斑。',32,'宋词/ci.song.16000.json','["湘妃泪染竹痕斑。", "风雨连朝下钓难。", "春浪急，石矶寒。", "买得茅柴味亦酸。"]'),
('song-ci-200','渔父词・渔父','王谌','宋','宋词','song-ci','渔父词・渔父','[]','满湖飞雪搅长空。',32,'宋词/ci.song.16000.json','["满湖飞雪搅长空。", "急起呼儿上短蓬。", "箬笠具，画图同。", "铁笛声长曲未终。"]'),
('song-ci-201','渔父词・渔父','王谌','宋','宋词','song-ci','渔父词・渔父','[]','离骚读罢怨声声。',32,'宋词/ci.song.16000.json','["离骚读罢怨声声。", "曾向江边问屈平。", "醒还醉，醉还醒。", "笑指沧浪可濯缨。"]'),
('song-ci-202','渔父词・渔父','王谌','宋','宋词','song-ci','渔父词・渔父','[]','白发髼松不记年。',32,'宋词/ci.song.16000.json','["白发髼松不记年。", "扁舟泊在荻花边。", "天上月，水中天。", "夜夜烟波得意眠。"]'),
('song-ci-203','渔父词・渔父','王谌','宋','宋词','song-ci','渔父词・渔父','[]','只在青山可卜邻。',32,'宋词/ci.song.16000.json','["只在青山可卜邻。", "妻儿笑语意全真。", "休识字，莫嫌贫。", "方是安闲第一人。"]'),
('song-ci-204','万年欢','厉寺正','宋','宋词','song-ci','万年欢','[]','卫武期颐，与文公福艾，俱号贤相。',124,'宋词/ci.song.16000.json','["卫武期颐，与文公福艾，俱号贤相。", "今我元台，齿德又居其上。", "玉立擎天一柱，似泰华、气凌秋庄。", "明良会，千载风云，长为龙衮凭仗。", "清知孔山叠嶂。", "有猿吟鹤舞，日俟鸠杖。", "无忝苍生依依，未容高尚。", "待整顿、乾坤了当，与蓬岛、神仙来往。", "摩铜狄，点检笙歌，菊浮香泛新酿。"]'),
('song-ci-205','摸鱼儿','施枢','宋','宋词','song-ci','摸鱼儿','[]','柳蒙茸、暗凌波路。',140,'宋词/ci.song.16000.json','["柳蒙茸、暗凌波路。", "烟飞惨淡平楚。", "七香车驻猊环掩，遥认翠华云母。", "芳景暮。", "鸳甃悄、铢衣来按飞琼舞。", "凄凉洛浦。", "渐玉漏沈沈，清阴满地，乘月步虚去。", "销凝处。", "谁说三生小杜。", "翔螭声断箫鼓。", "情知禁苑酥尘涴，羞与倡红同谱。", "春几度。", "想依旧、苔痕长印唐昌土。", "风流千古。", "人在小红楼，朱帘半卷，香注玉壶露。"]'),
('song-ci-206','疏影','施枢','宋','宋词','song-ci','疏影','[]','低枝亚实。',134,'宋词/ci.song.16000.json','["低枝亚实。", "望翠阴护晓，幽梦难觅。", "凄楚霓裳，琼阙瑶台，经年暗锁清逸。", "春风似怪重门掩，未许入、玉堂吟笔。", "想寿阳，却厌新妆，倦抹粉花宫额。", "还记孤山旧路，未应便负了，波冷蟾白。", "莫寄相思，惟有寒烟，伴我骚人闲寂。", "东君须自怜疏影，又何待、山前雪积。", "好试敲、羯鼓声催，与约鼎羹消息。"]'),
('song-ci-207','柳梢青','施枢','宋','宋词','song-ci','柳梢青','[]','飞露初霜。',61,'宋词/ci.song.16000.json','["飞露初霜。", "冷侵金井，响到银床。", "懊恨碧梧，不留一叶，月占纱窗。", "雁声做尽凄凉。", "又陡顿、衾寒夜长。", "曲曲屏山，重重客梦，无限思量。"]'),
('song-ci-208','齐天乐','储泳','宋','宋词','song-ci','齐天乐','[]','东风一夜吹寒食，枝头片红犹恋。',123,'宋词/ci.song.16000.json','["东风一夜吹寒食，枝头片红犹恋。", "宿酒初醒，新吟未稳，凭久栏杆留暖。", "将春买断。", "恨苔径榆阶，翠钱难贯。", "陌上秋千，相逢谁认旧时伴。", "轻衫粉痕褪了，丝缘馀梦在，良宵偏短。", "柳线经烟，莺梭织雾，一片旧愁新怨。", "慵拈象管。", "待寄与深情，难凭双燕。", "不似杨花，解随人去远。"]'),
('song-ci-209','西江月','储泳','宋','宋词','song-ci','西江月','[]','壁断何人旧字，炉寒隔岁残香。',58,'宋词/ci.song.16000.json','["壁断何人旧字，炉寒隔岁残香。", "洞天人去海茫茫。", "玩世仙翁已往。", "西日长安道远，春风赵国台荒。", "行人谁不悟黄粮。", "依旧红尘陌上。"]'),
('song-ci-210','念奴娇','刘子实','宋','宋词','song-ci','念奴娇','[]','一门相种，剩河英岳粹，共扶昌录。',120,'宋词/ci.song.16000.json','["一门相种，剩河英岳粹，共扶昌录。", "夹辅正宜资鲁卫，左右秉持钧轴。", "缓驾轻车，任回虎节，何事劳山国。", "东民欲靖，作新少借康叔。", "况是鸑鷟佳辰，雪霜深处，秀孕椿松绿。", "天意特教荣晚节，挺挺世臣乔木。", "绣斧功成，衮衣促觐，莫恨公归速。", "一陶和气，要令天下蒙福。"]'),
('song-ci-211','沁园春','刘子实','宋','宋词','song-ci','沁园春','[]','腊后寒收，柳眼青归，梅花笑生。',139,'宋词/ci.song.16000.json','["腊后寒收，柳眼青归，梅花笑生。", "正阳和有脚，日边送暖，洪钧换轴，天上回星。", "试巧春盘，介眉春酒，生意从头乐意新。", "须知道，是东风近也，玉燕逢辰。", "举头阊阖开明。", "便稳驾轻车熟路行。", "向玉堂青琐，从容洒翰，长淮赤壁，谈笑麾兵。", "周洛犹尘，商岩未雨，天下苍生望太平。", "休盘涧，任清溪九曲，不放舟横。"]'),
('song-ci-212','贺新郎','翁合','宋','宋词','song-ci','贺新郎','[]','世事今如许。',140,'宋词/ci.song.16000.json','["世事今如许。", "祗先生、寿身寿国，尚堪撑拄。", "一脉宽仁忠厚意，留到如今可数。", "问谁是、擎天一柱。", "名节难全官职易，这娥眉、肯效争妍妒。", "几而作，色斯举。", "沧州万顷舟横渡。", "对和风、桃花流水，一蓑烟雨。", "亲得紫阳传正印，且作斯文宗主。", "世望皋夔伊傅。", "天意须酬平治愿，抚参同、一卷长生谱。", "平治了，仙为侣。"]'),
('song-ci-213','卜算子','翁合','宋','宋词','song-ci','卜算子','[]','口诵百中经，手运周天数。',54,'宋词/ci.song.16000.json','["口诵百中经，手运周天数。", "试问薇垣一小星，谁知是、韩王普。", "知得客星来，知得贤人聚。", "我若乘槎犯斗牛，莫向常人语。"]'),
('song-ci-214','贺新郎','王庚','宋','宋词','song-ci','贺新郎','[]','满劝黄封酒。',141,'宋词/ci.song.16000.json','["满劝黄封酒。", "是年年、春色长绕，径花宫柳。", "碧水丹山添清气，岁月兰亭癸丑。", "看枢极、光腾台斗。", "细数中书堂壁记，自欧韩、富范题名后，还有似、我公否。", "好知天意生贤候，正造化安排，孕出五阳之秀。", "何物一阴犹踯躅，尽决还公只手。", "这一著、邦家之寿。", "宰相时来须教做，算人间、是处鱼羹有。", "名与节，久轩久。"]'),
('song-ci-215','小重山','黄铸','宋','宋词','song-ci','小重山','[]','凉入秋檐雨意长。',70,'宋词/ci.song.16000.json','["凉入秋檐雨意长。", "竹深啼络纬，响虚堂。", "一枝灯影耿昏黄。", "疏帘外，风度木樨香。", "心事易成伤。", "燕支坡下路，语如簧。", "定仙螺子玉钗梁。", "鸳屏梦，应到旧韦郎。"]'),
('song-ci-216','秋蕊香令','黄铸','宋','宋词','song-ci','秋蕊香令','[]','花外数声风定。',56,'宋词/ci.song.16000.json','["花外数声风定。", "烟际一痕月净。", "水晶屏小敧醉枕。", "院静鸣蛩相应。", "香销斜掩青铜镜。", "背灯影。", "寒砧夜半和雁阵。", "秋在刘郎绿鬓。"]'),
('song-ci-217','庆清朝','李宏模','宋','宋词','song-ci','庆清朝','[]','碧玉云深，彤绡雾薄，芳丛乱迷秋渚。',118,'宋词/ci.song.16000.json','["碧玉云深，彤绡雾薄，芳丛乱迷秋渚。", "重城傍水，中有吹箫俦侣。", "应是琼楼夜冷，月明谁伴乘鸾女。", "仙游处。", "翠帟障尘，红绮随步。", "别岸玉容伫倚，爱浅抹蜂黄，淡笼纨素。", "娇羞未语，脉脉悲烟泣露。", "彩扇何人，妙笔丹青，招得花魂住。", "歌声暮。", "梦入锦江，香里归路。"]'),
('song-ci-218','木兰花慢','杨子咸','宋','宋词','song-ci','木兰花慢','[]','紫凋红落后，忽十丈，玉虬横。',123,'宋词/ci.song.16000.json','["紫凋红落后，忽十丈，玉虬横。", "望众绿帏中，蓝田璞碎，鲛室珠倾。", "柔条系风无力，更不禁、连日峭寒清。", "空与蝶圆香梦，枉教莺诉春情。", "深深。", "苔径悄无人。", "栏槛湿香尘。", "叹宝髻髼松，粉铅狼藉，谁管飘零。", "不愁素云易散，恨此花、开后更无春。", "安得胡床月夜，玉醅满蘸瑶英。"]'),
('song-ci-219','临江仙','太学士人','宋','宋词','song-ci','临江仙','[]','莫怪钱神容易致，钱神尽是愚夫。',70,'宋词/ci.song.16000.json','["莫怪钱神容易致，钱神尽是愚夫。", "为何此鬼却相於。", "只因频展义，长是泣穷途。", "韩氏有文曾饯汝，临行慎莫踌躇。", "青灯双点照平湖。", "蕉船从此逝，相共送陶朱。"]'),
('song-ci-220','失调名','李之问','宋','宋词','song-ci','失调名','[]','愿得年年，长共我儿解粽。',12,'宋词/ci.song.16000.json','["愿得年年，长共我儿解粽。"]'),
('song-ci-221','失调名','吴敏德','宋','宋词','song-ci','失调名','[]','御符争带，更有天师神咒。',12,'宋词/ci.song.16000.json','["御符争带，更有天师神咒。"]'),
('song-ci-222','失调名','郭子正','宋','宋词','song-ci','失调名','[]','清晓开庭，茱萸初佩。',10,'宋词/ci.song.16000.json','["清晓开庭，茱萸初佩。"]'),
('song-ci-223','舜韶新','郭子正','宋','宋词','song-ci','舜韶新','[]','香满西风，催岁晚东篱，黄花争吐。',124,'宋词/ci.song.16000.json','["香满西风，催岁晚东篱，黄花争吐。", "嫩英细蕊，金艳繁、妆点高秋偏富。", "寒地花媒少，算自结、多情烟雨。", "每年年妆面，谢他拒霜相顾。", "宝马王孙，休笑孤芳，陶令因谁，便思归去。", "负春何事，此恨惟、才子登高能赋。", "千古风流在，占定泛、重阳芳醑。", "堪吟看醉赏，何须杏园深处。"]'),
('song-ci-224','望海潮','鄱阳护…','宋','宋词','song-ci','望海潮','[]','云收飞脚，日祛怒暑，新蝉高柳鸣时。',126,'宋词/ci.song.16000.json','["云收飞脚，日祛怒暑，新蝉高柳鸣时。", "兰佩紫囊，蒲抽碧剑，吴丝两腕双垂。", "闻道五陵儿。", "蛟龙吼波面，冲碎琉璃。", "画鼓声中，锦标争处飐红旗。", "使君冠盖追。", "正霞翻酒浪，翠敛歌眉。", "扇动水风生玉宇，微凉透入单衣。", "日暮楚天低。", "金蛇掣电漾，千顷霜溪。", "宴罢休燃宝蜡，凭月照人归。"]'),
('song-ci-225','西江月','尹词客','宋','宋词','song-ci','西江月','[]','韩愈文章盖世，谢安才貌风流。',58,'宋词/ci.song.16000.json','["韩愈文章盖世，谢安才貌风流。", "良辰开宴在西楼。", "敢劝一卮芳酒。", "记得南宫高第，弟兄都占鳌头。", "金炉玉殿瑞香浮。", "名在甲科第九。"]'),
('song-ci-226','玉楼春','尹词客','宋','宋词','song-ci','玉楼春','[]','浣花溪上风光主。',64,'宋词/ci.song.16000.json','["浣花溪上风光主。", "燕集瀛洲开幕府。", "商岩本是作霖人，也使闲花沾雨露。", "谁怜氏族传簪组。", "狂迹偶为风月误。", "愿教朱户柳藏春，免作飘零堤上絮。"]'),
('song-ci-227','菩萨蛮','王氏','宋','宋词','song-ci','菩萨蛮','[]','横湖十顷琉璃碧。',52,'宋词/ci.song.16000.json','["横湖十顷琉璃碧。", "画桥百步通南北。", "沙暖睡鸳鸯。", "春风花草香。", "闲来撑小艇。", "划破楼台影。", "四面望青山。", "浑如蓬莱间。"]'),
('song-ci-228','水调歌头','虞㠭','宋','宋词','song-ci','水调歌头','[]','憔悴朔家种，零落雪边枝。',114,'宋词/ci.song.16000.json','["憔悴朔家种，零落雪边枝。", "淡妆素艳，无桃笑面柳眉低。", "懒向深宫点额，甘与孤山结社，照影水之湄。", "不怨风霜虐，我本岁寒姿。", "谢东君。", "开冷蕊，弄斜晖。", "强颜红紫同□，皎洁性难移。", "祗好竹篱茅舍，若话玉堂金鼎，老恐负心期。", "歌罢饮先醉，残月坠深卮。"]'),
('song-ci-229','月华清','洪瑹','宋','宋词','song-ci','月华清','[]','花影摇春，虫声吟暮，九霄云幕初卷。',123,'宋词/ci.song.16000.json','["花影摇春，虫声吟暮，九霄云幕初卷。", "谁驾冰蟾，拥出桂轮天半。", "素魄映、青琐窗前，皓彩散、画阑干畔。", "凝眄。", "见金波滉漾，分辉鹊殿。", "况是风柔夜暖。", "正燕子新来，海棠微绽。", "不似秋光，只照离人肠断。", "恨无奈、利锁名缰，谁为唤、舞裙歌扇。", "吟玩。", "怕铜壶催晓，玉绳低转。"]'),
('song-ci-230','水龙吟','洪瑹','宋','宋词','song-ci','水龙吟','[]','经年不见书来，后期杳杳从谁问。',126,'宋词/ci.song.16000.json','["经年不见书来，后期杳杳从谁问。", "柳英蜡小，柳枝金嫩，艳阳春近。", "罗幕风柔，泛红浮绿，连朝花信。", "念平生多少，情条恨叶，镇长使、芳心困。", "可是风流薄命。", "镜台前、松松蝉鬓。", "茜桃凝粉，薰兰涨腻，翠愁红损。", "纵使归来，灯前月下，恐难相认。", "卷重帘憔悴，残妆泪洗，把罗襟搵。"]'),
('song-ci-231','蓦山溪','洪瑹','宋','宋词','song-ci','蓦山溪','[]','潮平风稳，行色催津鼓。',102,'宋词/ci.song.16000.json','["潮平风稳，行色催津鼓。", "回首望重城，但满眼、红云紫雾。", "分香解佩，空记小楼东，银烛暗，绣帘垂，昵昵凭肩语。", "关山千里，垂柳河桥路。", "燕子又归来，但惹得、满身花雨。", "彩笺不寄，兰梦更无凭，灯影下，月明中，魂断金钗股。"]'),
('song-ci-232','齐天乐','洪瑹','宋','宋词','song-ci','齐天乐','[]','辘轳声破银床冻，霜寒又侵鸳被。',123,'宋词/ci.song.16000.json','["辘轳声破银床冻，霜寒又侵鸳被。", "皓月疏钟，悲风断漏，惊起画楼人睡。", "银屏十二。", "叹尘满丝簧，暗消金翠。", "可恨风流，故人迢递隔千里。", "相思情绪最苦，旧欢无续处，魂梦空费。", "断雁无情，离鸾有恨，空想吴山越水。", "花憔玉悴。", "但翠黛愁横，红铅泪洗。", "待剪江梅，倩人传此意。"]'),
('song-ci-233','菩萨蛮','洪瑹','宋','宋词','song-ci','菩萨蛮','[]','断虹远饮横江水。',52,'宋词/ci.song.16000.json','["断虹远饮横江水。", "万山紫翠斜阳里。", "系马短亭西。", "丹枫明酒旗。", "浮生长客路。", "事逐孤鸿去。", "又是月黄昏。", "寒灯人闭门。"]'),
('song-ci-234','菩萨蛮','洪瑹','宋','宋词','song-ci','菩萨蛮','[]','吴姬压酒浮红蚁。',52,'宋词/ci.song.16000.json','["吴姬压酒浮红蚁。", "少年未饮心先醉。", "驻马绿阳阴。", "酒楼三月春。", "相看成一笑。", "遗恨知多少。", "回首欲魂销。", "长桥连断桥。"]'),
('song-ci-235','踏莎行','洪瑹','宋','宋词','song-ci','踏莎行','[]','满满金杯，垂垂玉筋。',68,'宋词/ci.song.16000.json','["满满金杯，垂垂玉筋。", "离歌不放行人去。", "醉中扶上木兰船，醒来忘却桃源路。", "带绾同心，钗分一股。", "断魂空草高唐赋。", "秋山万叠水云深，茫茫无著相思处。"]'),
('song-ci-236','瑞鹤仙','洪瑹','宋','宋词','song-ci','瑞鹤仙','[]','听梅花吹动，凉夜何其，明星有烂。',126,'宋词/ci.song.16000.json','["听梅花吹动，凉夜何其，明星有烂。", "相看泪如霰。", "问而今去也，何时会面。", "匆匆聚散。", "恐便作、秋鸿社燕。", "最伤情、夜来枕上，断云零雨何限。", "因念。", "人生万事，回首悲凉，都成梦幻。", "芳心缱绻。", "空惆怅，巫阳馆。", "况船头一转，三千馀里，隐隐高城不见。", "恨无情、春水连天，片帆似箭。"]'),
('song-ci-237','浪淘沙','洪瑹','宋','宋词','song-ci','浪淘沙','[]','花雾涨冥冥。',64,'宋词/ci.song.16000.json','["花雾涨冥冥。", "欲雨还晴。", "薄罗衫子正宜春。", "无奈今宵鸳帐里，身是行人。", "别酒不须斟。", "难洗离情。", "丝鞘如电紫骝鸣。", "肠断画桥芳草路，月晓风清。"]'),
('song-ci-238','南柯子・南歌子','洪瑹','宋','宋词','song-ci','南柯子・南歌子','[]','柳浪摇晴沼，荷风度晚檐。',62,'宋词/ci.song.16000.json','["柳浪摇晴沼，荷风度晚檐。", "碧天如水印新蟾。", "一罅清光斜露、玉纤纤。", "宝镜微开匣，金钩半押帘。", "西楼今夜有人忺。", "应傍妆台低照、画眉尖。"]'),
('song-ci-239','永遇乐','洪瑹','宋','宋词','song-ci','永遇乐','[]','歌雪徘徊，梦云溶曳，欲劝春住。',128,'宋词/ci.song.16000.json','["歌雪徘徊，梦云溶曳，欲劝春住。", "薄幸杨花，无端杜宇，抵死催教去。", "参差烟岫，千回百匝，不解禁春归路。", "病厌厌，那堪更听，小楼一夜风雨。", "金钗斗草，玉盘行菜，往事了无凭据。", "合数松儿，分香帕子，总是牵情处。", "小桃朱户，题诗在否，尚忆去年崔护。", "绿阴中，莺莺燕燕，也应解语。"]'),
('song-ci-240','谒金门','洪瑹','宋','宋词','song-ci','谒金门','[]','风共雨。',53,'宋词/ci.song.16000.json','["风共雨。", "催尽乱红飞絮。", "百计留春春不住。", "杜鹃声更苦。", "细柳官河狭路。", "几被婵娟相误。", "空忆坠鞭遗扇处。", "碧窗眉语度。"]'),
('song-ci-241','菩萨蛮','洪瑹','宋','宋词','song-ci','菩萨蛮','[]','玉琴不疗文园病。',52,'宋词/ci.song.16000.json','["玉琴不疗文园病。", "对花长抱深深恨。", "恨入鬓霜边。", "才情输少年。", "蛾眉梳坠马。", "翠袖薰兰麝。", "醉梦未全醒。", "绿窗啼晓莺。"]'),
('song-ci-242','阮郎归','洪瑹','宋','宋词','song-ci','阮郎归','[]','东风吹破藻池冰。',56,'宋词/ci.song.16000.json','["东风吹破藻池冰。", "晴光开五云。", "绿情红意两逢迎。", "扶春来远林。", "花艳艳，玉英英。", "罗衣金缕明。", "闹蛾儿簇小蜻蜓。", "相呼看试灯。"]'),
('song-ci-243','行香子','洪瑹','宋','宋词','song-ci','行香子','[]','楚楚精神。',84,'宋词/ci.song.16000.json','["楚楚精神。", "杨柳腰身。", "是风流、天上飞琼。", "凌波微步，罗袜生尘。", "有许多娇，许多韵，许多情。", "十年心事，两字眉婚。", "问何时、真个行云。", "秋衾半冷，窗月窥人。", "想为人愁，为人瘦，为人颦。"]'),
('song-ci-244','鹧鸪天','洪瑹','宋','宋词','song-ci','鹧鸪天','[]','意态婵娟画不如。',64,'宋词/ci.song.16000.json','["意态婵娟画不如。", "莹然初日照芙蕖。", "笑捐琼佩遗交甫，肯把文梭掷幼舆。", "花上蝶，水中凫。", "芳心密意两相於。", "情知不作庭前柳，到得秋来日日疏。"]'),
('song-ci-245','水龙吟','楼枎','宋','宋词','song-ci','水龙吟','[]','素蛾洗尽繁妆，夜深步月秋千地。',126,'宋词/ci.song.16000.json','["素蛾洗尽繁妆，夜深步月秋千地。", "轻腮晕玉，柔肌笼粉，缁尘敛避。", "霁雪留香，晓云同梦，昭阳宫闭。", "怅仙园路杳，曲栏人寂，疏雨湿、盈盈泪。", "未放游峰叶底。", "怕春归、不禁狂吹。", "象床困倚，冰魂微醒，莺声唤起。", "愁对黄昏，恨催寒食，满襟离思。", "想千红过尽，一枝独冷，把梅花比。"]'),
('song-ci-246','菩萨蛮','楼枎','宋','宋词','song-ci','菩萨蛮','[]','丝丝杨柳莺声近。',52,'宋词/ci.song.16000.json','["丝丝杨柳莺声近。", "晚风吹过秋千影。", "寒色一帘轻。", "灯残梦不成。", "耳边消息在。", "笑指花梢待。", "又是不归来。", "满庭花自开。"]'),
('song-ci-247','沁园春','楼枎','宋','宋词','song-ci','沁园春','[]','开辟以来，便有此山，独当怒涛。',140,'宋词/ci.song.16000.json','["开辟以来，便有此山，独当怒涛。", "正秋空万里，寒催雁信，尘寰一簇，轻等鸿毛。", "小可诗情，寻常酒量，到此应须分外豪。", "难为水，算平生未有，此番登高。", "飘飘。", "身踏金鳌。", "笑终日风波无限劳。", "看樯乌缥缈，帆归远浦，廛鱼杂沓，网带馀潮。", "待约诗人，相将月夜，取次携杯持蟹螯。", "乘桴意，问谁人领解，空立亭皋。"]'),
('song-ci-248','念奴娇','章谦亨','宋','宋词','song-ci','念奴娇','[]','垂杨得地，在楼台侧畔，无人攀折。',120,'宋词/ci.song.16000.json','["垂杨得地，在楼台侧畔，无人攀折。", "不似津亭舟系处，只伴客愁离别。", "丝过摇金，带铺新翠，雅称莺调舌。", "芳筵相映，最宜斜挂残月。", "却得连日春寒，未教轻滚，一片庭前雪。", "应恨张郎今老去，难比风流时节。", "醉眼浑醒，愁眉都展，舞困腰肢怯。", "有时微笑，把伊绾个双结。"]'),
('song-ci-249','步蟾宫','章谦亨','宋','宋词','song-ci','步蟾宫','[]','团圞小酌醺醺醉。',67,'宋词/ci.song.16000.json','["团圞小酌醺醺醉。", "厮捱著、没人肯睡。", "呼卢直到五更头，便铺了妆台梳洗。", "庭前鼓吹喧人耳。", "蓦忽地、又添一岁。", "休嫌不足少年时，有多少、老如我底。"]'),
('song-ci-250','摸鱼儿','章谦亨','宋','宋词','song-ci','摸鱼儿','[]','想先生、跨鹤归去。',140,'宋词/ci.song.16000.json','["想先生、跨鹤归去。", "依然上界官府。", "胸中邱壑经营巧，留下午桥别墅。", "堪爱处。", "山对起、飞来万马平坡驻。", "带湖鸥鹭。", "犹不忍寒盟，时寻门外，一片芰荷浦。", "秋水观，环绕滔滔瀑布。", "参天林木奇古。", "云烟只在阑干角，生出晚来微雨。", "东道主。", "爱宾客、梅花烂漫开樽俎。", "满怀尘土。", "扫荡已无馀，□□时上，玉峤翠瀛语。"]'),
('song-ci-251','念奴娇','章谦亨','宋','宋词','song-ci','念奴娇','["\u897f\u6e56"]','画楼侧畔，试与君、管领南枝风物。',120,'宋词/ci.song.16000.json','["画楼侧畔，试与君、管领南枝风物。", "影浸西湖清浅水，旁倚云崖烟壁。", "艾纳全披，檀心俱露，一片前村雪。", "碧松修竹，岁寒真是三杰。", "长向酒欲冰时，魁英相放，不待阳和发。", "一任无情风又雨，毕竟清香难灭。", "幻玉精神，添酥标致，羞上萧萧发。", "脆圆可爱，更看春二三月。"]'),
('song-ci-252','浪淘沙','章谦亨','宋','宋词','song-ci','浪淘沙','[]','台上凭阑干。',64,'宋词/ci.song.16000.json','["台上凭阑干。", "犹怯春寒。", "被谁偷了最高山。", "将谓六丁移取去，不在人间。", "却是晓云闲。", "特地遮拦。", "与天一样白漫漫。", "喜得东风收卷尽，依旧追还。"]'),
('song-ci-253','小重山','章谦亨','宋','宋词','song-ci','小重山','[]','久雨初晴天气佳。',70,'宋词/ci.song.16000.json','["久雨初晴天气佳。", "远峰犹□被，乱峰遮。", "更无一朵路旁花。", "春归也，光景只桑麻。", "山径曲如蛇。", "□□□□□，□□□。", "薄醪邀客去程赊。", "都输与，鷖鹭立平沙。"]'),
('song-ci-254','石州引・石州慢','章谦亨','宋','宋词','song-ci','石州引・石州慢','[]','半角庭阴，弓月映眉，珠露侵靸。',123,'宋词/ci.song.16000.json','["半角庭阴，弓月映眉，珠露侵靸。", "花棚倒挂风枝，低罥鬓唇ぢ叶。", "凭肩笑问，甚日罢织流黄，泥人无语吟虫答。", "灯近悄分携，溜钗钿犀合。", "一霎。", "莲丝易折。", "未稳栖鸳，陡惊弹鸭。", "几度空阶，宵永笛声孤擫。", "玉腰烟瘦，□□梨梦香消，醒来凉袖阑干压。", "不尽度檐云，写闲愁千叠。"]'),
('song-ci-255','水调歌头','章谦亨','宋','宋词','song-ci','水调歌头','[]','解变西崑体，一赋冠群英。',114,'宋词/ci.song.16000.json','["解变西崑体，一赋冠群英。", "清风峡畔，至今堂以读书名。", "富贵轻於尘土，孝义重於山岳，惜不大其成。", "陵谷纵迁改，草木亦光荣。", "与仇香，穿阮屐，试同登。", "石龛虽窄，可容一几短檠灯。", "千仞苍崖如削，四面翠屏不断，云雾镇长生。", "最爱岩前水，犹作诵弦声。"]'),
('song-ci-256','画堂春','章谦亨','宋','宋词','song-ci','画堂春','[]','连朝檐溜几曾乾。',32,'宋词/ci.song.16000.json','["连朝檐溜几曾乾。", "韶华一似衰颜。", "牡丹开尽木香残。", "忆家山，愁倚危阑。"]'),
('song-ci-257','阮郎归','王同祖','宋','宋词','song-ci','阮郎归','[]','一帘疏雨细於尘。',56,'宋词/ci.song.16000.json','["一帘疏雨细於尘。", "春寒愁杀人。", "桐花庭院近清明。", "新烟浮旧城。", "寻蝶梦，怯莺声。", "柳丝如妾情。", "丙丁帖子画教成。", "妆台求晚晴。"]'),
('song-ci-258','摸鱼儿','王同祖','宋','宋词','song-ci','摸鱼儿','[]','记年时、荔枝香里，深红一片成阵。',140,'宋词/ci.song.16000.json','["记年时、荔枝香里，深红一片成阵。", "迎风浴露精神爽，谁似阿娇丰韵。", "黄昏近。", "望翠幕玳席，粉面云鬟映。", "娇波微瞬。", "向烛影交相，歌声闲绕，私语画阑并。", "佳期事，好处天还悭吝。", "莺啼燕语无定。", "一轮明月人千里，空梦云温雨润。", "萧郎病。", "恨天阔鸿稀，杳杳沈芳讯。", "日长人静。", "但时把好山，学他媚妩，偷就眉峰印。"]'),
('song-ci-259','西江月','王同祖','宋','宋词','song-ci','西江月','[]','往事星移物换，旧游雨冷云沈。',58,'宋词/ci.song.16000.json','["往事星移物换，旧游雨冷云沈。", "真娘墓草几回青。", "问著寒潮不应。", "何处芙蓉别馆，依前杨柳离亭。", "东风吹泪入重扃。", "为唤香魂教醒。"]'),
('song-ci-260','踏莎行','杨伯','宋','宋词','song-ci','踏莎行','[]','梅观初花，蕙庭残叶。',68,'宋词/ci.song.16000.json','["梅观初花，蕙庭残叶。", "当时惯听山阴雪。", "东风吹梦到清都，今年雪比年前别。", "重酿宫醪，双钩官帖。", "伴翁一笑成三绝。", "夜深何用对青藜，窗前一片蓬莱月。"]'),
('song-ci-261','木兰花慢','李彭老','宋','宋词','song-ci','木兰花慢','[]','正千门系柳，赐宫烛、散青烟。',126,'宋词/ci.song.16000.json','["正千门系柳，赐宫烛、散青烟。", "看秀靥芳唇，涂妆晕色，试尽春妍。", "田田。", "满阶榆荚，弄轻阴、浅冷似秋天。", "随处饧香杏暖，燕飞斜亸秋千。", "朱弦。", "几换华年。", "扶浅醉、落花前。", "记旧时游冶，灯楼倚扇，水院移船。", "吟边。", "梦云飞远，有题红、都在薛涛笺。", "听绝残箫倦笛，夜堂明月窥帘。"]'),
('song-ci-262','壶中天・念奴娇','李彭老','宋','宋词','song-ci','壶中天・念奴娇','[]','素飙荡碧，喜云飞寥廓，清透凉宇。',120,'宋词/ci.song.16000.json','["素飙荡碧，喜云飞寥廓，清透凉宇。", "倦鹊惊翻台榭迥，叶叶秋声归树。", "珠斗斜河，冰轮辗雾，万里青冥路。", "香深屏翠，桂边满袖风露。", "烟外冷逼玻璃，渔郎歌渺，击空明归去。", "怨鹤知更莲漏悄，竹里筛金帘户。", "短发吹寒，闲情吟远，弄影花前舞。", "明年今夜，玉樽知醉何处。"]'),
('song-ci-263','高阳台','李彭老','宋','宋词','song-ci','高阳台','[]','飘粉杯宽，盛香袖小，青青半掩苔痕。',122,'宋词/ci.song.16000.json','["飘粉杯宽，盛香袖小，青青半掩苔痕。", "竹里遮寒，谁念灭尽芳云。", "么凤叫晚吹晴雪，料水空、烟冷西泠。", "感雕零。", "残缕遗钿，迤逦成尘。", "东园曾趁花前约，记按筝筹酒，戏挽飞琼。", "环佩无声，草暗台榭春深。", "欲倩怨笛传清谱，怕断霞、难返吟魂。", "转消凝。", "点点随波，望极江亭。"]'),
('song-ci-264','法曲献仙音','李彭老','宋','宋词','song-ci','法曲献仙音','[]','云木槎桠，水荭摇落，瘦影半临清浅。',114,'宋词/ci.song.16000.json','["云木槎桠，水荭摇落，瘦影半临清浅。", "翠羽迷空，粉容羞晓，年华柱弦频换。", "甚何逊、风流在，相逢共寒晚。", "总依黯。", "念当时、看花游冶，曾锦缆移舟，宝筝随辇。", "池苑锁荒凉，嗟事逐、鸿飞天远。", "香径无人，甚苍藓、黄尘自满。", "听鸦啼春寂，暗雨萧萧吹怨。"]'),
('song-ci-265','一萼红','李彭老','宋','宋词','song-ci','一萼红','[]','过蔷薇。',133,'宋词/ci.song.16000.json','["过蔷薇。", "正风暄云淡，春去未多时。", "古岸停桡，单衣试酒，满眼芳草斜晖。", "故人老、经年赋别，灯晕里、相对夜何其。", "泛剡清愁，买花芳事，一卷新诗。", "流水孤帆渐远，想家山猿鹤，喜见重归。", "北阜寻幽，青津问钓，多情杨柳依依。", "最难忘、吟边旧雨，数菖蒲、花老是来期。", "几夕相思梦蝶，飞绕苹溪。"]'),
('song-ci-266','高阳台','李彭老','宋','宋词','song-ci','高阳台','["\u897f\u6e56"]','石笋埋云，风篁啸晚，翠微高处幽居。',122,'宋词/ci.song.16000.json','["石笋埋云，风篁啸晚，翠微高处幽居。", "缥简云签，人间一点尘无。", "绿深门户啼鹃外，看堆床、宝晋图书。", "尽萧闲，浴砚临池，滴露研朱。", "旧时曾写桃花扇，弄霏香秀笔，春满西湖。", "松菊依然，柴桑自爱吾庐。", "冰弦玉柱风流在，更秋兰、香染衣裾。", "照窗明，小字珠玑，重见欧虞。"]'),
('song-ci-267','探芳讯','李彭老','宋','宋词','song-ci','探芳讯','[]','对芳昼。',108,'宋词/ci.song.16000.json','["对芳昼。", "甚怕冷添衣，伤春疏酒。", "正绯桃如火，相看自依旧。", "闲帘深掩梨花雨，谁问东阳瘦。", "几多时，涨绿莺枝，坠红鸳甃。", "堤上宝鞍骤。", "记草色薰晴，波光摇岫。", "苏小门前，题字尚存否。", "繁华短梦随流水，空有诗千首。", "更休言，张绪风流似柳。"]'),
('song-ci-268','祝英台近','李彭老','宋','宋词','song-ci','祝英台近','[]','杏花吹，梅花过，时节又春半。',95,'宋词/ci.song.16000.json','["杏花吹，梅花过，时节又春半。", "帘影飞梭，轻阴小庭院。", "旧时月底秋千，吟香醉玉，曾细听、歌珠一串。", "忍重见。", "描金小字题情，生绡合欢扇。", "老了刘郎，天远玉箫伴。", "几番莺外斜阳，阑干倚遍，恨杨柳、遮愁不断。"]'),
('song-ci-269','踏莎行','李彭老','宋','宋词','song-ci','踏莎行','[]','紫曲迷香，绿窗梦月。',68,'宋词/ci.song.16000.json','["紫曲迷香，绿窗梦月。", "芳心如对春风说。", "蛮笺象管写新声，几番曾试琼壶觖。", "庾信书愁，江淹赋别。", "桃花红雨梨花雪。", "周郎先自足风流，何须更拟秦箫咽。"]'),
('song-ci-270','浪淘沙','李彭老','宋','宋词','song-ci','浪淘沙','[]','泼火雨初晴。',64,'宋词/ci.song.16000.json','["泼火雨初晴。", "草色青青。", "傍檐垂柳卖春饧。", "画舫载花花解语，绾燕吟莺。", "箫鼓入西泠。", "一片轻阴。", "钿车罗盖竞归城。", "别有水窗人唤酒，弦月初生。"]'),
('song-ci-271','四字令・醉太平','李彭老','宋','宋词','song-ci','四字令・醉太平','[]','兰汤晚凉。',46,'宋词/ci.song.16000.json','["兰汤晚凉。", "鸾钗半妆。", "红巾腻雪初香。", "擘莲房赌双。", "罗纨素珰。", "冰壶露床。", "月移花影西厢。", "数流萤过墙。"]'),
('song-ci-272','生查子','李彭老','宋','宋词','song-ci','生查子','[]','罗襦隐绣茸，玉合消红豆。',48,'宋词/ci.song.16000.json','["罗襦隐绣茸，玉合消红豆。", "深院落梅钿，寒峭收灯后。", "心事卜金钱，月上鹅黄柳。", "拜了夜香休，翠被听春漏。"]'),
('song-ci-273','壶中天・念奴娇','李彭老','宋','宋词','song-ci','壶中天・念奴娇','[]','水西云北，记前回同载，高阳伴侣。',120,'宋词/ci.song.16000.json','["水西云北，记前回同载，高阳伴侣。", "一色荷花香十里，偷把秋期频数。", "脆管排云，轻桡喷雪，不信催诗雨。", "碧筒呼酒，秀笺题遍新句。", "谁念病损文园，岁华摇落，事与孤鸿去。", "露井邀凉吹短发，梦入苹洲菱浦。", "暗草飞萤，乔枝翻鹊，看月山中住。", "一声清唱，醉乡知有仙路。"]'),
('song-ci-274','木兰花慢','李彭老','宋','宋词','song-ci','木兰花慢','[]','折秦淮露柳，带明月、倚归船。',126,'宋词/ci.song.16000.json','["折秦淮露柳，带明月、倚归船。", "看佩玉纫兰，囊诗贮锦，江满吴天。", "吟边。", "唤回梦蝶，想故山、薇长已多年。", "草得梅花赋了，棹歌远和离舷。", "风弦。", "尽入吟篇。", "伤倦客、对秋莲。", "过旧经行处，渔乡水驿，一路闻蝉。", "留连。", "漫听燕语，便江湖、夜语隔灯前。", "潮返浔阳暗水，雁来好寄瑶笺。"]'),
('song-ci-275','祝英台近','李彭老','宋','宋词','song-ci','祝英台近','[]','载轻寒、低鸣橹。',95,'宋词/ci.song.16000.json','["载轻寒、低鸣橹。", "十里杏花雨。", "露草迷烟，萦绿过前浦。", "青青陌上垂杨，绾丝摇佩，渐遮断、旧曾吟处。", "听莺语。", "吹笙人远天长，谁翻水西谱。", "浅黛凝愁，远岫带眉妩。", "画阑闲倚多时，不成春醉，趁几点、白鸥归去。"]'),
('song-ci-276','清平乐','李彭老','宋','宋词','song-ci','清平乐','[]','合欢扇子。',54,'宋词/ci.song.16000.json','["合欢扇子。", "扑蝶花阴里。", "半醉海棠扶不起。", "淡日秋千闲倚。", "宝筝弹向谁听。", "一春能几番晴。", "帐底柳绵吹满，不教好梦分明。"]'),
('song-ci-277','章台月・一斛珠','李彭老','宋','宋词','song-ci','章台月・一斛珠','[]','露轻风细。',67,'宋词/ci.song.16000.json','["露轻风细。", "中庭夜色凉如水。", "荷香柳影成秋意。", "萤冷无光，凉入树声碎。", "玉箫金缕西楼醉。", "长吟短舞花阴地。", "素娥应笑人憔悴。", "漏歇帘空，低照半床睡。"]'),
('song-ci-278','青玉案','李彭老','宋','宋词','song-ci','青玉案','[]','楚峰十二阳台路。',80,'宋词/ci.song.16000.json','["楚峰十二阳台路。", "算只有、飞红去。", "玉合香囊曾暗度。", "榴裙翻酒，杏帘吹粉，不识愁来处。", "燕忙莺懒青春暮。", "蕙带空留断肠句。", "草色天涯情几许。", "荼䕷开尽，旧家池馆，门掩风和雨。"]'),
('song-ci-279','浣溪沙','李彭老','宋','宋词','song-ci','浣溪沙','[]','玉雪庭心夜色空。',48,'宋词/ci.song.16000.json','["玉雪庭心夜色空。", "移花小槛斗春红。", "轻衫短帽醉歌重。", "彩扇旧题烟雨外，玉箫新谱燕莺中。", "阑干到处是春风。"]'),
('song-ci-280','天香','李彭老','宋','宋词','song-ci','天香','[]','捣麝成尘，薰薇注露，风酣百和花气。',117,'宋词/ci.song.16000.json','["捣麝成尘，薰薇注露，风酣百和花气。", "品重云头，叶翻蕉样，共说内家新制。", "波浮海沫，谁唤觉、鲛人春睡。", "清润俱饶片脑，芬馡半是沈水。", "相逢酒边花外。", "火初温、翠炉烟细。", "不似宝珠金缕，领巾红坠。", "荀令如今憔悴。", "消未尽、当时爱香意。", "炉暖灯寒，秋声素被。"]'),
('song-ci-281','摸鱼子','李彭老','宋','宋词','song-ci','摸鱼子','[]','过垂虹、四桥飞雨，沙痕初涨春水。',140,'宋词/ci.song.16000.json','["过垂虹、四桥飞雨，沙痕初涨春水。", "腥波十里吴歈远，绿蔓半萦船尾。", "连复碎。", "爱滑卷青绡，香袅冰丝细。", "山人隽味。", "笑杜老无情，香羹碧涧，空只赋芹美。", "归期早，谁似季鹰高致。", "鲈鱼相伴菰米。", "红尘如海丘园梦，一叶又秋风起。", "湘湖外。", "看采撷、芳条际晓随鱼市。", "旧游漫记。", "但望里江南，秦鬟贺镜，渺渺隔烟翠。"]'),
('song-ci-282','失调名','李彭老','宋','宋词','song-ci','失调名','[]','暗雨敲花，柔风过柳。',10,'宋词/ci.song.16000.json','["暗雨敲花，柔风过柳。"]'),
('song-ci-283','惜红衣','李莱老','宋','宋词','song-ci','惜红衣','[]','笛送西泠，帆过杜曲。',108,'宋词/ci.song.16000.json','["笛送西泠，帆过杜曲。", "昼阴芳绿。", "门巷清风，还寻故人屋。", "苍华发冷，笑瘦影、相看如竹。", "幽谷。", "烟树晚莺，诉经年愁独。", "残阳古木。", "书画归船，匆匆又南北。", "苹洲鸥鹭素熟。", "旧盟续。", "甚日浩歌招隐，听雨弁阳同宿。", "料重来时候，香荡几湾红玉。"]'),
('song-ci-284','青玉案','李莱老','宋','宋词','song-ci','青玉案','["\u897f\u6e56"]','吟情老尽江南句。',80,'宋词/ci.song.16000.json','["吟情老尽江南句。", "几千万、垂丝缕。", "花冷絮飞寒食路。", "渔烟鸥雨，燕昏莺晓，总入昭华谱。", "红衣妆靓凉生渚。", "环碧斜阳旧时树。", "拈叶分题觞咏处。", "荀香犹在，庾愁何许，云冷西湖赋。"]'),
('song-ci-285','扬州慢','李莱老','宋','宋词','song-ci','扬州慢','[]','玉倚风轻，粉凝冰薄，土花祠冷无人。',121,'宋词/ci.song.16000.json','["玉倚风轻，粉凝冰薄，土花祠冷无人。", "听吹箫月底，传暮草金城。", "笑红紫、纷纷成雨，溯空如蝶，恐堕珠尘。", "叹而今、杜郎还见，应赋悲春。", "佩环何许，纵无情、莺燕犹惊。", "怅朱槛香消，绿屏梦渺，肠断瑶琼。", "九曲迷楼依旧，沈沈夜、想觅行云。", "但荒烟幽翠，东风吹作秋声。"]'),
('song-ci-286','谒金门','李莱老','宋','宋词','song-ci','谒金门','[]','春意态。',53,'宋词/ci.song.16000.json','["春意态。", "闲却远山横黛。", "香径莓苔嗟粉坏。", "凤靴双斗彩。", "折得花枝懒戴。", "犹恋鸳鸯飞盖。", "旧恨新愁都只在。", "东风吹柳带。"]'),
('song-ci-287','浪淘沙','李莱老','宋','宋词','song-ci','浪淘沙','["\u897f\u6e56"]','榆火换新烟。',64,'宋词/ci.song.16000.json','["榆火换新烟。", "翠柳朱檐。", "东风吹得落花颠。", "帘影翠梭悬绣带，人倚秋千。", "犹忆十年前。", "西子湖边。", "斜阳吹入画楼船。", "归醉夜堂歌舞月，拼却春眠。"]'),
('song-ci-288','生查子','李莱老','宋','宋词','song-ci','生查子','[]','妾情歌柳枝，郎意怜桃叶。',48,'宋词/ci.song.16000.json','["妾情歌柳枝，郎意怜桃叶。", "罗带绾同心，谁信愁千结。", "楼上数残更，马上看新月。", "绣被怨春寒，怕学鸳鸯叠。"]'),
('song-ci-289','高阳台','李莱老','宋','宋词','song-ci','高阳台','[]','门掩香残，屏摇梦冷，珠细糁缀芳尘。',122,'宋词/ci.song.16000.json','["门掩香残，屏摇梦冷，珠细糁缀芳尘。", "临水搴花，流来疑是行云。", "藓梢空挂凄凉月，想鹤归、犹怨黄昏。", "黯消凝。", "人老天涯，雁影沈沈。", "断肠不在听横笛，在江皋解佩，翳玉飞琼。", "烟湿荒村，背春无限愁深。", "迎风点点飘寒粉，怅秋娘、燕袖啼痕。", "更关情。", "青子悬枝，绿树成阴。"]'),
('song-ci-290','木兰花慢','李莱老','宋','宋词','song-ci','木兰花慢','[]','向烟霞堆里，著吟屋、最高层。',126,'宋词/ci.song.16000.json','["向烟霞堆里，著吟屋、最高层。", "望海日翻红，林霏散白，猿鸟幽深。", "双岑。", "倚天翠湿，看浮云、收尽雨还晴。", "晓色千松逗冷，照人眼底长青。", "闲情。", "玉尘风生。", "摹茧字，校鹅经。", "爱静翻缃帙，芸台棐几，荷制兰缨。", "分明。", "晋人旧隐，掩岩扉、月午籁沈沈。", "三十六梯树杪，溯空遥想登临。"]'),
('song-ci-291','清平乐','李莱老','宋','宋词','song-ci','清平乐','[]','绿窗初晓。',54,'宋词/ci.song.16000.json','["绿窗初晓。", "枕上闻啼鸟。", "不恨王孙归不早。", "只恨天涯芳草。", "锦书红泪千行。", "一春无限思量。", "折得垂杨寄与，丝丝都是愁肠。"]'),
('song-ci-292','台城路・齐天乐','李莱老','宋','宋词','song-ci','台城路・齐天乐','[]','半空河影流云碎，亭皋嫩凉收雨。',123,'宋词/ci.song.16000.json','["半空河影流云碎，亭皋嫩凉收雨。", "井叶还惊，江莲乱落，弦月初生商素。", "堂深几许。", "渐爽入云帱，翠绡千缕。", "纨扇恩疏，晚萤光冷照窗户。", "文园憔悴顿老，又西风暗换，丝鬓无数。", "灯外残砧，琴边瘦枕，一一情伤迟暮。", "故人倦旅。", "料渭水长安，感时吟苦。", "正自多愁，砌蛩终夜语。"]'),
('song-ci-293','浪淘沙','李莱老','宋','宋词','song-ci','浪淘沙','[]','宝押绣帘斜。',64,'宋词/ci.song.16000.json','["宝押绣帘斜。", "莺燕谁家。", "银筝初试合琵琶。", "柳色春罗裁袖小，双戴桃花。", "芳草满天涯。", "流水韶华。", "晚风杨柳绿交加。", "闲倚阑干无藉在，数尽归鸦。"]'),
('song-ci-294','杏花天','李莱老','宋','宋词','song-ci','杏花天','["\u897f\u6e56"]','年时中酒风流病。',65,'宋词/ci.song.16000.json','["年时中酒风流病。", "正雨暗、蘼芜深径。", "人家寒食烟初禁。", "狼藉梨花雪影。", "西湖梦、红沈翠冷。", "记舞板、歌裙厮趁。", "斜阳苦与黄昏近。", "生怕画船归尽。"]'),
('song-ci-295','小重山','李莱老','宋','宋词','song-ci','小重山','[]','画檐簪柳碧如城。',70,'宋词/ci.song.16000.json','["画檐簪柳碧如城。", "一帘风雨里，近清明。", "吹箫门巷冷无声。", "梨花月，今夜负中庭。", "远岫敛修颦。", "春愁吟入谱，付莺莺。", "红尘没马翠埋轮。", "西泠曲，欢梦絮飘零。"]'),
('song-ci-296','倦寻芳','李莱老','宋','宋词','song-ci','倦寻芳','[]','缭墙黏藓，糁径飞梅，春绪无赖。',118,'宋词/ci.song.16000.json','["缭墙黏藓，糁径飞梅，春绪无赖。", "绣压垂帘，骨有许多寒在。", "宝幄香消龙麝饼，钿车尘冷鸳鸯带。", "想西园，被一程风雨，群芳都碍。", "逗晓色、莺啼人起，倦倚银屏，愁沁眉黛。", "待拼千金，却恨好榷难买。", "翠苑欢游孤解佩。", "青门佳约妨挑菜。", "柳初黄，罩池塘、万丝愁霭。"]'),
('song-ci-297','点绛唇','李莱老','宋','宋词','song-ci','点绛唇','[]','绿染春波，袖罗金缕双鸂鶒。',50,'宋词/ci.song.16000.json','["绿染春波，袖罗金缕双鸂鶒。", "小桃匀碧。", "香衬蝉云湿。", "舞带歌钿，闲傍秋千立。", "情何极。", "燕莺尘迹。", "芳草斜阳笛。"]'),
('song-ci-298','西江月','李莱老','宋','宋词','song-ci','西江月','[]','绿染晓云冉冉，红酣晴雾冥冥。',58,'宋词/ci.song.16000.json','["绿染晓云冉冉，红酣晴雾冥冥。", "银簪悬烛锦官城。", "困倚墙头半影。", "雨后遍饶艳冶，燕来同作清明。", "更深犹唤玉靴笙。", "不管西池露冷。"]'),
('song-ci-299','清平乐','李莱老','宋','宋词','song-ci','清平乐','[]','日寒风细。',54,'宋词/ci.song.16000.json','["日寒风细。", "庭馆浮花气。", "白发潘郎吟欲醉。", "绿暗シ芜千里。", "西园南浦东城。", "一春多少闲情。", "日暮采苹歌远，梦回唤得愁生。"]'),
('song-ci-300','念奴娇','黄应武','宋','宋词','song-ci','念奴娇','[]','乾坤开辟，桂林有、元气自来融结。',120,'宋词/ci.song.16000.json','["乾坤开辟，桂林有、元气自来融结。", "石磴盘空行木杪，天柱屹然中立。", "窟宅幽深，泉源清远，不是灵神擘。", "潜通后洞，张刘万古遗迹。", "输我长剑凌虚，六尘尽扫，银海秋波碧。", "志气飘飘游物外，惟有清风知得。", "唤起白龙，护持飙驭，稽首朝金阙。", "山灵欣喜，紫云已在诗壁。"]'),
('song-ci-301','满庭芳','如愚居士','宋','宋词','song-ci','满庭芳','[]','吾乃当涂，弃儒奉道，遵行圣诲多年。',118,'宋词/ci.song.16000.json','["吾乃当涂，弃儒奉道，遵行圣诲多年。", "已逾三纪，截灭六尘缘。", "因习业、自营度日，未尝谒见豪贤。", "般若力，掀翻烦恼，坦荡独け然。", "来斯，十四载，装銮佛像，塔宇尽光鲜。", "造遮晹石道，直至水□边。", "都系束修己镪，舍为助道安禅。", "知惭愧，了无所得，本觉性明圆。"]'),
('song-ci-302','满江红','林革','宋','宋词','song-ci','满江红','[]','十载扁舟，几来往、三吾溪上。',115,'宋词/ci.song.16000.json','["十载扁舟，几来往、三吾溪上。", "天宝事，一回看著，一回惆怅。", "笔画模糊犹雅健，文章褒贬添悲壮。", "枉教人、字字费沈吟，评轻重。", "西北望，情无量。", "东南气，真长王。", "想忠臣应读，宋中兴颂。", "主圣自然皆乐土，时平正合储良将。", "笑此身、老大尚奔驰，知何用。"]'),
('song-ci-303','水调歌头','曾宏正','宋','宋词','song-ci','水调歌头','[]','风月无尽藏，泉石有膏肓。',114,'宋词/ci.song.16000.json','["风月无尽藏，泉石有膏肓。", "古今桂岭奇胜，骚客费平章。", "不假鬼谋神运，自是地藏天作，圆魂镇相望。", "举首吸空翠，赤脚踏沧浪。", "惊龙卧，攀栖鹘，翳鸾凰。", "秋爽一天凉露，桂子更飘香。", "坐我水精宫阙，呼彼神仙伴侣，大杓挹琼浆。", "主醉客起舞，今夕是何乡。"]'),
('song-ci-304','沁园春','吴景伯','宋','宋词','song-ci','沁园春','[]','再上高台，访谪仙兮，仙何所之。',140,'宋词/ci.song.16000.json','["再上高台，访谪仙兮，仙何所之。", "但石城西踞，潮平白鹭，浮图南峙，云淡乌衣。", "凤鸟不来，长安何处，惟有碧梧三数枝。", "兴亡事，对江山休说，谁是谁非。", "庭花飘尽胭脂。", "算结绮、繁华能几时。", "问何人重向，新亭挥泪，何人更到，别墅围棋。", "笑拍阑干，功名未了，宁肯绿蓑寻钓矶。", "深深饮，任玉山醉倒，明月扶归。"]'),
('song-ci-305','点绛唇','邓有功','宋','宋词','song-ci','点绛唇','[]','卷上珠帘，晚来一阵东风恶。',50,'宋词/ci.song.16000.json','["卷上珠帘，晚来一阵东风恶。", "客怀萧索。", "看尽残花落。", "自把银瓶，买酒成孤酌。", "伤漂泊。", "知音难托。", "闷倚阑干角。"]'),
('song-ci-306','过秦楼','邓有功','宋','宋词','song-ci','过秦楼','[]','燕蹴飞红，莺迁新绿，几阵晚来风急。',135,'宋词/ci.song.16000.json','["燕蹴飞红，莺迁新绿，几阵晚来风急。", "谢家池馆，金谷园林，还又把春虚掷。", "年时恨雨愁云，物换星移，有谁曾忆。", "把一尊试酹，落花芳草，总成尘迹。", "频自笑、流浪孤萍，沾泥弱絮，有底困春无力。", "银屏香暖，宝簟波寒，又负月明今夕。", "往事梦里，沈思惟有罗襟，泪痕犹湿。", "奈垂杨万缕，不系西风白日。"]'),
('song-ci-307','浪淘沙','李振祖','宋','宋词','song-ci','浪淘沙','[]','春在画桥西。',64,'宋词/ci.song.16000.json','["春在画桥西。", "画舫轻移。", "粉香何处度涟漪。", "认得一船杨柳外，帘影垂垂。", "谁倚碧阑低。", "酒晕双眉。", "鸳鸯并浴燕交飞。", "一片闲情春水隔，斜日人归。"]'),
('song-ci-308','二郎神','汤恢','宋','宋词','song-ci','二郎神','[]','琐窗睡起，闲伫立、海棠花影。',128,'宋词/ci.song.16000.json','["琐窗睡起，闲伫立、海棠花影。", "记翠楫银塘，红牙金缕，杯泛梨花冷。", "燕子衔来相思字，道玉瘦、不禁春病。", "应蝶粉半销，鸦云斜坠，暗尘侵镜。", "还省。", "香痕碧唾，春衫都凝。", "悄一似荼䕷，玉肌翠帔，消得东风唤醒。", "青杏单衣，杨花小扇，闲却晚春风景。", "最苦是、蝴蝶盈盈弄晚，一帘风静。"]'),
('song-ci-309','倦寻芳','汤恢','宋','宋词','song-ci','倦寻芳','["\u897f\u6e56"]','饧箫吹暖，蜡烛分烟，春思无限。',118,'宋词/ci.song.16000.json','["饧箫吹暖，蜡烛分烟，春思无限。", "风到楝花，二十四番吹遍。", "烟湿浓堆杨柳色，昼长闲坠梨花片。", "悄帘栊，听幽禽对语，分明如翦。", "记旧日、西湖行乐，载酒寻春，十里尘软。", "背后腰肢，彷佛画图曾见。", "宿粉残香随梦冷，落花流水和天远。", "但如今，病厌厌、海棠池馆。"]'),
('song-ci-310','满江红','汤恢','宋','宋词','song-ci','满江红','[]','小院无人，正梅粉、一阶狼藉。',115,'宋词/ci.song.16000.json','["小院无人，正梅粉、一阶狼藉。", "疏雨过，溶溶天气，早如寒食。", "啼鸟惊回芳草梦，峭风吹浅桃花色。", "漫玉炉、沈水熨春衫，花痕碧。", "绿縠水，红香陌。", "紫桂棹，黄金勒。", "怅前欢如梦，后游何日。", "酒醒香消人自瘦，天空海阔春无极。", "又一林、新月照黄昏，梨花白。"]'),
('song-ci-311','祝英台近','汤恢','宋','宋词','song-ci','祝英台近','[]','宿酲苏，春梦醒，沈水冷金鸭。',95,'宋词/ci.song.16000.json','["宿酲苏，春梦醒，沈水冷金鸭。", "落尽桃花，无人扫红雪。", "渐催煮酒园林，单衣庭院，春又到、断肠时节。", "恨离别。", "长忆人立荼䕷，珠帘卷香月。", "几度黄昏，琼枝为谁折。", "都将千里芳心，十年幽梦，分付与、一声啼鴂。"]'),
('song-ci-312','祝英台近','汤恢','宋','宋词','song-ci','祝英台近','["\u6d1e\u5ead\u6e56"]','月如冰，天似水，冷浸画阑湿。',95,'宋词/ci.song.16000.json','["月如冰，天似水，冷浸画阑湿。", "桂树风前，醲香半狼藉。", "此翁对此良宵，别无可恨，恨只恨、古人头白。", "洞庭窄。", "谁道临水楼台，清光最先得。", "万里乾坤，原无片云隔。", "不妨彩笔云笺，翠尊冰酝，自管领、一庭秋色。"]'),
('song-ci-313','八声甘州','汤恢','宋','宋词','song-ci','八声甘州','[]','摘青梅荐酒，甚残寒、犹怯苎萝衣。',117,'宋词/ci.song.16000.json','["摘青梅荐酒，甚残寒、犹怯苎萝衣。", "正柳腴花瘦，绿云冉冉，红雪霏霏。", "隔屋秦筝依约，谁品春词。", "回首繁华梦，流水斜晖。", "寄隐孤山山下，但一瓢饮水，深掩苔扉。", "羡青山有思，白鹤忘机。", "怅年华、不禁搔首，又天涯、弹泪送春归。", "销魂远，千山啼鴂，十里荼䕷。"]'),
('song-ci-314','失调名','汤恢','宋','宋词','song-ci','失调名','[]','绾燕吟莺。',5,'宋词/ci.song.16000.json','["绾燕吟莺。"]'),
('song-ci-315','二郎神','汤恢','宋','宋词','song-ci','二郎神','[]','碧崖倒影，浸一片、寒江如练。',126,'宋词/ci.song.16000.json','["碧崖倒影，浸一片、寒江如练。", "正岸岸柳花，村村修竹，唤醒春风笔砚。", "溯水舟轻轻如叶，只消得、溪风一箭。", "看水部雄文，太师健笔，月寒波卷。", "游倦。", "片云孤鹤，江湖都遍。", "慨金屋藏妖，绣屏包祸，欲与三郎痛辩。", "回首前朝，断魂残照，几度山花崖藓。", "无限都付窊尊，漠漠水天远。"]'),
('song-ci-316','八声甘州','汤恢','宋','宋词','song-ci','八声甘州','[]','想当年、龙舟凤艒，乐宸游、摇曳锦帆斜。',33,'宋词/ci.song.16000.json','["想当年、龙舟凤艒，乐宸游、摇曳锦帆斜。", "伤心是，御香染处，树树栖鸦。"]'),
('song-ci-317','摸鱼儿','李演','宋','宋词','song-ci','摸鱼儿','[]','又西风、四桥疏柳，惊蝉相对秋语。',140,'宋词/ci.song.16000.json','["又西风、四桥疏柳，惊蝉相对秋语。", "琼荷万笠花云重，袅袅红衣如舞。", "鸿北去。", "渺岸芷汀芳，几点斜阳字。", "吴亭旧树。", "又系我扁舟，渔乡钓里，秋色淡归鹭。", "长干路。", "草莽疏烟断墅。", "商歌如写羁旅。", "丹溪翠岫登临事，苔屐尚黏苍土。", "鸥且住。", "怕月冷吟魂，婉冉空江暮。", "明灯暗浦。", "更短笛衔风，长云弄晚，天际画秋句。"]'),
('song-ci-318','声声慢','李演','宋','宋词','song-ci','声声慢','[]','轻鞯绣谷。',119,'宋词/ci.song.16000.json','["轻鞯绣谷。", "柔屐烟堤，六年遗赏新续。", "小舫重来，惟有寒沙鸥熟。", "徘徊旧情易冷，但溶溶、翠波如縠。", "愁望远，甚云销月老，暮山自绿。", "嚬笑人生悲乐，且听我尊前，渔歌樵曲。", "旧阁尘封，长得树阴如屋。", "凄凉五桥归路，载寒秀、一枝疏玉。", "翠袖薄，晚无言、空倚修竹。"]'),
('song-ci-319','醉桃源・阮郎归','李演','宋','宋词','song-ci','醉桃源・阮郎归','[]','双鸳初放步云轻。',56,'宋词/ci.song.16000.json','["双鸳初放步云轻。", "香帘蒸未晴。", "杏熔暗泪结红冰。", "留春蝴蝶情。", "寒薄薄，日阴阴。", "锦鸠花底鸣。", "春怀一似草无凭。", "东风吹又生。"]'),
('song-ci-320','南乡子','李演','宋','宋词','song-ci','南乡子','[]','芳水戏桃英。',66,'宋词/ci.song.16000.json','["芳水戏桃英。", "小滴燕支浸绿云。", "待觅琼觚藏彩信，流春。", "不似题红易得沈。", "天上许飞琼。", "吹下蓉笙染玉尘。", "可惜素鸾留不得，更深。", "误剪灯花断了心。"]'),
('song-ci-321','八六子','李演','宋','宋词','song-ci','八六子','[]','乍鸥边、一番腴绿，流红又怨苹花。',106,'宋词/ci.song.16000.json','["乍鸥边、一番腴绿，流红又怨苹花。", "看晚吹、约晴归路，夕阳分落渔家。", "轻云半遮。", "萦情芳草无涯。", "还报舞香一曲，玉瓢几许春华。", "正细柳青烟，旧时芳陌，小桃朱户，去年人面，谁知此日重来系马，东风淡墨敧鸦。", "黯窗纱。", "人归绿阴自斜。"]'),
('song-ci-322','祝英台近','李演','宋','宋词','song-ci','祝英台近','[]','采芳苹，萦去舻。',95,'宋词/ci.song.16000.json','["采芳苹，萦去舻。", "归步翠微雨。", "柳色如波，萦恨满烟浦。", "东君若是多情，未应花老，心已在、绿成阴处。", "困无语。", "柔被褰损梨云，间修牡丹谱。", "妒粉争香，双燕为谁舞。", "年年红紫如尘，五桥流水，知送了、几番愁去。"]'),
('song-ci-323','贺新凉・贺新郎','李演','宋','宋词','song-ci','贺新凉・贺新郎','[]','笛叫东风起。',142,'宋词/ci.song.16000.json','["笛叫东风起。", "弄尊前、杨花小扇，燕毛初紫。", "万点淮峰孤角外，惊下斜阳似绮。", "又婉娩、一番春意。", "歌舞相缪愁自猛，卷长波、一洗空人世。", "闲热我，醉时耳。", "绿芜冷叶瓜州市。", "最怜予、洞箫声尽，阑干独倚。", "落落东南墙一角，谁护山河万里。", "问人在、玉关归未。", "老矣青山灯火客，抚佳期、漫洒新亭泪。", "歌哽咽，事如水。"]'),
('song-ci-324','水调歌头','卫宗武','宋','宋词','song-ci','水调歌头','[]','风雨卷春去，绿紫总无馀。',114,'宋词/ci.song.16000.json','["风雨卷春去，绿紫总无馀。", "窈窕一川芳渚，软草接新蒲。", "杨柳垂垂飘絮，桑柘阴阴成幄，殷绿正棻敷。", "迁木莺呼友，营垒燕将雏。", "金蕉举，珠樱累，豆梅腴。", "寿乡歌舞，樽前暂得皱眉舒。", "往事南柯印绶，晚岁北山杖屦，寂寞笑今吾。", "幸作耆年侣，写入洛英图。"]'),
('song-ci-325','摸鱼儿','卫宗武','宋','宋词','song-ci','摸鱼儿','[]','小林峦、一年芳事，乱红还又飞雨。',140,'宋词/ci.song.16000.json','["小林峦、一年芳事，乱红还又飞雨。", "生香冉冉花阴转，云擘满空晴絮。", "游宴处。", "看乐意相关，庭下胎仙舞。", "歌声缓度。", "任圆玉敲寒，飞觞传晓，未许放春去。", "闲中趣。", "明月清风当户。", "莘莘容屋陈俎。", "翦裁妙语频赓唱，巧胜郢斤般斧。", "心自许。", "拼凋景颓龄，为莺俦燕侣。", "同盟会取。", "共花下小车，竹间三径，长作老宾主。"]'),
('song-ci-326','摸鱼儿','卫宗武','宋','宋词','song-ci','摸鱼儿','[]','见春来、又将春尽，狂风那更痴雨。',140,'宋词/ci.song.16000.json','["见春来、又将春尽，狂风那更痴雨。", "一番芳径催人老，回首绿杨飘絮。", "欢会处。", "有小小池亭，止欠妙歌舞。", "光阴梭度。", "对草木幽姿，候禽雅奏，客至未应去。", "十年里，冷落翟公庭户。", "朋来草草樽俎。", "投闲赢得浮生乐，肯羡油幢绣斧。", "春几许。", "任洛谱名葩，留宴耆英侣。", "浮荣竞取。", "纵带玉围腰，印金系肘，争似莺花主。"]'),
('song-ci-327','木兰花慢','卫宗武','宋','宋词','song-ci','木兰花慢','[]','聚林园芳景，尽输韩圃陶篱。',123,'宋词/ci.song.16000.json','["聚林园芳景，尽输韩圃陶篱。", "任雨虐风饕，露凝霜压，丛木离披。", "正色幽香不减，与冬兰、并秀结心知。", "天赋花中名节，不教桃李同时。", "清奇。", "秋后尤宜。", "浮卉尽、尚芬菲。", "称处士庭除，先生简册，声续吾伊。", "便好竹间松下，擅晚芳、长伴岁寒姿。", "懊恨携樽已晚，明年来把花枝。"]'),
('song-ci-328','酹江月・念奴娇','卫宗武','宋','宋词','song-ci','酹江月・念奴娇','[]','露华凝聚，夜更长、寒压一床衾重。',120,'宋词/ci.song.16000.json','["露华凝聚，夜更长、寒压一床衾重。", "局缩龟藏灯幌悄，明灭银釭欲冻。", "鼻观流珠，肌纹浮粟，敧枕难成梦。", "明蟾交映，一窗清影梅弄。", "晓见黄陨丹空，但琼华点缀，万梢森耸。", "橘柚香来分好景，书后尽堪题送。", "青女呈工，玉妃传信，渐六霙飞动。", "瑞花盈尽，看看叠嶂银涌。"]'),
('song-ci-329','酹江月・念奴娇','卫宗武','宋','宋词','song-ci','酹江月・念奴娇','[]','暮云凝冻，耸玉楼、拈断冰髯知几。',120,'宋词/ci.song.16000.json','["暮云凝冻，耸玉楼、拈断冰髯知几。", "今岁天公悭破白，未放六霙呈瑞。", "瘗马发祥，妖麋应祷，终解从人意。", "腊前三白，瑶光一瞬千里。", "便好翦刻漫空，落花飞絮，滚滚随风起。", "莫待东皇催整驾，点点消成春水。", "巧思裁云，新词胜雪，引动眉间喜。", "欺梅压竹，看看还助吟醉。"]'),
('song-ci-330','满江红','卫宗武','宋','宋词','song-ci','满江红','[]','屑玉飞霙，正堪称、冯夷展布。',115,'宋词/ci.song.16000.json','["屑玉飞霙，正堪称、冯夷展布。", "空几度、痴云凝聚，狂风掀舞。", "点点抛扬珠作霰，纤纤断续丝垂雨。", "借银河、翦刻六花飘，天应许。", "水漠漠，斜桥渡。", "烟淡淡，长亭路。", "望寒莎衰草，总成愁绪。", "坡老新堤须好在，逋仙孤屿犹堪去。", "共寻梅、止欠雪双清，烦青女。"]'),
('song-ci-331','满江红','卫宗武','宋','宋词','song-ci','满江红','[]','弧矢开祥，喜从此、旬兼九日。',115,'宋词/ci.song.16000.json','["弧矢开祥，喜从此、旬兼九日。", "新岁改、椒盘献颂，齐头七十。", "渐入唐人诸老画，可追洛社耆英集。", "有陶潜、三径健吟哦，贫而适。", "摘仙桂，探蟾窟。", "敛洪藻，归麟笔。", "总古先传记，讥评得失。", "不朽芬芳垂简册，浮荣土苴轻簪笏。", "看年如、卫武粲成章，诗传抑。"]'),
('song-ci-332','天仙子','卫宗武','宋','宋词','song-ci','天仙子','[]','搭宅亭园虽不大。',80,'宋词/ci.song.16000.json','["搭宅亭园虽不大。", "花木成阴难论价。", "豪端点缀有珠玑，竹一带。", "梅一派。", "明月清风何用买。", "子子孙孙纡寿彩。", "家庆成图和蔼蔼。", "更添三岁古来稀，酒满斝。", "诗满架。", "直到耆颐年未艾。"]'),
('song-ci-333','水龙吟','卫宗武','宋','宋词','song-ci','水龙吟','[]','桑蓬扫尽闲愁，未应人比梅花瘦。',126,'宋词/ci.song.16000.json','["桑蓬扫尽闲愁，未应人比梅花瘦。", "眉峰顿展，恰如云卷，北山□九。", "萦锦绣肠，袖丝纶手，骎骎希有。", "□□□博取，巍科□□，儒冠於我何负。", "初度年来年去，喜称觞、腊前还又。", "安时委命，金鱼玉带，傥来斯受。", "傍屋园林，抚松对竹，共朋三寿。", "且逍遥、安乐窝中，岁岁进、长生酒。"]'),
('song-ci-334','金缕曲・贺新郎','卫宗武','宋','宋词','song-ci','金缕曲・贺新郎','[]','强半秋澄穆。',142,'宋词/ci.song.16000.json','["强半秋澄穆。", "半月弦、南极躔高，寿星明煜。", "今岁户庭殊旧岁，洗尽闲愁千斛。", "沸春夏、欢声相续。", "兰已种成香满砌，更蕣华、得偶颜如玉。", "双捧劝，寿齐祝。", "郗枝芳映庄椿绿。", "觉这番、初度称觞，桂增芬馥。", "生子生孙从此始，剩有人传祖笏。", "看八座、青毡须复。", "两两闺中俱秀质，待子平、婚嫁人人足。", "碧桃下，跨青鹿。"]'),
('song-ci-335','沁园春','李敬则','宋','宋词','song-ci','沁园春','[]','南渡盛时，壬寅之秋，生此伟人。',140,'宋词/ci.song.16000.json','["南渡盛时，壬寅之秋，生此伟人。", "是皇家柱石，端平君子，吾儒宗主，意一先生。", "自起丹山，晋登紫府，天下欣然望太平。", "至夷狄，亦慕吾中国，司马声名。", "愿君为尧舜之君。", "举一世民皆尧舜民。", "羡当年三渐，直声已著，近来四蜀，先虑尤深。", "事验平凉，眷隆当宁，指日须还公秉钧。", "愿公寿，以寿吾国脉，以寿斯文。"]'),
('song-ci-336','玉楼春','吴益','宋','宋词','song-ci','玉楼春','[]','玉楼春信梅传早。',64,'宋词/ci.song.16000.json','["玉楼春信梅传早。", "三八芳辰阳复后。", "称觞喜对一椿高，莱庭双桂森兰茂。", "惭无好语为公寿。", "富贵荣华公自有，请歌诗雅祝遐龄，永如松柏如山阜。"]'),
('song-ci-337','绿头鸭・多丽','利登','宋','宋词','song-ci','绿头鸭・多丽','[]','晚春天。',173,'宋词/ci.song.16000.json','["晚春天。", "柳丝初透晴烟。", "黯离怀、绿房深处，艳游曾记当年。", "衬龙绡、亭亭玉树，步鸯褥、窄窄金莲。", "烧蜜调蜂，翦花挑蝶，香云微湿绿弯鬟。", "嬉游困，倚郎私语，还爱抚郎肩。", "共携手，海棠院左，翡翠帘边。", "恨无情、锦笼鹦鹉，等闲轻语花前。", "昔相怜、关山咫尺，今相望、咫尺关山。", "是妾心阑，是郎意懒，是郎无分妾无缘。", "都休问、金枝云里，何日跨金鸾。", "深盟在，香囊暗解，终值双鸳。"]'),
('song-ci-338','菩萨蛮','利登','宋','宋词','song-ci','菩萨蛮','[]','玉阑干外重帘晚。',52,'宋词/ci.song.16000.json','["玉阑干外重帘晚。", "流云欲度长天远。", "花草不知名。", "春来各自春。", "绿鞍游冶客。", "何处垂杨陌。", "不信不归来。", "海棠花又开。"]'),
('song-ci-339','玉楼春','利登','宋','宋词','song-ci','玉楼春','[]','夹帘不卷重堂暮。',64,'宋词/ci.song.16000.json','["夹帘不卷重堂暮。", "白骑少年何处去。", "云根稚藕已胜花，烟外子松今作树。", "金Ι月涩知无与。", "宝瑟风惊犹自语。", "斜河一道界相思，横隔天心寒似雾。"]'),
('song-ci-340','水调歌头','利登','宋','宋词','song-ci','水调歌头','[]','日月换飞涧，风雨老孤松。',114,'宋词/ci.song.16000.json','["日月换飞涧，风雨老孤松。", "千岩万壑秋重，白气接长空。", "一笑掀髯徐起，苍佩腰间相照，犹自涌晴虹。", "桑海几番覆，人尚醉春风。", "横白石，结绿绮，送飞鸿。", "十年梦事消歇，长剑吼青龙。", "却笑人间多事，一壳蜗涎光景，颠倒死英雄。", "云日空濛里，玉鹤任西东。"]'),
('song-ci-341','洞仙歌','利登','宋','宋词','song-ci','洞仙歌','[]','弄香吹粉，记前回酒困。',100,'宋词/ci.song.16000.json','["弄香吹粉，记前回酒困。", "绿露沈沈转花影。", "翠帘深，隐隐红雾依人，荷月静，新样双鸾交映。", "如今谁念省。", "短雨长云，曾托琵琶再三问。", "最苦绿屏孤，夜久星寒，无处顿、风流心性。", "又莫是偷香寄韩郎，到漏泄春风，一枝花信。"]'),
('song-ci-342','过秦楼','利登','宋','宋词','song-ci','过秦楼','[]','眉黛山分，靥朱星合，郁郁夜堂初见。',135,'宋词/ci.song.16000.json','["眉黛山分，靥朱星合，郁郁夜堂初见。", "芙蓉寄隐，豆蔻传香，便许翠鬟偷剪。", "迎夜易羞，欲晨先怯，风流楚楚未惯。", "正流苏帐掩，绿玉屏深，红香自暖。", "谁信道、媚月难留，惊云易散，从此三桥路远。", "巢燕春归，剪花词在，难寄红题一片。", "料想伊家，如今羞傍琴窗，慵题花院。", "但碧桃影下，应对流红自叹。"]'),
('song-ci-343','齐天乐','利登','宋','宋词','song-ci','齐天乐','[]','淡云荒草秋汀暮，归心又寒烟水。',123,'宋词/ci.song.16000.json','["淡云荒草秋汀暮，归心又寒烟水。", "论槛移花，量船载酒，寂寞当年情味。", "孤蓬夜闭。", "听四壁松声，欲高还细。", "似近如遥，露鸿声乱楚天外。", "蓝桥人断岁久，旧家曾共赏，九华花事。", "艳雪初融，生香自暖，消得金莲贴地。", "相思破睡。", "谩一点琴心，暗关千里。", "愁怯潮生，晓帆风又起。"]'),
('song-ci-344','鹧鸪天','利登','宋','宋词','song-ci','鹧鸪天','[]','凤尾鬟香再叠梳。',64,'宋词/ci.song.16000.json','["凤尾鬟香再叠梳。", "藕丝衫嫩蹙双鱼。", "闲收末利熏藤枕，自插芙蓉绕翠幮。", "新浴后，浅妆初。", "卫夫人帖学行书。", "西窗一霎黄昏雨，笑问新凉饮酒无。"]'),
('song-ci-345','风流子','利登','宋','宋词','song-ci','风流子','[]','梨园花柳地，扶残醉、曾记问妖娆。',135,'宋词/ci.song.16000.json','["梨园花柳地，扶残醉、曾记问妖娆。", "叹惹住轻烟，柔丝未改，霏零疏雨，腻粉先飘。", "更低道，花无三日艳，柳有一年娇。", "卷翠未迟，醉红易失，共偎香影，同赏良宵。", "如今知何处，三山远，云水一望迢迢。", "傍砌青鸾好在，谁送归飚。", "但花下红云，尚通夕照，柳边白月，自落寒潮。", "最是无端，子规啼破寒梢。"]'),
('song-ci-346','风入松','利登','宋','宋词','song-ci','风入松','[]','断芜幽树际烟平。',90,'宋词/ci.song.16000.json','["断芜幽树际烟平。", "山外又山青。", "天南海北知何极，年年是、匹马孤征。", "看尽好花成子，暗惊新笋抽林。", "岁华情事苦相寻。", "弱雪鬓毛侵。", "十千斗酒悠悠醉，斜河界、白日云心。", "孤鹤尽边天阔，清猿咽处山深。"]'),
('song-ci-347','水调歌头','利登','宋','宋词','song-ci','水调歌头','[]','相聚不知好，相别始知愁。',112,'宋词/ci.song.16000.json','["相聚不知好，相别始知愁。", "笋舆伊轧，穿尽斜照古平州。", "今夜荒风脱木，明夜山长水远，后夜已他州。", "转觉家山远，何计去来休。", "酒堪沽，花可买，月能留。", "相思酒醒，花落五更头。", "长记疏梅影底，一笛紫云飞动，相对大江流。", "此别无一月，一月一千秋。"]'),
('song-ci-348','失调名','利登','宋','宋词','song-ci','失调名','[]','花外潮回，剑边虹去，抚寒江千里。',16,'宋词/ci.song.16000.json','["花外潮回，剑边虹去，抚寒江千里。"]'),
('song-ci-349','虞美人','利登','宋','宋词','song-ci','虞美人','[]','当时养士知何许。',33,'宋词/ci.song.16000.json','["当时养士知何许。", "总把降幡去。", "汉家王气塞乾坤。", "一树盈盈、不为汉家春。"]'),
('song-ci-350','沁园春','吴势卿','宋','宋词','song-ci','沁园春','[]','碧瓦霜融，绣阁寒经，春浮寿杯。',139,'宋词/ci.song.16000.json','["碧瓦霜融，绣阁寒经，春浮寿杯。", "羡华年七帙，人生稀有，新阳七日，天意安排。", "丹凤门开，黄麾仗立，此际应须召促回。", "人道是，却暂时绣斧，索笑盐梅。", "旴江假守非才，犹记得当时传庾台。", "算良机再会，抠衣来久，归鞭何速，祝寿方才。", "应与邦人，传为佳话，只为先生诞日来。", "明年看，是侬方九曲，公已三台。"]'),
('song-ci-351','满江红','刘浩','宋','宋词','song-ci','满江红','[]','岳渎储精，冰壶里、精神可掬。',115,'宋词/ci.song.16000.json','["岳渎储精，冰壶里、精神可掬。", "三万卷、龙蛇落纸，琅玕撑腹。", "便合弹冠登要路。", "如何袖手缄空谷。", "又谁知、天独授先生，长生箓。", "鹤易怨，龟多缩。", "竹太瘦，梅偏独。", "算人间何物，可传心曲。", "但愿君如天上月，年年此夜团如玉。", "更有人、千里共蝉娟，偷香祝。"]'),
('song-ci-352','沁园春','赵希汰','宋','宋词','song-ci','沁园春','[]','持节浙东，六十年前，紫阳老师。',139,'宋词/ci.song.16000.json','["持节浙东，六十年前，紫阳老师。", "看粟移七郡，功深到处，棠阴一道，民尚思之。", "心印亲传，雨岩来括，寅岁幸无庚子饥。", "仁同视，更备存先具，仓积千斯。", "青州阴德天知。", "只此事堪为崧岳祈。", "与太夫人寿，相看华发，转中书令，长著斑衣。", "岁岁梅花，樽前索笑，霜月先圆两夜规。", "称觞了，报春风千里，班觐龙墀。"]'),
('song-ci-353','西江月','徐俨夫','宋','宋词','song-ci','西江月','[]','曲折迷春院宇，参差近水楼台。',58,'宋词/ci.song.16000.json','["曲折迷春院宇，参差近水楼台。", "吹箫人去燕归来。", "空有落梅香在。", "花底三更过雨，酒阑一枕惊雷。", "明朝飞梦隔天涯。", "肠断流莺声碎。"]'),
('song-ci-354','宝鼎现','陈合','宋','宋词','song-ci','宝鼎现','[]','神鳌谁断，几千年再，乾坤初造。',190,'宋词/ci.song.16000.json','["神鳌谁断，几千年再，乾坤初造。", "算当日、枰棋如许，争一著、吾其衽左。", "谈笑顷、又十年生聚，处处豳风葵枣。", "江如镜，楚氛馀几，猛听甘泉捷报。", "天衣细意从头补。", "烂山龙、华虫黼藻。", "宫漏永、千门鱼钥，截断红尘飞不到。", "街九轨，看千貂避路，庭院五侯深锁。", "好一部、太平六典，一一周公手做。", "赤舄绣裳，消得道、斑斓衣好。", "尽庞眉鹤发，天上千秋难老。", "甲子平头才一过，未说汾阳考。", "看金盘，露滴瑶池，龙尾放班回早。"]'),
('song-ci-355','木兰花慢','李芸子','宋','宋词','song-ci','木兰花慢','[]','占西风早处，一番雨，一番秋。',123,'宋词/ci.song.16000.json','["占西风早处，一番雨，一番秋。", "记故国斜阳，去年今日，落叶林幽。", "悲歌几回激烈，寄疏狂、酒令与诗筹。", "遗恨清商易改，多情紫燕难留。", "嗟休。", "触绪茧丝抽。", "旧事续何由。", "奈予怀渺渺，羁愁郁郁，归梦悠悠。", "生平不如老杜，便如它、飘泊也风流。", "寄语庭柯径竹，甚时得棹孤舟。"]'),
('song-ci-356','洞仙歌','张韫','宋','宋词','song-ci','洞仙歌','[]','花泥絮浪，殢春怀如酒。',99,'宋词/ci.song.16000.json','["花泥絮浪，殢春怀如酒。", "书卷炉熏梦清昼。", "唤玉京稳携手松乔，飞光里，笑傲白云林岫。", "仙人犹狡狯，洒雪吹冰，声落星河翠蛟走。", "问箬下留丹，别已千年，华表鹤、亦归来否。", "有洞口、桃花识刘郎，共一笑相迎，朱颜如旧。"]'),
('song-ci-357','念奴娇','游子西','宋','宋词','song-ci','念奴娇','[]','暑尘收尽，快晚来急雨，一番初过。',120,'宋词/ci.song.16000.json','["暑尘收尽，快晚来急雨，一番初过。", "是处凉飙回爽气，直把残云吹破。", "星律飞流，银河摇荡，只恐冰轮堕。", "云梯稳上，琼楼今夜无锁。", "便觉浮世卑沈，回翔偃薄，似蚁空旋磨。", "想得九天高绝处，不比人间更火。", "独立乾坤，浩歌春雪，可惜无人和。", "广寒宫里，有谁潇洒如我。"]'),
('song-ci-358','清平乐','施乘之','宋','宋词','song-ci','清平乐','[]','风消云缕。',54,'宋词/ci.song.16000.json','["风消云缕。", "一碧无今古。", "欲坏上元天不许。", "晴了晚来些雨。", "莫言冷落山家。", "山翁本厌繁华。", "试问莲灯千炬，何如月上梅花。"]'),
('song-ci-359','八声甘州','周济川','宋','宋词','song-ci','八声甘州','["\u897f\u6e56"]','有乾坤、清气入诗脾，随龙散神仙。',119,'宋词/ci.song.16000.json','["有乾坤、清气入诗脾，随龙散神仙。", "蘸西湖和墨，长空为纸，几度诗圆。", "消得宫妃捧砚，夜烛照金莲。", "试问隔屏坐，谁后谁先。", "长是花香柳色，更风清月白，天入吟笺。", "自霞觞误覆，谪下玉皇边。", "笑随归、山中随隐，且醉拼、斗酒写新篇。", "天应笑，呼来时后，记上襟船。"]'),
('song-ci-360','点绛唇','应次蘧','宋','宋词','song-ci','点绛唇','[]','雪意娇春，腊前妆点春风面。',50,'宋词/ci.song.16000.json','["雪意娇春，腊前妆点春风面。", "粉痕冰片。", "一笑重相见。", "倚竹偎松，谁道罗浮远。", "寒更转。", "楚骚为伴。", "韵绕香篝暖。"]'),
('song-ci-361','水龙吟','李璮','宋','宋词','song-ci','水龙吟','[]','腰刀首帕从军，戍楼独倚闲凝眺。',125,'宋词/ci.song.16000.json','["腰刀首帕从军，戍楼独倚闲凝眺。", "中原气象，狐居兔穴，暮烟残照。", "投笔书怀，枕戈待旦，陇西年少。", "叹光阴掣电，易生髀肉，不如易腔改调。", "世变沧海成田，奈群生、几番惊扰。", "干戈烂漫，无时休息，凭谁驱扫。", "眼底山河，胸中事业，一声长啸。", "太平时、相将近也，稳稳百年燕赵。"]'),
('song-ci-362','贺新郎','黄升','宋','宋词','song-ci','贺新郎','[]','倦整摩天翼。',141,'宋词/ci.song.16000.json','["倦整摩天翼。", "笑归来、点画亭台，按行泉石。", "落落元龙湖海气，更著高楼百尺。", "收揽尽、水光山色。", "曾驾飚车蟾宫去，几回批、借月支风敕。", "斯二者，惯相识。", "玲珑窗户青红湿。", "夜深时、寒光爽气，洗清肝膈。", "似此交游真洒落，判与升堂入室。", "有万象、来为宾客。", "不用笙歌轻点涴，看仙翁手搦虹霓笔。", "吟思远，两峰碧。"]'),
('song-ci-363','贺新郎','黄升','宋','宋词','song-ci','贺新郎','[]','风送行春步。',142,'宋词/ci.song.16000.json','["风送行春步。", "渐行行、山回路转，入云深处。", "问讯花梢春几许，半在诗人杖屦。", "点点是、祥烟膏露。", "中有瑶池千岁种，整严妆、来作巢仙侣。", "相妩媚，试凝伫。", "风流坐上挥谈尘。", "更多情、多才多调，缓歌金缕。", "趁取芳时同宴赏，莫惜清樽缓举。", "有明月、随人归去。", "从此一春须一到，愿东君、长与花为主。", "泉共石，闻斯语。"]'),
('song-ci-364','贺新郎','黄升','宋','宋词','song-ci','贺新郎','[]','莫恨黄花瘦。',142,'宋词/ci.song.16000.json','["莫恨黄花瘦。", "正千林、风霜摇落，暮秋时候。", "晚节相看元不恶，采采东篱独秀。", "试揽结、幽香盈手。", "几劫修来方得到，与渊明、千载为知旧。", "同冷淡，比兰友。", "柴桑心事君知否。", "把人间、功名富贵，付之尘垢。", "不肯折腰营口腹，一笑归欤五柳。", "怅此意、而今安有。", "若得风流如此老，也何妨、相对无杯酒。", "诗自可，了重九。"]'),
('song-ci-365','贺新郎','黄升','宋','宋词','song-ci','贺新郎','[]','自扫梅花下。',142,'宋词/ci.song.16000.json','["自扫梅花下。", "问梢头、冷蕊疏疏，几时开也。", "间者阔焉今久矣，多少幽怀欲写。", "有谁是、孤山流亚。", "香月一联真绝唱，与诗人、千载为嘉话。", "馀兴味，付来者。", "清癯不恋华亭榭。", "待与君、白发相亲，竹篱茅舍。", "喜甚今年无酒禁，溜溜小槽压蔗。", "已准拟、雪天霜夜。", "自醉自吟仍自笑，任解冠、落珮从嘲骂。", "书此意，寄同社。"]'),
('song-ci-366','木兰花慢','黄升','宋','宋词','song-ci','木兰花慢','[]','自沈香梦断，风雨外、失馀春。',122,'宋词/ci.song.16000.json','["自沈香梦断，风雨外、失馀春。", "怅袍锦淋漓，金銮论奏，四海无人。", "蛾眉古来见妒，奈昭阳、飞燕亦成尘。", "惟有空梁落月，至今能为传神。", "神游八表跨长鲸。", "谁是再来身。", "爱云月溪头，玉环一曲，笔力千钧。", "人间不堪著眼，但香名、百世尚如新。", "乞我九霞蜚佩，梯空共上秋旻。"]'),
('song-ci-367','木兰花慢','黄升','宋','宋词','song-ci','木兰花慢','[]','问潘郎两鬓，更禁得、几番秋。',123,'宋词/ci.song.16000.json','["问潘郎两鬓，更禁得、几番秋。", "怅病骨臞臞，幽怀渺渺，短发飕飕。", "云边一声长笛，这风情、多属赵家楼。", "敧枕困寻药裹，薰衣慵讯香篝。", "悠悠。", "老矣复焉求。", "何止赋三休。", "念少日书癖，中年酒病，晚岁诗愁。", "已攀桂花作证，便从今、把笔一齐勾。", "只有烟霞痼疾，相陪风月交游。"]'),
('song-ci-368','木兰花慢','黄升','宋','宋词','song-ci','木兰花慢','[]','问春春不语，谩新绿、满芳洲。',123,'宋词/ci.song.16000.json','["问春春不语，谩新绿、满芳洲。", "记历历前游，看花南陌，命酒西楼。", "东风翠红围绕，把功名、一笑付糟丘。", "醉里了忘身世，吟边自负风流。", "风流。", "莫莫复休休。", "白发渐盈头。", "怅十载重来，略无欢意，惟有闲愁。", "多情向人似旧，但小桃、婀娜柳纤柔。", "望断残霞落日，水天拍拍飞鸥。"]'),
('song-ci-369','南柯子・南歌子','黄升','宋','宋词','song-ci','南柯子・南歌子','[]','天上传新火，人间试夹衣。',62,'宋词/ci.song.16000.json','["天上传新火，人间试夹衣。", "定巢新燕觅香泥。", "不为绣帘朱户、说相思。", "侧帽吹飞絮，凭栏送落晖。", "粉痕销淡锦书稀。", "怕见山南山北、子规啼。"]'),
('song-ci-370','南柯子・南歌子','黄升','宋','宋词','song-ci','南柯子・南歌子','[]','兰佩秋风冷，茱囊晓露新。',62,'宋词/ci.song.16000.json','["兰佩秋风冷，茱囊晓露新。", "多情多感怯芳辰。", "强折黄花来照、碧粼粼。", "落帽参军醉，空樽靖节贫。", "世间那复有斯人。", "目送归鸿西去、一伤神。"]'),
('song-ci-371','行香子','黄升','宋','宋词','song-ci','行香子','[]','寒意方浓。',84,'宋词/ci.song.16000.json','["寒意方浓。", "暖信才通。", "是晴阳、暗拆花封。", "冰霜作骨，玉雪为容。", "看体清癯，香淡伫，影朦胧。", "孤城小驿，断角残钟。", "又无边、散与春风。", "芳心一点，幽恨千重。", "任雪霏霏，云漠漠，月溶溶。"]'),
('song-ci-372','卖花声','黄升','宋','宋词','song-ci','卖花声','[]','莺蝶太匆匆。',64,'宋词/ci.song.16000.json','["莺蝶太匆匆。", "恼杀衰翁。", "牡丹开尽状元红。", "俯仰之间增感慨，花事成空。", "垂柳绿阴中。", "粉絮濛濛。", "多情多病转疏慵。", "不是东风孤负我，我负东风。"]'),
('song-ci-373','卖花声','黄升','宋','宋词','song-ci','卖花声','[]','秋色满层霄。',64,'宋词/ci.song.16000.json','["秋色满层霄。", "剪剪寒飚。", "一襟残照两无聊。", "数尽归鸦人不见，落木萧萧。", "往事欲魂消。", "梦想风标。", "春江绿涨水平桥。", "侧帽停鞭沽酒处，柳软莺娇。"]'),
('song-ci-374','长相思','黄升','宋','宋词','song-ci','长相思','[]','天悠悠。',44,'宋词/ci.song.16000.json','["天悠悠。", "水悠悠。", "月印金枢晓未收。", "笛声人倚楼。", "芦花秋。", "蓼花秋。", "催得吴霜点鬓稠。", "香笺莫寄愁。"]'),
('song-ci-375','长相思','黄升','宋','宋词','song-ci','长相思','[]','砧声齐。',44,'宋词/ci.song.16000.json','["砧声齐。", "杵声齐。", "金井栏边败叶飞。", "夜寒乌不栖。", "风凄凄。", "露凄凄。", "影转梧桐月已西。", "花冠窗外啼。"]'),
('song-ci-376','长相思','黄升','宋','宋词','song-ci','长相思','[]','惜春归。',44,'宋词/ci.song.16000.json','["惜春归。", "爱春归。", "脱了罗衣著苎衣。", "绿阴黄鸟啼。", "酒醒时。", "梦醒时。", "清簟疏帘一局棋。", "丁东风马儿。"]'),
('song-ci-377','感皇恩','黄升','宋','宋词','song-ci','感皇恩','[]','骑鹤上扬州，腰缠十万。',81,'宋词/ci.song.16000.json','["骑鹤上扬州，腰缠十万。", "拈起诗人旧公案。", "看山看水，此去胜游须遍。", "烦君收拾取，归吟卷。", "少日风流，暮年萧散。", "佳处何妨小留款。", "沙河塘上，落日绣帘争卷。", "也须拂拭起，看花眼。"]'),
('song-ci-378','蝶恋花','黄升','宋','宋词','song-ci','蝶恋花','[]','百计留春春不住。',70,'宋词/ci.song.16000.json','["百计留春春不住。", "褪粉吹香，日日催教去。", "心事欲凭莺语诉。", "流莺划地无凭据。", "绿玉阑干围绮户。", "一点柔红，应在深深处。", "想倚翠帘吹柳絮。", "浅颦惆怅芳期误。"]'),
('song-ci-379','月照梨花・河传','黄升','宋','宋词','song-ci','月照梨花・河传','[]','昼景。',68,'宋词/ci.song.16000.json','["昼景。", "方永。", "重帘花影。", "好梦犹酣，莺声唤醒。", "门外风絮交飞。", "送春归。", "修蛾画了无人问。", "几多别恨。", "泪洗残妆粉。", "不知郎马何处嘶。", "烟草萋迷。", "鹧鸪啼。"]'),
('song-ci-380','摸鱼儿','黄升','宋','宋词','song-ci','摸鱼儿','[]','问山中、小桃开后，曾经多少晴雨。',140,'宋词/ci.song.16000.json','["问山中、小桃开后，曾经多少晴雨。", "遥知载酒花边去，唱我旧歌金缕。", "行乐处。", "正蝶绕蜂围，锦绣迷无路。", "风光有主。", "想倚杖西阡，停杯北望，望断碧云暮。", "花知道，应倩蜚鸿寄语。", "年来老子安否。", "一春一到成虚约，不道树犹如此。", "烦说与。", "但岁岁、东风妆点红云坞。", "刘郎老去。", "待有日重来，同君一笑，拈起看花句。"]'),
('song-ci-381','水龙吟','黄升','宋','宋词','song-ci','水龙吟','[]','少年有志封侯，弯弓欲挂扶桑外。',126,'宋词/ci.song.16000.json','["少年有志封侯，弯弓欲挂扶桑外。", "一朝敛缩，萧然清兴，了无拘碍。", "袖里阴符，枕中鸿宝，功名蝉蜕。", "看舌端霹雳，剧谈玄妙，人间世、疑无对。", "阆苑醉乡佳处，想当年、绿阴犹在。", "群仙寄语，不须点勘，鬼神功罪。", "碧海千寻，赤城万丈，风高浪快。", "待踞龟食蛤，相期汗漫，与烟霞会。"]'),
('song-ci-382','西河','黄升','宋','宋词','song-ci','西河','[]','天似洗。',124,'宋词/ci.song.16000.json','["天似洗。", "残秋未有寒意。", "何人短笛弄西风，数声壮伟。", "倚栏感慨展双眸，离离烟树如荠。", "少年事，成梦里。", "客愁付与流水。", "笔床茶具老空山，未妨肆志。", "世间富贵要时贤，深居宜有馀味。", "大江东去日西坠。", "想悠悠千古兴废。", "此地阅人多矣。", "且挥弦寄兴、氛埃之外。", "目送蜚鸿归天际。"]'),
('song-ci-383','清平乐','黄升','宋','宋词','song-ci','清平乐','[]','珠帘寂寂。',54,'宋词/ci.song.16000.json','["珠帘寂寂。", "愁背银缸泣。", "记得少年初选入。", "三十六宫第一。", "当年掌上承恩。", "而今冷落长门。", "又是羊车过也，月明花落黄昏。"]'),
('song-ci-384','清平乐','黄升','宋','宋词','song-ci','清平乐','[]','深深禁篽。',54,'宋词/ci.song.16000.json','["深深禁篽。", "霁日明莺羽。", "风动槐龙交翠舞。", "恰恰花阴亭午。", "一帘暖絮悠扬。", "金炉旋炷沈香。", "天子方看谏疏，内人休斗新妆。"]'),
('song-ci-385','酹江月・念奴娇','黄升','宋','宋词','song-ci','酹江月・念奴娇','[]','玉林何有，有一弯莲沼，数间茅宇。',120,'宋词/ci.song.16000.json','["玉林何有，有一弯莲沼，数间茅宇。", "断堑疏篱聊补葺，那得粉墙朱户。", "禾黍秋风，鸡豚晓日，活脱田家趣。", "客来茶罢，自挑野菜同煮。", "多少甲第连云，十眉环座，人醉黄金坞。", "回首邯郸春梦破，零落珠歌翠舞。", "得似衰翁，萧然陋巷，长作溪山主。", "紫芝可采，更寻岩谷深处。"]'),
('song-ci-386','酹江月・念奴娇','黄升','宋','宋词','song-ci','酹江月・念奴娇','[]','西风解事，为人间、洗尽三庚烦暑。',120,'宋词/ci.song.16000.json','["西风解事，为人间、洗尽三庚烦暑。", "一枕新凉宜客梦，飞入藕花深处。", "冰雪襟怀，琉璃世界，夜气清如许。", "划然长啸，起来秋满庭户。", "应笑楚客才高，兰成愁悴，遗恨传千古。", "作赋吟诗空自好，不直一杯秋露。", "淡月阑干，微云河汉，耿耿天催曙。", "此情谁会，梧桐叶上疏雨。"]'),
('song-ci-387','浣沙溪・浣溪沙','黄升','宋','宋词','song-ci','浣沙溪・浣溪沙','[]','锺磬泠泠夜未央。',48,'宋词/ci.song.16000.json','["锺磬泠泠夜未央。", "梨花庭院月如霜。", "步虚声里拜瑶章。", "紫极清都云渺渺，红尘浊世事茫茫。", "未知谁有返魂香。"]'),
('song-ci-388','鹧鸪天','黄升','宋','宋词','song-ci','鹧鸪天','[]','沈水香销梦半醒。',64,'宋词/ci.song.16000.json','["沈水香销梦半醒。", "斜阳恰照竹间亭。", "戏临小草书团扇，自拣残花插净瓶。", "莺宛转，燕丁宁。", "晴波不动晚山青。", "玉人只怨春归去，不道槐云绿满庭。"]'),
('song-ci-389','鹧鸪天','黄升','宋','宋词','song-ci','鹧鸪天','[]','雨过芙蕖叶叶凉。',64,'宋词/ci.song.16000.json','["雨过芙蕖叶叶凉。", "摩挲短发照横塘。", "一行归鹭拖秋色，几树鸣蝉饯夕阳。", "花侧畔，柳旁相。", "微云澹月又昏黄。", "风流不在谈锋胜，袖手无言味最长。"]'),
('song-ci-390','秦楼月・忆秦娥','黄升','宋','宋词','song-ci','秦楼月・忆秦娥','[]','心如结。',56,'宋词/ci.song.16000.json','["心如结。", "西风老尽黄花节。", "黄花节。", "塞鸿声断，冷烟凄月。", "汉朝陵庙唐宫阙。", "兴衰万变从谁说。", "从谁说。", "千年青史，几人华发。"]'),
('song-ci-391','重叠金・菩萨蛮','黄升','宋','宋词','song-ci','重叠金・菩萨蛮','[]','西风半夜惊罗扇。',52,'宋词/ci.song.16000.json','["西风半夜惊罗扇。", "蛩声入梦传幽怨。", "碧藕试初凉。", "露痕啼粉香。", "清冰凝簟竹。", "不许双鸳宿。", "又是五更钟。", "鸦啼金井桐。"]'),
('song-ci-392','重叠金・菩萨蛮','黄升','宋','宋词','song-ci','重叠金・菩萨蛮','[]','南山未解松梢雪。',52,'宋词/ci.song.16000.json','["南山未解松梢雪。", "西山已挂梅梢月。", "说似玉林人。", "人间无此清。", "此身元是客。", "小住娱今夕。", "拍手凭阑干。", "霜风吹鬓寒。"]'),
('song-ci-393','重叠金・菩萨蛮','黄升','宋','宋词','song-ci','重叠金・菩萨蛮','[]','银幡彩胜参差剪。',52,'宋词/ci.song.16000.json','["银幡彩胜参差剪。", "东风吹上钗头燕。", "一笑绕花身。", "小桃先报春。", "新春今日是。", "明日新年至。", "擘茧莫探官。", "人间行路难。"]'),
('song-ci-394','谒金门','黄升','宋','宋词','song-ci','谒金门','[]','花事浅。',53,'宋词/ci.song.16000.json','["花事浅。", "方费化工匀染。", "墙角红梅开未遍。", "小桃才数点。", "人在暮寒庭院。", "闲续茶经香传。", "酒思如冰诗思懒。", "雨声帘不卷。"]'),
('song-ci-395','南乡子','黄升','宋','宋词','song-ci','南乡子','[]','多病带围宽。',66,'宋词/ci.song.16000.json','["多病带围宽。", "未到衰年已鲜欢。", "梦破小楼风马响，珊珊。", "缺月无情转画栏。", "凉入苎衾单。", "起探灯花夜欲阑。", "书册满床空伴睡，慵观。", "拈得渔樵笛谱看。"]'),
('song-ci-396','南乡子','黄升','宋','宋词','song-ci','南乡子','[]','万籁寂无声。',66,'宋词/ci.song.16000.json','["万籁寂无声。", "衾铁棱棱近五更。", "香断灯昏吟未稳，凄清。", "只有霜华伴月明。", "应是夜寒凝。", "恼得梅花睡不成。", "我念梅花花念我，关情。", "起看清冰满玉瓶。"]'),
('song-ci-397','花发沁园春','黄升','宋','宋词','song-ci','花发沁园春','[]','晓燕传情，午莺喧梦，起来检校芳事。',128,'宋词/ci.song.16000.json','["晓燕传情，午莺喧梦，起来检校芳事。", "荼䕷褪雪，杨柳吹绵，迤逦麦秋天气。", "翻阶傍砌。", "看芍药、新妆娇媚。", "正凤紫匀染绡裳，猩红轻透罗袂。", "昼暖朱阑困倚。", "是天姿妖娆，不减姚魏。", "随蜂惹粉，趁蝶栖香，引动少年情味。", "花浓酒美。", "人正在、翠红围里。", "问谁是、第一风流，折花簪向云髻。"]'),
('song-ci-398','阮郎归','黄升','宋','宋词','song-ci','阮郎归','[]','粉香吹暖透单衣。',56,'宋词/ci.song.16000.json','["粉香吹暖透单衣。", "金泥双凤飞。", "闲来花下立多时。", "春风酒醒迟。", "桃叶曲，柳枝词。", "芳心空自知。", "湘皋月冷佩声微。", "雁归人不归。"]'),
('song-ci-399','鹊桥仙','黄升','宋','宋词','song-ci','鹊桥仙','[]','青林雨歇，珠帘风细，人在绿阴庭院。',68,'宋词/ci.song.16000.json','["青林雨歇，珠帘风细，人在绿阴庭院。", "夜来能有几多寒，已瘦了、梨花一半。", "宝钗无据，玉琴难托，合造一襟幽怨。", "云窗雾阁事茫茫，试与问、杏梁双燕。"]'),
('song-ci-400','鹧鸪天','黄升','宋','宋词','song-ci','鹧鸪天','[]','天气清和仅两旬。',64,'宋词/ci.song.16000.json','["天气清和仅两旬。", "一旬前是佛生辰。", "当年来应徐卿梦，此夕遥瞻寿宿明。", "拼一笑，对诸贤。", "山翁何以祝龟龄。", "蟠桃瓜枣皆虚诞，愿把阴功福后人。"]'),
('song-ci-401','瑞龙吟','杨泽民','宋','宋词','song-ci','瑞龙吟','[]','城南路。',163,'宋词/ci.song.16000.json','["城南路。", "凝望映竹摇风，酒旗标树。", "郊原游子停车，问山崦里，人家甚处。", "去还伫。", "徐见画桥流水，小窗低户。", "深沈绿满垂杨，芳阴娅姹，娇莺解语。", "多谢佳人情厚，卷帘羞得，庭花飘舞。", "可谓望风知心，倾盖如故。", "犹殢香玉，休赋断肠句。", "堪怜处、生尘罗袜，凌波微步。", "底事匆匆去。", "为他系绊，离情万绪。", "空有愁如缕。", "忆桃李春风，梧桐秋雨。", "又还过却，落花飘絮。"]'),
('song-ci-402','琐窗寒','杨泽民','宋','宋词','song-ci','琐窗寒','[]','倦拂鸳衾，羞临鹊鉴，懒开窗户。',122,'宋词/ci.song.16000.json','["倦拂鸳衾，羞临鹊鉴，懒开窗户。", "韶华暗度，又过妒花风雨。", "掩熏炉、怕闻旧香，柳阴只有黄莺语。", "似向人、欲说离愁，因念未归行旅。", "春暮。", "知何处。", "便不念芳年，正当三五。", "轻衫快马，去逐狂朋怪侣。", "便罗帷、香阁顿忘，枕边要语曾记否。", "趁芳时、即早归来，尚可殢清俎。"]'),
('song-ci-403','风流子','杨泽民','宋','宋词','song-ci','风流子','[]','佳胜古钱塘。',135,'宋词/ci.song.16000.json','["佳胜古钱塘。", "帝居丽、金屋对昭阳。", "有风月九衢，凤皇双阙，万年芳树，千雉宫墙。", "户十万，家家堆锦绣，处处鼓笙簧。", "三竺胜游，两峰奇观，涌金仙舸，丰乐霞觞。", "芙蓉城何似，楼台簇中禁，帘卷东厢。", "盈望虎貔分列，鸳鹭成行。", "向玉宇夜深，时闻天乐，绛霄风软，吹下炉香。", "惟恨小臣资浅，朝觐犹妨。"]'),
('song-ci-404','渡江云','杨泽民','宋','宋词','song-ci','渡江云','["\u957f\u6c5f"]','渔乡回落照，晚风势急，骛鹭集汀沙。',124,'宋词/ci.song.16000.json','["渔乡回落照，晚风势急，骛鹭集汀沙。", "解鞍将憩息，细径疏篱，竹隐两三家。", "山肴野蔌，竞素朴、都没浮华。", "回望时，绕村流水，万点舞寒鸦。", "休嗟。", "明年秋暮，一叶扁舟，望平川北下。", "应免劳、尘巾乌帽，宵炬红纱。", "青蓑短棹长江碧，弄几曲、羌管吹葭。", "人借问，鸣桹便入芦花。"]'),
('song-ci-405','应天长','杨泽民','宋','宋词','song-ci','应天长','[]','夭桃弄粉，繁杏透香，依然旧日颜色。',120,'宋词/ci.song.16000.json','["夭桃弄粉，繁杏透香，依然旧日颜色。", "奈彼妒花风雨，连阴过寒食。", "金钗试寻妙客。", "正昼永、院深人寂。", "善歌更解舞，传闻触处声藉。", "当日俊游时，屡向平康，吟咏共题壁。", "自后纵经回曲，难寻阿姨宅。", "芳华苑，罗绮陌。", "怎断得、怪踪狂迹。", "惯来往，柳外花间，莺燕都识。"]'),
('song-ci-406','荔枝香','杨泽民','宋','宋词','song-ci','荔枝香','[]','瞰水自多佳处。',92,'宋词/ci.song.16000.json','["瞰水自多佳处。", "春未去。", "绣桷斗起凌空，隐隐笼轻雾。", "已飞画栋朝云，又卷西山雨。", "相与。", "共煮新茶取花乳。", "开宴处。", "俯北榭、临南浦。", "迤扁逦舟，双浆棹歌齐举。", "座上嘉宾，妙句无非赋鹦鹉。", "莫惜高烧蜡炬。"]'),
('song-ci-407','荔枝香','杨泽民','宋','宋词','song-ci','荔枝香','[]','未论离亭话别，涕先泫。',91,'宋词/ci.song.16000.json','["未论离亭话别，涕先泫。", "旋涤瑶觯，深挹芳醪，凝愁满眼。", "偎人大白须卷。", "歌遍。", "三劝。", "记得当时送□远。", "素蟾屡明晦，彩云易散。", "后约难知，又却似、阳关宴。", "乌丝写恨，帕子分香为郎翦。", "愿郎安信频遣。"]'),
('song-ci-408','还京乐','杨泽民','宋','宋词','song-ci','还京乐','[]','春光至，欲访清歌妙舞重为理。',125,'宋词/ci.song.16000.json','["春光至，欲访清歌妙舞重为理。", "念莺轻燕怯媚容，百斛明珠须费。", "算枕前盟誓。", "深诚密约堪凭委。", "意正美，娇眼又洒，梨花春泪。", "记罗帷底。", "向鸳鸯、灯畔相偎，共把前回，词语咏味。", "无端浪迹萍蓬，奈区区、又催行李。", "忍重看、小岸柳梳风，江梅鉴水。", "待学鹣鹣翼，从他名利荣悴。"]'),
('song-ci-409','扫花游・扫地游','杨泽民','宋','宋词','song-ci','扫花游・扫地游','[]','素秋渐老，正叶落吴江，雁横南楚。',117,'宋词/ci.song.16000.json','["素秋渐老，正叶落吴江，雁横南楚。", "暮霞散缕。", "听寒蝉断续，乱鸦鼓舞。", "客舍凄清，那更西风送雨。", "又东去。", "过野杏小桥，都在元处。", "心事天未许。", "似误出桃源，再寻仙路。", "去年燕俎。", "记芳腮妒李，细腰束素。", "事没双全，自古瓜甜蒂苦。", "欲停伫。", "奈江头、早催行鼓。"]'),
('song-ci-410','解连环','杨泽民','宋','宋词','song-ci','解连环','[]','塞鸿难托。',132,'宋词/ci.song.16000.json','["塞鸿难托。", "奈云深雾阔，水遥山邈。", "感两情、浑若连环，念恩爱厚深，利名浮薄。", "便好归来，怎禁得、许多萧索。", "免恹恹瘦减，漫滞寝饘，枉费汤药。", "伊心料应未若。", "对香消兽吻，月转楼角。", "凭便是、铁石心肠，有当日盟言，怎忍辜却。", "冶叶倡条，尚自得、连枝双萼。", "不成将、异葩艳卉，便教谢落。"]'),
('song-ci-411','玲珑四犯','杨泽民','宋','宋词','song-ci','玲珑四犯','[]','韵胜江梅，笑杏俗桃粗，空眩妖艳。',120,'宋词/ci.song.16000.json','["韵胜江梅，笑杏俗桃粗，空眩妖艳。", "尽屏铅华，天赋翠眉丹脸。", "门闭昼永春长，看燕子、并飞撩乱。", "叹岁华若箭频换。", "深院有谁能见。", "夜来初得同相荐。", "便门阑、瑞烟葱茜。", "天然素质真颜色，直是惊人眼。", "曾向众里较量，似六个、骰儿六点。", "应自来恨闷，和想忆，都消散。"]'),
('song-ci-412','丹凤吟','杨泽民','宋','宋词','song-ci','丹凤吟','[]','荏苒秋光虚度，玩月池台，登高楼阁。',137,'宋词/ci.song.16000.json','["荏苒秋光虚度，玩月池台，登高楼阁。", "风传霜信，遍送晓寒侵幕。", "凄凉细雨，洒窗飘户，漏永更长，枕单衾薄。", "梦里惊鸿唤起，坐对寒釭，犹听晨漏残角。", "先自宿酲似病，共愁造合滋味恶。", "虽有丁宁语，怕旁人多口，还类金铄。", "如斯情绪，戚戚怎禁牢落。", "纵欲凭江鱼寄往，漫霜毫频握。", "几时得见，诸事都记著。"]'),
('song-ci-413','满江红','杨泽民','宋','宋词','song-ci','满江红','[]','袅娜身材，经行处、金莲涉足。',115,'宋词/ci.song.16000.json','["袅娜身材，经行处、金莲涉足。", "晨妆罢，黛眉新晕，素腰如束。", "丹脸匀红香在臂，秀肌腻滑凉生肉。", "记那回、同赌选花图，赢全局。", "相思病，休殢卜。", "辜负却，杨枝曲。", "漫榴花堆火，翠阴笼屋。", "菡萏方池闲艳蕊，画堂未许归云宿。", "任利名、踪迹久尘埃，教谁扑。"]'),
('song-ci-414','瑞鹤仙','杨泽民','宋','宋词','song-ci','瑞鹤仙','[]','依山仍负郭。',126,'宋词/ci.song.16000.json','["依山仍负郭。", "有松桂扶疏，烟霞渺漠。", "一年自成落。", "奈孤踪还系，蝇头蜗角。", "休嗤句弱。", "赋郊居、何让沈约。", "记乡人过我，傩立阼阶，酒行先酌。", "远映江山奇胜，下瞰重湖，上飞高阁。", "风帘絮幕。", "筑新槛，种花药。", "幸瓜期已近，秋风归去，免得奔驰味恶。", "待开池、剩起林亭，共同宴乐。"]'),
('song-ci-415','西平乐','杨泽民','宋','宋词','song-ci','西平乐','[]','圃韭畦蔬，嫩鸡野腊，邻酝稚子能赊。',165,'宋词/ci.song.16000.json','["圃韭畦蔬，嫩鸡野腊，邻酝稚子能赊。", "罗幕新裁，画楼高耸，松梧柳竹交遮。", "应便作归休计去，高揖渊明，下视林逋，到此如何，又走风沙。", "都为啼号累我，思量事、未遂即咨嗟。", "连年奔逐，旁州外邑，舟楫轻扬，鞭□倾斜。", "仍冒触、烟岚邃险，风雪纵横，每值初寒在路，炎暑登车，空向长途度岁华。", "消减少年，英豪气宇，潇洒襟怀，似此施为，纵解封侯，宁如便早还家。"]'),
('song-ci-416','浪淘沙慢','杨泽民','宋','宋词','song-ci','浪淘沙慢','[]','禁城外，青青细柳，翠拂高堞。',160,'宋词/ci.song.16000.json','["禁城外，青青细柳，翠拂高堞。", "征鼓催人骤发。", "长亭渐觉宴阕。", "情绪似丁香千百结。", "忍重看、手简亲折。", "听怨举离歌寄深意，新声更清绝。", "心切。", "暮天塞草烟阔。", "正乍裛轻尘，新睛后，汨汨清渭咽。", "闻西度阳关，风致全别。", "玉杯屡竭。", "思故人千里，唯同明月。", "扶上雕鞍还三叠。", "那堪第四声未歇。", "念蟾魄、能圆还解缺。", "况人事、莫苦悲伤悴艳色。", "归来复见头应雪。"]'),
('song-ci-417','忆旧游','杨泽民','宋','宋词','song-ci','忆旧游','[]','念区区远宦，带月侵晨，燃烛中宵。',124,'宋词/ci.song.16000.json','["念区区远宦，带月侵晨，燃烛中宵。", "在昔曾游遍，过三湘下浙，二水通潇。", "小舟暂辍兰棹，羸马复鞭摇。", "但旧日雄图，平生壮气，往往潜消。", "迢迢。", "向年事，记艳质平堤，曾共听镖。", "醉□游沙市，被疏狂伴侣，朝暮相招。", "怎知后约难再，牛女隔星桥。", "待远结双成，他时去窃千岁桃。"]'),
('song-ci-418','蓦山溪','杨泽民','宋','宋词','song-ci','蓦山溪','[]','当年苏小，家住苕溪尾。',102,'宋词/ci.song.16000.json','["当年苏小，家住苕溪尾。", "一棹采莲归，悄羞得、鸳鸯飞避。", "苹洲蓼岸，花脸两难分，崖半倚。", "风乍起。", "荡漾烟光里。", "平生强项，未肯轻鱼水。", "溪上偶相逢，这一段、风情怎已。", "纫兰解佩，不负有情人，金尊侧，罗帐底。", "占尽人间美。"]'),
('song-ci-419','少年游','杨泽民','宋','宋词','song-ci','少年游','[]','金炉喷兽枕敧山。',60,'宋词/ci.song.16000.json','["金炉喷兽枕敧山。", "衾帐不知寒。", "数片飞花，初临窗外，犹作堕梅看。", "明年此际应东去，藤轿逐征鞍。", "山水屏中，莺花堆里，相与下临安。"]'),
('song-ci-420','少年游','杨泽民','宋','宋词','song-ci','少年游','[]','三分芳髻拢青丝。',60,'宋词/ci.song.16000.json','["三分芳髻拢青丝。", "花下见仙姿。", "殢雨情怀，沾风踪迹，相见恨欢迟。", "能言艳色如桃李，曾折最先枝。", "冶叶丛中，闲花堆里，那有者相知。"]'),
('song-ci-421','秋蕊香','杨泽民','宋','宋词','song-ci','秋蕊香','[]','向晓银瓶香暖。',56,'宋词/ci.song.16000.json','["向晓银瓶香暖。", "宿蕊犹残娇面。", "风尘一缕透窗眼。", "恨入春山黛浅。", "短书封了凭金线。", "系双燕。", "良人贪逐利名远。", "不忆幽花静院。"]'),
('song-ci-422','渔家傲','杨泽民','宋','宋词','song-ci','渔家傲','[]','秾李素华曾缟昼。',72,'宋词/ci.song.16000.json','["秾李素华曾缟昼。", "当年独冠群芳秀。", "今日再来眉暗斗。", "谁人后。", "追思恰似章台柳。", "先自病来迟唧溜。", "肌肤瘦减宽襟袖。", "已是无聊仍断酒。", "徘徊久。", "者番枉走长亭候。"]'),
('song-ci-423','渔家傲','杨泽民','宋','宋词','song-ci','渔家傲','[]','未把金杯心已恻。',72,'宋词/ci.song.16000.json','["未把金杯心已恻。", "少年病酒还成积。", "一昨宦游来水国。", "心知得。", "陶陶大醉何人识。", "日近偶然频燕客。", "尊前巾帽时敧仄。", "致得沈疴盟枕席。", "吾方适。", "从今更不尝涓滴。"]'),
('song-ci-424','南乡子','杨泽民','宋','宋词','song-ci','南乡子','[]','乘月上高楼。',66,'宋词/ci.song.16000.json','["乘月上高楼。", "一片清光浩莫收。", "帘卷好风知客意，飕飕。", "山自纵横水自流。", "却绕古城头。", "尘事匆匆得少休。", "遥送征鸿千里外，明眸。", "消尽人间万种愁。"]'),
('song-ci-425','望江南・忆江南','杨泽民','宋','宋词','song-ci','望江南・忆江南','[]','寻胜去，驱马上南堤。',64,'宋词/ci.song.16000.json','["寻胜去，驱马上南堤。", "信脚不知人远近，醉眠犹劝玉东西。", "归帽任冲泥。", "春雨过，农事在瓜蹊。", "野卉无名随路满，山禽著意傍人啼。", "鼓角已悲凄。"]'),
('song-ci-426','浣溪沙','杨泽民','宋','宋词','song-ci','浣溪沙','[]','芳蕊鬅松夹道垂。',48,'宋词/ci.song.16000.json','["芳蕊鬅松夹道垂。", "珠幢玉节下瑶池。", "异香团就小花儿。", "应念裴航佳句好，休论白傅送行悲。", "月娥亲自送仙衣。"]'),
('song-ci-427','浣溪沙','杨泽民','宋','宋词','song-ci','浣溪沙','[]','原上芳华已乱飞。',48,'宋词/ci.song.16000.json','["原上芳华已乱飞。", "林间佛日却晖晖。", "一花六叶殿春归。", "身外色香空荏苒，鼻端消息正霏微。", "禅林曲几坐忘时。"]'),
('song-ci-428','浣溪沙','杨泽民','宋','宋词','song-ci','浣溪沙','[]','金粟蒙茸翠叶垂。',48,'宋词/ci.song.16000.json','["金粟蒙茸翠叶垂。", "月宫仙种下天涯。", "儿曹攀折有云梯。", "枕畔幽芳醒睡思，炉中换骨脱金泥。", "待持金翦怕儿啼。"]'),
('song-ci-429','迎春乐','杨泽民','宋','宋词','song-ci','迎春乐','[]','池边刺竹初成屋。',63,'宋词/ci.song.16000.json','["池边刺竹初成屋。", "拨芳瓮、酒初熟。", "奈巾车秣马催人速。", "还又伴、孤云宿。", "蜗角蝇头相窘束。", "满眼地、水青山绿。", "要解别来愁，除是再偎香玉。"]'),
('song-ci-430','迎春乐','杨泽民','宋','宋词','song-ci','迎春乐','[]','沈吟暗想狂踪迹。',65,'宋词/ci.song.16000.json','["沈吟暗想狂踪迹。", "亲曾作、燕堂客。", "赏春风、共醉垂杨陌。", "云鬓亸、金钗侧。", "对酒何曾辞大白。", "十年后、音尘俱息。", "今日走江西，空怅望、荆湖北。"]'),
('song-ci-431','点绛唇','杨泽民','宋','宋词','song-ci','点绛唇','[]','流水泠泠，闭门时候廉纤雨。',50,'宋词/ci.song.16000.json','["流水泠泠，闭门时候廉纤雨。", "菱歌齐举。", "风暖飘香絮。", "一叶扁舟，过尽莺啼处。", "空凝伫。", "到头辛苦。", "暮色闻津鼓。"]'),
('song-ci-432','一落索','杨泽民','宋','宋词','song-ci','一落索','[]','水与东风俱秀。',56,'宋词/ci.song.16000.json','["水与东风俱秀。", "一池春皱。", "满庭花卉尽芳菲，只有朵、江梅瘦。", "谱里知名自久。", "真情难有。", "纵然时下有真情，又还似、章台柳。"]'),
('song-ci-433','一落索','杨泽民','宋','宋词','song-ci','一落索','[]','识尽人间甘苦。',56,'宋词/ci.song.16000.json','["识尽人间甘苦。", "不如归去。", "先来孤馆客愁多，更倾下、连宵雨。", "尽日登山绕树。", "禄非尺素。", "竹鸡啼了杜鹃啼，甚都在、人愁处。"]'),
('song-ci-434','满庭芳','杨泽民','宋','宋词','song-ci','满庭芳','[]','春过园林，雨馀池沼，嫩荷点点青圆。',118,'宋词/ci.song.16000.json','["春过园林，雨馀池沼，嫩荷点点青圆。", "昼长人静，芳树欲生烟。", "一径幽通邃竹，松风漱、石齿溅溅。", "平生志，功名未就，先觅五湖船。", "不如，归去好，良田二顷，茅舍三椽。", "任高歌月下，痛饮花前。", "果解忘情寄意，又何在、频抚无弦。", "烟波友，扁舟过我，相伴白鸥眠。"]'),
('song-ci-435','隔浦莲近拍','杨泽民','宋','宋词','song-ci','隔浦莲近拍','[]','桑阴柔弄羽葆。',88,'宋词/ci.song.16000.json','["桑阴柔弄羽葆。", "莲渚芳容窈。", "翠叶浓障屋，绵蛮时啭黄鸟。", "闲步挼嫩草。", "鱼儿闹。", "作队游苹沼。", "画屏小。", "纱厨簟枕，接挼沈醉犹倒。", "华胥境界，燕子几声催晓。", "携手兰房未步到。", "还觉。", "衷情知向谁表。"]'),
('song-ci-436','法曲献仙音','杨泽民','宋','宋词','song-ci','法曲献仙音','[]','汀蓼收红，井梧凋绿，呖呖征鸿南度。',115,'宋词/ci.song.16000.json','["汀蓼收红，井梧凋绿，呖呖征鸿南度。", "静听寒砧，闷敧孤枕，蟾光夜深窥户。", "露暗滴、芭蕉重，潇潇本非雨。", "砌蛩语。", "怎知人、漏长无寐，因念游子，路修道又阻。", "早起懒晨妆，自秋来、眉黛谁妩。", "净几明窗，但无憀、空对蛮素。", "早知伊、别后恁久，悔教伊去。"]'),
('song-ci-437','选官子・选冠子','杨泽民','宋','宋词','song-ci','选官子・选冠子','[]','塞雁呼云，寒蝉噪晚，绕砌夜蛩凄断。',138,'宋词/ci.song.16000.json','["塞雁呼云，寒蝉噪晚，绕砌夜蛩凄断。", "迢迢玉宇，耿耿银河，明月又歌团扇。", "行客暮泊邮亭，孤枕难禁，一窗风箭。", "念松荒三迳，门低五柳，故山犹远。", "堪叹处。", "对敌风光，题评景物，恶句斐然挥染。", "风埃世路，冷暖人情，一瞬几分更变。", "唯有芳姿为人，歌意尤深，笑容偏倩。", "把新词拍段，偎人低唱，凤鞋轻点。"]'),
('song-ci-438','侧犯','杨泽民','宋','宋词','song-ci','侧犯','[]','九衢艳质，看来怎比他闲靓。',95,'宋词/ci.song.16000.json','["九衢艳质，看来怎比他闲靓。", "清韵。", "似照水横斜暮临镜。", "林间顿画阁，花底藏芳径。", "幽静。", "将绛烛、高烧照双影。", "琼瑶皓素，未及肌肤莹。", "伊试省。", "我从今、还肯再孤另。", "记取兰房，夜深人迥。", "窗外月照，一方天井。"]'),
('song-ci-439','塞翁吟','杨泽民','宋','宋词','song-ci','塞翁吟','[]','院宇临池水，桥边绕水胧□。',113,'宋词/ci.song.16000.json','["院宇临池水，桥边绕水胧□。", "桥左右，水西东。", "水木两芙蓉。", "低疑洛浦凌波步，高如弄玉凌空。", "叶百叠，蕊千重。", "更都染轻红。", "冲冲。", "能消尽，忧心似结，看艳色、浑如梦中。", "为爱惜芳容未尽，好移去，满插家园，特与培封。", "年年对赏美质，朝朝披玩香风。"]'),
('song-ci-440','苏幕遮','杨泽民','宋','宋词','song-ci','苏幕遮','[]','日烘晴，风却暑。',76,'宋词/ci.song.16000.json','["日烘晴，风却暑。", "帘幕中间，紫燕呢喃语。", "嫩竹新荷初沐雨。", "曲栏幽轩，四面明窗举。", "夏初临，春又去。", "不愿封侯，祗怕为羁旅。", "溪上故人无恙否。", "欲唱菱歌，发棹归南浦。"]'),
('song-ci-441','浣溪沙','杨泽民','宋','宋词','song-ci','浣溪沙','[]','南国幽花比并香。',48,'宋词/ci.song.16000.json','["南国幽花比并香。", "直从初夏到秋凉。", "素馨茉莉占时光。", "梅□正寒方著蕊，芙蓉过暑即空塘。", "个中春色最难量。"]'),
('song-ci-442','浣溪沙','杨泽民','宋','宋词','song-ci','浣溪沙','[]','一径栽培九畹成。',48,'宋词/ci.song.16000.json','["一径栽培九畹成。", "丛生幽谷免敧倾。", "异芳止合在林亭。", "馥郁国香难可拟，纷纭俗眼不须惊。", "好风披拂雨初晴。"]'),
('song-ci-443','浣溪沙','杨泽民','宋','宋词','song-ci','浣溪沙','[]','仙子何年下太空。',48,'宋词/ci.song.16000.json','["仙子何年下太空。", "凌波微步笑芙蓉。", "水风残月助惺忪。", "矾弟梅兄都在眼，银台金盏正当胸。", "为伊一醉酒颜红。"]'),
('song-ci-444','浣溪沙','杨泽民','宋','宋词','song-ci','浣溪沙','[]','风递馀花点素缯。',48,'宋词/ci.song.16000.json','["风递馀花点素缯。", "日烘芳炷下萝藤。", "为谁雕琢碎春冰。", "玉蕊观中犹得誉，木樨岩下尚驰声。", "何如高架任伊凭。"]'),
('song-ci-445','点绛唇','杨泽民','宋','宋词','song-ci','点绛唇','[]','雨歇方塘，清圆一一风荷举。',50,'宋词/ci.song.16000.json','["雨歇方塘，清圆一一风荷举。", "舣舟南浦。", "忘却来时路。", "醉拍春衫，便欲随君去。", "犹回顾。", "阿蛮樊素。", "更有留人处。"]'),
('song-ci-446','诉衷情','杨泽民','宋','宋词','song-ci','诉衷情','[]','眼前时果漫堆盘。',54,'宋词/ci.song.16000.json','["眼前时果漫堆盘。", "莫是又贪酸。", "因何近来销减，微褪脸霞丹。", "还只为，枕衾闲。", "泪痕斑。", "我能医疗，一服收功，只霎时间。"]'),
('song-ci-447','风流子','杨泽民','宋','宋词','song-ci','风流子','[]','行乐平生志，方从事、未出已思归。',135,'宋词/ci.song.16000.json','["行乐平生志，方从事、未出已思归。", "叹欢宴会同，类多暌阻，冶游踪迹、还又参差。", "年华换，利名虚岁月，交友半云泥。", "休忆旧游，免成春瘦，莫怀新恨，恐惹秋悲。", "惟思行乐处，几思为春困，醉枕罗衣。", "何事暗辜芳约，偷负佳期。", "念待月西厢，花阴浅浅，倚楼南陌，云意垂垂。", "别后顿成消黯，伊又争知。"]'),
('song-ci-448','华胥引','杨泽民','宋','宋词','song-ci','华胥引','[]','征车将动，愁不成歌，对颦翠叶。',105,'宋词/ci.song.16000.json','["征车将动，愁不成歌，对颦翠叶。", "静掩兰房，香铺卧鸭烟罢唼。", "别后羞看霓裳，更把筝休轧。", "频数更筹，乍寒孤枕偏怯。", "尝为霜髭，弄纤纤、向人轻镊。", "旧词新句，幽窗时时并阅。", "药饵衣衾，愁顿放、一番行箧。", "朝晚归家，又烦春笋重叠。"]'),
('song-ci-449','宴清都','杨泽民','宋','宋词','song-ci','宴清都','[]','早作听晨鼓。',126,'宋词/ci.song.16000.json','["早作听晨鼓。", "征车动、画桥乘月先度。", "邻鸡唱晓，人家未起，尚扃柴户。", "沙边塞雁声遥，料不见、当时伴侣。", "似怎地、满眼愁悲，秋如宋玉难赋。", "休论爱合暌离，微官系缚，期会良苦。", "封侯万里，金堆北斗，不如归去。", "欢娱渐入佳趣，算画在、屏帏邃处。", "仗小词、说与相思，伊还会否。"]'),
('song-ci-450','四园竹','杨泽民','宋','宋词','song-ci','四园竹','[]','残霞殿雨，皞气入窗扉。',94,'宋词/ci.song.16000.json','["残霞殿雨，皞气入窗扉。", "井梧堕叶，寒砌叫蛩，秋满屏帏。", "罗袖匆匆叙别，凄凉客里，异乡谁更相知。", "念伊其。", "当时芍药同心，谁知又爽佳期。", "直待金风到后，红叶秋时。", "细写情辞。", "何用纸。", "又却恐、秋深叶渐稀。"]'),
('song-ci-451','齐天乐','杨泽民','宋','宋词','song-ci','齐天乐','[]','护霜云澹兰皋暮，行人怕临昏晚。',123,'宋词/ci.song.16000.json','["护霜云澹兰皋暮，行人怕临昏晚。", "皓月明楼，梧桐雨叶，一片离愁难翦。", "殊乡异景，奈频易寒暄，屡更茵簟。", "案牍纷纭，夜深犹看两三卷。", "平川回棹未久，简书还授命，又催程限。", "贡浦南游，桃江西下，还是水行陆转。", "天寒雁远。", "但独拥兰衾，枕檀谁荐。", "再促征车，月华犹未敛。"]'),
('song-ci-452','木兰花・玉楼春','杨泽民','宋','宋词','song-ci','木兰花・玉楼春','[]','奇容压尽群芳秀。',64,'宋词/ci.song.16000.json','["奇容压尽群芳秀。", "枕臂浓香犹在袖。", "自从草草为传杯，但觉厌厌长病酒。", "堤上路长官柳瘦。", "愁在月明霜落后。", "须知斗帐夜寒多，早趁西风回鹢首。"]'),
('song-ci-453','霜叶飞','杨泽民','宋','宋词','song-ci','霜叶飞','[]','朔风严紧，长空布、同云低黯天表。',132,'宋词/ci.song.16000.json','["朔风严紧，长空布、同云低黯天表。", "更堪中夕振寒威，敧枕风声悄。", "望皓洁、窗纱向晓。", "珠帘才上银钩小。", "听美人都惊□，老尽群山，远近相照。", "深意劝客金尊，皑皑千里，琼台瑶圃重到。", "绮罗香暖恣欢娱，暂尔宽怀抱。", "更几朵、梅花开了。", "巡檐聊与花相调。", "算瑞气、丰穰兆。", "来岁强如，旧年多少。"]'),
('song-ci-454','蕙兰芳・蕙兰芳引','杨泽民','宋','宋词','song-ci','蕙兰芳・蕙兰芳引','[]','池亭小，帘幕初下，散飞凫骛。',103,'宋词/ci.song.16000.json','["池亭小，帘幕初下，散飞凫骛。", "乍风约云开，遥障几眉横绿。", "画桥架月，映四岸、垂杨遮屋。", "绕翠栏满槛，尽是新栽花竹。", "风送荷香，凉生冰簟，岂畏炎燠。", "便催唤双成，看舞相时丽曲。", "及瓜虽近，要娱我目。", "教后人行乐，亦非吾独。"]'),
('song-ci-455','塞垣春','杨泽民','宋','宋词','song-ci','塞垣春','[]','绣阁临芳野。',113,'宋词/ci.song.16000.json','["绣阁临芳野。", "向晚把、花枝卸。", "世间寻觅，除是图画。", "这欢娱已系人心也。", "更翰墨、新挥洒。", "展蛮笺、明窗底，把□心事都写。", "谢女与檀郎，清才对、真态俱雅。", "凤枕乐春宵，绛帷度秋夜。", "便同云黯淡，冰霰纵横，也并眠鸳衾下。", "假使过炎暑，共将罗扇把。"]'),
('song-ci-456','丁香结','杨泽民','宋','宋词','song-ci','丁香结','[]','梅雨犹清，冷风乘急，遥送万丝斜陨。',122,'宋词/ci.song.16000.json','["梅雨犹清，冷风乘急，遥送万丝斜陨。", "听水翻雷迅。", "冒雾湿，但觉衣裘皆润。", "乱山烟嶂外，轻寒透、未免强忍。", "崎岖危石，耸峭峻岭，都齐行尽。", "指引。", "看负弩旌旗，谩卷空、排素阵。", "向晚收云，黎明见日，渐生红晕。", "堪叹萍泛浪迹，□事无长寸。", "但新来纤瘦，谁信非因病损。"]'),
('song-ci-457','氐州第一','杨泽民','宋','宋词','song-ci','氐州第一','[]','潇潇寒庭，深院绣盖，佳人就中娇小。',126,'宋词/ci.song.16000.json','["潇潇寒庭，深院绣盖，佳人就中娇小。", "半额装成，纤腰浴罢，初著铢衣缥缈。", "徐整鸾钗，向凤鉴、低徊斜照。", "情态方浓，憨痴不管，绿稀红老。", "阆苑春回花枝少。", "漫微步、芳丛频绕。", "密意难窥，幽欢未讲，时把琵琶抱。", "但多才强傅粉，何须用、千金买笑。", "一枕春酲，笑巫阳、朝云易晓。"]'),
('song-ci-458','解蹀躞','杨泽民','宋','宋词','song-ci','解蹀躞','[]','一掬金莲微步。',90,'宋词/ci.song.16000.json','["一掬金莲微步。", "堪向盘中舞。", "主人开阖，呼来慰行旅。", "暂时略得舒怀，事如橄榄，馀甘卒难回苦。", "惹愁绪。", "便□偎人低唱，如何当奇遇。", "怎生真得、欢娱效云雨。", "有计应不为难，待□押出门时，却教休去。"]'),
('song-ci-459','少年游','杨泽民','宋','宋词','song-ci','少年游','[]','鸾胎麟角，金盘玉箸，芳果荐香橙。',62,'宋词/ci.song.16000.json','["鸾胎麟角，金盘玉箸，芳果荐香橙。", "洛浦佳人，缑山仙子，高会共吹笙。", "挥毫便扫千章曲，一字不须更。", "绛阙瑶台，星桥云帐，全胜少年行。"]'),
('song-ci-460','庆春宫・高阳台','杨泽民','宋','宋词','song-ci','庆春宫・高阳台','[]','曲渚澜生。',126,'宋词/ci.song.16000.json','["曲渚澜生。", "遥峰云敛，据鞍又出江城。", "青子垂枝，翠阴遮道，乍闻一两蝉声。", "素蟾犹在，但惟有、长庚殿星。", "征夫前路，应怪劳生，尘事相萦。", "年来厌逐时迎。", "千里追寻，两鬓凋零。", "佳景良辰，无憀虚度，谁怜客里凄清。", "不如归去，任儿辈、功名遂成。", "旧欢重理，莫笑渊明，却赋闲情。"]'),
('song-ci-461','醉桃源・阮郎归','杨泽民','宋','宋词','song-ci','醉桃源・阮郎归','[]','十年依旧破衫青。',56,'宋词/ci.song.16000.json','["十年依旧破衫青。", "空书制敕绫。", "但知心似玉壶冰。", "牛衣休涕零。", "聊蹇傲，莫升腾。", "毋为附骥蝇。", "前山可数且徐行。", "不须催去程。"]'),
('song-ci-462','醉桃源・阮郎归','杨泽民','宋','宋词','song-ci','醉桃源・阮郎归','[]','大都修炼似蒸沙。',56,'宋词/ci.song.16000.json','["大都修炼似蒸沙。", "阴阳失两家。", "正如飞鳖舞长蛇。", "宁知饮月华。", "回老貌，假群娃。", "熏蒸成绛霞。", "但教心地不倾斜。", "巢中能养鸦。"]'),
('song-ci-463','点绛唇','杨泽民','宋','宋词','song-ci','点绛唇','[]','岸草离离，暮天雨过添清润。',50,'宋词/ci.song.16000.json','["岸草离离，暮天雨过添清润。", "小舟移近。", "怕得江头信。", "无奈风高，雁字难成阵。", "思排闷。", "管弦难趁。", "怎解心头恨。"]'),
('song-ci-464','夜游宫','杨泽民','宋','宋词','song-ci','夜游宫','[]','一叶飘然下水。',71,'宋词/ci.song.16000.json','["一叶飘然下水。", "船头转、已行十里。", "冷落杯盘荐梅子。", "又经过，岭边村，江上市。", "那更轻帆底。", "一路上、翠飘红坠。", "深夜方眠五更起。", "说相思，试挥毫，还满纸。"]'),
('song-ci-465','夜游宫','杨泽民','宋','宋词','song-ci','夜游宫','[]','泪眼偎人强敛。',71,'宋词/ci.song.16000.json','["泪眼偎人强敛。", "鲛绡上、尚馀斑点。", "别后何愁不相见。", "只愁伊，被旁人，施暗箭。", "致得心肠转。", "教令得、神魂撩乱。", "那更日疏又日远。", "恁时节，想难为，看我面。"]'),
('song-ci-466','诉衷情','杨泽民','宋','宋词','song-ci','诉衷情','[]','侵晨呵手怯清霜。',54,'宋词/ci.song.16000.json','["侵晨呵手怯清霜。", "闲写两三行。", "都将旧游新恨，收拾入行装。", "人乍别，路尤长。", "漫嗟伤。", "不如归去，只者温柔，便是仙乡。"]'),
('song-ci-467','伤情怨・清商怨','杨泽民','宋','宋词','song-ci','伤情怨・清商怨','[]','娇痴年纪尚小。',51,'宋词/ci.song.16000.json','["娇痴年纪尚小。", "试晚妆初了。", "自戴黄花，开奁还自照。", "临岐离思浩渺。", "道未寒、须管来到。", "记取叮咛，教人归且早。"]'),
('song-ci-468','红林擒近','杨泽民','宋','宋词','song-ci','红林擒近','[]','轻有鹅毛体，白如龙脑香。',94,'宋词/ci.song.16000.json','["轻有鹅毛体，白如龙脑香。", "琼笋缀飞桷，冰壶鉴方塘。", "浑如瑶台阆苑，更无茅舍蓬窗。", "画阁自有梅装。", "贪耍罢弹簧。", "鼓舞沽酒市，蓑笠钓鱼乡。", "遐观自乐，吾心何必濠梁。", "待乔木都冻，千山尽老，更烦玉指劝羽觞。"]'),
('song-ci-469','红林擒近','杨泽民','宋','宋词','song-ci','红林擒近','[]','梅信初回暖，风棱犹壮寒。',94,'宋词/ci.song.16000.json','["梅信初回暖，风棱犹壮寒。", "禾稼响圭璧，帘旌隐琅玕。", "门外群山尚满，窗前数片馀残。", "冻底潜有鱼翻。", "东风渐生澜。", "杖策扶半醉，燕寝有馀欢。", "儿童自捧，皑皑调蜜盈盘。", "兆丰穰和气，来呈美瑞，莫同轻薄飞絮看。"]'),
('song-ci-470','满路花・促拍满路花','杨泽民','宋','宋词','song-ci','满路花・促拍满路花','[]','双眼滟秋波，两脸凝春雪。',101,'宋词/ci.song.16000.json','["双眼滟秋波，两脸凝春雪。", "尊前初见处，琴心绝。", "千磨百难，石上琼簪折。", "人非天样阔。", "车马难通，奈何没个关节。", "深盟密约，啮臂曾流血。", "须知弦断有，鸾胶接。", "别离日久，转觉归心切。", "先把新词说。", "憔悴相容，怕伊相见难别。"]'),
('song-ci-471','解语花','杨泽民','宋','宋词','song-ci','解语花','[]','星桥夜度，火树宵开，灯月光交射。',124,'宋词/ci.song.16000.json','["星桥夜度，火树宵开，灯月光交射。", "翠檐铜瓦。", "相辉映、隐隐绛霞飘下。", "风流艳雅。", "向柳陌、纤纤共把。", "筵宴时、频酌香醪，宝鸭喷沈麝。", "已是欢娱尽夜。", "对芳时堪画，条倡叶冶。", "鸳灯诗帕。", "嬉游看、到处骤轮驰马。", "十千换也。", "惟好事、寸心难谢。", "听九衢、三市行歌，到晓钟才罢。"]'),
('song-ci-472','倒犯','杨泽民','宋','宋词','song-ci','倒犯','[]','黛眉新扫。',118,'宋词/ci.song.16000.json','["黛眉新扫。", "芳容衬缟。", "佳人在、翠帘深窈。", "逡巡遽赠诗语，因询屏帏悄。", "道自有、蓝桥美质诚堪表。", "倩纤纤、捧芳醥。", "琴剑度关，望玉京人，迢迢天样窵。", "下马叩靖宇，见仙女、云英小。", "算冠绝、人间好。", "饮刀圭、神丹同得道。", "感向日，夫人指示相垂照。", "寿齐天后老。"]'),
('song-ci-473','大酺','杨泽民','宋','宋词','song-ci','大酺','[]','渐雨回春，风清夏，垂柳凉生芳屋。',162,'宋词/ci.song.16000.json','["渐雨回春，风清夏，垂柳凉生芳屋。", "馀花犹满地，引蜂游蝶戏，慢飞轻触。", "院宇深沈，帘栊寂静，苍玉时敲疏竹。", "雕梁新来燕，恣呢喃不住，似曾相熟。", "但双去并来，漫萦幽恨，枕单衾独。", "仙郎去又速。", "料今在、何许停双毂。", "任梦想、频登台榭，遍倚阑干，水云千里空流目。", "纵遇双鱼客，难尽写、别来心曲。", "媚容幸倾城国。", "今日何事，还又难分麰菽。", "寸心天上可烛。"]'),
('song-ci-474','玉烛新','杨泽民','宋','宋词','song-ci','玉烛新','[]','梨花寒食后。',123,'宋词/ci.song.16000.json','["梨花寒食后。", "被丽日和风，一时开就。", "濛濛雨歇，香犹嫩、渐觉芳心彰漏。", "墙头月下，似旧日莺莺相候。", "纤手为、攀折翘枝，轻盈露沾红袖。", "风流出浴杨妃，向海上何人，更询安否。", "百花任斗。", "应粉艳、未减杏粗梅瘦。", "肤丰肉秀。", "□可与群芳推首。", "□方待、酣饮花前，轻歌缓奏。"]'),
('song-ci-475','花犯','杨泽民','宋','宋词','song-ci','花犯','[]','百花中，夭桃秀色，堪餐作珍味。',126,'宋词/ci.song.16000.json','["百花中，夭桃秀色，堪餐作珍味。", "武陵溪上，□宋玉墙头，全胜姝丽。", "去年此日佳人倚。", "凝情心暗喜。", "恨未得、合欢鸳帐，归来犹半被。", "寻春记前约因□，题诗算怎耐、相思憔悴。", "攀玩对、东君道，莫教轻坠。", "尖纤向、鬓边戴秀，芳艳在、多情云翠里。", "看媚脸、与花争好，休夸空觅水。"]'),
('song-ci-476','丑奴儿・采桑子','杨泽民','宋','宋词','song-ci','丑奴儿・采桑子','[]','冰姿冠绝人间世，傲雪凌霜。',52,'宋词/ci.song.16000.json','["冰姿冠绝人间世，傲雪凌霜。", "蕊点檀黄。", "更看红唇间素妆。", "清芬不是先桃李，桃李无香。", "回出林塘。", "万木丛中独秉阳。"]'),
('song-ci-477','水龙吟','杨泽民','宋','宋词','song-ci','水龙吟','[]','腻金匀点繁英，好风更与花为地。',126,'宋词/ci.song.16000.json','["腻金匀点繁英，好风更与花为地。", "梅魂蕙魄，素馨□长，酴醿请避。", "拍塞清香，远闻十里，如何藏闭。", "笑东篱嫩菊，空攒细蕊，祗供得、重阳泪。", "争似青青叶底。", "傍西窗、时复轻吹。", "玉炉换骨，宝瓶熏梦，幽人睡起。", "管领秋光，留连佳景，几多新意。", "怕姮娥、不□蟾宫桂种，□高枝比。"]'),
('song-ci-478','六丑','杨泽民','宋','宋词','song-ci','六丑','[]','叹浓欢易散，便忍把、恩情抛掷。',171,'宋词/ci.song.16000.json','["叹浓欢易散，便忍把、恩情抛掷。", "恁时寸心，惟思生翅翼。", "别后踪迹。", "不定如萍泛，暂抛江沔，又留连京国。", "芳容料见尤光泽。", "共赏青楼，同游绮陌。", "皆曾痛怜深惜。", "纵鳞鸿托意，云水犹隔。", "兰房深寂。", "映轻红淡碧。", "翠竹名花底、同燕息。", "杯盘屡肯留客。", "见真诚厚爱，意深情极。", "乌纱翦为新冠帜。", "谁知道、荏苒尘埃带抹，任他倾侧。", "朝云信、且候潮汐。", "但寸心、未改伊人在，应须近得。"]'),
('song-ci-479','虞美人','杨泽民','宋','宋词','song-ci','虞美人','[]','层层楼阁薰风暖。',66,'宋词/ci.song.16000.json','["层层楼阁薰风暖。", "花里香苞短。", "清芬不逐火云消。", "看了一重姿媚、一重娇。", "几回池上寻芳径。", "惊见波中影。", "似将千叶再苞封。", "肠断昭阳一笑、付飞鸿。"]'),
('song-ci-480','虞美人','杨泽民','宋','宋词','song-ci','虞美人','[]','小池芳蕊初开遍。',66,'宋词/ci.song.16000.json','["小池芳蕊初开遍。", "恰似新妆面。", "扁舟一叶过吴门。", "只向花间高卧、度朝昏。", "浮萍点缀因风絮。", "更共鸳鸯语。", "花间有女恰如云。", "不惜一生常作、采花人。"]'),
('song-ci-481','兰陵王','杨泽民','宋','宋词','song-ci','兰陵王','[]','翠竿直。',158,'宋词/ci.song.16000.json','["翠竿直。", "一叶扁舟漾碧。", "澄江上、几度啸日迎风，怡怡钓秋色。", "渔乡共水国。", "都属沧浪傲客。", "烟波外，风笠雨蓑，才掷丝纶便千尺。", "飘然去无迹。", "恣脚扣双船，帆挂轻席。", "盈钩香饵鱼争食。", "更拨棹葭岸，放篙菱浦，才过新栅又旧驿。", "占江南江北。", "堪恻。", "利名积。", "算纵有豪华，难比清寂。", "须知此乐天无极。", "有一斗芳酒，数声横笛。", "芦花深夜，半醉里、任露滴。"]'),
('song-ci-482','蝶恋花','杨泽民','宋','宋词','song-ci','蝶恋花','[]','蜡尽江南梅发后。',70,'宋词/ci.song.16000.json','["蜡尽江南梅发后。", "万点黄金，娇眼初窥牖。", "曾见渭城人劝酒。", "嫩条轻拂传杯手。", "料峭东风寒欲透。", "暗点轻烟，便觉添疏秀。", "莫道故人今白首。", "人虽有故心无旧。"]'),
('song-ci-483','蝶恋花','杨泽民','宋','宋词','song-ci','蝶恋花','[]','初过元宵三五后。',70,'宋词/ci.song.16000.json','["初过元宵三五后。", "曲槛依依，终日摇金牖。", "瘦损舞腰非为酒。", "长条聊赠垂鞭手。", "几叶小梅春已透。", "信是风流，占尽人间秀。", "走马章台还举首。", "可人标韵强如旧。"]'),
('song-ci-484','蝶恋花','杨泽民','宋','宋词','song-ci','蝶恋花','[]','寂寞春残花谢后。',70,'宋词/ci.song.16000.json','["寂寞春残花谢后。", "落絮轻盈，点点穿风牖。", "浓绿阴中人买酒。", "凉生午扇都停手。", "叶密啼莺飞不透。", "要咏清姿，除是凭才秀。", "往日周郎为唱首。", "今将高韵重翻旧。"]'),
('song-ci-485','蝶恋花','杨泽民','宋','宋词','song-ci','蝶恋花','[]','百卉千花都绽后。',70,'宋词/ci.song.16000.json','["百卉千花都绽后。", "浥露依风，翠影笼芳牖。", "杏脸桃腮匀著酒。", "青红相映如携手。", "一段帘丝风约透。", "妆点亭台，表里俱清秀。", "几度长提频矫首。", "青青颜色新如旧。"]'),
('song-ci-486','西河','杨泽民','宋','宋词','song-ci','西河','[]','形势地。',123,'宋词/ci.song.16000.json','["形势地。", "岳阳事见图记。", "因山峭拔耸孤城，画楼涌起。", "楚吴巨泽坼东南，惊涛浮动空际。", "半天楼栏翠倚。", "记人凤舸难系。", "空馀细草没章华，但存故垒。", "二妃祠宇隔黄陵，精魂遥接云水。", "蟹鱼橘柚渐上市。", "是当年屈宋乡里。", "别有老仙高世。", "袖青蛇屡入，都无人对。", "唯有枯松城南里。"]'),
('song-ci-487','三部乐','杨泽民','宋','宋词','song-ci','三部乐','[]','浓绿丛中，露半坼芳苞，自然奇绝。',123,'宋词/ci.song.16000.json','["浓绿丛中，露半坼芳苞，自然奇绝。", "水亭风槛，正是蕤宾之月。", "固知道、春色无多，但绛英数点，照眼先发。", "为君的皪，尽是重心千叶。", "红巾又成半蹙。", "试寻双寄意，向丽人低说。", "但将一枝，插著翠环丝发。", "映秋波、艳云近睫。", "知厚意、深情更切。", "赏玩未已，看叶下、珍味还结。"]'),
('song-ci-488','菩萨蛮','杨泽民','宋','宋词','song-ci','菩萨蛮','[]','吟风敲遍阑干曲。',52,'宋词/ci.song.16000.json','["吟风敲遍阑干曲。", "极目澄江千顷绿。", "长笛下扁舟。", "一声人倚楼。", "床头醅正发。", "帐底人如雪。", "月色夜来看。", "可堪霜信寒。"]'),
('song-ci-489','品令','杨泽民','宋','宋词','song-ci','品令','[]','日长风静。',66,'宋词/ci.song.16000.json','["日长风静。", "浓香在、珠帘花影。", "棋具对著明窗近。", "未排角势，鸦鹭先分阵。", "双叠远山非有恨。", "正藏机休问。", "便如喝采争堂印。", "局番无定。", "有幸君须尽。"]'),
('song-ci-490','玉楼春','杨泽民','宋','宋词','song-ci','玉楼春','[]','笔端点染相思泪。',64,'宋词/ci.song.16000.json','["笔端点染相思泪。", "尽写别来无限意。", "祗知香阁有离愁，不信长途无好味。", "行轩一动须千里。", "王事催人难但已。", "床头酒熟定归来，明月一庭花满地。"]'),
('song-ci-491','满路花・促拍满路花','杨泽民','宋','宋词','song-ci','满路花・促拍满路花','[]','愁得鬓丝斑，没得心肠破。',101,'宋词/ci.song.16000.json','["愁得鬓丝斑，没得心肠破。", "上梢恩共爱，忒过火。", "一床锦被，将为都包裹。", "刚被旁人隔，不似鸳鸯，等闲常得双卧。", "非无意智，触事应偏左。", "那堪名与利，相羁锁。", "一番记著，一夜还难过。", "伊还思念我。", "等得归来，恁时早早来呵。"]'),
('song-ci-492','声声慢','陈郁','宋','宋词','song-ci','声声慢','[]','澄空初霁，暑退银塘，冰壶雁程寥寞。',119,'宋词/ci.song.16000.json','["澄空初霁，暑退银塘，冰壶雁程寥寞。", "天阙清芬，何事早飘岩壑。", "花神更裁丽质，涨红波、一奁梳掠。", "凉影里，算素娥仙队，似曾相约。", "闲把两花商略。", "开时候、羞趁观桃阶药。", "绿幕黄帘，好顿胆瓶儿著。", "年年粟金万斛，拒严霜、绵丝围幄。", "秋富贵，又何妨、与民同乐。"]'),
('song-ci-493','宝鼎现','陈郁','宋','宋词','song-ci','宝鼎现','[]','虞弦清暑，佳气葱郁，非烟非雾。',191,'宋词/ci.song.16000.json','["虞弦清暑，佳气葱郁，非烟非雾。", "人正在、东闱堂上，分瑞祥辉腾翠渚。", "奉玉斝，总欢呼称颂，争羡神光葆聚。", "庆诞节、弥生二佛，接踵瑶池仙母。", "最好英慧由天赋。", "有仁慈宽厚襟宇。", "每留念、修身忱意，博问谦勤亲保傅。", "染宝翰、镇规随宸画，心授家传有素。", "更吟咏、形容雅颂，隐隐赓歌风度。", "恩重汉殿传觞，宣付祝、恭承天语。", "对南薰初试，宫院笙箫竞举。", "但长愿，际升平世，万载皇基因睹。", "问寝日，俟鸡鸣舞拜，龙楼深处。"]'),
('song-ci-494','绛都春','陈郁','宋','宋词','song-ci','绛都春','[]','晴天媚晓。',121,'宋词/ci.song.16000.json','["晴天媚晓。", "正禁苑乍暖，莺声娇小。", "柳拂玉阑，花映朱帘韶光早。", "熙朝多暇舒长昼。", "庆圣主、新颁飞诏。", "贻谋恩重，齐家有训，万邦仪表。", "偏称宫闱欢笑。", "酿和气共结，天香缭绕。", "侍宴回车，韶部将迎金莲照。", "鸡鸣警戒丁宁了。", "但管取、咸常同道。", "东皇先报宜男，已生瑞草。"]'),
('song-ci-495','念奴娇','陈郁','宋','宋词','song-ci','念奴娇','[]','没巴没鼻，霎时间、做出漫天漫地。',120,'宋词/ci.song.16000.json','["没巴没鼻，霎时间、做出漫天漫地。", "不论高低并上下，平白都教一例。", "鼓动滕六，招邀巽二，一任张威势。", "识他不破，只今道是祥瑞。", "却恨鹅鸭池边，三更半夜，误了吴元济。", "东郭先生都不管，关上门儿稳睡。", "一夜东风，三竿暖日，万事随流水。", "东皇笑道，山河原是我底。"]'),
('song-ci-496','玉连环・解连环','冯伟寿','宋','宋词','song-ci','玉连环・解连环','[]','谪仙往矣，问当年、饮中俦侣，於今谁在。',116,'宋词/ci.song.16000.json','["谪仙往矣，问当年、饮中俦侣，於今谁在。", "叹沈香醉梦，胡尘日月，流浪锦袍宫带。", "高吟三峡动，舞剑九州隘。", "玉皇归觐，半空遗下，诗囊酒佩。", "云月仰挹清芬，揽虬须、尚友千载。", "晋宋颓波，羲皇春梦，尊前一慨。", "待相将共蹑，龙肩鲸背。", "海山何处，五云叆叆。"]'),
('song-ci-497','春风袅娜','冯伟寿','宋','宋词','song-ci','春风袅娜','[]','被梁间双燕，话尽春愁。',154,'宋词/ci.song.16000.json','["被梁间双燕，话尽春愁。", "朝粉谢，午花柔。", "倚红阑故与，蝶围蜂绕，柳绵无数，飞上搔头。", "凤管声圆，蚕房香暖，笑挽罗衫须少留。", "隔院兰馨趁风远，邻墙桃影伴烟收。", "些子风情未减，眉头眼尾，万千事、欲说还休。", "蔷薇露，牡丹球。", "殷勤记省，前度绸缪。", "梦里飞红，觉来无觅，望中新绿，别后空稠。", "相思难偶，叹无情明月，今年已是，三度如钩。"]'),
('song-ci-498','春云怨','冯伟寿','宋','宋词','song-ci','春云怨','[]','春风恶劣。',124,'宋词/ci.song.16000.json','["春风恶劣。", "把数枝香锦，和莺吹折。", "雨重柳腰娇困，燕子欲扶扶不得。", "软日烘烟，乾风吹雾，芍药荼䕷弄颜色。", "帘幕轻阴，图书清润，日永篆香绝。", "盈盈笑靥宫黄额。", "试红鸾小扇，丁香双结。", "团凤眉心倩郎贴。", "教洗金罍，共看西堂，醉花新月。", "曲水成空，丽人何处，往事暮云万叶。"]'),
('song-ci-499','云仙引','冯伟寿','宋','宋词','song-ci','云仙引','[]','紫凤台高，红鸾镜里，馡馡几度秋馨。',120,'宋词/ci.song.16000.json','["紫凤台高，红鸾镜里，馡馡几度秋馨。", "黄金重，绿云轻。", "丹砂鬓边滴粟，翠叶玲珑烟剪成。", "含笑出帘，月香满袖，天雾萦身。", "年时花下逢迎。", "有游女、翩翩如五云。", "乱掷芳英，为簪斜朵，事事关心。", "长向金风，一枝在手，嗅蕊悲歌双黛颦。", "绕临溪树，对初弦月，露下更深。"]'),
('song-ci-500','眼儿媚','冯伟寿','宋','宋词','song-ci','眼儿媚','[]','自颦双黛听啼鸦。',58,'宋词/ci.song.16000.json','["自颦双黛听啼鸦。", "帘外翠烟斜。", "社前风雨，已归燕子，未入人家。", "鞋儿试著无人看，莫是忒宽些。", "想它楼上，闷拈箫管，憔悴莺花。"]'),
('song-ci-501','木兰花慢','冯伟寿','宋','宋词','song-ci','木兰花慢','[]','酒醒人世换，碧桃靓、海山春。',122,'宋词/ci.song.16000.json','["酒醒人世换，碧桃靓、海山春。", "任青鸟沈沈，紫鳞杳杳，有玉林人。", "宫袍掉头未爱，爱荷衣、不染市朝尘。", "仙样蓬莱翰墨，云间鸾凤精神。", "笑呼银汉入金鲸。", "琼苑自由身。", "羡咳唾成章，香薰花雾，音和韵钧。", "六丁夜来捧去，便天人、也自叹尖新。", "那得金笺飞洒，浩歌飞步苍旻。"]'),
('song-ci-502','失调名','陈无咎','宋','宋词','song-ci','失调名','[]','一年一度春来，何时是了。',113,'宋词/ci.song.16000.json','["一年一度春来，何时是了。", "花落花开浑是梦，只解把人引调。", "可怜浮世，等闲过日，却不识，绿水青山，四时都好。", "遇笔题诗，逢人饮酒，世间万事，看尽多多少少。", "怎得似、羽扇纶巾，云屏烟障，几曾受些儿烦恼。", "便乘风归去小蓬莱，听门外、猿啼鹤啸。"]'),
('song-ci-503','沁园春','陈草阁','宋','宋词','song-ci','沁园春','[]','霜剥枯崖，何处邮亭，玉龙夜呼。',139,'宋词/ci.song.16000.json','["霜剥枯崖，何处邮亭，玉龙夜呼。", "唤经年幽梦，悠然独觉，参横璇汉，漏彻铜壶。", "漠漠风烟，昏昏水月，醉耸诗肩骑瘦驴。", "孤吟处，更寻香吊影，搔首踟蹰。", "古心落落如予。", "悄独立高寒凌万夫。", "对荒烟野草，浅溪沙路，班荆三嗅，此意谁如。", "高卧南阳，归来彭泽，借问风光还似无。", "难穷处，待凭将妙手，作岁寒图。"]'),
('song-ci-504','木兰香・减字木兰花','徐介轩','宋','宋词','song-ci','木兰香・减字木兰花','[]','一帘疏雨。',52,'宋词/ci.song.16000.json','["一帘疏雨。", "道是无情还有思。", "坐久魂销。", "风动珠唇点点娇。", "生平浩气。", "静乐机关随处是。", "熏透寒衾。", "蝴蝶休萦万里心。"]'),
('song-ci-505','步蟾宫','章耐轩','宋','宋词','song-ci','步蟾宫','[]','未开大如木犀蕊。',69,'宋词/ci.song.16000.json','["未开大如木犀蕊。", "开后是、梅花小底。", "け然只欲住山林，肯容易、结根城市。", "叶儿又与冬青比。", "算何止、香闻七里。", "不因山谷品题来，谁知道、是水仙兄弟。"]'),
('song-ci-506','浣溪沙','昭顺老人','宋','宋词','song-ci','浣溪沙','[]','的皪堪为席上珍。',48,'宋词/ci.song.16000.json','["的皪堪为席上珍。", "银铛百沸麝脐薰。", "萧娘欲饵意中人。", "拈处玉纤笼蚌颗，剥时琼齿嚼香津。", "仙郎入口即轻身。"]'),
('song-ci-507','南柯子・南歌子','陈舜翁','宋','宋词','song-ci','南柯子・南歌子','[]','德祖家珍熟，钱塘五月中。',62,'宋词/ci.song.16000.json','["德祖家珍熟，钱塘五月中。", "碧梧桐盖翠筠笼。", "倾向水晶盘内、斗尝空。", "绛粟成团小，清甜笑蜜浓。", "微酸犹解惨人容。", "最是玉纤拈处、染轻红。"]'),
('song-ci-508','浪淘沙','洪子大','宋','宋词','song-ci','浪淘沙','[]','上苑又春残。',64,'宋词/ci.song.16000.json','["上苑又春残。", "樱颗如丹。", "明光宫里水晶盘。", "想得退朝花底散，宣赐千官。", "往事记金銮。", "荔子难攀。", "多情更有酪浆寒。", "蜀客筠笼相赠处，愁忆长安。"]'),
('song-ci-509','八声甘州','郑子玉','宋','宋词','song-ci','八声甘州','[]','渐莺声近也，探年芳、河畔扼轻轮。',118,'宋词/ci.song.16000.json','["渐莺声近也，探年芳、河畔扼轻轮。", "旋东风染绿，绵绵平野，无际烟春。", "最苦夕阳天外，愁损倚阑人。", "无奈潇湘杳，留滞王孙。", "冷落池塘残梦，是送君归后，南浦消魂。", "赖东君能客，醉卧展香茵。", "尽教更、行人远，也相伴、连水复连云。", "关山道，算无今古，客恨长新。"]'),
('song-ci-510','虞美人','文珏','宋','宋词','song-ci','虞美人','[]','歌唇乍启尘飞处。',68,'宋词/ci.song.16000.json','["歌唇乍启尘飞处。", "翠叶轻轻举。", "似通舞态逞妖容。", "嫩条纤丽玉玲珑。", "怯秋风。", "虞姬珠碎兵戈里。", "莫认埋魂地。", "只应遗恨寄芳丛。", "露和清泪湿轻红。", "古今同。"]'),
('song-ci-511','虞美人','顾卞','宋','宋词','song-ci','虞美人','[]','帐前草草军情变。',68,'宋词/ci.song.16000.json','["帐前草草军情变。", "月下旗旌乱。", "褫衣推枕惜离情。", "远风吹下楚歌声。", "正三更。", "抚鞍欲上重相顾。", "艳态花无主。", "手中莲萼凛秋霜。", "九泉归路是仙乡。", "恨茫茫。"]'),
('song-ci-512','壶中天・念奴娇','陈景沂','宋','宋词','song-ci','壶中天・念奴娇','[]','江邮湘驿。',120,'宋词/ci.song.16000.json','["江邮湘驿。", "问暮年何事，暮冬行役。", "马首摇摇经历处，多少山南溪北。", "冷著烟扉，孤芳云掩，瞥见如相识。", "相逢相劳，如痴如诉如忆。", "最是近晓霜浓，初弦月挂，傅粉金鸾侧。", "冷淡生涯忧忘乐，不管冰檐雪壁。", "魁榜虚夸，调羹浪语，那里求真的。", "暗香来历，自家还要知得。"]'),
('song-ci-513','点绛唇','陈景沂','宋','宋词','song-ci','点绛唇','[]','今古凡花，词人尚作词称庆。',50,'宋词/ci.song.16000.json','["今古凡花，词人尚作词称庆。", "紫薇名盛。", "似得花之圣。", "为底时人，一曲稀流咏。", "花端正。", "花无郎病。", "病亦归之命。"]'),
('song-ci-514','水龙吟','陈景沂','宋','宋词','song-ci','水龙吟','[]','阶前砌下新凉，嫩姿弱质婆娑小。',126,'宋词/ci.song.16000.json','["阶前砌下新凉，嫩姿弱质婆娑小。", "仙家甚处，凤雏飞下，化成窈窕。", "尖叶参差，柔枝袅娜，体将玉造。", "自川葵放后，堂萱谢了，是圆苑、无花草。", "自恨西风太早。", "逞芳容、紫围绯绕。", "管里低昂，篦头约略，空成懊恼。", "圆胎结就，小铃垂下，直开临□。", "□凡间谪堕，不如西帝，曾关宸抱。"]'),
('song-ci-515','念奴娇','松洲','宋','宋词','song-ci','念奴娇','[]','麦场桑陇，道都是、六代宫城遗迹。',121,'宋词/ci.song.16000.json','["麦场桑陇，道都是、六代宫城遗迹。", "梦里江山经几觉，还似堠旁征驿。", "燕去燕来，花开花谢，那个成端的。", "人烟牢落，晚风何处羌笛。", "堪叹挥泪新亭，算兴亡莫补、万分之一。", "到我凭阑，休更向酒畔，是今非昔。", "击楫誓清，闻鸡起舞，毕竟英难得。", "伤心残照，塔尖遥露秋碧。"]'),
('song-ci-516','浣溪沙','韩准','宋','宋词','song-ci','浣溪沙','[]','潇洒梧桐几度秋。',56,'宋词/ci.song.16000.json','["潇洒梧桐几度秋。", "凤凰飞去旧山幽。", "风景不殊人物换，恨悠悠。", "衰草远从烟际合，夕阳空趁水西流。", "恰好凭楼便回首，怕生愁。"]'),
('song-ci-517','沁园春','王云焕','宋','宋词','song-ci','沁园春','[]','四十君王，三百载间，兴亡一家。',139,'宋词/ci.song.16000.json','["四十君王，三百载间，兴亡一家。", "叹幕府峰高，生涯社燕，胭脂井暗，富贵飞花。", "山骨呈羞，江声带恨，磨尽英雄岁月赊。", "君知否，是枋头霸上，著数全差。", "倚空长剑吁嗟。", "奈争战年来似乱麻。", "但苍陵古冢，白杨啼鴂，荒园废沼，青草鸣蛙。", "旗盖东南，风涛天堑，难比兴亡隙地些。", "休凝伫，望长安路杳，夕照愁鸦。"]'),
('song-ci-518','满江红','王淮','宋','宋词','song-ci','满江红','[]','踏遍江南，予岂为、解衣推食。',115,'宋词/ci.song.16000.json','["踏遍江南，予岂为、解衣推食。", "谩赢得、烟波短棹，月楼长笛。", "看剑功名心已死，积薪涕泪今谁滴。", "想中原、一望一伤情，英雄客。", "形势地，还如昔。", "谈笑里，封侯觅。", "岂有於前代，无於今日。", "龙豹莫藏韬略手，犬羊快扫腥膻迹。", "看诸公、事业卜枭卢，何劳掷。"]'),
('song-ci-519','莺啼序','叶润','宋','宋词','song-ci','莺啼序','[]','离骚困吟梦醒，访台城旧路。',299,'宋词/ci.song.16000.json','["离骚困吟梦醒，访台城旧路。", "问流水、东入沧溟，还解流转西否。", "乌衣梦、浪传故国，晴烟冉冉宫墙树。", "念吟魂凄断，待随燕子来去。", "回首十年，阑锦花场，趁吟云赋雨。", "可曾对、宝瑟知音，高轩为谁轻驻。", "倚东风、愁长笑短，水云深、春江日暮。", "伴羁怀，唯有征衫，贮寒半缕。", "高情谩赋，蕙带兰襟，蛾眉古来相妒。", "英雄到、江南易老。", "后来谁更，风景伤心，泪沾樽俎。", "登山宴水，横江酹酒，倾将慷慨酬形势，付兴亡、一笑翻歌舞。", "独醒难继山公，上马旌旗动，又还惊起鸥鹭。", "危亭恨极，落尽寒香，怕道断肠句。", "有多少、行星翠点，春浅寒深，孕粉藏香，蝶清蜂瘦。", "因孤彩笔芳笺，拟待倩取游丝，系却离绪。", "旋□□、写入鸣弦柱。", "曲高调古。", "更人何在，谁比和、此幽素。"]'),
('song-ci-520','柳梢青','张杜','宋','宋词','song-ci','柳梢青','[]','燕里花深，鹭汀云澹，客梦江皋。',61,'宋词/ci.song.16000.json','["燕里花深，鹭汀云澹，客梦江皋。", "日日言归，淮山笑我，尘锁征袍。", "几回把酒凭高。", "阑干外、魂飞暮涛。", "只有南园，一番风雨，过了樱桃。"]'),
('song-ci-521','风流子','王泳祖','宋','宋词','song-ci','风流子','[]','东风长是客，帘栊静、燕子一双飞。',135,'宋词/ci.song.16000.json','["东风长是客，帘栊静、燕子一双飞。", "看花坞日高，翠阴护晓，柳塘风细，绿涨浮漪。", "肠断处，渭城春树远，江国暮云低。", "芳径听莺，暗惊心事，画檐闻鹊，试卜归期。", "小楼凝伫地，疏窗下，几度对说相思。", "记得菱花交照，素手曾携。", "有新恨两眉，向谁说破，芳心一点，惟我偏知。", "休为多情瘦却，重有来时。"]'),
('song-ci-522','氐州第一','刘天游','宋','宋词','song-ci','氐州第一','[]','冰缩寒流，川凝冻霭，前回鹭渚冬晚。',127,'宋词/ci.song.16000.json','["冰缩寒流，川凝冻霭，前回鹭渚冬晚。", "燕阁红炉，驼峰翠釜，曾忆花柔酒软。", "云海沧洲，甚又寄、南来客雁。", "洒雪朱门，回桡剡曲，镜华霜满。", "万里银霄凝望眼。", "恁吟袖、画阑空暖。", "树带潮墟，笳鸣古戍，簇仲宣幽怨。", "想愁思、春近也，随宫绣、时宽一线。", "昨夜扁舟，梦湖山、眉横黛浅。"]'),
('song-ci-523','摸鱼儿','柴望','宋','宋词','song-ci','摸鱼儿','["\u957f\u6c5f"]','问长江、几分秋色，三分浑在烟雨。',140,'宋词/ci.song.16000.json','["问长江、几分秋色，三分浑在烟雨。", "何人折尽丝丝柳，此日送君南浦。", "帆且驻。", "试说著、羊裘钓雪今何许。", "鱼虾自舞。", "但一舸芦花，数声霜笛，鸥鹭自来去。", "年年事，流水朝朝暮暮。", "天涯长叹飘聚。", "衾寒不转钧天梦，楼外谁歌白纻。", "君莫诉。", "君试按、秦筝未必如锺吕。", "乡心最苦。", "算只有娟娟，马头皓月，今夜照归路。"]'),
('song-ci-524','齐天乐','柴望','宋','宋词','song-ci','齐天乐','[]','青青杨柳丝丝雨，他乡又逢寒食。',123,'宋词/ci.song.16000.json','["青青杨柳丝丝雨，他乡又逢寒食。", "几度刘郎，当年曼倩，迢递水村烟驿。", "寻踪访迹。", "正马上相逢，杏花狼藉。", "惟有沙边，旧时鸥鹭似相识。", "天涯流浪最久，十年何所事，幽愫历历。", "换字鹅归，看梅鹤去，回首征衫泪渍。", "新欢旧忆。", "笑客处如归，归处如客。", "独倚危阑，乱山无数碧。"]'),
('song-ci-525','祝英台・祝英台近','柴望','宋','宋词','song-ci','祝英台・祝英台近','[]','小船儿，双去橹。',95,'宋词/ci.song.16000.json','["小船儿，双去橹。", "红湿海棠雨。", "燕子归时，芳草暗南浦。", "自从翠袖香消，明珰声断，怕回首、旧寻芳处。", "向谁语。", "可怜金屋无人，冷落凤箫谱。", "翠入菱花，蛾眉为谁妩。", "断肠明月天涯，春风海角，恨不做、杨花飞去。"]'),
('song-ci-526','阳关三叠','柴望','宋','宋词','song-ci','阳关三叠','[]','西风吹鬓，残发早星星。',162,'宋词/ci.song.16000.json','["西风吹鬓，残发早星星。", "叹故国斜阳，断桥流水，荣悴本无凭。", "但朝朝、才雨又晴。", "人生飘聚等浮萍。", "谁知桃叶，千古是离情。", "正无奈、黯黯离情。", "渡头烟暝，愁杀渡江人。", "伤情处，送君且待江头月，人共月、千里难并。", "笳鼓发，戍云平。", "此夜思君，肠断不禁。", "尽思君送君。", "立尽江头月，奈此去、君出阳关，纵有明月，无酒酌故人。", "奈此去、君出阳关，明朝无故人。"]'),
('song-ci-527','摸鱼儿','柴望','宋','宋词','song-ci','摸鱼儿','[]','这情怀、怎生消遣。',140,'宋词/ci.song.16000.json','["这情怀、怎生消遣。", "思量只是凄怨。", "一春长为花和柳，风雨又还零乱。", "君试看。", "便杜牧风流，也则肠先断。", "更深漏短。", "更听得杜宇，一声声切，流水画桥畔。", "人间世，本只阴晴易换。", "斜阳衰草何限。", "悲欢毕竟年年事，千古漫嗟修短。", "无处问。", "是闲倚帘栊，尽日厌厌闷。", "浮名尽懒。", "但笑拍阑干，连呼大白，心事付归燕。"]'),
('song-ci-528','念奴娇','柴望','宋','宋词','song-ci','念奴娇','[]','匆匆别去，算别来、又是几番春暮。',120,'宋词/ci.song.16000.json','["匆匆别去，算别来、又是几番春暮。", "酒债不偿还似可，负了若干吟句。", "渭北春天，江南夜雨，总是伤情处。", "黯然消歇，绿杨一阵莺语。", "空记十载嬉游，如今蓦地，两处成离阻。", "纵是相逢天涯路，难觅年时欢侣。", "寄语东君，岁华不驻，谁为留春住。", "小楼昨夜，东风依旧飞絮。"]'),
('song-ci-529','摸鱼儿','柴望','宋','宋词','song-ci','摸鱼儿','[]','便无他、杜鹃催去，匆匆春事能几。',140,'宋词/ci.song.16000.json','["便无他、杜鹃催去，匆匆春事能几。", "看来不见春归路，飞絮又随流水。", "留也是。", "怎禁得、东风红紫还飘坠。", "天涯万里。", "怅燕子人家，沈沈夜雨，添得断肠泪。", "嬉游事。", "早觉相如倦矣。", "谢娘庭院犹记。", "闲情已付孤鸿去，依旧被莺呼起。", "谁料理。", "正乍暖还寒，未是晴天气。", "无言自倚。", "想旧日桃花，而今人面，都是梦儿里。"]'),
('song-ci-530','满江红','柴望','宋','宋词','song-ci','满江红','[]','载酒何人，登临处、沧洲空阔。',115,'宋词/ci.song.16000.json','["载酒何人，登临处、沧洲空阔。", "凭阑外、晴杨两岸，晚烟泼□。", "水鸟不知梁燕去，溪山半属冬青阁。", "有小舟、隐约载歌姝，调新曲。", "留与去，如何得。", "风又雨，催行色。", "共白苹红蓼，好生飘泊。", "别后三年重会面，人生几度三年别。", "正乡心、客梦两绸缪，城头角。"]'),
('song-ci-531','贺新郎','柴望','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','满酌西湖酒。',142,'宋词/ci.song.16000.json','["满酌西湖酒。", "觉湖山、依然未老，游人如旧。", "数过清明才六日，欲暖未晴时候。", "正画舫、春明波透。", "记得名园曾驻马，锦鞍鞯、浅映堤桥柳。", "寻胜赏，重回首。", "不妨旋摘枝头有。", "喜青青、垂丸带子，脆圆如豆。", "想是和羹消息近，报与醉翁太守。", "道玉铉、有人启奏。", "红药当阶明似锦，觉娇莺、舞燕皆称寿。", "唱此曲，付红袖。"]'),
('song-ci-532','念奴娇','柴望','宋','宋词','song-ci','念奴娇','[]','登高回首，叹山河国破，於今何有。',120,'宋词/ci.song.16000.json','["登高回首，叹山河国破，於今何有。", "台上金仙空已去，零落逋梅苏柳。", "双塔飞云，六桥流水，风景还依旧。", "凤笙龙管，何人肠断重奏。", "闻道凝碧池边，宫槐叶落，舞马衔杯酒。", "旧恨春风吹不断，新恨重重还又。", "燕子楼高，乐昌镜远，人比花枝瘦。", "伤情万感，暗沾啼血襟袖。"]'),
('song-ci-533','念奴娇','柴望','宋','宋词','song-ci','念奴娇','[]','春来多困，正日移帘影，银屏深闭。',120,'宋词/ci.song.16000.json','["春来多困，正日移帘影，银屏深闭。", "唤梦幽禽烟柳外，惊断巫山十二。", "宿酒初醒，新愁半解，恼得成憔悴。", "髼鬆云鬓，不忺鸾镜梳洗。", "门外满地香风，残梅零乱，玉糁苍苔碎。", "乍暖乍寒浑莫拟，欲试罗衣犹未。", "斗草雕阑，买花深院，做踏青天气。", "晴鸠鸣处，一池昨夜春水。"]'),
('song-ci-534','桂枝香','柴望','宋','宋词','song-ci','桂枝香','[]','今宵月色。',124,'宋词/ci.song.16000.json','["今宵月色。", "叹暗水流花，年事非昨。", "潇洒江南似画，舞枫飘柞。", "谁家又唱江南曲，一番听、一番离索。", "孤鸿飞去，残霞落尽，怨深难托。", "又肠断、丁香画雀。", "记牡丹时候，归燕帘幕。", "梦里襄王，想念王孙飘泊。", "如今雪上萧萧鬓，更相思、连夜花发。", "柘枝犹在，春风那似，旧时宋玉。"]'),
('song-ci-535','齐天乐','柴望','宋','宋词','song-ci','齐天乐','[]','凄凄杨柳潇潇雨，悄窗怎禁滴沥。',123,'宋词/ci.song.16000.json','["凄凄杨柳潇潇雨，悄窗怎禁滴沥。", "思里传螀，愁边落雁，多少东吴山色。", "知他恨极。", "料为我窗前，强鸣刀尺。", "竟日西风，那堪无寐更邻笛。", "黄花开遍未也，花开应笑我，年少难觅。", "灞上长安，河边渭水，都把韶华暗掷。", "何人碎璧。", "尚衰草连天，暮烟凝碧。", "怕说相思，撼枫喧夜寂。"]'),
('song-ci-536','朝中措','王玉','宋','宋词','song-ci','朝中措','[]','杨花绕昼暖风多。',57,'宋词/ci.song.16000.json','["杨花绕昼暖风多。", "晴云点池波。", "戏数翠萍几靥，零星未碍圆荷。", "软人天气，半如溽暑，半似清和。", "说与香篝緼火，酒痕梅却衣罗。"]'),
('song-ci-537','菩萨蛮','张桂','宋','宋词','song-ci','菩萨蛮','[]','东风忽骤无人见。',52,'宋词/ci.song.16000.json','["东风忽骤无人见。", "玉塘烟浪浮花片。", "步湿下香阶。", "苔黏金凤鞋。", "翠鬟愁不整。", "临水闲窥影。", "摘得野蔷薇。", "游蜂相趁归。"]'),
('song-ci-538','浣溪沙','张桂','宋','宋词','song-ci','浣溪沙','[]','雨压杨花路半乾。',48,'宋词/ci.song.16000.json','["雨压杨花路半乾。", "蜂遗花粉在阑干。", "牡丹开尽正春寒。", "懒品么弦金雁并，瘦惊双钏玉鱼宽。", "新愁不放翠眉间。"]'),
('song-ci-539','瑞鹤仙','张枢','宋','宋词','song-ci','瑞鹤仙','["\u897f\u6e56"]','卷帘人睡起。',128,'宋词/ci.song.16000.json','["卷帘人睡起。", "放燕子归来，商量春事。", "风光又能几。", "减芳菲、都在卖花声里。", "吟边眼底。", "被嫩绿、移红换紫。", "甚等闲、半委东风，半委小桥流水。", "还是。", "苔痕湔雨，竹影留云，待晴犹未。", "兰舟静舣。", "西湖上、多少歌吹。", "粉蝶儿、守定落花不去，湿重寻香两翅。", "怎知人、一点新愁，寸心万里。"]'),
('song-ci-540','风入松','张枢','宋','宋词','song-ci','风入松','[]','春寒懒下碧云楼。',90,'宋词/ci.song.16000.json','["春寒懒下碧云楼。", "花事等闲休。", "红绵湿透秋千索，记伴仙、曾倚娇柔。", "重叠黄金约臂，玲珑翠玉搔头。", "薰炉谁熨暖衣篝。", "消遣酒醒愁。", "旧巢未著新来燕，任珠帘、不上琼钩。", "何处东风院宇，数声揭调甘州。"]'),
('song-ci-541','南歌子','张枢','宋','宋词','song-ci','南歌子','[]','柳户朝云湿，花窗午篆清。',62,'宋词/ci.song.16000.json','["柳户朝云湿，花窗午篆清。", "东风未放十分晴。", "留恋海棠颜色、过清明。", "垒润栖新燕，笼深锁旧莺。", "琵琶可是不堪听。", "无奈愁人把做、断肠声。"]'),
('song-ci-542','谒金门','张枢','宋','宋词','song-ci','谒金门','[]','春梦怯。',53,'宋词/ci.song.16000.json','["春梦怯。", "人静玉闺平帖。", "睡起眉心端正贴。", "绰枝双杏叶。", "重整金泥蹀躞。", "红皱石榴裙褶。", "款步花阴寻蛱蝶。", "玉纤和粉捻。"]'),
('song-ci-543','庆宫春・高阳台','张枢','宋','宋词','song-ci','庆宫春・高阳台','[]','斜日明霞，残虹分雨，软风浅掠苹波。',126,'宋词/ci.song.16000.json','["斜日明霞，残虹分雨，软风浅掠苹波。", "声冷瑶笙，情疏宝扇，酒醒无奈秋何。", "彩云轻散，漫敲缺、铜壶浩歌。", "眉痕留怨，依约远峰，学敛双蛾。", "银床露洗凉柯。", "屏掩香销，忍扫裀罗。", "楚驿梅边，吴江枫畔，庾郎从此愁多。", "草蛩喧砌，料催织、回文凤棱。", "相思遥夜，帘卷翠楼，月冷星河。"]'),
('song-ci-544','壶中天・念奴娇','张枢','宋','宋词','song-ci','壶中天・念奴娇','[]','雁横迥碧，渐烟收极浦，渔唱催晚。',120,'宋词/ci.song.16000.json','["雁横迥碧，渐烟收极浦，渔唱催晚。", "临水楼台乘醉倚，云引吟情闲远。", "露脚飞凉，山眉锁暝，玉宇冰奁满。", "平波不动，桂华底印清浅。", "应是琼斧修成，铅霜捣就，舞霓裳曲遍。", "窈窕西窗谁弄影，红冷芙蓉深苑。", "赋雪词工，留云歌断，偏惹文箫怨。", "人归鹤唳，翠帘十二空卷。"]'),
('song-ci-545','恋绣衾','张枢','宋','宋词','song-ci','恋绣衾','[]','屏绡裛润惹篆烟。',68,'宋词/ci.song.16000.json','["屏绡裛润惹篆烟。", "小窗闲、人泥昼眠。", "正雪暖、荼䕷架，奈愁春、尘锁雁弦。", "杨花做了香云梦，化池萍、犹泛翠钿。", "自不怨、东风老，怨东风、轻信杜鹃。"]'),
('song-ci-546','清平乐','张枢','宋','宋词','song-ci','清平乐','[]','凤楼人独。',40,'宋词/ci.song.16000.json','["凤楼人独。", "飞尽罗心烛。", "梦绕屏山三十六。", "依约水西云北。", "晓奁懒试脂铅。", "一緺鸾髻微偏。"]'),
('song-ci-547','木兰花慢','张枢','宋','宋词','song-ci','木兰花慢','[]','歌尘凝燕垒，又软语、在雕梁。',123,'宋词/ci.song.16000.json','["歌尘凝燕垒，又软语、在雕梁。", "记剪烛调弦，翻香校谱，学品伊凉。", "屏山梦云正暖，放东风、卷雨入巫阳。", "金冷红绦孔雀，翠间彩结鸳鸯。", "银缸。", "焰冷小兰房。", "夜悄怯更长。", "待采叶题诗，含情赠远，烟水茫茫。", "春妍尚如旧否，料啼痕、暗里浥红妆。", "须觅流莺寄语，为谁老却刘郎。"]'),
('song-ci-548','惜花春起早','张枢','宋','宋词','song-ci','惜花春起早','[]','琐窗明。',4,'宋词/ci.song.16000.json','["琐窗明。"]'),
('song-ci-549','失调名','张枢','宋','宋词','song-ci','失调名','[]','金谷移春，玉壶贮暖。',10,'宋词/ci.song.16000.json','["金谷移春，玉壶贮暖。"]'),
('song-ci-550','失调名','张枢','宋','宋词','song-ci','失调名','[]','拥石池台，约花阑槛。',10,'宋词/ci.song.16000.json','["拥石池台，约花阑槛。"]'),
('song-ci-551','兰陵王','叶隆礼','宋','宋词','song-ci','兰陵王','[]','大堤直。',158,'宋词/ci.song.16000.json','["大堤直。", "袅袅游云蘸碧。", "兰舟上，曾记那回，拂粉涂黄弄春色。", "施颦托倾国。", "金缕尊前劝客。", "阳台路，烟树万重，空有相思寄鱼尺。", "飘零叹萍迹。", "自懒展罗衾，羞对瑶席。", "折钗分镜盟难食。", "看桃叶迎笑，柳枝垂结。", "萋萋芳草暗水驿。", "肠断画阑北。", "寒恻。", "泪痕积。", "想柱雁尘侵，笼羽声寂。", "天涯流水情何极。", "悲沈约宽带，马融怨笛。", "那堪灯幌，听夜雨，镇暗滴。"]'),
('song-ci-552','水调歌头','家铉翁','宋','宋词','song-ci','水调歌头','[]','瀛台居北界，觌面是重城。',114,'宋词/ci.song.16000.json','["瀛台居北界，觌面是重城。", "老龙蹲踞不动，潭影净无尘。", "此地高阳胜处，天付仙翁为主，那肯借闲人。", "暂挂西堂锡，仍同旦过宾。", "六年里，五迁舍，得比邻。", "儒馆豆笾於粲，弦诵有遗音。", "甚喜黄冠为侣，更得青衿来伴，应不叹飘零。", "夜宿东华榻，朝餐泮水芹。"]'),
('song-ci-553','念奴娇','家铉翁','宋','宋词','song-ci','念奴娇','[]','神仙何处，人尽道、我州三神之一。',120,'宋词/ci.song.16000.json','["神仙何处，人尽道、我州三神之一。", "为问何年飞到此，拔地倚天无迹。", "缥缈琼宫，溟茫朱户，不与尘寰隔。", "翩然鹤下，时传云外消息。", "露冷风清夜阑，梦高人过我，欢如畴昔。", "道骨仙风谁得似，谈笑云生几席。", "共踏银虬，迫随绛节，恍遇群仙集。", "云韶九奏，不类人间金石。"]'),
('song-ci-554','念奴娇','家铉翁','宋','宋词','song-ci','念奴娇','[]','南来数骑，问征尘、正是江头风恶。',120,'宋词/ci.song.16000.json','["南来数骑，问征尘、正是江头风恶。", "耿耿孤忠磨不尽，惟有老天知得。", "短棹浮淮。", "轻毡渡汉，回首觚棱泣。", "缄书欲上，惊传天外清跸。", "路人指示荒台，昔汉家使者，曾留行迹。", "我节君袍雪样明，俯仰都无愧色。", "送子先归，慈颜未老，三径有馀乐。", "逢人问我，为说肝肠如昨。"]'),
('song-ci-555','清平乐','石正伦','宋','宋词','song-ci','清平乐','[]','香摇穗碧。',54,'宋词/ci.song.16000.json','["香摇穗碧。", "梅巧红酥滴。", "云涴宝钗蝉坠翼。", "娇小争禁酒力。", "绣窗芳思迟迟。", "无端又敛双眉。", "贪把兰亭学字，一冬忘了弹棋。"]'),
('song-ci-556','绮寮怨','石正伦','宋','宋词','song-ci','绮寮怨','[]','绿野春浓停骑，暖风飘醉襟。',129,'宋词/ci.song.16000.json','["绿野春浓停骑，暖风飘醉襟。", "渐触目、景物凄悲，花无语、曲径沈沈。", "重檐缭垣静锁，丹青暗、断轴尘半侵。", "叹绛纱、玉臂封时，何期掩、夜泉流恨深。", "已矣霜凋蕙心。", "兰昌旧事，云容好信难寻。", "伫立孤吟。", "怕凤履、有遗音。", "今宵佩环奏月，知倦客、若登临。", "惊飞翠禽。", "松杉弄碎影、晴又阴。"]'),
('song-ci-557','渔家傲','石正伦','宋','宋词','song-ci','渔家傲','[]','春入桃腮生妩媚。',72,'宋词/ci.song.16000.json','["春入桃腮生妩媚。", "妆成日日行云意。", "贪听新声翻歇指。", "工尺字。", "窗前自品琼箫试。", "玉碾鸾钗珠结桂。", "金泥络缝乾红袂。", "从把画图夸绝世。", "金莲地。", "六朝未识双鸳细。"]'),
('song-ci-558','霓裳中序第一','石正伦','宋','宋词','song-ci','霓裳中序第一','[]','凭高快醉目。',125,'宋词/ci.song.16000.json','["凭高快醉目。", "翠拂遥峰相对簇。", "千丈涟漪泻谷。", "爱溶漾坠红，染波芬馥。", "何人笑掬。", "想温泉、初卸绡縠。", "春风荡，六宫丽质，那日赐汤沐。", "双浴。", "绣凫飘逐。", "恍记展、江南数幅。", "而今鬓边渐鹄。", "阮洞音稀，懒访仙躅。", "系船桥畔宿。", "听静夜、泠泠奏曲。", "长安远，渭流香腻，暗忆晚鬟绿。"]'),
('song-ci-559','宝鼎现','陈著','宋','宋词','song-ci','宝鼎现','[]','玉宸凝眷。',192,'宋词/ci.song.16000.json','["玉宸凝眷。", "要得培□，神皋根本。", "天赋与、经纶好手，门外红尘谈笑遣。", "任草色、遍空庭交翠，月往风来自便。", "但纸帐、时供小憩，长理灯窗公案。", "五行俱下流光电。", "笔如神、毫发都见。", "是则是、霜严雪劲，到底春风生意满。", "唤得应、雨和晴恰好，旗舞粳艘百万。", "更社鼠城狐扫影，雁鹜惊人避箭。", "最是满腹精神，担负处、浑身皆胆。", "又谁知、条理元在，规模里面。", "天下事、又何难办。", "待副苍生愿。", "渺宇宙、多少关心，留取功名久远。"]'),
('song-ci-560','真珠帘','陈著','宋','宋词','song-ci','真珠帘','[]','纶巾古貌尘寰表。',123,'宋词/ci.song.16000.json','["纶巾古貌尘寰表。", "风流处、别是英雄才调。", "胸次著乾坤，触景皆诗料。", "金碧楼台新筑就，傍翠麓、旋添花草。", "仙棹。", "更逍遥来访，十洲三岛。", "遮眼富贵人多，算如公有子，人间应少。", "看膝下功名，共月林清皎。", "象简绯袍亲侍策，且胜赏、先春独笑。", "都道。", "馆中书就养，云翘偕老。"]'),
('song-ci-561','大酺','陈著','宋','宋词','song-ci','大酺','[]','把雪冰心，钧韶手，飞上青云时早。',164,'宋词/ci.song.16000.json','["把雪冰心，钧韶手，飞上青云时早。", "红尘难染著，十年前曾坐，凤池鳌岛。", "晕锦锵环，重金压带，相去能争多少。", "从容何心问，到如今都领，绣春花草。", "算耐处光阴，淡中滋味，世人那晓。", "笺天新有稿。", "要归去、盘礴山阴道。", "便整顿、随琴霜鹤，带石秋兰，约松乔、倚风清啸。", "争奈俞音杳。", "明月棹、又还停了。", "但珍重、经纶料。", "时来须做，休管急流人笑。", "功名尽迟尽好。"]'),
('song-ci-562','大酺','陈著','宋','宋词','song-ci','大酺','[]','问大江东，长淮上，缘分如何修到。',164,'宋词/ci.song.16000.json','["问大江东，长淮上，缘分如何修到。", "轻裘还熟局，第三番又是，五年春了。", "菜饭工夫，露香心事，惟靠天公分晓。", "林泉琴书梦，算飞笺觅去，不知多少。", "奈雅意难酬，又还留住，口衔新诏。", "都无他嗜好。", "玉麟静、公事供谈笑。", "满眼是、风花飘忽，惟有长松，雪霜里、插天苍老。", "休忆家山好。", "安乐处、便成蓬岛。", "正春雨、秧畴饱。", "边城如画，处处绿杨芳草。", "青溪不妨寄傲。"]'),
('song-ci-563','大酺','陈著','宋','宋词','song-ci','大酺','[]','自有乾坤，扶人极，宗主须还人物。',164,'宋词/ci.song.16000.json','["自有乾坤，扶人极，宗主须还人物。", "今为何时节，满红尘富贵，絮花飘忽。", "抵障狂澜，提携正印，一柱天擎突兀。", "平生分明处，是从容处□，不差毫发。", "把朝市山林，一般看了，无边风月。", "深衣清到骨。", "紫枢府、谁信曾簪笏。", "炊脱粟、黄鸡白酒，补菊栽梅，碧溪绕、竹篱茅屋。", "无限轻描貌。", "都说道、诏书催发。", "想回首、招黄鹄。", "微微自笑，惟有赤松衣钵。", "相陪对门石佛。"]'),
('song-ci-564','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','潇洒书斋，香清缕直，灯冷晕圆。',139,'宋词/ci.song.16000.json','["潇洒书斋，香清缕直，灯冷晕圆。", "忽惊窗鸣瓦，霰如筛下，裁冰翦玉，片似花鲜。", "深怕妨梅，也愁折竹，才作还休亦偶然。", "更深也，漫题窗记瑞，诗思绵绵。", "闻君礼佛日千。", "浪说道繁华不值钱。", "想鸳衾底下，都将命乞，蒲龛里畔，未必心安。", "兜率天宫，清凉境界，总是由心不是缘。", "雪山上，自有人坐了，不到君边。"]'),
('song-ci-565','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','出禁城西，湖光自别，唤醒两瞳。',140,'宋词/ci.song.16000.json','["出禁城西，湖光自别，唤醒两瞳。", "有画桥几处，通人南北，绿堤十里，分水西东。", "问柳旗亭，簇山梵所，空翠烟飞半淡浓。", "偏奇处，看笙歌千舫，泛绮罗宫。", "从容。", "莫问城中。", "是则是繁华九市通。", "奈一番雨过，沾衣泥黑，三竿日上，扑面尘红。", "那壁喧器，这边清丽，咫尺中间敻不同。", "休归去，便舣舟荷外，梦月眠风。"]'),
('song-ci-566','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','潇洒纶巾，风流野服，红尘外身。',139,'宋词/ci.song.16000.json','["潇洒纶巾，风流野服，红尘外身。", "向南窗听雨，澜翻墨客，北亭恋月，笔走诗神。", "倚竹听琴，逢花倒磕，更得放晴游冠春。", "清闲好，算东洲人物，难得如君。", "华堂瑞气如云。", "西风到帘帷才一分。", "喜星桥鹊语，佳传依旧，缑山鹤舞，仙样翻新。", "箫玉香中，烛花影里，听取捧觞低祝人。", "千千岁，看功名事业，都在儿孙。"]'),
('song-ci-567','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','月旦评中，有如公者，更谁与俦。',140,'宋词/ci.song.16000.json','["月旦评中，有如公者，更谁与俦。", "看纷纷仁意，春风和气，堂堂义事，砥柱中流。", "已重物轻，身穷道泰，却占人间第一筹。", "回头笑，彼纷纷名利，过影浮沤。", "夷犹。", "庭户清幽。", "算此境神仙别一洲。", "但烧香挂画，呼童扫地，对山揖水，共客登楼。", "付与儿孙，只将方寸，此外无求百不忧。", "宜多寿，自今开八帙，到八千秋。"]'),
('song-ci-568','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','小枕屏儿，面儿素净，吾自爱之。',139,'宋词/ci.song.16000.json','["小枕屏儿，面儿素净，吾自爱之。", "向春晴欲晓，低斜半展，夜寒如水，屈曲深围。", "消得题诗，不须作画，潇洒风流未易涯。", "人间世，但此身安处，是十分奇。", "笑他富贵家儿。", "这长物何为著意□。", "便绮罗六扇，何如玉洁，丹青万状，都是钱痴。", "假托伊来，遮阑便了，免得惊风侵梦时。", "何须泥，要物常随我，不物之随。"]'),
('song-ci-569','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','运在东南，温厚气锺，吾葺芷翁。',139,'宋词/ci.song.16000.json','["运在东南，温厚气锺，吾葺芷翁。", "羡檠窗学问，迂斋正印，玉堂词翰，攻愧流风。", "制胜枢庭，参谋政府，一片平心扶大中。", "黄扉近，却翻然东顾，归宴方蓬。", "潘舆日奉从容。", "全胜□貂蝉趋汉宫。", "如名山镇静，出云相望，大川渟蓄，有水皆宗。", "吾道胚腪，诸贤命脉，阴受春风和气浓。", "宜多寿，与瑶图同庆，绿竹歌公。"]'),
('song-ci-570','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','吾竹窗兄，吾能评者，只将竹看。',140,'宋词/ci.song.16000.json','["吾竹窗兄，吾能评者，只将竹看。", "是丹山佳气，胚腪茂直，嵩溪润脉，滋养清坚。", "雪虐霜凌，风饕雨恶，撼顿侵欺今几年。", "元无损，这虚心实节，却自依然。", "人间。", "输此君贤。", "可曾向红尘里著鞭。", "称翩翩侣凤，舞依翡翠，昂昂雏鹤，立倚琅玕。", "动处非情，静中自韵，全得生来潇洒天。", "须长在，在月窗窗北，石涧东边。"]'),
('song-ci-571','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','吾菊坡兄，细观花□，元来一般。',139,'宋词/ci.song.16000.json','["吾菊坡兄，细观花□，元来一般。", "是鄮山佳气，胚腪长茂，鄞江润脉，滋养清妍。", "移傍云霄，浓沾雨露，曾亚百花头上班。", "谁知道，待芬香透了，收敛东边。", "笑他红紫纷然。", "算眼底何曾长久看。", "这秋芳自韵，不争春艳，霜根难老，偏耐风寒。", "占得清名，尊为寿客，晚节谁能如此全。", "千千岁，把黄金正色，照映人间。"]'),
('song-ci-572','水龙吟','陈著','宋','宋词','song-ci','水龙吟','[]','玉麟堂上神仙，算来便合归廊庙。',126,'宋词/ci.song.16000.json','["玉麟堂上神仙，算来便合归廊庙。", "天教且住，堂堂裘带，舒舒旗纛。", "一笑谈中，遍江淮上，太平花草。", "待金瓯揭了，黄扉坐处，祗依此、规模好。", "恰似虹流节后，庆生申、佳期还到。", "乾坤开泰，君臣相遇，机缘恁巧。", "谁信苍生，举头凝望，锋车催召。", "向芜湖，更有无言桃李，顾春风早。"]'),
('song-ci-573','水龙吟','陈著','宋','宋词','song-ci','水龙吟','[]','玉鳌头上蓬莱，十分好处饶松壑。',126,'宋词/ci.song.16000.json','["玉鳌头上蓬莱，十分好处饶松壑。", "无边风月，阴阴乔木，重重华萼。", "秋水门庭，淡交簪履，随宜斟酌。", "向西风回首，双旌缥缈，从天下、招琴鹤。", "是则阳春有脚。", "被金华、洞天留著。", "相传好语，新来初见，分明鼓角。", "田里相安，裤襦歌了，却来持橐。", "称年年，橘绿橙黄时节，与松乔约。"]'),
('song-ci-574','瑞鹤仙','陈著','宋','宋词','song-ci','瑞鹤仙','[]','云无心出岫。',127,'宋词/ci.song.16000.json','["云无心出岫。", "游戏间、声名掀揭宇宙。", "红尘事看透。", "任高官惟有，鹤随诗瘦。", "溪山如绣。", "小轩亭、篘新话旧。", "想时时，梦到家林，但未有归时候。", "知否。", "分明世界，多少经纶，莫轻回首。", "平生抱负。", "金銮殿，有新奏。", "便相扶君相，从头做去，他又谁能出手。", "看明年、此日传宣，赐酴醿酒。"]'),
('song-ci-575','摸鱼儿','陈著','宋','宋词','song-ci','摸鱼儿','[]','碧油幢、一开藩后，便思量早归去。',140,'宋词/ci.song.16000.json','["碧油幢、一开藩后，便思量早归去。", "工夫著紧新城好，风月万家笙鼓。", "游宴处。", "要管领春光，补种花无数。", "何须更驻。", "只画了潇湘，扁舟径发，挥手谢南楚。", "江帆卸、撑入清溪绿树。", "家山三两程路。", "安排小马随猿鹤，勾引诗朋酒侣。", "潇洒处。", "是则是初心，只恐难留驻。", "忙须著句。", "把泉石烟霞，平章一遍，回首凤纶舞。"]'),
('song-ci-576','洞仙歌','陈著','宋','宋词','song-ci','洞仙歌','[]','冰肌玉骨，自清凉无汗。',103,'宋词/ci.song.16000.json','["冰肌玉骨，自清凉无汗。", "云影鬅鬙翠山远。", "颤金莲缓步，手托珠帘，风微透，扇底荷花香满。", "归檐双飞燕，流盼消凝，微带羞红上娇面。", "又还黄昏近，一片闲情，天涯去、云也遮阑不断。", "回首处、沈思梦时曾，对十二屏山，怕拈秦阮。"]'),
('song-ci-577','洞仙歌','陈著','宋','宋词','song-ci','洞仙歌','[]','冰肌玉骨，自清凉无汗，午梦醒来盼娇满。',101,'宋词/ci.song.16000.json','["冰肌玉骨，自清凉无汗，午梦醒来盼娇满。", "扇轻拈又放，浅炷兰薰，微笑处、吹著烟丝散乱。", "凉亭还独步，曾是凭阑，携手心盟指云汉。", "碧云斜阳外，信有如今，音书杳、寸肠千转。", "漫伫立、无言对荷花，看转眼秋风，翠移红换。"]'),
('song-ci-578','念奴娇','陈著','宋','宋词','song-ci','念奴娇','[]','洛阳地脉，是谁人、缩到海涯天角。',120,'宋词/ci.song.16000.json','["洛阳地脉，是谁人、缩到海涯天角。", "绿树成阴芳雾底，得见当年台阁。", "园杏贵客，海棠姬侍，拥入青油幕。", "人间那有，风流天上标格。", "如困如懒如羞，夜来应梦入，西瑶仙宅。", "为你闲风轻过去，□□不教妨却。", "娇不能行，笑还无语，惟把香狼藉。", "花花听取，年年无负春约。"]'),
('song-ci-579','念奴娇','陈著','宋','宋词','song-ci','念奴娇','[]','轻衫短旆，几年来、游遍江南江北。',120,'宋词/ci.song.16000.json','["轻衫短旆，几年来、游遍江南江北。", "扰扰浮生争富贵，金碧楼台满目。", "厦屋千间，夜床八尺，此理谁能烛。", "翩然归去，家山是事都足。", "笑指旧隐逍遥，分猿鹤地，云顶栽花竹。", "乘兴生涯随处好，卜市心□新筑。", "山色窥帘，杏阴依户，门外从尘俗。", "朱颜雪鬓，清闲十二分福。"]'),
('song-ci-580','念奴娇','陈著','宋','宋词','song-ci','念奴娇','[]','暑天向晚，最相宜、一簇凉生新竹。',120,'宋词/ci.song.16000.json','["暑天向晚，最相宜、一簇凉生新竹。", "潇洒轩窗还此景，此景真非凡俗。", "猿鹤相随，烟霞自在，与我交情熟。", "人生如梦，个中堪把心卜。", "休叹乌兔如飞，功名富贵，有分终须足。", "不管他非非是是，不管他荣和辱。", "净几明窗，残编断简，且恁闲劳碌。", "流萤过去，文章如在吾目。"]'),
('song-ci-581','念奴娇','陈著','宋','宋词','song-ci','念奴娇','[]','紧头上立，问如何、犹向清溪盘礴。',120,'宋词/ci.song.16000.json','["紧头上立，问如何、犹向清溪盘礴。", "应为春防须熟局，且借轻裘弹压。", "野聚晴炊，烟波暖唱，尽出江南北。", "从容归衮，三年功满棋柝。", "真个福比南山，谁无富贵，无此团圞乐。", "锦瑟瑶琴清对处，青紫诸郎参错。", "楚楚孙枝，温温婿玉，帘幕欢声拍。", "抠衣小子，寿公也趁龟鹤。"]'),
('song-ci-582','满江红','陈著','宋','宋词','song-ci','满江红','[]','落枕鸿声，龙山梦、蓦然惊觉。',115,'宋词/ci.song.16000.json','["落枕鸿声，龙山梦、蓦然惊觉。", "还堪喜、木樨香底，鹊声翻晓。", "弄雨未成霜意懒，望寒先怯山容老。", "最难逢、无一点西风，惊乌帽。", "竹叶酒，倾杯小。", "橙齑鲙，银盆好。", "称良辰欢宴，及今年少。", "须信从来黄菊寿，未应便放青霜恼。", "但看花、日日是重阳，金尊倒。"]'),
('song-ci-583','满江红','陈著','宋','宋词','song-ci','满江红','[]','越水稽山，清明气、锺为人极。',115,'宋词/ci.song.16000.json','["越水稽山，清明气、锺为人极。", "彯缨早、□中学问，从头施设。", "不受尘来霜壁立，常生意处春流活。", "与世间、别是一规模，师夔契。", "仙岛上，分风月。", "苍梧下，怀冰雪。", "更双亲犹是，朱颜时节。", "熏业要从青鬓上，乾坤如许丹山折。", "看凤衔、芝诏下层霄，朝金阙。"]'),
('song-ci-584','满江红','陈著','宋','宋词','song-ci','满江红','[]','修茂堂深，芳尘满、沈烟一朵。',115,'宋词/ci.song.16000.json','["修茂堂深，芳尘满、沈烟一朵。", "帘半卷，好风催晓，晴光才破。", "新润顿教萱草鬯，轻寒未放酴醿过。", "称鱼轩、容与寿如山，群仙贺。", "琴帏底，声调和。", "庭阶下，儿孙大。", "喜新来咿喔，又还添个。", "总是人生如意处，休将时事关眉锁。", "趁莺花、时节绮罗筵，年年作。"]'),
('song-ci-585','烛影摇红','陈著','宋','宋词','song-ci','烛影摇红','[]','风月堂中，画屏不动香猊吐。',116,'宋词/ci.song.16000.json','["风月堂中，画屏不动香猊吐。", "珠翘环拥蕊宫仙，双鬓青如许。", "相对童颜寿侣。", "看庭前、绯袍拜舞。", "十洲三岛，柳探春时，梅欺雪处。", "甲子花周，自从今日重新数。", "碧瑶杯重翠涛深，笑领飞琼语。", "此去华筵喜聚。", "听传宣、云间紫府。", "万分如意，凤诏便蕃，香轩容与。"]'),
('song-ci-586','水调歌头','陈著','宋','宋词','song-ci','水调歌头','[]','风骨最魁岸，宇宙更宽平。',114,'宋词/ci.song.16000.json','["风骨最魁岸，宇宙更宽平。", "□人皆道，天上南极寿星精。", "随意后园花木，满眼家山松竹，尽可适平生。", "门外底须问，好占菊轩清。", "听乡评，义方训，莫如兄。", "元方既玉就□，更要季方成。", "不使尘劳顿挫，他日功名入手，当不负椿庭。", "不见窦谏议，教子有馀荣。"]'),
('song-ci-587','水调歌头','陈著','宋','宋词','song-ci','水调歌头','[]','身到紫枢府，一蹴凤池间。',114,'宋词/ci.song.16000.json','["身到紫枢府，一蹴凤池间。", "何妨到头富贵，却自恋家山。", "多少名缰利锁，尘满霜髯雪鬓，役役不知还。", "桃李竞春事，坡菊自清闲。", "绿杨边，门径小，似僧关。", "吟情饮兴相将，二十载优闲。", "无限功名事业，分付儿孙纵靶，青镜尽朱颜。", "一语劝公酒，天下达尊三。"]'),
('song-ci-588','千秋岁','陈著','宋','宋词','song-ci','千秋岁','[]','燕前莺底。',87,'宋词/ci.song.16000.json','["燕前莺底。", "一日春犹在。", "香雾晓，祥云霁。", "烟交槐影重，风约花尘卸。", "当此际。", "桃源不是人间世。", "彩袖环庭砌。", "华裾纷珂佩。", "欢声洽，童颜醉。", "金丹功已到，绿发生须再。", "箫鼓沸。", "飞琼来祝千千岁。"]'),
('song-ci-589','踏莎行','陈著','宋','宋词','song-ci','踏莎行','[]','杏苑长春，椿姿耐老。',68,'宋词/ci.song.16000.json','["杏苑长春，椿姿耐老。", "画堂琴幌融融调。", "生涯分付宁馨儿，西园手种闲花草。", "露浴明河，风浮素颢。", "桂花著蕊今年早。", "佳占端的在孙枝，明年寿席唲呕笑。"]'),
('song-ci-590','鹊桥仙','陈著','宋','宋词','song-ci','鹊桥仙','[]','云南锺秀，间生人望。',68,'宋词/ci.song.16000.json','["云南锺秀，间生人望。", "底事未成美况。", "当知大器大成时，更莫叹、贤关难上。", "前程分定，算来无妄。", "命达时终不放。", "且须寄语甲科人，断不下、一筹中榜。"]'),
('song-ci-591','一翦梅','陈著','宋','宋词','song-ci','一翦梅','[]','记得儿时识景年。',72,'宋词/ci.song.16000.json','["记得儿时识景年。", "翕忽光阴，二十馀年。", "梅边聚首又三年。", "结得因缘。", "五百来年。", "把酒君前欲问年。", "笑指松椿，当是同年。", "愿从今后八千年。", "长似今年。", "长似今年。"]'),
('song-ci-592','惜分飞','陈著','宋','宋词','song-ci','惜分飞','[]','筑垒愁城书一纸。',58,'宋词/ci.song.16000.json','["筑垒愁城书一纸。", "雁雁儿将不起。", "好去西风里。", "到家分付眉颦底。", "落日阑干羞独倚。", "十里江山万里。", "容易成憔悴。", "惟归来是归来是。"]'),
('song-ci-593','西江月','陈著','宋','宋词','song-ci','西江月','[]','宝瑟屏金深深处，斑衣箫玉香中。',59,'宋词/ci.song.16000.json','["宝瑟屏金深深处，斑衣箫玉香中。", "人生二美古难逢。", "杏苑今朝喜共。", "一霎豆花新雨，半帘梧叶清风。", "年年此景绿尊同。", "笑指南山称颂。"]'),
('song-ci-594','西江月','陈著','宋','宋词','song-ci','西江月','[]','箫玉和鸣云里，彩衣娱舞风前。',58,'宋词/ci.song.16000.json','["箫玉和鸣云里，彩衣娱舞风前。", "好从龟鹤问长年。", "看取蟠桃结遍。", "事业都随今定，儿孙也靠心传。", "隐耕窗下腹便便。", "相去神仙不远。"]'),
('song-ci-595','西江月','陈著','宋','宋词','song-ci','西江月','[]','当此朱炎火日，恨无玉骨冰肌。',58,'宋词/ci.song.16000.json','["当此朱炎火日，恨无玉骨冰肌。", "问来思欲动凉飔。", "宝箑荷君相遗。", "如铁又添颜甲，报琼难续声诗。", "愿言长在奉扬时。", "似恁团圞到底。"]'),
('song-ci-596','小重山','陈著','宋','宋词','song-ci','小重山','[]','松是交朋竹是邻。',70,'宋词/ci.song.16000.json','["松是交朋竹是邻。", "横枝临水瘦，月黄昏。", "冲寒香入岭头云。", "清到底，人共一般清。", "好句更无痕。", "门前无俗客，不须扃。", "暂将骚致答花神。", "从此去，题动玉堂春。"]'),
('song-ci-597','柳梢青','陈著','宋','宋词','song-ci','柳梢青','[]','淡淡新妆，盈盈娇态，谁道荷花。',61,'宋词/ci.song.16000.json','["淡淡新妆，盈盈娇态，谁道荷花。", "料想香肌，不禁畏日，翠盖儿遮。", "我来胜赏高歌。", "故敛著、芳心为何。", "莫是伊花，恨余来晚，欲媚晨霞。"]'),
('song-ci-598','柳梢青','陈著','宋','宋词','song-ci','柳梢青','[]','缥缈瑶城。',61,'宋词/ci.song.16000.json','["缥缈瑶城。", "客情春小，本分寒轻。", "霞佩云裾，步联西母，笑倚飞琼。", "那堪四美都并。", "喜气与、祥云共生。", "自在风流，融融箫玉，楚楚兰馨。"]'),
('song-ci-599','霜天晓角','陈著','宋','宋词','song-ci','霜天晓角','[]','江寒雁咽。',54,'宋词/ci.song.16000.json','["江寒雁咽。", "短棹还催发。", "曾是玉堂仙伯，相别处、满篷雪。", "此别。", "那堪说。", "溯风空泪血。", "惟有梅花依旧，香不断、夜来月。"]'),
('song-ci-600','卜算子','陈著','宋','宋词','song-ci','卜算子','[]','一自梦卢头，应学乘裴蹇。',52,'宋词/ci.song.16000.json','["一自梦卢头，应学乘裴蹇。", "元是都门向上人，大用何嫌晚。", "三岁事非遥，三捷功非远。", "管取微生共此荣，联步云程稳。"]'),
('song-ci-601','卜算子','陈著','宋','宋词','song-ci','卜算子','[]','雨逗一分寒，未放晴光透。',51,'宋词/ci.song.16000.json','["雨逗一分寒，未放晴光透。", "绮席春风十分，畅饮长春酒。", "花气渐薰帘，佳致归诗手。", "的是诗中陆地仙，左挹浮丘袖。"]'),
('song-ci-602','卜算子','陈著','宋','宋词','song-ci','卜算子','[]','风急雁声高，露冷蛩吟切。',52,'宋词/ci.song.16000.json','["风急雁声高，露冷蛩吟切。", "枕剩衾寒不耐烦，长是伤离别。", "望得眼儿穿，巴得心头热。", "且喜重阳节又来，黄菊花先发。"]'),
('song-ci-603','减字木兰花','陈著','宋','宋词','song-ci','减字木兰花','[]','浮萍踪迹。',52,'宋词/ci.song.16000.json','["浮萍踪迹。", "又作南东□□客。", "不奈秋阳。", "一似朱明赫赫光。", "惊雷叱雨。", "料是阿香怜逆旅。", "好个凉天。", "称我前程步步便。"]'),
('song-ci-604','减字木兰花','陈著','宋','宋词','song-ci','减字木兰花','[]','夜帆初上。',52,'宋词/ci.song.16000.json','["夜帆初上。", "准拟今朝过越上。", "及到今朝。", "却被西风挫一潮。", "丈亭一处。", "要得纵观赢得住。", "行止皆天。", "谁道人生客路难。"]'),
('song-ci-605','如梦令','陈著','宋','宋词','song-ci','如梦令','[]','家在明山南住。',40,'宋词/ci.song.16000.json','["家在明山南住。", "身在明山西路。", "回首碧云端，自笑不如飞鹜。", "飞去。", "飞去。", "飞入明山深处。"]'),
('song-ci-606','如梦令','陈著','宋','宋词','song-ci','如梦令','[]','晚泊江湾平处。',40,'宋词/ci.song.16000.json','["晚泊江湾平处。", "楚楚苹花自舞。", "风翦雨丝轻，江上潮生船去。", "看取。", "看取。", "湿橹不惊鸥鹭。"]'),
('song-ci-607','捣练子','陈著','宋','宋词','song-ci','捣练子','[]','花影乱，晓窗明。',32,'宋词/ci.song.16000.json','["花影乱，晓窗明。", "莺弄春笙柳外声。", "和梦卷帘飞絮入，牡丹无语正盈盈。"]'),
('song-ci-608','鹧鸪天','陈著','宋','宋词','song-ci','鹧鸪天','[]','看了山中薜荔衣。',64,'宋词/ci.song.16000.json','["看了山中薜荔衣。", "手将安石种分移。", "花鲜绚日猩红妒，叶密乘风翠羽飞。", "新结子，绿垂枝。", "老来眼底转多宜。", "牙齿不入甜时样，醋醋何妨荐酒卮。"]'),
('song-ci-609','念奴娇','陈著','宋','宋词','song-ci','念奴娇','[]','翠云弄晓，芰荷香、微透凉飔帘箔。',120,'宋词/ci.song.16000.json','["翠云弄晓，芰荷香、微透凉飔帘箔。", "彩袂蹁跹欢舞处，勾引衔桃双鹤。", "骤马风前，奔鲸浪里，独有壶天乐。", "如何不醉，放教杯量宽著。", "消得寿八千春，百分才一，更童颜如渥。", "听取飞琼含笑道，堪学孩儿书额。", "舄令骖凫，瑶仙跨凤，喜聚家人醵。", "心香遥上，也随风过蓬弱。"]'),
('song-ci-610','摸鱼儿','陈著','宋','宋词','song-ci','摸鱼儿','[]','竹洲西、有人如玉，南柯一觉归早。',140,'宋词/ci.song.16000.json','["竹洲西、有人如玉，南柯一觉归早。", "青山绿水亭轩旧，犹有未荒花草。", "谁信道。", "又自爱湖光，买屋三间小。", "都无长好。", "但凤跃雄文，蝇书小楷，转老转奇妙。", "人间世，如许年高是少。", "浮生惟有闲好。", "回头翻讶磻溪叟，轻把一丝抛了。", "凉新到。", "记当日天香，露浴如今老。", "瑶卮寿晓。", "称酒到眉间，醺醺醉也，儿女满前笑。"]'),
('song-ci-611','庆春泽','陈著','宋','宋词','song-ci','庆春泽','[]','翔凤阑干，啼鹃院宇，相逢似梦才醒。',122,'宋词/ci.song.16000.json','["翔凤阑干，啼鹃院宇，相逢似梦才醒。", "谁道无情，飞红舞翠欢迎。", "青春绿发花前饮，醉自歌、记那时曾。", "到如今，心事凄凉，怕说芳盟。", "追思艮岳归来后，稳依山护得，雨翮风翎。", "燕燕莺莺，从他巧舌饶声。", "翩翩一种天然艳，笑向人、不与春争。", "羡花花，好岁寒交，有卧云亭。"]'),
('song-ci-612','庆春泽','陈著','宋','宋词','song-ci','庆春泽','[]','春困时光，风流昨梦，逢花便自醒醒。',122,'宋词/ci.song.16000.json','["春困时光，风流昨梦，逢花便自醒醒。", "回首宣和，宫莺掖燕相迎。", "归来只恋春山好，到上林、枉是亲曾。", "又谁知，自有蟠松，相与论盟。", "阑干可是妨飞去，怕惊尘涴却，翠羽红翎。", "舞态亭亭，浑疑暗折韶声。", "忺人眼处还看破，道凤来、难与真争。", "醉扶归，但见啼鹃，怨夕阳亭。"]'),
('song-ci-613','水龙吟','陈著','宋','宋词','song-ci','水龙吟','[]','蓬莱风月神仙，却来平地为霖雨。',126,'宋词/ci.song.16000.json','["蓬莱风月神仙，却来平地为霖雨。", "乾坤清了，如今多是，退行一步。", "寸寸归心，轻轩娱侍，竹溪花圃。", "奈君王眷眷，苍生恋恋，那肯放、钱塘渡。", "天也知公此意，问升平、要抽身去。", "把些夏潦，和些秋哨，轻轻缀住。", "一转移来，元勋力量，他谁堪付。", "待汾阳、了却中书，别又商量出处。"]'),
('song-ci-614','真珠帘','陈著','宋','宋词','song-ci','真珠帘','[]','鱼轩富贵人间少。',123,'宋词/ci.song.16000.json','["鱼轩富贵人间少。", "那堪更、有子雍容廊庙。", "衮绣当斑衣，转色难心小。", "手把乾坤重整顿，略□□、微生一笑。", "分晓。", "是慈闱心事，如今著到。", "帘幕早是寒生，又橙黄近也，菊花香了。", "已劝九霞觞，春意浓於酒。", "玉带金鱼欢舞处，更捷骑、红尘峡□。", "知否。", "这花添锦上，年年重九。"]'),
('song-ci-615','宝鼎现','陈著','宋','宋词','song-ci','宝鼎现','[]','著林仙叟，梦境炊得，才香还觉。',192,'宋词/ci.song.16000.json','["著林仙叟，梦境炊得，才香还觉。", "回首渺，觚棱何处，云与商量浮计小。", "矮矮屋、半弓来闲地，也著三花两草。", "沸眼底、鞭风笠雨，不满茶边一笑。", "寿骨奇耸神清峭。", "散人装、游戏尘表。", "帘昼永、长留雅伴，吟唾宽飞潇洒料。", "最好是、瑟和琴同调，眉里相看耐老。", "更绿草、孙枝可意，谱得家传较早。", "争指画额儿儿，欢祝处、荷薰吹晓。", "记兰汤初试，当日风光又到。", "拚醵饮、任金尊倒。", "醉把羲娥傲。", "算万事、都是空花，雪柏霜松镇好。"]'),
('song-ci-616','宝鼎现','陈著','宋','宋词','song-ci','宝鼎现','[]','问今何日，旧也曾尾，东风鹓鹭。',192,'宋词/ci.song.16000.json','["问今何日，旧也曾尾，东风鹓鹭。", "回首念，家山桃李，归去来兮闻早赋。", "梦境里、尽何妨疏散，时趁莺晴信步。", "是则是、清闲自好，一点心犹怀古。", "记得平世痴儿女。", "自灯宵、游了三五。", "还次第、湖边去也，寒食清明炊未住。", "是处处、是丹青图画，随意狂歌醉舞。", "奈蓦被、烟花浪手，一掷残阳孤注。", "须信乐极悲来，谁道是、曾歌琼树。", "夕阳亭遗涴，翻得江涛似许。", "忍望著、□天津路。", "最是鹃啼苦。", "算世事、消把春看，还有落花飞絮。"]'),
('song-ci-617','真珠帘','陈著','宋','宋词','song-ci','真珠帘','[]','如梅在壑清标格。',123,'宋词/ci.song.16000.json','["如梅在壑清标格。", "襟怀好、又是融融春拍。", "鸳梦早惊飞，惯一窗岑寂。", "谱曲裁诗心自在，任雪月、风花需索。", "奇特。", "问生涯却道，浮云如得。", "回首门外黄尘，算何如、稳占溪光山色。", "八百岁为期，却十分才一。", "弟自高歌儿自舞，簇小小、榴花筵席。", "真率。", "镇无妨欢醉，年年今日。"]'),
('song-ci-618','真珠帘','陈著','宋','宋词','song-ci','真珠帘','[]','青云玉树南薰扇。',123,'宋词/ci.song.16000.json','["青云玉树南薰扇。", "京华地、别是潇湘图展。", "茉莉芰荷香，拍满笙箫院。", "雪藕盈盈歌袅处，早已带、秋声凄怨。", "堪叹。", "把时光轻靠，冰山一片。", "从古幻境如轮，问铜驼、应是多番曾见。", "谁把笛吹凉，总是腔新换。", "水枕风船空入梦，但极目、波流云远。", "消黯。", "更华林蝉咽，系人肠断。"]'),
('song-ci-619','真珠帘','陈著','宋','宋词','song-ci','真珠帘','[]','闲居是念随云散。',123,'宋词/ci.song.16000.json','["闲居是念随云散。", "琴帘底、却自平生心满。", "百二十年期，笑道今才半。", "一味齑盐清得瘦，婉娩似、梅花香晚。", "相伴。", "老霜松宁耐，溪山寒惯。", "探借十日前春，小杯盘、也做寿筵模范。", "绕膝舞斑衣，有酒从他劝。", "但任真来浑是处，梦不到、笙歌瑶燕。", "双健。", "任旁人播尽，风流眉案。"]'),
('song-ci-620','金盏子','陈著','宋','宋词','song-ci','金盏子','[]','眼底时光，奈老来、如何奈得秋何。',125,'宋词/ci.song.16000.json','["眼底时光，奈老来、如何奈得秋何。", "黄叶最多情，天分付、凉意一声先做。", "是处著露莎蛩，也酸吟相和。", "新雁想，飞到故都徘徊，未忍轻过。", "往事是堪唾。", "红枣信、烽折尽任他。", "湖山桂香自好，笙歌舫、沈沈醉也谁拖。", "可怜瘦月凄凉，把兴亡看破。", "如今□，但留下满城□，西风悲些。"]'),
('song-ci-621','玉漏迟','陈著','宋','宋词','song-ci','玉漏迟','[]','故都冬亦好。',115,'宋词/ci.song.16000.json','["故都冬亦好。", "风光可是，人间曾有。", "问雪楼台，肉阵不教寒透。", "妙手搀春弄巧，唤得应、千花如绣。", "灯市酒。", "笙歌镇似，元宵时候。", "见说是事都新，但破冻潮声，去来依旧。", "老梦无情，不到六桥风柳。", "回首孤山好景，倩人问、梅花安否。", "应自瘦。", "雪霜可能僝僽。"]'),
('song-ci-622','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','天盖西倾，地轴东翻，两年以来。',139,'宋词/ci.song.16000.json','["天盖西倾，地轴东翻，两年以来。", "那关中形势，已归勃勃，江南人马，都是回回。", "咄咄书空，栖栖问路，岁晚山空风雪催。", "如何得，与浑家踏遍，雪顶岩隈。", "谁知有客敲推。", "把世变心烦都说开。", "道严霜不杀，不成葭苇，冱寒惯耐，方是松梅。", "万事过前，一场梦里，分付茅柴三两杯。", "犹痴望，有太平时节，游戏春台。"]'),
('song-ci-623','沁园春','陈著','宋','宋词','song-ci','沁园春','["\u897f\u6e56"]','旗盖运迁，衣冠事乖，岂非命来。',139,'宋词/ci.song.16000.json','["旗盖运迁，衣冠事乖，岂非命来。", "自黄粱枕觉，分明看破，翠蓬舟近，及早抽回。", "谁料山深，也同鼎沸，步步危机忙里催。", "愁无奈，过青山万叠，碧水千隈。", "此愁何计能推。", "算何日天教眉锁开。", "记六桥花舫，晴边访柳，孤山草酌，雪后评梅。", "回首西湖，伤心前事，覆水如何收上杯。", "东风好，问如今吹入，谁处楼台。"]'),
('song-ci-624','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','人生功名，在醉梦中，早须掉头。',139,'宋词/ci.song.16000.json','["人生功名，在醉梦中，早须掉头。", "自南宫一券，尘泥偶脱，前程双毂，日月如流。", "蕙帐真盟，菜羹馀味，江上归舟谁得留。", "谁知道，有邵平瓜圃，何日封侯。", "天天又不人由。", "奈危世山林也有忧。", "况青岗不助，晋家风鹤，黑云直卷，吴分星牛。", "分寸残生，万千魔障，他事如今都罢休。", "关心处，是离离禾黍，故国宗周。"]'),
('song-ci-625','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','无价韶华，一笑相酬，青钱似苔。',139,'宋词/ci.song.16000.json','["无价韶华，一笑相酬，青钱似苔。", "奈东风轻劣，催红雨去，西园次第，放绿阴回。", "老后时光，眉间心事，恰似怕酸人著梅。", "须知道，有谁能百岁，日日开怀。", "从教世变轮推。", "也莫问人间春去来。", "看渊明归了，有形谁役，少陵醉里，无闷堪排。", "贫贼何妨，风流自别，不是沈沈浊世杯。", "层霄上，与大鹏盘礴，下视浮埃。"]'),
('song-ci-626','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','人生几何，如何不自，珍重此生。',139,'宋词/ci.song.16000.json','["人生几何，如何不自，珍重此生。", "向蠹残字上，甘心抛掷，蜗尖争处，著意丁宁。", "箭过时光，剑炊世界，谁带经锄谁笔耕。", "分明似，满一锅汤沸，无处清□。", "输兄。", "练得闲成。", "□无辱无忧惧惊。", "但菜羹粝饭，不求他味，芒鞋竹杖，足畅幽情。", "八十年来，万千看破，胸次春风秋月明。", "梅花帐，称困眠醒起，无打门声。"]'),
('song-ci-627','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','信书成痴，捱到如今，无生可谋。',140,'宋词/ci.song.16000.json','["信书成痴，捱到如今，无生可谋。", "奈浑家梦饭，谷难虚贷，长年断肉，菜亦悭搜。", "风雨潇潇，江山落落，死又还生春复秋。", "八十岁，是这般多活，堪吊堪羞。", "休休。", "盍自回头。", "要铁汉须从穷处求。", "那袁安闭户，恬然僵卧，少陵任妇，长是贫愁。", "一等清风，千年佳话，蚁蚋看他金谷楼。", "是是是，笑出门天阔，一片云浮。"]'),
('song-ci-628','水龙吟','陈著','宋','宋词','song-ci','水龙吟','[]','好花天也多悭，放迟留做残春主。',126,'宋词/ci.song.16000.json','["好花天也多悭，放迟留做残春主。", "丰肌弱骨，晴娇无奈，新妆相妒。", "翠幕高张，玉阑低护，怕惊风雨。", "记年时、多少诗朋酒伴，逢花醉、簪花舞。", "那料无情光景，到如今、水流云去。", "残枝剩叶，依依如梦，不堪相觑。", "心事谁知，杜鹃饶舌，自能分诉。", "日西斜，烟草凄凄，望断洛阳何处。"]'),
('song-ci-629','水龙吟','陈著','宋','宋词','song-ci','水龙吟','[]','百花开遍园林，又春归也谁为主。',126,'宋词/ci.song.16000.json','["百花开遍园林，又春归也谁为主。", "深黄浅紫，娇红腻白，他谁能妒。", "似不胜情，醉归花月，梦回云雨。", "又丰肌、恰被东风摇动，盈盈底、霓裳舞。", "世事纷纷无据。", "与杨花、飞来飞去。", "当年斗大，知他多少，蜂窥蝶觑。", "金谷春移，玉华人散，此愁难诉。", "漫寻思，承诏沈香亭上，倚阑干处。"]'),
('song-ci-630','水龙吟','陈著','宋','宋词','song-ci','水龙吟','[]','杜鹃啼正忙时，半风半雨春悭霁。',126,'宋词/ci.song.16000.json','["杜鹃啼正忙时，半风半雨春悭霁。", "酴醿未过，樱甜初熟，梅酸微试。", "一种红芳，九苞真色，舞窗翻砌。", "自仙樊去后，无人题凤，阑干外、成孤媚。", "谁信阳春妙手，锦云机、新番裁制。", "东君冷看，如何描摸，天然艳美。", "浑欲乘风，又如羞日，做双飞体。", "伫骖鸾，称得花前弄玉，与吟箫婿。"]'),
('song-ci-631','瑞鹤仙','陈著','宋','宋词','song-ci','瑞鹤仙','[]','对南山翠峭。',127,'宋词/ci.song.16000.json','["对南山翠峭。", "几百年、银青门第转好。", "梅花弄春小。", "向重帘暖处，华筵开早。", "斑衣簇绕。", "舞香云、哄堂颂祷。", "稳生涯、都自心田，自有老天堪靠。", "应道。", "□□□□，乐事难逢，可轻过了。", "鲈肥蟹健，桑落酒、酿来妙。", "称瑶卮争劝，襟怀宽放，一点尘嚣不到。", "但从今、家庆年年，醉乡里笑。"]'),
('song-ci-632','洞仙歌','陈著','宋','宋词','song-ci','洞仙歌','[]','清溪带竹，竹外山光抱。',101,'宋词/ci.song.16000.json','["清溪带竹，竹外山光抱。", "新筑浑如图画了。", "称闲心、管领昨夜天风，吹送□，端的琅音恰到。", "谁知青云上，鸾凤翱翔，曾把功名试多少。", "到如今梦觉，佩著飞霞，浑家问、玉芝瑶草。", "试冷看、重门外如何，恁得似，壶中羽衣尘表。"]'),
('song-ci-633','贺新郎','陈著','宋','宋词','song-ci','贺新郎','["\u897f\u6e56"]','北马飞江过。',141,'宋词/ci.song.16000.json','["北马飞江过。", "画图中、花城柳郭，万摧千挫。", "羌管直惊猿鹤梦，愁得千山翠锁。", "有多少、风餐雨卧。", "回首西湖空溅泪，醉沈沈、轻掷金瓯破。", "平地浪，如何亸。", "君家志气从来大。", "舞蓝袍、牵丝幕外，肯饶他个。", "谁料腥埃妨阔步，孤瘦依然故我。", "待天有情时须可。", "且占雪溪清绝处，看精神、全是梅花做。", "嫌暖饱，耐寒饿。"]'),
('song-ci-634','念奴娇','陈著','宋','宋词','song-ci','念奴娇','[]','晓村深处，记当年、轻被东风吹别。',120,'宋词/ci.song.16000.json','["晓村深处，记当年、轻被东风吹别。", "重得相看春雨屋，心事从头细说。", "深院灯寒，流苏帐暖，曾梦梅花月。", "如今何在，消凝分付啼鴂。", "亭馆飞入腥烟，残香惟有，数朵酴醿雪。", "旧燕寻巢来又去，也觉双飞声咽。", "泛梗生涯，空花世界，且做杯中活。", "可人兰玉，风光还有时节。"]'),
('song-ci-635','念奴娇','陈著','宋','宋词','song-ci','念奴娇','[]','百年光景，算山中、多占人间分数。',120,'宋词/ci.song.16000.json','["百年光景，算山中、多占人间分数。", "一片清风梅是主，弹压粗花俗树。", "小小鱼池，深深莺谷，曲曲香云路。", "堪诗堪画，是天分付闲处。", "闻要跨鹤西游，家林自好，且何妨留驻。", "趁取酴醿新煮酒，烧笋煎花为具。", "万事皆空，千金一刻，底用闲愁苦。", "无情杜宇，笑他催我归去。"]'),
('song-ci-636','念奴娇','陈著','宋','宋词','song-ci','念奴娇','[]','雨帘高卷，见榴花、应怪风流人老。',120,'宋词/ci.song.16000.json','["雨帘高卷，见榴花、应怪风流人老。", "是则年年佳节在，无奈闲心悄悄。", "巧扇风轻，香罗雪湿，梦里曾看了。", "如今溪上，欢盟分付年少。", "偏是眉好相宜，呼儿扶著，把菖蒲迎笑。", "说道浮生饶百岁，能有时光多少。", "幸自清贫，何妨乐趣，谱入瑶琴调。", "杯杯酒满，这般滋味谁晓。"]'),
('song-ci-637','绮罗香','陈著','宋','宋词','song-ci','绮罗香','[]','障暑稠阴，梳凉细缕，□□□□□□。',128,'宋词/ci.song.16000.json','["障暑稠阴，梳凉细缕，□□□□□□。", "露腋玲珑，多少闹中幽趣。", "断又续、可是无情，□相送、短长亭路。", "记春风、曾著莺啼，便娇那得袅如许。", "知音人自暗省，凝睇青云影里，黄昏犹伫。", "一部笙𥱧，消得翠腰供舞。", "堪对景、翻入新妆，鬓影低、衬教眉妩。", "试回头、旧日章台，怕听声咽处。"]'),
('song-ci-638','绮罗香','陈著','宋','宋词','song-ci','绮罗香','[]','袅入风腔，清含露脉，声在丝丝烟碧。',128,'宋词/ci.song.16000.json','["袅入风腔，清含露脉，声在丝丝烟碧。", "破暑吹凉，天付弄娇双腋。", "似恋恋、舞翠纤腰，断还续、忍相离拆。", "最欢时、微雨初晴，夕阳犹湿淡云隔。", "新来多少怆感，心怕无情过马，攀条惊著。", "梦里妆台，休说听来曾昨。", "凝伫漫、番节笙音，暗自将、玉阑轻拍。", "问谁能、唤起陶潜，醉翁同赋却。"]'),
('song-ci-639','绮罗香','陈著','宋','宋词','song-ci','绮罗香','[]','霁晓楼台，斜阳渡口，凉腋新声初到。',128,'宋词/ci.song.16000.json','["霁晓楼台，斜阳渡口，凉腋新声初到。", "占断清阴，随意自成宫调。", "看取次、颤引薰风，想无奈、露餐清饱。", "有时如、柔袅𥱧丝，忽如笙咽转娇妙。", "谁知忧怨极处，轻把宫妆蜕了，飞吟枝杪。", "耳畔如今，凄感又添多少。", "愁绪正、萦绕妆台，怎更禁、被他相恼。", "送残音、立尽黄昏，月明深院悄。"]'),
('song-ci-640','满江红','陈著','宋','宋词','song-ci','满江红','[]','梦里京华，忽听得、庭花遗曲。',112,'宋词/ci.song.16000.json','["梦里京华，忽听得、庭花遗曲。", "到醒来、愁满东风山屋。", "春事已非空结绮，晓班无分随群玉。", "想天涯、沦落杜秋娘，攒眉绿。", "谁能顾，荒芜菊。", "谁能问，平安竹。", "任时光流转，都成虚辱。", "无可奈何天地隘，只饶走得溪山足。", "但逢人、相问麦青青，何时熟。"]'),
('song-ci-641','烛影摇红','陈著','宋','宋词','song-ci','烛影摇红','[]','吾菊山翁，鹤骖来自蓬云界。',116,'宋词/ci.song.16000.json','["吾菊山翁，鹤骖来自蓬云界。", "平铺心地有天知，楚楚生兰茝。", "膝下青衫舞拜。", "更参差、斑衣戏队。", "清闲无事，门外从他，惊尘飞隘。", "寿八千年，百分才一朱颜耐。", "何妨长主翠嵩春，酒约诗盟在。", "家庆堂前欢会。", "领霞卮、醺红浅带。", "是人说道，真吕先生，风流潇洒。"]'),
('song-ci-642','烛影摇红','陈著','宋','宋词','song-ci','烛影摇红','[]','潇洒琴帘，月灯归后新谐好。',116,'宋词/ci.song.16000.json','["潇洒琴帘，月灯归后新谐好。", "青云香里共清风，消得金花诰。", "争奈天颠地倒。", "好光阴、都惊散了。", "更听人说，七七年时，多多烦恼。", "捱到如今，信知空挂闲怀抱。", "天於负处最饶人，颦也翻成笑。", "牢闭柴门自好。", "对梅花、杯盘草草。", "满前儿女，耐后夫妻，齑盐偕老。"]'),
('song-ci-643','烛影摇红','陈著','宋','宋词','song-ci','烛影摇红','[]','双杏堂深，山明水秀潆洄著。',116,'宋词/ci.song.16000.json','["双杏堂深，山明水秀潆洄著。", "稳铺心事做平生，不买颦眉错。", "是则苍髯白发。", "笑微微、朱颜自渥。", "一团春意，半隐风流，他谁能学。", "六十年华，又从今起新花甲。", "葵榴初艳芰荷香，争赴开筵约。", "家庆真堪恣乐。", "碧瑶杯、须拚满酌。", "瑟琴声里，弟劝兄酬，儿歌孙拍。"]'),
('song-ci-644','声声慢','陈著','宋','宋词','song-ci','声声慢','[]','珍丛凤舞，曾是宣和，春风送归禁幄。',119,'宋词/ci.song.16000.json','["珍丛凤舞，曾是宣和，春风送归禁幄。", "翠浅红深，婉娩步空金落。", "腥尘未飞动处，是先知、早辞华萼。", "好在□，四并难多少，怨怀无托。", "猛拍阑干谁会，浮世事、悠悠白云黄鹤。", "有酒当花，休得是今非昨。", "花犹百年宁耐，算人生、能几欢乐。", "又忽忽，醉梦里、春去不觉。"]'),
('song-ci-645','祝英台近','陈著','宋','宋词','song-ci','祝英台近','["\u897f\u6e56"]','小盆池，新压藕，翠盖已擎雨。',95,'宋词/ci.song.16000.json','["小盆池，新压藕，翠盖已擎雨。", "巧弄红妆，明艳便能许。", "自怜华发萧萧，风流无分，醉时眼、何妨偷觑。", "黯然伫。", "回首今是何时，逢花笑还语。", "梦里西湖，双落泪如缕。", "斜阳十里烟芜，六桥风浪，有谁掉、采莲舟去。"]'),
('song-ci-646','江城子','陈著','宋','宋词','song-ci','江城子','[]','中秋佳月最端圆。',86,'宋词/ci.song.16000.json','["中秋佳月最端圆。", "老痴顽。", "见多番。", "杯酒相延，今夕不应悭。", "残雨如何妨乐事，声淅淅，点斑斑。", "天应有意故遮阑。", "拍人间。", "等闲看。", "好处时光，须用著些难。", "直待黄昏风卷霁，金滟滟，玉团团。"]'),
('song-ci-647','江城子','陈著','宋','宋词','song-ci','江城子','[]','人生难满百年心。',86,'宋词/ci.song.16000.json','["人生难满百年心。", "得分阴。", "胜千金。", "吹帽风流，时节又相寻。", "回首赐萸休说梦，真率具，自山林。", "逢迎一笑且开襟。", "酒频斟。", "量犹禁。", "相劝相期，长健似如今。", "醉也从他儿女手，争把菊，满头簪。"]'),
('song-ci-648','江城子','陈著','宋','宋词','song-ci','江城子','[]','纷纷都说会双星。',86,'宋词/ci.song.16000.json','["纷纷都说会双星。", "鹊桥成。", "凤骖迎。", "风雨凄凉，何故锁苍冥。", "儿女空愁谁解意，须道我，试来听。", "人间天上不同情。", "最无凭。", "是柔盟。", "应怪痴人，虚妄做浮生。", "正值楼台多簇燕，教没兴，不开晴。"]'),
('song-ci-649','江城子','陈著','宋','宋词','song-ci','江城子','[]','笼街弹压上元灯。',86,'宋词/ci.song.16000.json','["笼街弹压上元灯。", "满瑶城。", "簇珠星。", "老矣如今，谁记旧来曾。", "眼底相逢惟有月，空对面，若为情。", "残生消不尽齑茎。", "瘦棱棱。", "困腾腾。", "扶起眉间，杯酒酹寒檠。", "也为风光陪一笑，心下事，梦中惊。"]'),
('song-ci-650','江城子','陈著','宋','宋词','song-ci','江城子','[]','年年端午又今朝。',86,'宋词/ci.song.16000.json','["年年端午又今朝。", "鬓萧萧。", "思摇摇。", "应是南风，湘浦正波涛。", "千古独醒魂在否，无处问，有谁招。", "何人帘幕倚兰皋。", "看飞桡。", "夺高标。", "饶把笙歌，供笑醉陶陶。", "孤坐小窗香一篆，弦绿绮，鼓离骚。"]'),
('song-ci-651','青玉案','陈著','宋','宋词','song-ci','青玉案','["\u94b1\u5858\u6c5f"]','钱塘江上潮来去。',80,'宋词/ci.song.16000.json','["钱塘江上潮来去。", "花落花开六桥路。", "三竺三茅钟晓暮。", "当年梦境，如今故国，不忍回头处。", "他谁做得愁如许。", "平地波涛挟风雨。", "往事凄凄都有据。", "月堂笑里，夕亭话后，自是无人悟。"]'),
('song-ci-652','青玉案','陈著','宋','宋词','song-ci','青玉案','[]','青山流水迢迢去。',80,'宋词/ci.song.16000.json','["青山流水迢迢去。", "总是东风往回路。", "送得春来春又暮。", "莺如何诉。", "燕如何语。", "只有春知处。", "时光渐渐春如许。", "何用怜春怕红雨。", "到处空飞无实据。", "花开也好，花飞也好，此意须双悟。"]'),
('song-ci-653','渔家傲','陈著','宋','宋词','song-ci','渔家傲','[]','浪麦风微花雾扫。',72,'宋词/ci.song.16000.json','["浪麦风微花雾扫。", "痕沙水浅溪桥小。", "属玉双双飞杳杳。", "山宽绕。", "新晴绣得春分晓。", "独立无言心事渺。", "曾将宇宙思量了。", "世变何涯人已老。", "休烦恼。", "林泉况味终须好。"]'),
('song-ci-654','渔家傲','陈著','宋','宋词','song-ci','渔家傲','[]','山弄夕辉眉淡扫。',72,'宋词/ci.song.16000.json','["山弄夕辉眉淡扫。", "溪分新水支流小。", "醉梦风光凝望杳。", "云树绕。", "杜鹃怨处谁能晓。", "浮世悠悠波渺渺。", "蜗争何事何时了。", "天为无情方不老。", "休苦恼。", "随缘诗酒清闲好。"]'),
('song-ci-655','踏莎行','陈著','宋','宋词','song-ci','踏莎行','[]','豆雨空晴，桂花风静。',68,'宋词/ci.song.16000.json','["豆雨空晴，桂花风静。", "碧虚飞上圆明镜。", "谁能唤起秃翁吟，祗应笑得嫦娥醒。", "可奈良宵，不堪残境。", "强拚一醉偷光景。", "夜凉渐搅雪霜心，昏眵犹认山河影。"]'),
('song-ci-656','卖花声','陈著','宋','宋词','song-ci','卖花声','[]','残梦腾腾。',82,'宋词/ci.song.16000.json','["残梦腾腾。", "好鸟一声呼醒。", "小窗明、萧萧鬓影。", "当年头上，惯曾簪幡胜。", "到如今、有谁怀省。", "东风著面，却自依然相认。", "哄痴儿、忺声弄景。", "盘蔬杯酒，强教人欢领。", "也微酣、带些春兴。"]'),
('song-ci-657','鹊桥仙','陈著','宋','宋词','song-ci','鹊桥仙','[]','兄年八十，弟今年几，亦是七旬有九。',68,'宋词/ci.song.16000.json','["兄年八十，弟今年几，亦是七旬有九。", "人生取数已为多，更休问、前程无有。", "家贫是苦，算来又好，见得平生操守。", "杯茶盏水也风流，莫负了、桂时菊候。"]'),
('song-ci-658','蝶恋花','陈著','宋','宋词','song-ci','蝶恋花','[]','世变无情风挟雨。',70,'宋词/ci.song.16000.json','["世变无情风挟雨。", "长夜漫漫，何日开晴午。", "白发萧疏惊岁序。", "儿嬉漫说重重午。", "粒啄偷生如搏黍。", "过计何须，负郭多南亩。", "曾著宫衣沾雨露。", "如今掩袂悲湘浦。"]'),
('song-ci-659','虞美人','陈著','宋','宋词','song-ci','虞美人','[]','故园处处都荒雨。',66,'宋词/ci.song.16000.json','["故园处处都荒雨。", "寂寞蜗书户。", "人间春事杏桃花。", "独有诗人依旧、菊为家。", "老来犹解高叉手。", "遥上花前寿。", "华颠无分插花枝。", "乞取霜根风月、送将归。"]'),
('song-ci-660','浪淘沙','陈著','宋','宋词','song-ci','浪淘沙','[]','有约泛溪篷。',64,'宋词/ci.song.16000.json','["有约泛溪篷。", "游画图中。", "沙鸥引入翠重重。", "认取抱琴人住处，水浅山浓。", "一笑两衰翁。", "莫惜从容。", "瓮醅灰芋雪泥菘。", "直到梅花飞过也，桃李春风。"]'),
('song-ci-661','浪淘沙','陈著','宋','宋词','song-ci','浪淘沙','[]','记得去年时。',64,'宋词/ci.song.16000.json','["记得去年时。", "采菊东篱。", "眉间一笑捧花枝。", "说道愿如花不老，交劝双卮。", "又是菊花期。", "客况谁知。", "便无风雨也凄凄。", "白发夫妻时节酒，堪几参差。"]'),
('song-ci-662','浪淘沙','陈著','宋','宋词','song-ci','浪淘沙','[]','窗影弄晴红。',64,'宋词/ci.song.16000.json','["窗影弄晴红。", "欢笑成丛。", "一声春困到衰翁。", "回首太平儿戏事，雨过云空。", "人世暗尘中。", "如梦方浓。", "也须留取自惺憁。", "试问若教都困了，谁管春风。"]'),
('song-ci-663','浪淘沙','陈著','宋','宋词','song-ci','浪淘沙','[]','迟饭甑炊红。',64,'宋词/ci.song.16000.json','["迟饭甑炊红。", "青翦蔬丛。", "鸡声邻里狎田翁。", "兵后故人能有几，岁晚江空。", "谁信淡交中。", "依旧情浓。", "白头青眼转惺憁。", "相见莫教轻别去，负月孤风。"]'),
('song-ci-664','浪淘沙','陈著','宋','宋词','song-ci','浪淘沙','[]','春事紫和红。',64,'宋词/ci.song.16000.json','["春事紫和红。", "蜂蝶争丛。", "消磨多少看花翁。", "不用借他炊黍枕，何梦非空。", "茅屋菜畦中。", "村瓮醅浓。", "醉时啼鸟唤惺憁。", "不道白头添一岁，舞月歌风。"]'),
('song-ci-665','浪淘沙','陈著','宋','宋词','song-ci','浪淘沙','[]','年事夕阳红。',64,'宋词/ci.song.16000.json','["年事夕阳红。", "霜满髯丛。", "摩挲苍藓石婆翁。", "能见几人曾百岁，一笑书空。", "回首棣华中。", "消得春浓。", "平生心事两惺憁。", "杖履相从须放密，山月溪风。"]'),
('song-ci-666','糖多令・唐多令','陈著','宋','宋词','song-ci','糖多令・唐多令','[]','雁阵晓来霜。',74,'宋词/ci.song.16000.json','["雁阵晓来霜。", "鸦村夕照黄。", "满人间、风景凄凉。", "幸有菊窗堪一醉，争又滞、水云乡。", "沽酒也三行。", "邀风与较量。", "便明朝、吹送归航。", "趁得老盆新熟信，日日是、我重阳。"]'),
('song-ci-667','糖多令・唐多令','陈著','宋','宋词','song-ci','糖多令・唐多令','[]','蟹熟晕橙霜。',74,'宋词/ci.song.16000.json','["蟹熟晕橙霜。", "蛆浮染菊黄。", "淡交情、都没炎凉。", "说道白头难会面，留一日、醉中乡。", "世事与轮行。", "时光逐寸量。", "任人间、涛海风航。", "拜了老庞归去也，高著枕、卧南阳。"]'),
('song-ci-668','糖多令・唐多令','陈著','宋','宋词','song-ci','糖多令・唐多令','[]','倦枕寄渔乡。',74,'宋词/ci.song.16000.json','["倦枕寄渔乡。", "篷低被怯霜。", "月窥人、多少思量。", "自是欲眠眠不稳，禁听得、雁声双。", "和梦早催行。", "归来梅竹窗。", "小柴门、分破闲忙。", "翻笑白云飞不定，谙得静、憩诗床。"]'),
('song-ci-669','行香子','陈著','宋','宋词','song-ci','行香子','[]','吾辈么麽。',84,'宋词/ci.song.16000.json','["吾辈么麽。", "休叹蹉跎。", "得闲时、且逐时过。", "人间名利，都是浮华。", "但退如进，失如得，少如多。", "谁信生来，从发尖磨。", "到如今、方见霜涯。", "算天亦自，无奈吾何。", "是饥能忍，寒能耐，老能歌。"]'),
('song-ci-670','恋绣衾','陈著','宋','宋词','song-ci','恋绣衾','[]','梅窗归坐几岁寒。',68,'宋词/ci.song.16000.json','["梅窗归坐几岁寒。", "老生涯、寂寞自便。", "最喜得、双双健，与粗茶、淡饭结缘。", "眉前把酒深深劝，这时光、惟有靠天。", "看许大、痴儿女，且随宜、笑到百年。"]'),
('song-ci-671','西江月','陈著','宋','宋词','song-ci','西江月','[]','老去坐来睡重，病多吟得诗悭。',58,'宋词/ci.song.16000.json','["老去坐来睡重，病多吟得诗悭。", "有时忽自拍阑干。", "一点心随天远。", "柳絮飞从何处，莺声啼破空山。", "春风依旧满人间。", "不奈双颦闲管。"]'),
('song-ci-672','西江月','陈著','宋','宋词','song-ci','西江月','[]','华胄银青气脉，仙风斑白须眉。',58,'宋词/ci.song.16000.json','["华胄银青气脉，仙风斑白须眉。", "儿孙玉雪满庭帏。", "家庆人间难比。", "浮世事等云过，平生心有天知。", "举杯相约小春时。", "岁岁梅花里醉。"]'),
('song-ci-673','卜算子','陈著','宋','宋词','song-ci','卜算子','[]','月下百年缘，天上双星样。',52,'宋词/ci.song.16000.json','["月下百年缘，天上双星样。", "九秩齐开自是稀，清健那堪两。", "红叶景翻新，黄菊香宜晚。", "笑拥眉开祝寿声，满劝鸳鸯盏。"]'),
('song-ci-674','卜算子','陈著','宋','宋词','song-ci','卜算子','[]','喜气满清门，庆集还新样。',52,'宋词/ci.song.16000.json','["喜气满清门，庆集还新样。", "卜醉筵开意转浓，昨日今朝两。", "愧我一年多，见汝双欢晚。", "自觉人生此会稀，有酒宁论盏。"]'),
('song-ci-675','南乡子','陈著','宋','宋词','song-ci','南乡子','[]','流景去难縻。',66,'宋词/ci.song.16000.json','["流景去难縻。", "浮世危如拍浪埼。", "才遇中秋聊对月，佳期。", "最怕晴明未可涯。", "人月本相依。", "果是今朝恰背违。", "孤负楼台多少醉，堪悲。", "何忍滂沱与毕离。"]'),
('song-ci-676','宝鼎现','陈著','宋','宋词','song-ci','宝鼎现','[]','望京门外，怕见催发，东风行马。',192,'宋词/ci.song.16000.json','["望京门外，怕见催发，东风行马。", "清到底、冰壶满了，欲借留来无计也。", "祖劝酒、看依依情恋，都在眉尖眼下。", "任万户、诗旗曲帐，有笔应难描写。", "是则龟组随瓜卸。", "好规模、分付来者。", "才泛绿、依红小暇，移讲芹宫时促驾。", "又指点、秀宁城来脉，疏瀹春流似画。", "更巧为、溪山著句，留作千年佳话。", "最念一邑酸寒，风雨暗、真几成假。", "向纛牙交处，还得儒珍旧价。", "便父母、又如何做，但结心香社。", "愿阔步、直上云霄，犹□回头奉化。"]'),
('song-ci-677','沁园春','陈著','宋','宋词','song-ci','沁园春','[]','莲叶山前，戎帐宏开，轰然最称。',139,'宋词/ci.song.16000.json','["莲叶山前，戎帐宏开，轰然最称。", "羡铺心如水，肯教尘涴，为民乞雨，唤得天应。", "紫逻□锋，绿林扫影，夜户都开无犬声。", "三乡里，笑嬉嬉度日，歌舞清平。", "溪头载月舟□，□□帐花旗忍送行。", "算浮云自在，初无著相，薰风正好，却问归程。", "折柳依依，憩棠□□，□□□春无尽情。", "趋朝去，看青冥玉钺，金辔红缨。"]'),
('song-ci-678','喜迁莺','陈著','宋','宋词','song-ci','喜迁莺','[]','南庐佳号。',126,'宋词/ci.song.16000.json','["南庐佳号。", "是自许孔明，经纶才调。", "对柳鸣琴，凭花制锦，小试一同谈笑。", "怎知画帘难驻，忽又星舆催召。", "但谶得、耀碑潭水月，交光相照。", "驿道。", "春正好。", "簇帐擎杯，听取殷勤祷。", "略鲙松鲈，便膺芝凤，陵溯紫清津要。", "当家得时行志，回首旧封文庙。", "疏化雨，障狂澜不尽，生生芹藻。"]'),
('song-ci-679','西江月','陈著','宋','宋词','song-ci','西江月','[]','钱影何曾过眼，笔头那肯亏心。',63,'宋词/ci.song.16000.json','["钱影何曾过眼，笔头那肯亏心。", "系门瘦马影沈沈。", "夜柝不惊春枕。", "一去轻如蕉梦，三乡都是棠阴。", "等闲换取印黄金。", "催上云程新任。", "（缺词文）"]'),
('song-ci-680','水龙吟','陈著','宋','宋词','song-ci','水龙吟','[]','（缺词文）',5,'宋词/ci.song.16000.json','["（缺词文）"]'),
('song-ci-681','谒金门','赵与','宋','宋词','song-ci','谒金门','[]','归去去。',53,'宋词/ci.song.16000.json','["归去去。", "风急兰舟不住。", "梦里海棠花下语。", "醒来无觅处。", "薄幸心情似絮。", "长是轻分轻聚。", "待得来时春几许。", "绿阴三月暮。"]'),
('song-ci-682','千年调','王义山','宋','宋词','song-ci','千年调','[]','胜地独湖山，满堂贮风月。',91,'宋词/ci.song.16000.json','["胜地独湖山，满堂贮风月。", "歌舞大平气象，雪回云遏。", "红鞋朱帽，隔岸唤船，芙蓉万叠。", "人稀到，这清绝。", "因思旧事，庄敞平泉宅。", "莫与他人树石，对儿孙说。", "难全晚节，不如一丘壑。", "住茅屋三间，任穷达。"]'),
('song-ci-683','水调歌头','王义山','宋','宋词','song-ci','水调歌头','[]','沆瀣金茎露，清洁玉壶冰。',114,'宋词/ci.song.16000.json','["沆瀣金茎露，清洁玉壶冰。", "分明昨夜，光见南极老人星。", "山甫秀锺崧岳，传说上符箕尾，造物为时生。", "一代词科伯，飞上到蓬瀛。", "紫薇天，丹禁地，掌丝纶。", "盘洲益国，个样人物只三人。", "辞却翰林风月，故就湖湘霖雨，天下共为春，试看玉堂□，太半秉洪钧。"]'),
('song-ci-684','临江仙','王义山','宋','宋词','song-ci','临江仙','[]','明日中元生上相，真上相上元生。',70,'宋词/ci.song.16000.json','["明日中元生上相，真上相上元生。", "满城灯火昼三更。", "台星呈瑞处，一点寿星明。", "和气薰蒸开泰运，湖山万里光荣。", "愿推天地发生仁。", "八荒开寿域，一气转洪钧。"]'),
('song-ci-685','满庭芳','王义山','宋','宋词','song-ci','满庭芳','["\u897f\u6e56"]','线柳迎风，锦棠媚日，十分春色豪奢。',119,'宋词/ci.song.16000.json','["线柳迎风，锦棠媚日，十分春色豪奢。", "青烟宫烛，飞入侍臣家。", "瑞霭深笼画戟，寿星照、曲纛高牙。", "因知是、崧高华旦，玳宴醉琼花。", "翻鸦。", "新诏墨，闻枢庭召入，已办宣麻。", "比汾阳福寿，公更穹华。", "伫看稠青叠紫，书香蔼、桂子兰芽。", "鸣珂处，西湖路上，接武筑堤沙。"]'),
('song-ci-686','水调歌头','王义山','宋','宋词','song-ci','水调歌头','[]','宇宙邮亭耳，游子问舟归。',114,'宋词/ci.song.16000.json','["宇宙邮亭耳，游子问舟归。", "滩上滩下，转柁欲速□□迟。", "安得泛河一叶，寻见江南归处，多只是旬馀。", "此身无地著，惊浪湿征衣。", "独张翰，见风起，早知机。", "谁把乘舟，偏重良策济明时。", "夷岛人烟相接，恰在永嘉上浦，猛忆浩然诗。", "乡闾万馀里，失路一相悲。"]'),
('song-ci-687','贺新郎','王义山','宋','宋词','song-ci','贺新郎','[]','雅有登山癖。',141,'宋词/ci.song.16000.json','["雅有登山癖。", "觉老来、尚可跻攀，浪游蹑屐。", "险怪嶕嶢称雁荡，争秀群山第一。", "更耸出、穹崖千尺。", "景物深藏长谷里，最上龛，水凿时冲激。", "硉矹处，巨□石。", "地生天作谁能识。", "睹江山如故，恨无一时人物。", "灵运当年为太守，佳处都曾游历。", "独不见、此山脚迹。", "风月直须人管领，怎不移、石壁题岩壁。", "今且著，老夫笔。"]'),
('song-ci-688','念奴娇','王义山','宋','宋词','song-ci','念奴娇','[]','南昌奇观，最东湖、好景重重叠叠。',120,'宋词/ci.song.16000.json','["南昌奇观，最东湖、好景重重叠叠。", "谁瞰湖光新佳阁，横挹翠峰嶻辥。", "十里芙蓉，海神捧出，一镜何明彻。", "鸢鱼飞跃，活机触处泼泼。", "容斋巨笔如椽，迎来一记，赢得芳名独。", "猛忆泛莲前日事，诗社杯盘频设。", "倚看斜阳，檐头燕子，如把兴亡说。", "谁迎谁送，一川无限风月。"]'),
('song-ci-689','瑞龙吟','王义山','宋','宋词','song-ci','瑞龙吟','[]','晨光曙。',163,'宋词/ci.song.16000.json','["晨光曙。", "遥见□灼文奎，照天心处。", "峨眉棱上西飞，北魁南极，腾辉灿丽。", "神皋地。", "争看碧幢旗戟，蔼然佳气。", "深深有美堂中，绣帏□幕，笙歌不住。", "知是元戎初度，玉觥频举，云堤烟市。", "时听笑声，都人相贺相语。", "人人说是，活佛生今世。", "襟怀内、严霜莹月，春风秋水。", "文肃貂蝉贵。", "南丰学问，文昭节义。", "若问庄椿岁。", "堪谁比，清源曾公寿齿。", "郎君宥府，衮衣荣侍。"]'),
('song-ci-690','贺新郎','王义山','宋','宋词','song-ci','贺新郎','[]','自笑斟醽醁。',140,'宋词/ci.song.16000.json','["自笑斟醽醁。", "作皤然一老，逍遥东湖湖曲。", "好事爆然来子舍，报道生孙新浴。", "算天也、从人所欲。", "万事足虽缘有子，见孙时、万事方为足。", "诗礼脉，今有续。", "吾家本是山阴族。", "见生来、风神稍秀，足娱吾目。", "吾子吾孙同此月，日月才争五六。", "喜听得、欢声满目。", "愚鲁聪明天所赋，只无灾无难为多福。", "且愿汝，书勤读。"]'),
('song-ci-691','乐语','王义山','宋','宋词','song-ci','乐语','[]','金阙深深，正夏日初长禁柳青。',119,'宋词/ci.song.16000.json','["金阙深深，正夏日初长禁柳青。", "祥烟纷簇，红云一朵，飞度彤庭。", "千妃随步处，觉薰风、微拂觚棱。", "天颜喜，向东朝长乐，献九霞觥。", "分明。", "西崑王母，来从光碧驾飞軿。", "为言今日，金仙新浴，共庆长生。", "捧桃上寿，天一笑、赐宴蓬瀛。", "沸欢声。", "道明朝前殿，又祝椿龄。"]'),
('song-ci-692','乐语','王义山','宋','宋词','song-ci','乐语','[]','西山元是神仙境，瑞气郁森森。',57,'宋词/ci.song.16000.json','["西山元是神仙境，瑞气郁森森。", "彩鸾飞下五云深。", "急管递繁音。", "碧鬓□斜花欲颤，轻盈莲步移金。", "紫檀催拍莫沈吟。", "传入柘枝心。"]'),
('song-ci-693','乐语','王义山','宋','宋词','song-ci','乐语','[]','慈元宫殿五云开。',57,'宋词/ci.song.16000.json','["慈元宫殿五云开。", "寿献九霞杯。", "步随王母共徘徊。", "仙子下瑶台。", "红袖引翻鸾镜媚，婆娑雪□风回。", "繁弦脆管莫相催。", "齐唱柘枝来。"]'),
('song-ci-694','乐语','王义山','宋','宋词','song-ci','乐语','[]','风吹仙袂飘飘举，底事下蓬莱。',58,'宋词/ci.song.16000.json','["风吹仙袂飘飘举，底事下蓬莱。", "东朝遥祝万年杯。", "玉液泻金垒。", "天上蟠桃又熟，晕酡颜、红染芳腮。", "年年摘取献天阶。", "齐舞柘枝来。"]'),
('song-ci-695','乐语','王义山','宋','宋词','song-ci','乐语','[]','千年紫极锁烟萝。',40,'宋词/ci.song.16000.json','["千年紫极锁烟萝。", "艳质含羞敛翠蛾。", "远睇慈元称寿处，不妨连臂，大家重与，楚舞更吴歌。"]'),
('song-ci-696','乐语','王义山','宋','宋词','song-ci','乐语','[]','秘传玉诀自灵修。',40,'宋词/ci.song.16000.json','["秘传玉诀自灵修。", "家在仙山最上头。", "更有仙茅香馥郁，年年今日，薰风时候，掇取献龙楼。"]'),
('song-ci-697','乐语','王义山','宋','宋词','song-ci','乐语','[]','自在云间白鹤飞。',40,'宋词/ci.song.16000.json','["自在云间白鹤飞。", "晴川浴罢不胜衣。", "旋裁五色冰蚕锦，千花覆处，三呼声里，惹得御香归。"]'),
('song-ci-698','乐语','王义山','宋','宋词','song-ci','乐语','[]','闲云潭影日悠悠。',40,'宋词/ci.song.16000.json','["闲云潭影日悠悠。", "暮倚朱帘更少留。", "龙寿本齐箕与翼，□从今日，一年一度，东极庆千秋。"]'),
('song-ci-699','乐语','王义山','宋','宋词','song-ci','乐语','[]','新吴曾遇许旌阳。',40,'宋词/ci.song.16000.json','["新吴曾遇许旌阳。", "宝气横空一剑长。", "愿祝慈闱长不老，天长地久，有如此柏，万古镇苍苍。"]'),
('song-ci-700','乐语','王义山','宋','宋词','song-ci','乐语','[]','龙楼日永，鹤禁风薰，拂晓寿星光现。',166,'宋词/ci.song.16000.json','["龙楼日永，鹤禁风薰，拂晓寿星光现。", "无限霞裾，欣传帝母，与佛同生华旦。", "佳气慈闱，看龙颜欢动，玉卮亲劝。", "捧祝殷勤，对萱草青松，菖蒲翠软。", "奇香喷，阶前芍药，频繁红深紫浅。", "遥望千官鹭序，晓仗初齐，趋觐慈元宫殿。", "更喜明朝，虹流佳节，同听嵩山呼万。", "湛露重重，燕庆两宫，盛事如今亲见。", "齐祝愿、西崑凝碧，南山增绿，与天齐算。", "身长好，年年拜舞宫花颤。"]'),
('song-ci-701','乐语','王义山','宋','宋词','song-ci','乐语','[]','先献此花名字好。',70,'宋词/ci.song.16000.json','["先献此花名字好。", "密叶长青，翠羽摇仙葆。", "紫禁风薰惊夏到。", "花飞细□香堪扫。", "拂晓宫娃争报道。", "无限琼妃，缥缈来蓬岛。", "来向慈闱勤颂祷。", "万年枝□同难老。"]'),
('song-ci-702','乐语','王义山','宋','宋词','song-ci','乐语','[]','端的长春春不老。',70,'宋词/ci.song.16000.json','["端的长春春不老。", "玉颊微红，酒晕精神好。", "多谢天工相懊恼。", "花间不问春迟早。", "风外新篁摇翠葆。", "长乐宫边，绿阴笼驰道。", "此际称觞非草草。", "绛仙亲下蓬莱岛。"]'),
('song-ci-703','乐语','王义山','宋','宋词','song-ci','乐语','[]','莫忘九疑山上侣。',70,'宋词/ci.song.16000.json','["莫忘九疑山上侣。", "住在山中，白石清泉处。", "好与长年沾雨露。", "灵根下遣蟠虬护。", "青青九节长如许。", "早晚成花，教见薰风度。", "十二节添须记取。", "千年一节从头数。"]'),
('song-ci-704','乐语','王义山','宋','宋词','song-ci','乐语','[]','岁岁丹霞天近处。',70,'宋词/ci.song.16000.json','["岁岁丹霞天近处。", "借问殷勤，何以逢兰杜。", "碧砌玉阑春不去。", "清香长逐薰风度。", "况是恩光新雨露。", "绿叶青青，葱翠长如许。", "端的萱花仙伴侣。", "年年今日阶前舞。"]'),
('song-ci-705','乐语','王义山','宋','宋词','song-ci','乐语','[]','犹是太真亲手植。',70,'宋词/ci.song.16000.json','["犹是太真亲手植。", "猩染鲜葩，岁岁如曾拭。", "绛节青旌光耀日。", "分明是个神仙匹。", "引领金扉红的的。", "下有仙妃，纤手轻轻摘。", "为道朱颜常似得。", "今朝摘取呈慈极。"]'),
('song-ci-706','乐语','王义山','宋','宋词','song-ci','乐语','[]','移向慈元供寿佛。',70,'宋词/ci.song.16000.json','["移向慈元供寿佛。", "压倒群花，端的成清绝。", "青萼玉包全未拆。", "薰风微处留香雪。", "未拆香包香已冽。", "沈水龙涎，不用金炉爇。", "花露轻轻和玉屑。", "金仙付与长生诀。"]'),
('song-ci-707','乐语','王义山','宋','宋词','song-ci','乐语','[]','还比蒲桃天上植。',70,'宋词/ci.song.16000.json','["还比蒲桃天上植。", "稚柳阴中，蜀锦开如织。", "万岁藤边娇五色。", "宜春馆里香寻觅。", "七十二行鲜的的。", "岁岁如今，早趁薰风摘。", "金掌露浓堪爱惜。", "龙涎华润凝光碧。"]'),
('song-ci-708','乐语','王义山','宋','宋词','song-ci','乐语','[]','日日传宣金掌露。',70,'宋词/ci.song.16000.json','["日日传宣金掌露。", "当殿芳菲，似约春长驻。", "微紫深红浑谩与。", "淡妆偏趁泥金缕。", "拂早薰风花里度。", "吹送香尘，东殿称觞处。", "歌罢花仙归洞府。", "彩鸾驾雾来南浦。"]'),
('song-ci-709','乐语','王义山','宋','宋词','song-ci','乐语','[]','戏衮玉球添一笑。',70,'宋词/ci.song.16000.json','["戏衮玉球添一笑。", "笑道轻狂，似恁人间少。", "偏倚龙池依凤沼。", "随风得得低回绕。", "掠面点衣夸百巧。", "似雪飞花，点束梁圆好。", "惹住金虬香篆袅。", "上林不放春光老。"]'),
('song-ci-710','乐语','王义山','宋','宋词','song-ci','乐语','[]','消息一年传一度。',70,'宋词/ci.song.16000.json','["消息一年传一度。", "万岁枝香，总是留春处。", "曾倚东风娇不语。", "玉阶霞袂飘飘举。", "蓬莱清浅红云路。", "结子新成，要荐金盘去。", "一实三千须记取。", "东朝宴罢回青羽。"]'),
('song-ci-711','乐语','王义山','宋','宋词','song-ci','乐语','[]','十样仙葩天也爱。',70,'宋词/ci.song.16000.json','["十样仙葩天也爱。", "留住春光，一一娇相赛。", "万里莺花开世界。", "园林点检随时采。", "□□□眉仙体态。", "天与司花，舞彻歌还再。", "献与千官头上戴。", "年年万岁声中拜。"]'),
('song-ci-712','蝶恋花','刘云甫','宋','宋词','song-ci','蝶恋花','[]','一点郎星光彻晓。',70,'宋词/ci.song.16000.json','["一点郎星光彻晓。", "许大乾坤，难著经纶手。", "拂袖归来应自笑。", "山翁偏爱林泉好。", "庭下儿孙歌寿酒。", "不献蟠桃，不数安期枣。", "且喜今朝云出岫。", "定知霖雨苍生早。"]'),
('song-ci-713','柳梢青','龚日升','宋','宋词','song-ci','柳梢青','[]','二十年前。',61,'宋词/ci.song.16000.json','["二十年前。", "君家桃李，种满螺川。", "凛凛英风，真如小范，不数梅仙。", "薰风吹送朝天。", "指何物、装添去船。", "千首新诗，一轮明月，两字清廉。"]'),
('song-ci-714','沁园春','陈若水','宋','宋词','song-ci','沁园春','[]','拂袖归来，懒踏前回，京华软尘。',139,'宋词/ci.song.16000.json','["拂袖归来，懒踏前回，京华软尘。", "算宦游虽好，何如生处，急流勇退，赢得闲人。", "身羡仙翁，萧然野服，笑咏东溪溪上亭。", "头犹黑、甚丰姿鹤瘦，标致梅清。", "今年转觉精神。", "便次第平头八十人。", "肯又抛渭钓，似周尚父，且来洛社，作宋耆英。", "报答明恩，一时分付，贤子贤孙事业新。", "丹心在，尚瓣香岁岁，遥祝尧龄。"]'),
('song-ci-715','宴清都','胡翼龙','宋','宋词','song-ci','宴清都','[]','梦雨随春远。',129,'宋词/ci.song.16000.json','["梦雨随春远。", "征衫薄、短篷犹逗寒浅。", "裁芳付叶，书愁沁壁，水窗竹院。", "别来被篝梅润，暗尘积、旧题纨扇。", "许多时，闲了阑干，放得藓痕青满。", "谁念。", "杜若还生，苹花又绿，不堪重□。", "山程水记，茶经砚谱，共谁闲展。", "湖山旧曾游遍。", "不怪得、近番心懒。", "恰今朝、水落洲平，江上楚帆风转。"]'),
('song-ci-716','徵招','胡翼龙','宋','宋词','song-ci','徵招','[]','苹花又绿江南岸，宾鸿带将寒去。',116,'宋词/ci.song.16000.json','["苹花又绿江南岸，宾鸿带将寒去。", "几许落梅愁，渺暗香何处。", "一春长是雨。", "剩费却、翠篝沉炷。", "冷隔帘旌，润销窗纸，有人吟苦。", "燕垒渍芹香，画堂永、关心去年情绪。", "愁压曲屏深，更小山无数。", "溅裙前事误。", "□□□、□□□□。", "□朱阑，不了销凝，移损秦筝柱。"]'),
('song-ci-717','八声甘州','胡翼龙','宋','宋词','song-ci','八声甘州','["\u6d1e\u5ead\u6e56"]','甚年年、心事占秋多，芳洲乱芜生。',123,'宋词/ci.song.16000.json','["甚年年、心事占秋多，芳洲乱芜生。", "正小山已桂，东篱又菊，秋为人清。", "肠断洞庭叶下，倚西风、谁可寄芳蘅。", "袅袅愁予处，欲醉还醒。", "为问素娥饮否，自谪仙去后，知与谁明。", "耿盈盈如此，分影落瑶觥。", "步高台、夜深人静，有飞仙、同跨海山鲸。", "归来也，远游歌罢，失却秋声。"]'),
('song-ci-718','洞仙歌','胡翼龙','宋','宋词','song-ci','洞仙歌','[]','半栏花雨。',104,'宋词/ci.song.16000.json','["半栏花雨。", "是夜来凭处。", "梦过溪桥逢柳住。", "乱莺声残酒醒，正是关情，山枕上、吟就回纹锦句。", "归鸿应别浦。", "绿涨弥茫，早近湖阴唤船路。", "览芳菲，歌窈窕，独立莎根，剩一掬、闲情凄楚。", "欲待折、微馨寄相思，又生怕相思，带将春去。"]'),
('song-ci-719','满庭芳','胡翼龙','宋','宋词','song-ci','满庭芳','[]','秋彻檐花，吟苦砚海，日长多费茶烟。',120,'宋词/ci.song.16000.json','["秋彻檐花，吟苦砚海，日长多费茶烟。", "怀芳心苦，持此过年年。", "雨外飞红何许，应流到、采绿洲边。", "销凝处，别离情绪，正是海棠天。", "吹花题叶事，如今梦里，记得依然。", "料归来、莺居春后，燕占人先。", "谁念文园倦客，琴空在、懒向人弹。", "愁何极，楚天老月，偏是到窗前。"]'),
('song-ci-720','鹧鸪天','胡翼龙','宋','宋词','song-ci','鹧鸪天','[]','六曲银屏梦隔云。',64,'宋词/ci.song.16000.json','["六曲银屏梦隔云。", "半分鸾影匣生尘。", "别来可是春愁觉，试著经衫不贴身。", "风月夜，短长亭。", "也须闻得子规声。", "归时莫看花梢上，但看芳洲绿浅深。"]'),
('song-ci-721','少年游','胡翼龙','宋','宋词','song-ci','少年游','[]','晓莺声脆雨花乾。',60,'宋词/ci.song.16000.json','["晓莺声脆雨花乾。", "倦枕梦初残。", "衣渍香留，窗深纸暗，把镜近檐看。", "断云压损溪桥柳，花迳雪阑斑。", "深倚屏根，闲敲诗字，酒醒倍春寒。"]'),
('song-ci-722','霓裳中序第一','胡翼龙','宋','宋词','song-ci','霓裳中序第一','[]','江郊雨正歇。',125,'宋词/ci.song.16000.json','["江郊雨正歇。", "燕子飞来人忆别。", "未了残梅怨结。", "渺野色波光，春与天接。", "相思辽阔。", "怕柳风、吹老吟发。", "关情处，满汀芳草，遮莫是鶗鴂。", "时节。", "一饷愁绝。", "谩料理、新翻几阕。", "山尊堪共谁设。", "梦到断桥，飞絮仍雪。", "岁华休省阅。", "早霍地、小园花发。", "已办著、海棠开后，独立半廊月。"]'),
('song-ci-723','夜飞鹊・夜飞鹊慢','胡翼龙','宋','宋词','song-ci','夜飞鹊・夜飞鹊慢','[]','星桥度情处，地久天长。',129,'宋词/ci.song.16000.json','["星桥度情处，地久天长。", "尘世无此匆忙。", "纤云淡荡凉蝉小，家家瓜果钱唐。", "愁人独无那，叹紫箫易断，青翼难将。", "返魂何在，漫空留、荀令馀香。", "忍记穿针儿女，篝尘想都暗，叠损衣裳。", "谁念才情减灭，老来何逊，少日卢郎。", "柳风荷露，黯销凝、罗扇綀囊。", "更银河曲曲，玉签点点，都是凄凉。"]'),
('song-ci-724','西江月','胡翼龙','宋','宋词','song-ci','西江月','[]','水霁芹香燕觜，林深风暖莺吭。',58,'宋词/ci.song.16000.json','["水霁芹香燕觜，林深风暖莺吭。", "一春心事锦机傍。", "忘却寻芳模样。", "柳絮池塘昼午，梨花院落昏黄。", "阑干曲曲是回肠。", "倚到西厢月上。"]'),
('song-ci-725','踏莎行','胡翼龙','宋','宋词','song-ci','踏莎行','[]','合数冰莲，注情金叶。',68,'宋词/ci.song.16000.json','["合数冰莲，注情金叶。", "臂痕犹记嗔时迹。", "小楼几个月黄昏，荷香柳影都知得。", "问字灯深，学书窗黑。", "衣襟诗卷留残墨。", "想思不抵藕丝长，梦云断处吴山碧。"]'),
('song-ci-726','南歌子','胡翼龙','宋','宋词','song-ci','南歌子','[]','山枕莺声晓，羽觞花片飞。',62,'宋词/ci.song.16000.json','["山枕莺声晓，羽觞花片飞。", "昨朝犹道未成归。", "不记春衫襟上、旧题诗。", "愁眼垂杨见，苦心红烛知。", "翻成怕见别离时。", "只寄一声将息、当相思。"]'),
('song-ci-727','长相思','胡翼龙','宋','宋词','song-ci','长相思','[]','南山钟。',44,'宋词/ci.song.16000.json','["南山钟。", "北山钟。", "一听钟声百念空。", "古今昏晓中。", "望秋风。", "数秋风。", "等得秋来等过鸿。", "灯前书一封。"]'),
('song-ci-728','兰陵王','刘之才','宋','宋词','song-ci','兰陵王','[]','此何夕。',158,'宋词/ci.song.16000.json','["此何夕。", "天水空明一碧。", "商量赋、如此江山，几个斜阳了今昔。", "荒台步晚色。", "沙鸟依稀曾识。", "啼鶬外，人远未归，江阔晴虹卧千尺。", "残碑藓痕积。", "记当日清游，夫君题墨。", "碧瑶仙去苍云隔。", "飞一镜秋冷，列屏天远，鸡声人语半郊邑。", "寄情又江国。", "愁寂。", "怕闻笛。", "正怨苦溪猿，飞倦汀翼。", "阴阴翡翠迷津驿。", "慨世事尘化，吾心形役。", "清吟孤往，渺醉影，夜翠湿。"]'),
('song-ci-729','玲珑四犯','刘之才','宋','宋词','song-ci','玲珑四犯','[]','几叠云山，隔不断阑干，天外凝眺。',122,'宋词/ci.song.16000.json','["几叠云山，隔不断阑干，天外凝眺。", "秋与愁并，梧迳雨痕先表。", "娇梦半握芙蓉，奈曲曲、翠屏深窈。", "问愁根，当年谁种，漠漠淡烟衰草。", "鸳鸯懒拂苹花影，记眉妩、萦情多少。", "辘轳玉虎牵丝转，听尽秋釭晓。", "算谁念、卧云衣冷，香压金蟾小。", "写新词、先寄江鸿归去，且教知道。"]'),
('song-ci-730','声声慢','刘之才','宋','宋词','song-ci','声声慢','[]','湘云织玉，楚葛篝香，澡兰帘幕风静。',119,'宋词/ci.song.16000.json','["湘云织玉，楚葛篝香，澡兰帘幕风静。", "怨抑难招，沉魄当年独醒。", "莫唱江南古调，念天涯、深情谁省。", "时暗换，最秦楼惆望，归期无定。", "曾是榴裙误写，怕照眼枝头，绛绡花并。", "巧篆盘丝，午镜绿窗闹影。", "香蒲也应细剪，但年年、断云愁冷。", "迎醉面，看银蟾、飞浴露井。"]'),
('song-ci-731','贺新郎','刘之才','宋','宋词','song-ci','贺新郎','[]','苍藓粘溪路。',142,'宋词/ci.song.16000.json','["苍藓粘溪路。", "帐山君、け然羽化，梦魂何许。", "曾约秋云萦客袖，舞傍吟皋砚坞。", "矫清唳、裂穿云宇。", "江碧空濛无处问，问孤山、梅底人知否。", "烟夜永，耿心语。", "瑶华一去成幽阻。", "倚修篁、抱琴愁绝，天寒日暮。", "城郭悲歌华表恨，此事销凝千古。", "有招隐、小山能赋。", "蕙帐空兮谁夜怨，算课骚、读易俱凄楚。", "步深窈，堕松露。"]'),
('song-ci-732','菩萨蛮','刘之才','宋','宋词','song-ci','菩萨蛮','[]','题花曾蘸花心露。',52,'宋词/ci.song.16000.json','["题花曾蘸花心露。", "当初误结丁香树。", "往事小蛮窗。", "新愁桃叶江。", "缓歌留薄醉。", "急镫人千里。", "梅瘦月阑干。", "断云春梦寒。"]'),
('song-ci-733','解连环','刘之才','宋','宋词','song-ci','解连环','[]','晚云粘湿。',132,'宋词/ci.song.16000.json','["晚云粘湿。", "正吴峰惨澹，雨迷烟接。", "早陡顿、秋事分携，甚连苑暮墙，菊荒苔匝。", "空阔愁乡，更天外、怨鸿声黠。", "怕吟肩易瘦，料理篝衣，细认香折。", "银缸半明半灭。", "念花营柳阵，何日消歇。", "可是□、凝黯兰成，为情润才松，丽赋多惬。", "洛浦溟濛，漫伫想、明珰钩袜。", "告梧桐、夜深略住，梦时一霎。"]'),
('song-ci-734','卖花声','萧汉杰','宋','宋词','song-ci','卖花声','[]','湿逗晚香残。',64,'宋词/ci.song.16000.json','["湿逗晚香残。", "春浅春寒，洒窗填户著幽兰。", "惨惨凄凄仍滴滴，做出多般。", "和霰撒珠盘。", "枕上更阑。", "芭蕉怨曲带愁弹。", "绿遍阶前苔一片，晓起谁看。"]'),
('song-ci-735','菩萨蛮','萧汉杰','宋','宋词','song-ci','菩萨蛮','[]','春愁一段来无影。',52,'宋词/ci.song.16000.json','["春愁一段来无影。", "著人似醉昏难醒。", "烟雨湿阑干。", "杏花惊蛰寒。", "唾壶敲欲破。", "绝叫凭谁和。", "今夜欠添衣。", "那人知不知。"]'),
('song-ci-736','蝶恋花','萧汉杰','宋','宋词','song-ci','蝶恋花','[]','一缕春情风里絮。',70,'宋词/ci.song.16000.json','["一缕春情风里絮。", "海阔天高，那更云无数。", "娇颤画梁非为雨。", "怜伊只合和伊去。", "欲话因缘愁日暮。", "细认帘旌，几度来还去。", "万一这回航可渡。", "共渠活处寻条路。"]'),
('song-ci-737','浪淘沙','萧汉杰','宋','宋词','song-ci','浪淘沙','[]','愁似晚天云。',64,'宋词/ci.song.16000.json','["愁似晚天云。", "醉亦无凭。", "秋光此夕属何人。", "贫得今年无月看，留滞江城。", "夜起候檐声。", "似雨还晴。", "旧家谁信此时情。", "惟有桂香时入梦，勾引诗成。"]'),
('song-ci-738','清平乐','罗椅','宋','宋词','song-ci','清平乐','[]','明虹收雨。',54,'宋词/ci.song.16000.json','["明虹收雨。", "两桨能吴语。", "人在江南荷叶浦。", "采得苹花无数。", "梦中舞燕栖鸾。", "起来烟渚风湾。", "一点愁眉天末，凭谁剗却春山。"]'),
('song-ci-739','八声甘州','罗椅','宋','宋词','song-ci','八声甘州','[]','甚匆匆岁月，又人家、插柳记清明。',119,'宋词/ci.song.16000.json','["甚匆匆岁月，又人家、插柳记清明。", "正南北高峰，山传笑响，水泛箫声。", "吹散楼台烟雨，莺语碎春晴。", "何地无芳草，惟此青青。", "谁管孤山山下，任种梅竹冷，荐菊泉清。", "看人情如此，沉醉不须醒。", "问何时、樊川归去，叹故乡、七十五长亭。", "君知否，洞云溪竹，笑我飘零。"]'),
('song-ci-740','柳梢青','罗椅','宋','宋词','song-ci','柳梢青','[]','萼绿华身，小桃花扇，安石榴裙。',61,'宋词/ci.song.16000.json','["萼绿华身，小桃花扇，安石榴裙。", "子野闻歌，周郎顾曲，曾恼夫君。", "悠悠羁旅愁人。", "似飘零、青天断云。", "何处销魂，初三夜月，第四桥春。"]'),
('song-ci-741','更漏子','罗椅','宋','宋词','song-ci','更漏子','[]','晚潮生，凉月细。',58,'宋词/ci.song.16000.json','["晚潮生，凉月细。", "一抹远山无蒂。", "收越棹，起吴樯。", "人间何限忙。", "石头城，西北角。", "杳杳天低鹘落。", "浑不似，此波光。", "清歌催夕阳。"]'),
('song-ci-742','长相思','徐霖','宋','宋词','song-ci','长相思','[]','听莺声。',44,'宋词/ci.song.16000.json','["听莺声。", "惜莺声。", "客里莺声最有情。", "家山何处青。", "问归程。", "数归程。", "行尽长亭又短亭。", "征衫脱未成。"]'),
('song-ci-743','点绛唇','朱埴','宋','宋词','song-ci','点绛唇','[]','绣被鸳鸯，宝香熏透蔷薇水。',50,'宋词/ci.song.16000.json','["绣被鸳鸯，宝香熏透蔷薇水。", "枕边一纸。", "明月人千里。", "宿酒初醒，全不忺梳洗。", "抬纤指。", "微签玉齿。", "百色思量起。"]'),
('song-ci-744','画堂春','朱埴','宋','宋词','song-ci','画堂春','[]','绿窗睡起小妆残。',55,'宋词/ci.song.16000.json','["绿窗睡起小妆残。", "玉钗低堕云鬟。", "回纹枉寄见伊难。", "心绪阑珊。", "翠袖两行珠泪，画楼十二阑干。", "销磨今古霎时间。", "恨杀青山。"]'),
('song-ci-745','南乡子','朱埴','宋','宋词','song-ci','南乡子','[]','花柳隔重扃。',66,'宋词/ci.song.16000.json','["花柳隔重扃。", "送过秋千笑语声。", "檐鹊也嗔人起晚，天晴。", "孤负东风趁踏青。", "细细砑红绫。", "小字相思写不成。", "心上可人云样远，寒盟。", "只恐恩情薄似云。"]'),
('song-ci-746','酹江月・念奴娇','张绍文','宋','宋词','song-ci','酹江月・念奴娇','[]','举杯呼月，问神京何在，淮山隐隐。',120,'宋词/ci.song.16000.json','["举杯呼月，问神京何在，淮山隐隐。", "抚剑频看勋业事，惟有孤忠挺挺。", "宫阙腥膻，衣冠沦没，天地凭谁整。", "一枰棋坏，救时著数宜紧。", "虽是幕府文书，玉关烽火，暂送平安信。", "满地干戈犹未戢，毕竟中原谁定。", "便欲凌空，飘然直上，拂拭山河影。", "倚风长啸，夜深霜露凄冷。"]'),
('song-ci-747','水龙吟','张绍文','宋','宋词','song-ci','水龙吟','[]','日迟风软花香，困人天气情怀懒。',126,'宋词/ci.song.16000.json','["日迟风软花香，困人天气情怀懒。", "牡丹谢了，酴醿开后，红稀绿暗。", "慵下妆楼，倦吟莺镜，粉轻脂淡。", "叹韶华迤逦，将春归去，沉思处、空肠断。", "长是愁蛾不展。", "话春心、只凭双燕。", "良辰美景，可堪虚负，登临心眼。", "雁杳鱼沉，信音难托，水遥山远。", "但无言，倚遍阑干十二，对芳天晚。"]'),
('song-ci-748','壶中天・念奴娇','张绍文','宋','宋词','song-ci','壶中天・念奴娇','[]','丹台仙伯，记踪迹当年、琼楼金阙。',120,'宋词/ci.song.16000.json','["丹台仙伯，记踪迹当年、琼楼金阙。", "底事来游人世界，为爱风云水月。", "结屋南园，境随人胜，不是溪山别。", "今朝初度，碧莲千顷齐发。", "况是鸳侣新偕，凤雏才长，占人间欢悦，且尽壶天终夕醉，听取妙歌千阙。", "待得西风，鹗书飞上，更复青毡物。", "功成名遂，赤松还伴高洁。"]'),
('song-ci-749','沁园春','张绍文','宋','宋词','song-ci','沁园春','[]','数遍时贤，谁似云溪，未老得闲。',139,'宋词/ci.song.16000.json','["数遍时贤，谁似云溪，未老得闲。", "自抽身州县，归休旧隐，灰心名利，跳出尘寰。", "卸却朝衣，笑拈拄杖，日在花阴竹径间。", "身轻健，任高眠晏起，渴饮饥餐。", "垂弧猛省当年。", "且约住春风开寿筵。", "况园亭池馆，新奇佳丽，弟兄子侄，歌笑团栾。", "绿鬓朱颜，纶巾羽扇，做个人间长寿仙。", "霞觞举，愿年年今日，长对南山。"]'),
('song-ci-750','八六子','杨缵','宋','宋词','song-ci','八六子','[]','怨残红。',108,'宋词/ci.song.16000.json','["怨残红。", "夜来无赖，雨催春去匆匆。", "但暗水、新流芳恨，蝶凄蜂惨，千林嫩绿迷空。", "那知国色还逢。", "柔弱华清扶倦，轻盈洛浦临风。", "细认得凝妆，点脂匀粉，露蝉耸翠，蕊金团玉成丛。", "几许悉随笑解，一声歌转春融。", "眼朦胧。", "凭阑干、半醒醉中。"]'),
('song-ci-751','一枝春','杨缵','宋','宋词','song-ci','一枝春','[]','竹爆惊春，竞喧填、夜起千门箫鼓。',116,'宋词/ci.song.16000.json','["竹爆惊春，竞喧填、夜起千门箫鼓。", "流苏帐暖，翠鼎缓腾香雾。", "停杯未举。", "奈刚要、送年新句。", "应自有、歌字清圆，未夸上林莺语。", "从他岁穷日暮。", "纵闲愁、怎减刘郎风度。", "屠苏办了，迤逦柳欺梅妒。", "宫壶未晓，早骄马、绣车盈路。", "还又把、月夜花朝，自今细数。"]'),
('song-ci-752','被花恼','杨缵','宋','宋词','song-ci','被花恼','[]','疏疏宿雨酿寒轻，帘幕静垂清晓。',116,'宋词/ci.song.16000.json','["疏疏宿雨酿寒轻，帘幕静垂清晓。", "宝鸭微温瑞烟少。", "檐声不动，春禽对语，梦怯频惊觉。", "敧珀枕，倚银床，半窗花影明东照。", "惆怅夜来风，生怕娇香混瑶草。", "披衣便起，小径回廊，处处多行到。", "正千红万紫竞芳妍，又还似、年时被花恼。", "蓦忽地，省得而今双鬓老。"]'),
('song-ci-753','瑞鹧鸪','史铸','宋','宋词','song-ci','瑞鹧鸪','[]','底事秋英色压黄。',64,'宋词/ci.song.16000.json','["底事秋英色压黄。", "喜行春令惜红妆。", "谢天分付千年品，特地搀先九日香。", "陶令骇观须把酒，崔生瞥见误成章。", "蜂情蝶思兼迷了，采蕊还如媚景忙。"]'),
('song-ci-754','恋绣衾','林洪','宋','宋词','song-ci','恋绣衾','[]','冰肌生怕雪未禁。',68,'宋词/ci.song.16000.json','["冰肌生怕雪未禁。", "翠屏前、短瓶满簪。", "真个是、疏枝瘦，认花儿、不要浪吟。", "等闲蜂蝶都休惹，暗香来、时借水沉。", "既得个、厮偎伴，任风霜、尽自放心。"]'),
('song-ci-755','点绛唇','吴大有','宋','宋词','song-ci','点绛唇','[]','江上旗亭，送君还是逢君处。',50,'宋词/ci.song.16000.json','["江上旗亭，送君还是逢君处。", "酒阑呼渡。", "云压沙鸥暮。", "漠漠萧萧，香冻梨花雨。", "添愁绪。", "断肠柔橹。", "相逐寒潮去。"]'),
('song-ci-756','浪淘沙','金淑柔','宋','宋词','song-ci','浪淘沙','[]','雨溜和风铃。',64,'宋词/ci.song.16000.json','["雨溜和风铃。", "滴滴丁丁。", "酿成一枕别离情。", "可惜当年陶学士，孤负邮亭。", "边雁带秋声。", "音信难凭。", "花须偷数卜归程。", "料得到家秋正晚，菊满寒城。"]'),
('song-ci-757','沁园春','陈人杰','宋','宋词','song-ci','沁园春','["\u957f\u6c5f"]','不恨穷途，所恨吾生，不见古人。',139,'宋词/ci.song.16000.json','["不恨穷途，所恨吾生，不见古人。", "似道傍郭泰，品题季伟，舟中谢尚，赏认袁宏。", "又似元之，与苏和仲，汲引孙子晁李秦。", "今安在，但高风凛凛，坟草青青。", "江东无我无卿。", "政自要胸中分渭泾。", "叹今人荣贵，祗修边幅，斯文寂寞，终欠宗盟。", "面蹉长江，目迷东野，却笑韩公接后生。", "知音者，恨黄金难铸，清泪如倾。"]'),
('song-ci-758','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','我梦登天，尽把不平，问之化工。',139,'宋词/ci.song.16000.json','["我梦登天，尽把不平，问之化工。", "似桂花开日，秋高露冷，梅花开日，岁老霜浓。", "如此清标，依然香性，长在凄凉索寞中。", "何为者，祗纷纷桃李，占断春风。", "一时列鼎分封。", "岂猿臂将军无寸功。", "想世间成败，不关工拙，男儿济否，只声遭逢。", "天曰果然，事皆偶尔，凿井得铜奴得翁。", "君归去，但力行好事，休问穷通。"]'),
('song-ci-759','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','春为谁来，谁遣之归，挽之不还。',140,'宋词/ci.song.16000.json','["春为谁来，谁遣之归，挽之不还。", "纵小桃秾李，大都寂寞，紫薇红药，未到阑珊。", "毕竟须归，何妨小驻，容我一尊烟雨间。", "春无语，只游丝舞蝶，懒上杯盘。", "故园。", "风物班班。", "奈声利羁留身未闲。", "望归鸿影尽，白云万里，啼鹃声切，落日千山。", "春却笑人，年来何事，要得一归如许难。", "君知否，百八盘世路，尽在长安。"]'),
('song-ci-760','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','太岁茫茫，犹有归时，我胡不归。',139,'宋词/ci.song.16000.json','["太岁茫茫，犹有归时，我胡不归。", "为桂枝关约，十年阙下，梅花梦想，半夜天涯。", "婪尾三杯，胶牙一标，节物依然心事非。", "长安市，只喧喧箫鼓，催老男儿。", "篝灯自理征衣。", "正历乱愁肠千万丝。", "想椒盘寂寞，空传旧颂，桃符冷落，谁撰新诗。", "世事乾忙，人生寡遂，何限春风抛路歧。", "身安处，且开眉一笑，何以家为。"]'),
('song-ci-761','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','为问杜鹃，抵死催归，汝胡不归。',139,'宋词/ci.song.16000.json','["为问杜鹃，抵死催归，汝胡不归。", "似辽东白鹤，尚寻华表，海中玄鸟，犹记乌衣。", "吴蜀非遥，羽毛自好，合趁东风飞向西。", "何为者，却身羁荒树，血洒芳枝。", "兴亡常事休悲。", "算人世荣华都几时。", "看锦江好在，卧龙已矣，玉山无恙，跃马何之。", "不解自宽，徒然相劝，我辈行藏君岂知。", "闽山路，待封侯事了，归去非迟。"]'),
('song-ci-762','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','春事方浓，寂寞此君，谁相品题。',139,'宋词/ci.song.16000.json','["春事方浓，寂寞此君，谁相品题。", "到僝桃僽李，鸠边雨急，埋薇瘗药，燕外泥肥。", "鸟影舒炎，黄埃涨暑，又过绿阴青子时。", "夫然后，向猷家载酒，诩室题诗。", "风标如此清奇。", "叹世俗炎凉真可悲。", "看眼空凡木，云霄直上，心交古干，霜雪相依。", "弹压溪山，留连风月，红紫纷纷谁似之。", "人间世，这澹中风味，儿辈争知。"]'),
('song-ci-763','沁园春','陈人杰','宋','宋词','song-ci','沁园春','["\u897f\u6e56"]','诗不穷人，人道得诗，胜如得官。',139,'宋词/ci.song.16000.json','["诗不穷人，人道得诗，胜如得官。", "有山川草木，纵横纸上，虫鱼鸟兽，飞动毫端。", "水到渠成，风来帆速，廿四中书考不难。", "惟诗也，是乾坤清气，造物须悭。", "金张许史浑闲。", "未必有功名久后看。", "算南朝将相，到今几姓，西湖名胜，只说孤山。", "象笏堆床，蝉冠满座，无此新诗传世间。", "杜陵老，向年时也自，井冻衣寒。"]'),
('song-ci-764','沁园春','陈人杰','宋','宋词','song-ci','沁园春','["\u897f\u6e56", "\u5cb3\u9633\u697c"]','记上层楼，与岳阳楼，酾酒赋诗。',139,'宋词/ci.song.16000.json','["记上层楼，与岳阳楼，酾酒赋诗。", "望长山远水，荆州形胜，夕阳枯木，六代兴衰。", "扶起仲谋，唤回玄德，笑杀景升豚犬儿。", "归来也，对西湖叹息，是梦耶非。", "诸君傅粉涂脂。", "问南北战争都不知。", "恨孤山霜重，梅凋老叶，平堤雨急，柳泣残丝。", "玉垒胜烟，珠淮飞浪，万里腥风吹鼓鼙。", "原夫辈，算事今如此，安用毛锥。"]'),
('song-ci-765','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','谁使神州，百年陆沉，青毡未还。',139,'宋词/ci.song.16000.json','["谁使神州，百年陆沉，青毡未还。", "怅晨星残月，北州豪杰，西风斜日，东帝江山。", "刘表坐谈，深源轻进，机会失之弹指间。", "伤心事，是年年冰合，在在风寒。", "说和说战都难。", "算未必江沱堪宴安。", "叹封侯心在，鱣鲸失水，平戎策就，虎豹当关。", "渠自无谋，事犹可做，更剔残灯抽剑看。", "麒麟阁，岂中兴人物，不画儒冠。"]'),
('song-ci-766','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','落日都门，买得扁舟，乘兴而东。',139,'宋词/ci.song.16000.json','["落日都门，买得扁舟，乘兴而东。", "正苕川半夜，月寒似水，苹洲一路，秋老多风。", "携妓溪山，寻春岁月，往事黄粱昨梦中。", "高楼上，问何人怀古，湖海元龙。", "诸君解后相逢。", "更休问奚奴金错空。", "向琐窗看镜，鬓无霜白，玉舠挥酒，脸有潮红。", "莼美鲈肥，橙香蟹壮，风味不如归兴浓。", "明朝去，有西门一水，直与天通。"]'),
('song-ci-767','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','此去长安，说似交游，我来自东。',139,'宋词/ci.song.16000.json','["此去长安，说似交游，我来自东。", "向蒹葭极浦，吟篷泊雨，梧桐孤店，醉帻敧风。", "青市生涯，白洲活计，都在水乡鱼稻中。", "邮亭上，俯清流长啸，惊起虬龙。", "霅山面面迎逢。", "便回首旧游云水空。", "有连天秋草，寒烟借碧，满城霜叶，落照争红。", "六代蜂窠，七贤蝶梦，勾引客愁如酒浓。", "人间世，只醉乡堪向，休问穷通。"]'),
('song-ci-768','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','草满姑苏，问讯夫差，今安在哉。',139,'宋词/ci.song.16000.json','["草满姑苏，问讯夫差，今安在哉。", "望虎丘苍莽，愁随月上，蠡湖浩渺，兴逐潮来。", "自古男儿，可人心事，惆怅要离招不回。", "离之后，似舞阳几个，成甚人才。", "西风斜照徘徊。", "比旧日江南尤可哀。", "叹茫茫马腹，黄尘如许，纷纷牛背，青眼难开。", "应物香销，乐天句杳，无限风情成死灰。", "都休问，向客边解后，祗好拈杯。"]'),
('song-ci-769','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','日薄风狞，万里空江，隐隐有声。',139,'宋词/ci.song.16000.json','["日薄风狞，万里空江，隐隐有声。", "旋千旗万棹，一时东指，青山断处，白浪成层。", "渐近渐高，可惊可喜，欻作雪峰楼外横。", "教人讶，是鲸掀鳌抃，蛟斗龙争。", "属镂忠恨腾腾。", "要句践城台都荡平。", "奈岸身不动，潮头自落，又如飞剑，斫倒鼍城。", "若到夜深，更和月看，组练分明十万兵。", "尤奇特，有稼轩一曲，真野狐精。"]'),
('song-ci-770','沁园春','陈人杰','宋','宋词','song-ci','沁园春','["\u897f\u6e56"]','把酒西湖，花月三年，不见家山。',139,'宋词/ci.song.16000.json','["把酒西湖，花月三年，不见家山。", "想荆州座上，消磨岁月，唐风集里，收卷波澜。", "鹤邑朝帆，鲈乡夕棹，来往菰蒲何处间。", "应思我，似骑驴杜甫，长在长安。", "相逢依旧开颜。", "听玉屑霏霏当暑寒。", "笑髯生如许，尚夸年少，心忙未了，浪说身闲。", "尘梦无凭，菟裘堪老，付子声名吾欲还。", "斜阳外，把平生心事，同倚阑干。"]'),
('song-ci-771','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','过了梅花，纵有春风，不如早还。',139,'宋词/ci.song.16000.json','["过了梅花，纵有春风，不如早还。", "正燕泥日暖，草绵别路，莺朝烟澹，柳拂征鞍。", "黎岭天高，建溪雷吼，归好不知行路难。", "龟山下，渐青梅初熟，卢橘犹酸。", "名场老我闲关。", "分岁晚诛茅湖上山。", "叹龙舒君去，尚留破砚，鱼轩人老，长把连环。", "镜影霜侵，衣痕尘暗，赢得狂名传世间。", "君归日，见家林旧竹，为报平安。"]'),
('song-ci-772','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','斗酒津亭，方送月芗，夫君又行。',139,'宋词/ci.song.16000.json','["斗酒津亭，方送月芗，夫君又行。", "正夕阳枯木，低回征路，寒烟衰草，迤逦离情。", "京洛风尘，吴兴山水，等是东西南北人。", "思君处，只梅花解后，心目开明。", "江湖夜雨青灯。", "曾说尽百年闲废兴。", "叹屠龙事业，依然汗漫，歌鱼岁月，政尔峥嵘。", "但使豫州，堪容玄德，何必区区依景升。", "需时耳，算不应长是，竖子成名。"]'),
('song-ci-773','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','塞外江山，如此萧条，可堪别离。',139,'宋词/ci.song.16000.json','["塞外江山，如此萧条，可堪别离。", "纵虹桥烟浪，要君怀古，凤城风雨，奈我相思。", "玉茧挥诗，金鲸泻酒，件件清狂分付谁。", "长安市，有几多心事，岁老相期。", "春风渐到梅枝。", "算我辈荣枯应似之。", "莫提携剑铗，悲歌一曲，摩挲髀肉，清泪双垂。", "话到辛酸，居然慷慨，跃马岁年心自知。", "君行矣，有广平东阁，堪著男儿。"]'),
('song-ci-774','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','未省吾生，石室云林，金门玉堂。',139,'宋词/ci.song.16000.json','["未省吾生，石室云林，金门玉堂。", "但吕公来说，风神清怪，甘公来说，寿禄高强。", "果若人言，自应年少，曳紫鸣珂游帝乡。", "何为者，更风尘牢落，歧路回皇。", "替人缝嫁衣裳。", "奈未遇良媒空自伤。", "岂平生犹欠，阴功活蚁，从前未卜，吉地眠羊。", "岁晏何如，时来便做，但恐鬓毛容易霜。", "今休问，且揆予初度，满引金觞。"]'),
('song-ci-775','沁园春','陈人杰','宋','宋词','song-ci','沁园春','["\u897f\u6e56"]','五彩云中，群玉峰头，是吾故乡。',140,'宋词/ci.song.16000.json','["五彩云中，群玉峰头，是吾故乡。", "为瑶池侍宴，偶违酒令，玉皇降敕，谪作诗狂。", "桧柏风姿，山林气象，未到中年先老苍。", "西湖路，尽留连光景，傲睨冰霜。", "东窗。", "翦烛焚香。", "剩满引梅花进寿觞。", "梦群仙相庆，烹炮麟凤，十洲同往，骖翳鸾凰。", "约向人间，尽偿吟债，依旧乘风来帝旁。", "如今未，且百年管领，橘绿橙黄。"]'),
('song-ci-776','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','如此男儿，可是疏狂，才大兴浓。',139,'宋词/ci.song.16000.json','["如此男儿，可是疏狂，才大兴浓。", "看曹瞒事业，雀台夜月，建封气概，燕子春风。", "叱咤生雷，肝肠似石，才到尊前都不同。", "人间世，只婵娟一剑，磨尽英雄。", "半生书剑无功。", "漫赢得闲情如二公。", "向紫云歌畔，玉舠最满，红桃笑里，金错长空。", "驼陌三年，牛腰几束，半在兰香巾笥中。", "君知否，是扬州景物，消得司封。"]'),
('song-ci-777','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','世路如秋，万里萧条，君何所之。',139,'宋词/ci.song.16000.json','["世路如秋，万里萧条，君何所之。", "想鲈乡烟水，尚堪垂钓，虎丘泉石，尽可题诗。", "橙弄霜黄，芦飘雪白，何处西风无酒旗。", "经行地，有会心之事，好吐胸奇。", "一邱封了要离。", "问世上男儿今有谁。", "但一尊相属，居然感慨，扁舟独往，可是嶔崎。", "齐邸歌鱼，扬州跨鹤，风味浅深君自知。", "匆匆去，算梅边春动，又是归期。"]'),
('song-ci-778','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','抚剑悲歌，纵有杜康，可能解忧。',139,'宋词/ci.song.16000.json','["抚剑悲歌，纵有杜康，可能解忧。", "为修名不立，此身易老，古心自许，与世多尤。", "平子诗中，庾生赋里，满目江山无限愁。", "关情处，是闻鸡半夜，击楫中流。", "澹烟衰草连秋。", "听鸣鴂声声相应酬。", "叹霸才重耳，泥涂在楚，雄心元德，岁月依刘。", "梦落莼边，神游菊外，已分他年专一丘。", "长安道，且身如王粲，时复登楼。"]'),
('song-ci-779','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','我自无忧，何用攒眉，今忧古忧。',140,'宋词/ci.song.16000.json','["我自无忧，何用攒眉，今忧古忧。", "叹风寒楚蜀，百年受病，江分南北，千载归尤。", "洛下铜驼，昭陵石马，物不自愁人替愁。", "兴亡事，向西风把剑，清泪双流。", "边头。", "依旧防秋。", "问诸将君恩酬未酬。", "怅书生浪说，皇王帝霸，功名已属，韩岳张刘。", "不许请缨，犹堪草檄，谁肯种瓜归故邱。", "江中蜃，识平生许事，吐气成楼。"]'),
('song-ci-780','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','尽典春衣，换酒津亭，送君此行。',139,'宋词/ci.song.16000.json','["尽典春衣，换酒津亭，送君此行。", "叹清朝有道，何曾逐客，有司议法，忍及书生。", "归去来兮，噫其甚矣，见说江涛也不平。", "君之友，岂都无义士，剖胆相明。", "挑诗行李如冰。", "正趁得越山桃李春。", "把从前豪举，著些老气，不应造物，到底无情。", "雁荡烟霞，凤城风雨，两地相思魂梦清。", "重来否，算海波未窄，犹可骑鲸。"]'),
('song-ci-781','沁园春','陈人杰','宋','宋词','song-ci','沁园春','["\u897f\u6e56"]','南北战争，惟有西湖，长如太平。',140,'宋词/ci.song.16000.json','["南北战争，惟有西湖，长如太平。", "看高楼倚郭，云边矗栋，小亭连苑，波上飞甍。", "太守风流，游人欢畅，气象迩来都斩新。", "秋千外，剩钗骈玉燕，酒列金鲸。", "人生。", "乐事良辰。", "况莺燕声中长是晴。", "正风嘶宝马，软红不动，烟分彩鹢，澄碧无声。", "倚柳分题，藉花传令，满眼繁华无限情。", "谁知道，有种梅处士，贫里看春。"]'),
('song-ci-782','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','万法皆空，空即是空，佛安在哉。',139,'宋词/ci.song.16000.json','["万法皆空，空即是空，佛安在哉。", "有云名妙净，可遮热恼，海名圆觉，堪洗尘埃。", "翠竹真如，黄花般若，心上种来心上开。", "教参熟，是菩提无树，明镜非台。", "偷闲来此徘徊。", "把人世黄粱都唤回。", "算五陵豪客，百年荣贵，何如衲子，一钵生涯。", "俯仰溪山，婆娑松桧，两腋清风茶一杯。", "拿舟去，更扫尘东壁，聊记曾来。"]'),
('song-ci-783','沁园春','陈人杰','宋','宋词','song-ci','沁园春','["\u897f\u6e56"]','懒学冯君，弹铗歌鱼，如今五年。',139,'宋词/ci.song.16000.json','["懒学冯君，弹铗歌鱼，如今五年。", "为西湖西子，费人料理，东林东老，特地留连。", "坐注虫鱼，行吟雌霓，竟负逍遥第一篇。", "过从少，但赤髭白足，时复谈禅。", "倚门白水平田。", "看数点青山无尽天。", "叹春风心事，已成待兔，夕阳时节，又听啼鹃。", "如此凄凉，若为排遣，不是诗边即酒边。", "中宵梦，有逋梅吹雪，坡柳摇烟。"]'),
('song-ci-784','沁园春','陈人杰','宋','宋词','song-ci','沁园春','["\u897f\u6e56"]','云锦亭西，记与诗人，拍浮酒船。',139,'宋词/ci.song.16000.json','["云锦亭西，记与诗人，拍浮酒船。", "看洛川妃子，锦衾照水，汉皋游女，玉佩摇烟。", "秋老芳心，波空艳质，惟见寒霜凋碧圆。", "争知道，有西湖五月，长在尊前。", "素纨红障相鲜。", "更澹静一枝真叶仙。", "向风轩摇动，但无香耳，蓼丛掩映，自是天然。", "猊背生烟，蜡心吐月，赢得吴娃歌采莲。", "陈公子，似日休锺爱，兴满吟边。"]'),
('song-ci-785','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','易得仲宣，难得世间，有刘景升。',139,'宋词/ci.song.16000.json','["易得仲宣，难得世间，有刘景升。", "叹男儿未到，鸣珂谒帝，此身那免，弹铗依人。", "橘自盈洲，莸难共器，一榻相看如越秦。", "元龙者，独门前有客，胸次无尘。", "君今重莅诗盟。", "载弄玉飞琼车后行。", "过鸱夷西子，曾游处所，水云应喜，重见娉婷。", "张禹堂深，马融帐暖，吟罢不妨丝竹声。", "松江上，约扁舟棹雪，同看梅春。"]'),
('song-ci-786','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','道骨仙风，自天上来，月潭主人。',139,'宋词/ci.song.16000.json','["道骨仙风，自天上来，月潭主人。", "把玉清宝印，按行川岳，神霄铁尺，鞭叱雷霆。", "雨部收晴，日君腾照，一寸灵章飞杳冥。", "幡旗外，觉阴风肃肃，奔走神兵。", "登坛沥酒刑牲。", "有法馔如山饱万灵。", "想乖龙惊起，碧潭无底，妖蟆戮尽，珪月长明。", "行比旌阳，功高李靖，玉府丹台登姓名。", "平生志，合为霖为雨，大慰苍生。"]'),
('song-ci-787','沁园春','陈人杰','宋','宋词','song-ci','沁园春','[]','禁鼓蓬蓬，忙杀公侯，穴城影中。',139,'宋词/ci.song.16000.json','["禁鼓蓬蓬，忙杀公侯，穴城影中。", "正花前豪士，宿酲未解，松间逋客，清梦才浓。", "龙尾危机，犀围长物，何必飞书交子公。", "人间世，只闲之一字，受用无穷。", "主人窗户玲珑。", "悟富贵荣华回首空。", "向竹梧侧畔，聚先秦录，兰荪里许，吟晚唐风。", "琴外鸿归，棋边鹭静，天把一丘荣此翁。", "孙刘辈，枉百年争战，一昧雌雄。"]'),
('song-ci-788','浣溪纱・浣溪沙','毛珝','宋','宋词','song-ci','浣溪纱・浣溪沙','[]','绿玉枝头一粟黄。',48,'宋词/ci.song.16000.json','["绿玉枝头一粟黄。", "碧纱帐里梦魂香。", "晓风和月步新凉。", "吟倚画栏怀李贺，笑持玉斧恨吴刚。", "素娥不嫁为谁妆。"]'),
('song-ci-789','踏莎行','毛珝','宋','宋词','song-ci','踏莎行','[]','顾曲多情，寻芳未老。',68,'宋词/ci.song.16000.json','["顾曲多情，寻芳未老。", "一庭风月知音少。", "梦随蝶去恨墙高，醉听莺语嫌笼小。", "红烛呼卢，黄金买笑。", "弹丝踮屣长安道。", "彩笺拈起锦囊花，绿窗留得罗裙草。"]'),
('song-ci-790','摸鱼儿','张矩','宋','宋词','song-ci','摸鱼儿','["\u897f\u6e56"]','又吴尘、暗斑吟袖，西湖深处能浣。',140,'宋词/ci.song.16000.json','["又吴尘、暗斑吟袖，西湖深处能浣。", "晴云片片平波影，飞趁棹歌声远。", "回首唤。", "仿佛记、春风共载斜阳岸。", "轻携分短。", "怅柳密藏桥，烟浓断径，隔水语音换。", "思量遍。", "前度高阳酒伴。", "离踪悲事何限。", "双峰塔露书空颖，情共暮鸦盘转。", "归兴懒。", "悄不似、留眠水国莲香畔。", "灯帘晕满。", "正蠹帙逢迎，沈煤半冷，风雨闭宵馆。"]'),
('song-ci-791','应天长','张矩','宋','宋词','song-ci','应天长','[]','曙林带暝，晴霭弄霏，莺花未认游客。',122,'宋词/ci.song.16000.json','["曙林带暝，晴霭弄霏，莺花未认游客。", "草色旧迎雕辇，蒙茸暗香陌。", "秋千架，闲晓索。", "正露洗、绣鸳痕窄。", "费人省，隔夜浓欢，酲处先觉。", "重过涌金楼，画舫红旌，催向段桥泊。", "又怕晚天无准，东风妒芳约。", "垂杨岸，今胜昨。", "水院近、占先春酌。", "恁时候，不道归来，香断灯落。"]'),
('song-ci-792','应天长','张矩','宋','宋词','song-ci','应天长','[]','候蛩探暝，书雁寄寒，西风暗剪绡织。',122,'宋词/ci.song.16000.json','["候蛩探暝，书雁寄寒，西风暗剪绡织。", "报道凤城催钥，笙歌散无迹。", "冰轮驾，天纬逼。", "渐款引、素娥游历。", "夜妆靓，独展菱花，淡绚秋色。", "人在涌金楼，漏迥绳低，光重袖香滴。", "笑语又惊栖鹊，南飞傍林阒。", "孤山影，波共碧。", "向此际、隐逋如识。", "梦仙游，倚遍霓裳，何处闻笛。"]'),
('song-ci-793','应天长','张矩','宋','宋词','song-ci','应天长','[]','甃澌冱晓，篙水涨漪，孤山渐卷云簇。',122,'宋词/ci.song.16000.json','["甃澌冱晓，篙水涨漪，孤山渐卷云簇。", "又见岸容舒腊，菱花照新沐。", "横斜树，香未北。", "倩点缀、数梢疏玉。", "断肠处，日影轻消，休怨霜竹。", "帘上涌金楼，酒滟酥融，金缕试春曲，最好半残鳷鹊，登临快心目。", "瑶台梦，春未足。", "更看取、洒窗填屋。", "灞桥外，柳下吟鞭，归趁游烛。"]'),
('song-ci-794','应天长','张矩','宋','宋词','song-ci','应天长','[]','磬圆树杪，舟乱柳津，斜阳又满东角。',122,'宋词/ci.song.16000.json','["磬圆树杪，舟乱柳津，斜阳又满东角。", "可是暮情堪剪，平分付烟郭。", "西风影，吹易薄。", "认满眼、脆红先落。", "算惟有，塔起金轮，千载如昨。", "谁信涌金楼，此际凭阑，人共楚天约。", "准拟换樽陪月，缯空卷尘幕。", "飞鸿倦，低未泊。", "斗倒指、数来还错。", "笑声里，立尽黄昏，刚道秋恶。"]'),
('song-ci-795','应天长','张矩','宋','宋词','song-ci','应天长','[]','换桥度舫，添柳护堤，坡仙题欠今续。',122,'宋词/ci.song.16000.json','["换桥度舫，添柳护堤，坡仙题欠今续。", "四面水窗如染，香波酿春曲。", "田田处，成暗绿。", "正万羽、背风斜矗。", "乱鸥去，不信双鸳，午睡犹熟。", "还记涌金楼，共抚雕阑，低度浣沙曲。", "自与故人轻别，荣枯换凉燠。", "亭亭影，惊艳目。", "忍到手、又成轻触。", "悄无语，独拈花须，心事曾卜。"]'),
('song-ci-796','应天长','张矩','宋','宋词','song-ci','应天长','[]','岸容浣锦，波影堕红，纤鳞巧避凫唼。',122,'宋词/ci.song.16000.json','["岸容浣锦，波影堕红，纤鳞巧避凫唼。", "禹浪未成头角，吞舟胆犹怯。", "湖山外，江海匝。", "怕自有、暗泉流接。", "楚天远，尺素无期，枉误停楫。", "四望涌金楼，带草帟烟，缥缈际城堞。", "渐见暮榔敲月，轻舫乱如叶。", "濠梁兴，归未惬。", "记旧伴、袖携留摺。", "指鱼水，总是心期，休怨三叠。"]'),
('song-ci-797','应天长','张矩','宋','宋词','song-ci','应天长','[]','翠屏对晚，鸟榜占堤，钟声又敛春色。',122,'宋词/ci.song.16000.json','["翠屏对晚，鸟榜占堤，钟声又敛春色。", "几度半空敲月，山南应山北。", "欢娱地，空浪迹。", "谩记省、五更闻得。", "洞天晓，夹柳桥疏，稳纵香勒。", "前度涌金楼，笑傲东风，鸥鹭半相识。", "暗数院僧归尽，长虹卧深碧。", "花间恨，犹记忆。", "正素手、暗携轻拆。", "夜深后，不道人来，灯细窗隙。"]'),
('song-ci-798','应天长','张矩','宋','宋词','song-ci','应天长','[]','翠迷倦舞，红驻老妆，流莺怕与春别。',122,'宋词/ci.song.16000.json','["翠迷倦舞，红驻老妆，流莺怕与春别。", "过了禁烟寒食，东风颤环铁。", "游人恨，柔带结。", "更唤醒、羽喉宫舌。", "画桥远，不认绵蛮，晚棹空歇。", "争似涌金楼，燕燕归来，钩转暮帘揭。", "对语画梁消息，香泥砌花屑。", "昆明事，休更说。", "费梦绕、建章宫阙。", "晓啼处，稳击金狨，双灯笼月。"]'),
('song-ci-799','应天长','张矩','宋','宋词','song-ci','应天长','[]','桂轮逼采，菱沼漾金，潜虬暗动鲛室。',122,'宋词/ci.song.16000.json','["桂轮逼采，菱沼漾金，潜虬暗动鲛室。", "水路乍疑霜雪，明眸洗春色。", "年时事，还记忆。", "对万顷，葑痕龟坼。", "旧游处，不认三潭，此际曾识。", "今度涌金楼，素练萦窗，频照庾侯席。", "自与影娥人约，移舟弄空碧。", "宵风悄，签漏滴。", "早未许、睡魂相觅。", "有时恨，月被云妨，天也拚得。"]'),
('song-ci-800','应天长','张矩','宋','宋词','song-ci','应天长','["\u897f\u6e56"]','暮屏翠冷，秋树赭疏，双峰对起南北。',122,'宋词/ci.song.16000.json','["暮屏翠冷，秋树赭疏，双峰对起南北。", "好与霁天相接，浮图现西极。", "苕嶢处，云共碧。", "漫费尽、少年游屐。", "故乡近，一望空遥，水断烟隔。", "闲凭涌金楼，潋滟波心，如洗梦淹笔。", "唤醒睡龙苍角，盘空壮商翼。", "西湖路，成倦客。", "待倩写、素缣千尺。", "便归去，酒底花边，犹自看得。"]'),
('song-ci-801','梅子黄时雨','张矩','宋','宋词','song-ci','梅子黄时雨','[]','云宿江楼，爱留人夜语，频断灯炷。',114,'宋词/ci.song.16000.json','["云宿江楼，爱留人夜语，频断灯炷。", "奈倦情如醉，黑甜清午。", "谩道迎薰何曾是，簟纹成浪衣成雨。", "茶瓯注。", "新期竹院，残梦莲渚。", "应误。", "重帘凄伫。", "记并刀剪翠，秋扇留句。", "信那回轻道，而今归否。", "十二曲阑随意凭，楚天不放斜阳暮。", "沉吟处。", "池草暗喧蛙鼓。"]'),
('song-ci-802','七娘子','吴申','宋','宋词','song-ci','七娘子','[]','君家诸子燕山盛。',68,'宋词/ci.song.16000.json','["君家诸子燕山盛。", "去年两见门弧庆。", "银蜡烧花，宝香熏烬。", "晬盘珠玉还相映。", "耳边好语凭君听。", "此儿不与群儿并。", "右执金戈，左持金印。", "功名当似王文正。"]'),
('song-ci-803','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','锦水双龙，鞭风驾霆，来游璧池。',140,'宋词/ci.song.16000.json','["锦水双龙，鞭风驾霆，来游璧池。", "有一龙跃出，精神电烨，一龙战退，鳞甲天飞。", "一样轩拿，殊途升蛰，造化真同戏小儿。", "时人眼，总羡他腾踏，笑我卑栖。", "促装且恁西归。", "信自古功名各有时。", "但而今莫问，谁强谁弱，只争些时节，来速来迟。", "无地楼台，有官鼎鼐，命到亨通事事宜。", "三年里，看龙头独露，雁塔同题。"]'),
('song-ci-804','贺新郎','姚勉','宋','宋词','song-ci','贺新郎','[]','剑吼蛟龙怒。',141,'宋词/ci.song.16000.json','["剑吼蛟龙怒。", "问苍天、功名两字，几时分付。", "生个英雄为世用，须早青云得路。", "却底事、知音未遇。", "两度入天飞折翼，谩教人、欲叹儒冠误。", "竟不晓，是何故。", "休休天也无凭据。", "有如椽健笔，蟾宫须还高步。", "若使长材终困踬，社稷谁教扶助。", "信浅水、留龙不住。", "万顷洪流通大海，向波涛、阔处兴云雾。", "须信道，这回做。"]'),
('song-ci-805','贺新郎','姚勉','宋','宋词','song-ci','贺新郎','[]','长啸山中卧。',139,'宋词/ci.song.16000.json','["长啸山中卧。", "叹从前、二十年来，因循空过。", "自是惺惺并了了，奈这五行尚左。", "遇好事、许多磨挫。", "浩荡醉乡狂莫检，算傍人、笑得唇焦破。", "谁信道，只恁麽。", "从今牢把江湖柁。", "要做些勋业，归来则个。", "不见彭余朱李辈，总是白身人作。", "震耀得、声名许大。", "万一老天青眼顾，又何难、印佩黄金颗。", "时来到，也还我。"]'),
('song-ci-806','霜天晓角','姚勉','宋','宋词','song-ci','霜天晓角','[]','秋怀轩豁。',54,'宋词/ci.song.16000.json','["秋怀轩豁。", "痛饮天机发。", "世界只如掌大，算只有、醉乡阔。", "烟抹。", "山态活。", "雨晴波面滑。", "艇子慢摇归去，莫搅碎、一湖月。"]'),
('song-ci-807','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','一部周官，学问渊源，山斋得来。',140,'宋词/ci.song.16000.json','["一部周官，学问渊源，山斋得来。", "最雄姿直气，不涂脂粉，仙风道骨，不涴尘埃。", "万里青云，相期阔步，底事向天门折翼回。", "君知否，这白衣御史，卿相胚胎。", "时人休用惊猜。", "机会到功名节节催。", "看蒲质易凋，何如松茂，菊花已老，须是梅开。", "万事何难，时来得做，且信天工次第排。", "从今去，愿径游璧水，直上兰台。"]'),
('song-ci-808','贺新郎','姚勉','宋','宋词','song-ci','贺新郎','[]','月转宫墙曲。',142,'宋词/ci.song.16000.json','["月转宫墙曲。", "六更残、钥鱼声亮，纷纷袍鹄。", "黼坐临轩清跸奏，天仗缀行森肃。", "望五色、云浮黄屋。", "三策忠嘉亲赐擢，动龙颜、人立班头玉，胪首唱，众心服。", "殿头赐宴宫花簇。", "写新诗、金笺竞进，绣床争蹙。", "御渥新沾催进谢，一点恩袍先绿。", "归袖惹、天香芬馥。", "玉勒金鞯迎夹路，九街人、尽道苍生福。", "争拥入，状元局。"]'),
('song-ci-809','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','忆昔东坡，秀夺眉山，生丙子年。',139,'宋词/ci.song.16000.json','["忆昔东坡，秀夺眉山，生丙子年。", "盖丙离子坎，四方中气，宜当此岁，间出英贤。", "河岳重灵，星辰再孕，来自赤城中洞天。", "新秋霁，萃一襟爽气，风露澄鲜。", "玉阶同听胪传。", "伴宝马如龙丝袅鞭。", "正椿庭未老，同跻荣路，萼楼争耀，相照魁躔。", "即似坡公，金莲夜对，身作玉堂云雾仙。", "怜同岁，但乞如梦得，分买山钱。"]'),
('song-ci-810','贺新郎','姚勉','宋','宋词','song-ci','贺新郎','[]','唱彻阳关调。',139,'宋词/ci.song.16000.json','["唱彻阳关调。", "伴行人、梅拂征鞍，晓霜寒峭。", "金甲雕戈开玉帐，尊俎风流谈笑。", "看策马、从容江表。", "自是药阶苔砌客，卷经纶、且泛芙蓉沼。", "襟量阔，江面小。", "允文事业从容了。", "要岷峨人物，后先相照。", "见说君王曾有问，似此人才多少。", "便咫尺、云霄清要。", "四世三公毡复旧，况蜀珍、先已登廊庙。", "但侧耳，听新诏。"]'),
('song-ci-811','念奴娇','姚勉','宋','宋词','song-ci','念奴娇','[]','雕裘夜冷，怪地炉煨酒，经时难热。',120,'宋词/ci.song.16000.json','["雕裘夜冷，怪地炉煨酒，经时难热。", "晓起盘风天舞絮，拍手儿童欢悦。", "客里新吟，天葩翦巧，思与梅争发。", "使君属和，雪花同是三绝。", "未说赋就梁园，阳春拍调，压倒唐元白。", "早晚联镳花底去，共看朝霞银阙。", "朝退归来，清虚堂里，醉洒淋漓墨。", "而今且对，聚星堂上宾客。"]'),
('song-ci-812','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','四海中间，第一清流，惟有可斋。',139,'宋词/ci.song.16000.json','["四海中间，第一清流，惟有可斋。", "看平生践履，真如冰玉，雄文光焰，不涴尘埃。", "元祐诸贤，纷纷台省，惟有景仁招不来。", "狂澜倒，独中流砥柱，屹立崔嵬。", "挂冠有请高哉。", "但清庙正需梁栋材。", "便撑舟野水，出航巨海，有官鼎鼐，无地楼台。", "制菊龄高，看萸人健，万顷秋江入寿杯。", "经纶了，却驭风骑气，阆苑蓬莱。"]'),
('song-ci-813','满江红','姚勉','宋','宋词','song-ci','满江红','[]','仙苑蟠桃，恰则是、而今初熟。',115,'宋词/ci.song.16000.json','["仙苑蟠桃，恰则是、而今初熟。", "王母遣、飞琼捧献，绛金红玉。", "笑把九霞鸾凤斝，满斟七宝蒲萄醁。", "为长庚、此日自天来，殷勤祝。", "仙子唱，长生曲。", "仙客献，长生箓。", "活千人邓禹，阴功俱足。", "五鹗即齐公府剡，万羊自有中书禄。", "更从头、安享八千年，人间福。"]'),
('song-ci-814','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','梅笑东风，只两日间，又新岁华。',140,'宋词/ci.song.16000.json','["梅笑东风，只两日间，又新岁华。", "有玉龟阿母，献三蟠实，蕊宫仙子，飞七香车。", "春满虾帘，雪晴鸳瓦，窗户非烟笼翠纱。", "萱堂上，看衣翻戏彩，觞捧流霞。", "君家。", "元是仙家。", "几度看菖蒲九节花。", "来剑池丹井，平分风月，一溪流水，犹泛胡麻。", "寿庆千秋，荣封两国，绿鬓犹深杨柳鸦。", "长生药，在蓬莱顶上，不必丹砂。"]'),
('song-ci-815','水调歌头','姚勉','宋','宋词','song-ci','水调歌头','[]','桃李河阳县，春又到花枝。',114,'宋词/ci.song.16000.json','["桃李河阳县，春又到花枝。", "先庚三日，鳌山晴雪放灯时。", "金宿争华玉婺，来入仙闺清梦，光动绣湖西。", "人物东都令，句法晚唐诗。", "两年春，三种异，十般奇。", "朝天近也，紫泥催起舄凫飞。", "总羡童颜绿发，荣绾金鱼玉带，日侍赭黄衣。", "来岁传柑宴，人在赏花池。"]'),
('song-ci-816','水调歌头','姚勉','宋','宋词','song-ci','水调歌头','[]','微雪弄新霁，寒月上初弦。',114,'宋词/ci.song.16000.json','["微雪弄新霁，寒月上初弦。", "长庚入梦，间生采石锦袍仙。", "分得天孙云织，掣断麒麟金锁，来自玉皇前。", "丹井凭泥轼，风月兴无边。", "诏书来，催入觐，占春先。", "柳边花底，细驺辇路骤鸣鞭。", "荣侍金銮殿上，更向沉香亭北，半醉拂华笺。", "来岁今朝里，人在八花砖。"]'),
('song-ci-817','满江红','姚勉','宋','宋词','song-ci','满江红','[]','万里西风，吹送到、五云鸾纸。',115,'宋词/ci.song.16000.json','["万里西风，吹送到、五云鸾纸。", "□催促、文章太守，入朝花底。", "清节高横秋一片，仁风散作春千里。", "漾恩波、溶泳锦江中，深如水。", "难卧辙，留行李。", "但侧听，星辰履。", "看麒麟案侧，即催荣侍。", "红药香中翻诏草，紫薇影畔裁诗绮。", "更宸旒、已自覆公名，金瓯里。"]'),
('song-ci-818','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','万里清风，吹送锦帆，入南浦云。',139,'宋词/ci.song.16000.json','["万里清风，吹送锦帆，入南浦云。", "看拂天旌旆，攀留不住，迷津舸舰，歌舞相迎。", "二许家声，三洪地望，今代风流第一人。", "蜚英早，合词林视草，书阁翻芸。", "飞刍远饷三军。", "特借作红莲入幕宾。", "把西山暮雨，暂时收卷，荷山明月，小试平分。", "苏醒枯鱼，剔除深蠹，个是人间有脚春。", "难淹久，看诏催入侍，香案麒麟。"]'),
('song-ci-819','水龙吟','姚勉','宋','宋词','song-ci','水龙吟','[]','芰荷香雨初收，竹风槐日凉清晓。',124,'宋词/ci.song.16000.json','["芰荷香雨初收，竹风槐日凉清晓。", "年年祝寿，今年不比，常年时候。", "教子收功，五云金殿，初承亲诏。", "早胪传三日，寿称千岁，多应是、如公少。", "遥想寿椿堂上，饮霞觞、捧孙微笑。", "已见儿荣，更看孙贵，茅分蒲召。", "上第归来，彩衣挂绿，兰阶生耀。", "九霄中、一点光明，寿星高照。"]'),
('song-ci-820','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','一叶新凉，又是西风，吹转素商。',139,'宋词/ci.song.16000.json','["一叶新凉，又是西风，吹转素商。", "揽玉壶英气，锺为人物，银河精采，融作文章。", "司巧天公，搀先七夕，分付天孙云锦裳。", "骑龙凤，自九霄飞至，万丈光芒。", "早年奏赋长杨。", "饱挹尽瀛洲风露香。", "问石渠天禄，借将班马，荷山锦水，暂作龚黄。", "药省春风，薇垣夜月，合佩仙花侍玉皇。", "明年里，饮寿椒何处，宣劝持觞。"]'),
('song-ci-821','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','鹤发鸦髫，欢捧霞觞，酌丹井泉。',139,'宋词/ci.song.16000.json','["鹤发鸦髫，欢捧霞觞，酌丹井泉。", "庆湘山峰顶，飞来古佛，剑池洞里，活底神仙。", "春雨悭时，千金斗粟，民仰使君为食天。", "公知否，只活人阴德，合寿千年。", "宝猊香喷沈烟。", "环艳翠明红拥寿筵。", "最一般奇特，凤雏新贵，斑衣绿绶，光彩相鲜。", "帝命师臣，钦哉有子，飞诏看看又月边。", "黄封酒，到明年今日，中使传宣。"]'),
('song-ci-822','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','超逸天才，文如三松，诗如卢溪。',139,'宋词/ci.song.16000.json','["超逸天才，文如三松，诗如卢溪。", "自白莲赋就，已高声价，梅花句出，远见襟期。", "玉尘精神，瑶林风韵，雪里神仙小氅衣。", "缑山夕，已再经旬浃，戏鹤重归。", "花间凫舄轻飞。", "便一似元规报十奇。", "最风流膝上，双亲未老，三槐手种，分付佳儿。", "人想夷吾，帝思王某，钧轴舍人知未迟。", "长生药，在玉盘麟脯，琼苑蟾芝。"]'),
('song-ci-823','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','摘玉蕊梅，泛金叶蕉，祝公寿龄。',139,'宋词/ci.song.16000.json','["摘玉蕊梅，泛金叶蕉，祝公寿龄。", "算今年比似，常年更别，翠烟红雾，香霭门屏。", "凤诏云霄，龙光牛斗，辉射南州孺子亭。", "看看是，伴元戎小队，花柳郊坰。", "传家有子明经。", "浑不要黄金遗满籝。", "向月中传与，一枝仙桂，斓斑衣上，更著袍青。", "明日瓜期，今朝椿寿，好醉芝兰玉树庭。", "公知否，老人星一点，映泰阶星。"]'),
('song-ci-824','贺新郎','姚勉','宋','宋词','song-ci','贺新郎','[]','冷眼三边处。',142,'宋词/ci.song.16000.json','["冷眼三边处。", "喜舍人、水滨跃马，上京西路。", "三国英雄千载矣，形胜依然如故。", "这勋业、向谁分付。", "袖里翰林风月手，也何妨、戮力风寒护。", "谈笑暇，诗吟虏。", "岘山几载无人顾。", "幸如今、翦除荆棘，扫清飚雾。", "换得东南新局面，政欠十分著数。", "算人物、须还羊杜。", "玉帐筹边机会好，把规模、赶出中原去。", "天下事，书生做。"]'),
('song-ci-825','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','崧岳降神，昴宿宣精，挺生伟人。',139,'宋词/ci.song.16000.json','["崧岳降神，昴宿宣精，挺生伟人。", "整淳祐乾坤，浸如嘉祐，太平事业，了却端平。", "扶日中天，拱辰北极，一洒甘霖埃雾清。", "春寰海，听农歌载路，边柝沈声。", "旗常万世勋铭。", "便与国无穷垂令名。", "似青山流水，涑川贤相，黄花晚节，魏国元臣。", "五纬芒寒，六符色正，辉映老人南极星。", "苍生福，开八荒寿域，一气洪钧。"]'),
('song-ci-826','沁园春','姚勉','宋','宋词','song-ci','沁园春','["\u957f\u6c5f"]','章武中兴，淮蔡欲平，晋公已生。',140,'宋词/ci.song.16000.json','["章武中兴，淮蔡欲平，晋公已生。", "信天生英杰，正为国计，擎天著柱，要自支撑。", "万里长江，古称天险，去岁里风涛忽震惊。", "公谈笑，把云腥霓翳，一日都清。", "归来奠枕于京。", "有辉焕明堂前一星。", "称衮衣廊庙，枫宸眷宠，彩衣公府，萱砌春荣。", "著片公心，辨双明眼，长与群贤扶太平。", "无它愿，植万年宗社，万古功名。"]'),
('song-ci-827','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','湖海元龙，逸气飘然，可百尺楼。',139,'宋词/ci.song.16000.json','["湖海元龙，逸气飘然，可百尺楼。", "爱文光万丈，星辰绚彩，爽襟一掬，风露澄秋。", "衔字冰清，班心玉立，海内而今第一流。", "繙书子，紫薇花浸月，夜揽词头。", "著身已是瀛洲。", "问更有长生别药不。", "是生来已带，神仙道骨，毫端自有，富贵封侯。", "拜赐黄封，承恩青琐，见说香名又覆瓯。", "从今去，了福公事业，从赤松游。"]'),
('song-ci-828','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','道骨仙风，海上骑鲸，端是后身。',138,'宋词/ci.song.16000.json','["道骨仙风，海上骑鲸，端是后身。", "把银河天巧，锺为文采，剑津宝气，融作精神。", "壶玉储冰，掌金擎露，胸次全无一点尘。", "年年里，早花朝六日，长庆生申。", "箳篁濯锦江滨。", "人尽道如公清最真。", "合沉香亭北，金笺奏曲，恩披兽锦，醉拭龙巾。", "泥紫颁来，渠黄飞去，自是八花砖上人。", "从后看，大钧播物，万象皆春。"]'),
('song-ci-829','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','明月扁舟，轻逐江鸥，翩然赋归。',139,'宋词/ci.song.16000.json','["明月扁舟，轻逐江鸥，翩然赋归。", "任颠风掀舞，涛山浪屋，少顷平定，一碧硫璃。", "柳絮浮云，有无根蒂，到底不磨真是非。", "呵呵笑，笑人情似纸，世事如棋。", "宜堂事事皆宜。", "把杯酒论文更有谁。", "记风云满席，吟情浩荡，龙蛇满壁，醉墨淋漓。", "别后相思，有书寄否，春在梅花第一枝。", "重相见，约柳堤撑舫，竹阁寻诗。"]'),
('song-ci-830','沁园春','姚勉','宋','宋词','song-ci','沁园春','[]','拂剑整装，光射紫霄，斗牛色寒。',139,'宋词/ci.song.16000.json','["拂剑整装，光射紫霄，斗牛色寒。", "大丈夫不作，儿曹离别，何须更唱，三叠阳关。", "尽锦还乡，油幢佐幕，谁道青天行路难。", "从今去，听声名焰焰，飞动岷山。", "征途少饮加餐。", "要做取功名久远看。", "卷长风吹醒，剑关云气，更须砥柱，三峡惊湍。", "闻道槐庭，已登安石，此去须弹贡禹冠。", "明年里，踏梅花有分，相见长安。"]'),
('song-ci-831','声声慢','姚勉','宋','宋词','song-ci','声声慢','["\u897f\u6e56"]','江涵石瘦，雪压桥低，森森万木寒僵。',119,'宋词/ci.song.16000.json','["江涵石瘦，雪压桥低，森森万木寒僵。", "不是争魁，百花谁敢先芳。", "冰姿皎然玉立，笑儿曹、粉面何郎。", "调羹鼎，只此花馀事，说甚宫妆。", "松竹岁寒三友，恨竹汗晋士，松涴秦皇。", "雪魄冰魂，回首世上无香。", "西湖有人觅句，但知渠、清浅黄昏。", "奇绝处，五更初、横月带霜。"]'),
('song-ci-832','柳梢青','姚勉','宋','宋词','song-ci','柳梢青','["\u897f\u6e56"]','长记西湖，水光山色，浓淡相宜。',61,'宋词/ci.song.16000.json','["长记西湖，水光山色，浓淡相宜。", "丰乐楼前，涌金门外，买个船儿。", "而今又是春时。", "清梦只、孤山赋诗。", "绿盖芙蓉，青丝杨柳，好在苏堤。"]'),
('song-ci-833','贺新郎','姚勉','宋','宋词','song-ci','贺新郎','[]','薄晚收残暑。',142,'宋词/ci.song.16000.json','["薄晚收残暑。", "叹西风、暗换流年，又还如许。", "鸦背斜阳初敛影，云淡新凉天宇。", "人袖手、阑干凝伫。", "邻笛唤将乡思动，听秋声、又入梧桐雨。", "秋到也，尚羁旅。", "故人只在江南渚。", "想应嫌、久恋东华，软红尘土。", "寄远裁衣知念否，新月家家砧杵。", "魂梦想、鹅黄金缕。", "雁影不来天更远，写书成、欲寄恁谁与。", "知客恨，两蛩语。"]'),
('song-ci-834','贺新凉・贺新郎','姚勉','宋','宋词','song-ci','贺新凉・贺新郎','[]','窗月梅花白。',142,'宋词/ci.song.16000.json','["窗月梅花白。", "夜堂深、烛摇红影，绣帘垂额。", "半醉金钗娇应坐，寒处也留春色。", "深意在、四弦轻摘。", "香坞花行听啄木，翠微边、细落仙人屐。", "星盼转，趁娇拍。", "人间此手真难得。", "向尊前、相逢有分，底须相识。", "愁浅恩深千万意，惆怅故人云隔。", "怕立损、弓鞋红窄。", "换取明珠知肯否，绿窗深、长共春怜惜。", "休恼乱，坐中客。"]'),
('song-ci-835','摸鱼儿','陈允平','宋','宋词','song-ci','摸鱼儿','[]','倚东风、画阑十二，芳阴帘幕低护。',140,'宋词/ci.song.16000.json','["倚东风、画阑十二，芳阴帘幕低护。", "玉屏翠冷梨花瘦，寂寞小楼烟雨。", "肠断处。", "怅折柳柔情，旧别长亭路。", "年华似羽。", "任锦瑟声寒，琼箫梦远，羞对彩莺舞。", "文园赋。", "重忆河桥眉妩。", "啼痕犹溅纨素。", "丁香共结相思恨，空托绣罗金缕。", "春已暮。", "踪燕约莺盟，无计留春住。", "伤春倦旅。", "趁暗绿稀红，扁舟短棹，载酒送春去。"]'),
('song-ci-836','木兰花慢','陈允平','宋','宋词','song-ci','木兰花慢','[]','杜鹃声渐老，过花信、几番风。',123,'宋词/ci.song.16000.json','["杜鹃声渐老，过花信、几番风。", "爱翠幄笼晴，文梭扬暖，阑槛青红。", "新妆步摇未稳，捧心娇、乍入馆娃宫。", "消得金壶万朵，护风帘幄重重。", "匆匆。", "少小忆相逢。", "诗鬓已成翁。", "且持杯秉烛，天香院落，同赏芳秾。", "花应怕春去早，尽迟迟、待取绿阴浓。", "拼却花前醉也，梦随蝴蝶西东。"]'),
('song-ci-837','绛都春','陈允平','宋','宋词','song-ci','绛都春','[]','秋千倦倚，正海棠半坼，不耐春寒。',117,'宋词/ci.song.16000.json','["秋千倦倚，正海棠半坼，不耐春寒。", "殢雨弄晴，飞梭庭院绣帘闲。", "梅妆欲试芳情懒。", "翠颦愁入眉弯。", "雾蝉香冷，霞绡泪搵，恨袭湘兰。", "悄悄池台步晚。", "任红薰杏靥，碧沁苔痕。", "燕子未来，东风无语又黄昏。", "琴心不度春云远。", "断肠难托啼鹃。", "夜深犹倚，垂杨二十四阑。"]'),
('song-ci-838','酹江月・念奴娇','陈允平','宋','宋词','song-ci','酹江月・念奴娇','[]','汉江露冷，是谁将瑶瑟，弹向云中。',120,'宋词/ci.song.16000.json','["汉江露冷，是谁将瑶瑟，弹向云中。", "一曲清泠声渐杳，月高人在珠宫。", "晕额黄轻，涂腮粉艳，罗带织青葱。", "天香吹散，佩环犹自丁东。", "回首杜若汀洲，金钿玉镜，何日得相逢。", "独立飘飘烟浪远，袜尘羞溅春红。", "渺渺予怀，迢迢良夜，三十六陂风。", "九疑何处，断云飞度千峰。"]'),
('song-ci-839','倦寻芳','陈允平','宋','宋词','song-ci','倦寻芳','[]','杏檐转午。',118,'宋词/ci.song.16000.json','["杏檐转午。", "青漏沈沈，春梦无据。", "凤锦龟纱，空闭酒尘香雾。", "流水行云天四远，玉箫声断人何处。", "倦寻芳，镇情尖翠压，强拈飞絮。", "记旧约、荼縻开后，屈指心期，数了还数。", "误我凭阑，几度片帆南浦。", "燕懒莺慵春去也，落花犹是东风主。", "正销凝，被愁鹃、又啼烟树。"]'),
('song-ci-840','大酺','陈允平','宋','宋词','song-ci','大酺','[]','渐入融和，金莲放、人在东风楼阁。',164,'宋词/ci.song.16000.json','["渐入融和，金莲放、人在东风楼阁。", "天香吹辇路，净无云一点，桂柳霜魄。", "雪霁梅飘，春柔柳嫩，半卷真珠帘箔。", "迢迢鸣鞘过，隘车钿辔玉，暗尘轻掠。", "拥琼管吹龙，朱弦弹凤，柳衢花陌。", "鳌山侵碧落。", "绛绡远，春霭浮鳷鹊。", "民共乐、金吾禁静，翠跸声闲，遍青门、尽停鱼钥。", "衩袜寒初觉。", "方怪失、绣鸳弓窄。", "误良夜、瑶台约。", "渐彩霞散，双阙星微烟薄。", "洞天共谁夸鹤。"]'),
('song-ci-841','永遇乐','陈允平','宋','宋词','song-ci','永遇乐','[]','玉腕笼寒，翠阑凭晓，莺调新簧。',128,'宋词/ci.song.16000.json','["玉腕笼寒，翠阑凭晓，莺调新簧。", "暗水穿苔，游丝度柳，人静芳昼长。", "云南归雁，楼西飞燕，去来惯认炎凉。", "王孙远，青青草色，几回望断柔肠。", "蔷薇旧约，尊前一笑，等闲孤负年光。", "斗草庭空，抛梭架冷，帘外风絮香。", "伤春情绪，惜花时候，日斜尚未成妆。", "闻嬉笑，谁家女伴，又还采桑。"]'),
('song-ci-842','月上海棠','陈允平','宋','宋词','song-ci','月上海棠','[]','游丝弄晚，卷帘看处，燕重来时候。',113,'宋词/ci.song.16000.json','["游丝弄晚，卷帘看处，燕重来时候。", "正秋千亭榭，锦窠春透。", "梦回褪浴华清，凝温泉、绛绡微皱。", "芳阴底，人立东风，露华如昼。", "宜酒。", "啼香泪薄，醉玉痕深，与春同瘦。", "想当年金谷，步帷初绣。", "彩云影里徘徊，娇无语、夜寒归后。", "莺窗晓，花间重携素手。"]'),
('song-ci-843','疏影','陈允平','宋','宋词','song-ci','疏影','[]','千峰翠玉。',134,'宋词/ci.song.16000.json','["千峰翠玉。", "送孤云伴我，罗窗清宿。", "拂晓凭虚，春碧生寒，衣单瘦倚筇竹。", "东风不解吹愁醒，但芳草、溪城南北。", "认雾鬟，遥锁修颦，眉妩为谁愁独。", "江上轻鸥似识，背昭亭两两，飞破晴渌。", "一片苍烟，隔断家山，梦绕石窗萝屋。", "相看不厌朝还暮，算几度、赤阑干曲。", "待倩诗、收拾归来，写作卧游屏幅。"]'),
('song-ci-844','暗香','陈允平','宋','宋词','song-ci','暗香','[]','霁天秋色。',120,'宋词/ci.song.16000.json','["霁天秋色。", "正倚楼待月，谁伴横笛。", "涨绿浮空，闲数河星手堪摘。", "弥望澄光练净，分付与、玄晖才笔。", "烟溆阔，云远波平，归鸟趁风席。", "南国。", "信音寂。", "怅雁渚渡闲，鹭汀沙积。", "藓碑露泣。", "时拊遗踪暗嗟忆。", "人事空随逝水。", "今古但、双流一碧。", "待办取、蓑共笠，小舟泛得。"]'),
('song-ci-845','水龙吟','陈允平','宋','宋词','song-ci','水龙吟','[]','杜鹃啼老春愁，泪痕吹作胭脂雨。',126,'宋词/ci.song.16000.json','["杜鹃啼老春愁，泪痕吹作胭脂雨。", "飞花乱点，东风枝上，红翔翠翥。", "丹穴鸣初，碧梧栖未，凄凉山坞。", "怅琼姬梦远，玉箫声断，孤鸾影、对谁舞。", "林下风光自许。", "算何必、玉京瑶圃。", "阑干醉倚，游尘香散，芳菲无主。", "经院僧眠，月楼钟静，欲飞还驻。", "待青松、化尽苍龙头角，共乘云去。"]'),
('song-ci-846','齐天乐','陈允平','宋','宋词','song-ci','齐天乐','[]','湖光祗在阑干外，凭虚远迷三楚。',123,'宋词/ci.song.16000.json','["湖光祗在阑干外，凭虚远迷三楚。", "旧柳犹青，平芜自碧，几度朝昏烟雨。", "天涯倦旅。", "爱小却游鞭，共挥谈尘。", "顿觉尘清，宦情高下等风絮。", "芝山苍翠缥缈，黯然仙梦杳，吟思飞去。", "故国楼台，斜阳巷陌，回首白云何处。", "无心访古。", "对双塔栖鸦，半汀归鹭。", "立尽荷香，月明人笑语。"]'),
('song-ci-847','酹江月・念奴娇','陈允平','宋','宋词','song-ci','酹江月・念奴娇','[]','霁空虹雨，傍螀啼莎草，宿鹭汀洲。',120,'宋词/ci.song.16000.json','["霁空虹雨，傍螀啼莎草，宿鹭汀洲。", "隔岸人家砧杵急，微寒先到帘钩。", "步幄尘高，征衫酒润，谁暖玉香篝。", "风灯微暗，夜长频换更筹。", "应是雁柱调筝，鸳梭织锦，付与两眉愁。", "不似尊前今夜月，几度同上南楼。", "红叶无情，黄花有恨，孤负十分秋。", "归心如醉，梦魂飞趁东流。"]'),
('song-ci-848','桂枝香','陈允平','宋','宋词','song-ci','桂枝香','[]','残蝉乍歇。',124,'宋词/ci.song.16000.json','["残蝉乍歇。", "又乱叶打窗，蛩韵凄切。", "寂寞天香院宇，露凉时节。", "乘鸾扇底婆娑影，幻清虚、广寒宫阙。", "小山秋重，千岩夜悄，举尊邀月。", "甚赋得、仙标道骨。", "倩谁捣玄霜，犹未成屑。", "回首蓝桥路迥，梦魂飞越。", "雕阑翠甃金英满，洒西风、非雨非雪。", "惜花心性，输他少年，等闲攀折。"]'),
('song-ci-849','汉宫春','陈允平','宋','宋词','song-ci','汉宫春','[]','开尽荼䕷，正桑云麦浪，天气如秋。',118,'宋词/ci.song.16000.json','["开尽荼䕷，正桑云麦浪，天气如秋。", "南园露梢半坼，金粟丝头。", "温香傍酒，尽多娇、不识春愁。", "莺院悄，轻阴弄晚，何人堪伴清游。", "偏爱紫蕤黄袅，想金壶胜赏，依旧扬州。", "花前夜阑醉后，斜月当楼。", "翻阶句好，记玄晖、此日风流。", "双鬓改，一枝帽底，如今应为花羞。"]'),
('song-ci-850','木兰花慢','陈允平','宋','宋词','song-ci','木兰花慢','[]','爱吟休问瘦，为诗句、几凭阑。',122,'宋词/ci.song.16000.json','["爱吟休问瘦，为诗句、几凭阑。", "有可画亭台，宜春帐箔，如寄身闲。", "胸中四时胜景，小蓬莱、幻出五云间。", "一掬苹香暗沼，半梢松影虚坛。", "相看。", "倦羽久知还。", "回首鹭盟寒。", "记步屧寻云，呼灯听雨，越岭吴峦。", "幽情未应共懒，把周郎旧曲谱新翻。", "帘外垂杨自舞，为君时按弓弯。"]'),
('song-ci-851','宝鼎见・宝鼎现','陈允平','宋','宋词','song-ci','宝鼎见・宝鼎现','[]','六鳌初驾，缥缈蓬阆，移来洲岛。',191,'宋词/ci.song.16000.json','["六鳌初驾，缥缈蓬阆，移来洲岛。", "还又是、梅飘冰泮，一夜青阳回海表。", "渐媚景、傍元宵时候，花底馀寒料峭。", "更喜报、三边晏静，人乐清平宇宙。", "画鼓簇队行春早。", "拥烟花、粉黛缭绕。", "开洞府、桃源路窈。", "戟外东风吹岸柳。", "正翠霭、映星桥月榭，十里红莲绽了。", "庆万家、珠帘半卷，绰约歌裙舞袖。", "重锦绣幄围香，阖凤管鸾丝环奏。", "望非烟非雾，春在壶天易晓。", "早隐隐、半空星斗。", "看取收灯后。", "趁凤书、吹入黄扉，立马金门玉漏。"]'),
('song-ci-852','八宝妆','陈允平','宋','宋词','song-ci','八宝妆','[]','望远秋平。',120,'宋词/ci.song.16000.json','["望远秋平。", "初过雨、微茫水满烟汀。", "乱葓疏柳，犹带数点残萤。", "待月重帘谁共倚，信鸿断续两三声。", "夜如何，顿凉骤觉，纨扇无情。", "还思骖莺素约，念凤箫雁瑟，取次尘生。", "旧日潘郎，双鬓半已星星。", "琴心锦意暗懒，又争奈、西风吹恨醒。", "屏山冷，怕梦魂、飞度蓝桥不成。"]'),
('song-ci-853','昼锦堂','陈允平','宋','宋词','song-ci','昼锦堂','[]','上苑寒收，西塍雨歇，东风是处花柳。',123,'宋词/ci.song.16000.json','["上苑寒收，西塍雨歇，东风是处花柳。", "步锦笼纱，依旧五陵台沼。", "绣帘珠箔金翠袅，琐窗雕槛青红斗。", "频回首。", "茶灶酒垆，春时几番携手。", "知否。", "人渐老。", "嗟眼为花狂，肩为诗瘦。", "唤醒乡心，无奈数声啼鸟。", "秉烛清游嫌夜短，采香新意输年少。", "归来好。", "皈趁故园池阁，绿阴芳草。"]'),
('song-ci-854','绮罗香','陈允平','宋','宋词','song-ci','绮罗香','[]','雁宇苍寒，蛩疏翠冷，又是凄凉时候。',128,'宋词/ci.song.16000.json','["雁宇苍寒，蛩疏翠冷，又是凄凉时候。", "小揭珠帘，夜润唾花罗皱。", "饶晓鹭、独立衰荷，溯归燕、尚栖残柳。", "想黄花，羞涩东篱，断无新句到重九。", "孤檠清梦易觉，肠断唐宫旧曲，声迷官漏。", "滴入愁心，秋似玉楼人瘦。", "烟槛外、催落梧桐，带西风、乱捎鸳甃。", "记画檐，灯影沈沈，共裁春夜韭。"]'),
('song-ci-855','探春・探春慢','陈允平','宋','宋词','song-ci','探春・探春慢','[]','上苑乌啼，中洲鹭起，疏钟才度云窈。',125,'宋词/ci.song.16000.json','["上苑乌啼，中洲鹭起，疏钟才度云窈。", "篆冷香篝，灯微尘幌，残梦犹吟芳草。", "搔首卷帘看，认何处、六桥烟柳。", "翠绕才舣西泠，趁取过湖人少。", "掠水风花缭绕。", "还暗忆年时，旗亭歌酒。", "隐约春声，钿车宝勒，次第凤城开了。", "惟有踏青心，纵早起、不嫌寒峭。", "画阑闲立，东风旧红谁扫。"]'),
('song-ci-856','秋霁','陈允平','宋','宋词','song-ci','秋霁','[]','千顷玻璃，远送目斜阳，渐下林阒。',128,'宋词/ci.song.16000.json','["千顷玻璃，远送目斜阳，渐下林阒。", "题叶人归，采菱舟散，望中水天一色。", "碾空桂魄。", "玉绳低转云无迹。", "有素鸥，闲伴夜深，呼棹过环碧。", "相思万里，顿隔婵媛，几回琼台，同驻鸾翼。", "对西风、恁谁问取，人间那得有今夕。", "应笑广寒宫殿窄。", "露冷烟淡，还看数点残星，两行新雁，倚楼横笛。"]'),
('song-ci-857','百字令・念奴娇','陈允平','宋','宋词','song-ci','百字令・念奴娇','[]','凝云冱晓，正シ花才积，荻絮初残。',120,'宋词/ci.song.16000.json','["凝云冱晓，正シ花才积，荻絮初残。", "华表翩跹何处鹤，爱吟人在孤山。", "冻解苔铺，冰融沙甃，谁凭玉勾阑。", "茸衫毡帽，冷香吹上吟鞍。", "将次柳际琼销，梅边粉瘦，添做十分寒。", "闲踏轻澌来荐菊，半潭新涨微澜。", "水北峰峦，城阴楼观，留向月中看。", "巘云深处，好风飞下晴湍。"]'),
('song-ci-858','扫花游・扫地游','陈允平','宋','宋词','song-ci','扫花游・扫地游','[]','数峰蘸碧，记载酒甘园，柳塘花坞。',117,'宋词/ci.song.16000.json','["数峰蘸碧，记载酒甘园，柳塘花坞。", "最堪避暑。", "爱莲香送晚，翠娇红妩。", "欸乃菱歌乍起，兰桡竞举。", "日斜处。", "望孤鹜断霞，初下芳杜。", "遥想山寺古。", "看倒影金轮，溯光朱户。", "瞑烟带树。", "有投林鹭宿，凭楼僧语。", "可惜流年，付与朝钟暮鼓。", "漫凝伫。", "步长桥、月明归去。"]'),
('song-ci-859','八声甘州','陈允平','宋','宋词','song-ci','八声甘州','["\u897f\u6e56"]','放船杨柳下，听鸣蝉、薰风小新堤。',117,'宋词/ci.song.16000.json','["放船杨柳下，听鸣蝉、薰风小新堤。", "正烟葓露蓼，飞尘酿玉，第五桥西。", "遥认青罗盖底，宫女夜游池。", "谁在鸳鸯浦，独棹玻璃。", "一片天机云锦，见凌波碧翠，照日胭脂。", "是西湖西子，晴抹雨妆时。", "便相将无情秋思，向菰蒲深处落红衣。", "醺醺里，半篙香梦，月转星移。"]'),
('song-ci-860','蓦山溪','陈允平','宋','宋词','song-ci','蓦山溪','[]','春波浮渌，小隐桃溪路。',102,'宋词/ci.song.16000.json','["春波浮渌，小隐桃溪路。", "烟雨正林塘，翠不碍、锦鳞来去。", "芹香藻腻，偏爱鲤花肥，檐影下，柳阴中，逐浪吹萍絮。", "宫沟泉滑，怕有题红句。", "钩饵已忘机，都付与、人间儿女。", "濠梁兴在，鸥鹭笑人痴。", "三湘梦，五湖心，云水苍茫处。"]'),
('song-ci-861','齐天乐','陈允平','宋','宋词','song-ci','齐天乐','[]','赤阑桥畔斜阳外，临江暮山凝紫。',123,'宋词/ci.song.16000.json','["赤阑桥畔斜阳外，临江暮山凝紫。", "戏鼓才停，渔榔乍歇，一片芙蓉秋水。", "馀霞散绮。", "正银钥停关，画船催舣。", "鱼板敲残，数声初入万松里。", "坡翁诗梦未老，翠微楼上月，曾共谁倚。", "御苑烟花，宫斜露草，几度西风弹指。", "黄昏尽也，有眠月闲僧，醉香游子。", "鹫岭啼猿，唤人吟思起。"]'),
('song-ci-862','黄莺儿','陈允平','宋','宋词','song-ci','黄莺儿','[]','六波烟黛浮空远，南陌嘤嘤，乔木初迁，纱窗无眠，画阑凭晓。',116,'宋词/ci.song.16000.json','["六波烟黛浮空远，南陌嘤嘤，乔木初迁，纱窗无眠，画阑凭晓。", "看并宿暗黄深，织雾金梭小。", "那人携酒听时，料把春来，诗梦惊觉。", "飞绕。", "翠接断桥云，绿漾新堤草。", "数声娇啭，婉娩如愁，调簧弄歌尖巧。", "随燕啅软尘低，蝶妥游丝袅。", "最怜舞絮飞花，唤却东风老。"]'),
('song-ci-863','渡江云','陈允平','宋','宋词','song-ci','渡江云','["\u897f\u6e56"]','三神山路杳，六鳌驾浪，幻境□西湖。',123,'宋词/ci.song.16000.json','["三神山路杳，六鳌驾浪，幻境□西湖。", "水连天四远，翠台如鼎，簇簇小浮图。", "烟沈雾迥，怪蜃楼、飞入清虚。", "秋夜长，一轮蟾素，渐渐出云衢。", "遥看寒光金镜，皓彩明珰，正人间三五。", "总输与、鸥眠葑蓼，鹭立菰蒲。", "笙歌唤醒鱼龙睡，向贝阙、争取明珠。", "清梦断，西风醉宿冰壶。"]'),
('song-ci-864','婆罗门引','陈允平','宋','宋词','song-ci','婆罗门引','[]','髻鬟对耸，万松扶玉上青冥。',93,'宋词/ci.song.16000.json','["髻鬟对耸，万松扶玉上青冥。", "西风共倚，烟南水北，石荒苔老，三十六梯平。", "爱翠尖如削，天外亭亭。", "高寒梦惊。", "是何夕堕双星。", "无限苍崖紫岫，谁拊棱层。", "薜萝深处，算少年、游屐几番登。", "河汉近、疑在蓬瀛。"]'),
('song-ci-865','明月引・江城梅花引','陈允平','宋','宋词','song-ci','明月引・江城梅花引','[]','雨馀芳草碧萧萧。',108,'宋词/ci.song.16000.json','["雨馀芳草碧萧萧。", "暗春潮。", "荡双桡。", "紫凤青鸾，旧梦带文箫。", "绰约佩环风不定，云欲堕，六铢香，天外飘。", "相思为谁兰恨销。", "渺湘魂、无处招。", "素纨犹在，真真意、还倩谁描。", "舞镜空圆，羞对月明宵。", "镜里心心心里月，君去矣，旧东风，新画桥。"]'),
('song-ci-866','糖多令・唐多令','陈允平','宋','宋词','song-ci','糖多令・唐多令','[]','何处是秋风。',74,'宋词/ci.song.16000.json','["何处是秋风。", "月明霜露中。", "算凄凉、未到梧桐。", "曾向垂虹桥上看，有几树、水边枫。", "客路怕相逢。", "酒浓愁更浓。", "数归期、犹是秋冬。", "欲寄相思无好句，聊折赠、雁来红。"]'),
('song-ci-867','江城子','陈允平','宋','宋词','song-ci','江城子','[]','东风吹恨上眉弯。',86,'宋词/ci.song.16000.json','["东风吹恨上眉弯。", "燕初还。", "杏花残。", "帘里春深，帘外雨声寒。", "拾翠芳期孤负却，空脉脉，倚阑干。", "流苏香重玉连环。", "绕屏山。", "宝筝闲。", "泪薄鲛绡，零露湿红兰。", "瘦却舞腰浑可事，银蹀躞，半阑珊。"]'),
('song-ci-868','思佳客','陈允平','宋','宋词','song-ci','思佳客','[]','一曲清歌酒一锺。',64,'宋词/ci.song.16000.json','["一曲清歌酒一锺。", "舞裙摇曳石榴红。", "宝筝弦矗冰蚕缕，珠箔香飘水麝风。", "娇娅姹，笑迎逢。", "合欢罗带两心同。", "彩云不觉归来晚，月转觚棱夜气中。"]'),
('song-ci-869','思佳客','陈允平','宋','宋词','song-ci','思佳客','[]','压鬓钗横翠凤头。',64,'宋词/ci.song.16000.json','["压鬓钗横翠凤头。", "玉柔春腻粉香流。", "红酣醉靥花含笑，碧翦颦眉柳弄愁。", "偏婀娜，太温柔。", "水情云意两绸缪。", "佯羞不顾双飞蝶，独背秋千傍画楼。"]'),
('song-ci-870','思佳客','陈允平','宋','宋词','song-ci','思佳客','[]','锦幄沉沉宝篆残。',64,'宋词/ci.song.16000.json','["锦幄沉沉宝篆残。", "惜春无语凭阑干。", "庭前芳草空惆怅，帘外飞花自往还。", "金屋静，玉箫闲。", "一尊芳酒驻红颜。", "东风落尽荼䕷雪，满院清香夜不寒。"]'),
('song-ci-871','思佳客','陈允平','宋','宋词','song-ci','思佳客','[]','玉辔青骢去不归。',64,'宋词/ci.song.16000.json','["玉辔青骢去不归。", "锦中频织断肠诗。", "窗凭绣日莺声婉，帘卷香云雁影回。", "金缕扇，碧罗衣。", "蝶魂飞度画阑西。", "花开花落春多少，独有层楼双燕知。"]'),
('song-ci-872','思佳客','陈允平','宋','宋词','song-ci','思佳客','[]','曾约双琼品凤箫。',64,'宋词/ci.song.16000.json','["曾约双琼品凤箫。", "玉台光映玉娇娆。", "银花烛冷飞罗暗，宝悄香融曲篆销。", "帘影乱，漏声迢。", "佩云清入楚天遥。", "题红未托相思约，明月空归第五桥。"]'),
('song-ci-873','惜分飞','陈允平','宋','宋词','song-ci','惜分飞','[]','钏阁桃腮香玉溜。',58,'宋词/ci.song.16000.json','["钏阁桃腮香玉溜。", "困倚银床倦绣。", "双燕归来后。", "相思叶底寻红豆。", "碧唾春衫还在否。", "重理弓弯舞袖。", "锦藉芙蓉皱。", "翠腰羞对垂杨瘦。"]'),
('song-ci-874','长相思','陈允平','宋','宋词','song-ci','长相思','[]','风萧萧。',44,'宋词/ci.song.16000.json','["风萧萧。", "雨骚骚。", "风雨萧骚梧叶飘。", "潇湘江畔楼。", "云迢迢。", "水遥遥。", "云水迢遥天尽头。", "相思心上秋。"]'),
('song-ci-875','祝英台近','陈允平','宋','宋词','song-ci','祝英台近','[]','待春来，春又到，花底自徘徊。',95,'宋词/ci.song.16000.json','["待春来，春又到，花底自徘徊。", "春浅花迟，携酒为春催。", "可堪碧小红微，黄轻紫艳，东风外、妆点池台。", "且衔杯。", "无奈年少心情，看花能几回。", "春自年年，花自为春开。", "是他春为花愁，花因春瘦，花残后、人未归来。"]'),
('song-ci-876','恋绣衾','陈允平','宋','宋词','song-ci','恋绣衾','[]','缃桃红浅柳褪黄。',68,'宋词/ci.song.16000.json','["缃桃红浅柳褪黄。", "燕初来、宫漏渐长。", "任日转、花梢也，倚兰屏、犹未试妆。", "秦鸾旧曲无心理，忆年时、相傍采桑。", "听绿树、娇莺啭，一声声、都是断肠。"]'),
('song-ci-877','南歌子','陈允平','宋','宋词','song-ci','南歌子','[]','素质盈盈瘦，娇姿淡淡妆。',62,'宋词/ci.song.16000.json','["素质盈盈瘦，娇姿淡淡妆。", "曲勾兰畔倚秋娘。", "一撮风流都在、晚西凉。", "彩线串层玉，金篝络细香。", "半钩新月浸牙床。", "犹记东华年少、那门相。"]'),
('song-ci-878','恋绣衾','陈允平','宋','宋词','song-ci','恋绣衾','[]','银鸳金凤画暗销。',68,'宋词/ci.song.16000.json','["银鸳金凤画暗销。", "晓帘栊、新翠渐交。", "算多少、相思恨，被东风，吹上柳梢。", "罗窗夜夜梨花瘦，奈月明、香梦易消。", "便拟倩、题红叶，趁落花、流过谢桥。"]'),
('song-ci-879','谒金门','陈允平','宋','宋词','song-ci','谒金门','[]','春欲去。',53,'宋词/ci.song.16000.json','["春欲去。", "无计得留春住。", "纵著天涯浑柳絮。", "春归还有路。", "恨煞多情杜宇。", "愁煞无情风雨。", "春自悠悠人自苦。", "莺花谁是主。"]'),
('song-ci-880','菩萨蛮','陈允平','宋','宋词','song-ci','菩萨蛮','[]','杏花枝上莺声嫩。',52,'宋词/ci.song.16000.json','["杏花枝上莺声嫩。", "凤屏倦倚人初困。", "金兽莫添香。", "香浓情转伤。", "云沉归雁杳。", "绿涨江南草。", "独倚夕阳楼。", "双帆何处舟。"]'),
('song-ci-881','青玉案','陈允平','宋','宋词','song-ci','青玉案','[]','凉亭背倚斜阳树。',80,'宋词/ci.song.16000.json','["凉亭背倚斜阳树。", "过几阵、菰蒲雨。", "自棹轻舟穿柳去。", "绿裙红袂，与花相似，撑入花深处。", "妾家住在鸳鸯浦。", "妾貌如花被花妒。", "折得花归娇厮觑。", "花心多怨，妾心多恨，胜似莲心苦。"]'),
('song-ci-882','恋绣衾','陈允平','宋','宋词','song-ci','恋绣衾','[]','多情无语敛黛眉。',68,'宋词/ci.song.16000.json','["多情无语敛黛眉。", "寄相思、偏仗柳枝。", "待折向、尊前唱，奈东风、吹做絮飞。", "归来醉抱瑟琶睡，正酒醒、香尽漏移。", "无赖是、梨花梦，被月明、偏照帐儿。"]'),
('song-ci-883','南歌子','陈允平','宋','宋词','song-ci','南歌子','[]','懒傍青鸾镜，慵簪翠凤翘。',62,'宋词/ci.song.16000.json','["懒傍青鸾镜，慵簪翠凤翘。", "玉屏春重宝香销。", "因甚不忺梳洗、怕登楼。", "载酒垂杨浦，停桡杜若洲。", "伤春情绪寄箜篌。", "流水残阳芳草、伴人愁。"]'),
('song-ci-884','醉桃源・阮郎归','陈允平','宋','宋词','song-ci','醉桃源・阮郎归','[]','东风开到坼桐花。',56,'宋词/ci.song.16000.json','["东风开到坼桐花。", "游蜂初报衙。", "兽环微掩是谁家。", "琐窗金绣纱。", "环佩小，领巾斜。", "绿云双髻鸦。", "佯羞无限托琵琶。", "笑拈萱草芽。"]'),
('song-ci-885','清平乐','陈允平','宋','宋词','song-ci','清平乐','[]','凤城春浅。',54,'宋词/ci.song.16000.json','["凤城春浅。", "寒压花梢颤。", "有约不来梁上燕。", "十二绣帘空卷。", "去年共倚秋千。", "今年独倚阑干。", "误了海棠时候，不成直待花残。"]'),
('song-ci-886','谒金门','陈允平','宋','宋词','song-ci','谒金门','[]','春又晚。',53,'宋词/ci.song.16000.json','["春又晚。", "枝上绿深红浅。", "燕语呢喃明似翦。", "采香人渐远。", "草色池塘碧软。", "丝竹谁家坊院。", "拂拂和风初著扇。", "蜂情愁不展。"]'),
('song-ci-887','浣溪沙','陈允平','宋','宋词','song-ci','浣溪沙','[]','杨柳烟深五凤楼。',47,'宋词/ci.song.16000.json','["杨柳烟深五凤楼。", "绣帘风扬玉梭球。", "夜寒谁伴锦香篝。", "残月情圆晓梦，落花无语诉春愁。", "宝笙偷按小梁州。"]'),
('song-ci-888','鹧鸪天','陈允平','宋','宋词','song-ci','鹧鸪天','[]','谁向瑶台品凤箫。',64,'宋词/ci.song.16000.json','["谁向瑶台品凤箫。", "碧虚浮动桂花秋。", "风从帘幕吹香远，人在阑干待月高。", "金粟地，蕊珠楼。", "佩云襟雾玉逍遥。", "仙娥已有玄霜约，便好骑鲸上九霄。"]'),
('song-ci-889','谒金门','陈允平','宋','宋词','song-ci','谒金门','[]','风不定。',53,'宋词/ci.song.16000.json','["风不定。", "吹漾一帘波影。", "归燕无期春正永。", "海棠眠未醒。", "筝雁别来谁整。", "好梦不堪重省。", "闲看鸳鸯交素颈。", "凭阑襟袖冷。"]'),
('song-ci-890','朝中措','陈允平','宋','宋词','song-ci','朝中措','[]','欲晴又雨雨还晴。',57,'宋词/ci.song.16000.json','["欲晴又雨雨还晴。", "时节又清明。", "红杏墙头燕语，碧桃枝上莺声。", "轻衫短帽，扁舟小棹，几度旗亭。", "斗草踏青天气，买花载酒心情。"]'),
('song-ci-891','小重山','陈允平','宋','宋词','song-ci','小重山','[]','岸柳黄深绿渐饶。',70,'宋词/ci.song.16000.json','["岸柳黄深绿渐饶。", "林塘初雨过，涨蒲萄。", "秋千亭榭彩旗交。", "莺声里，春在杏花梢。", "慵整翠云翘。", "眉尖愁两点，倩谁描。", "斜阳芳草暗魂销。", "东风远，犹凭赤阑桥。"]'),
('song-ci-892','霜天晓角','陈允平','宋','宋词','song-ci','霜天晓角','[]','玄霜绛雪。',54,'宋词/ci.song.16000.json','["玄霜绛雪。", "散作秋林缬。", "昨夜西风吹过，最好是、睡时节。", "香绝。", "高处折。", "中秋还有月。", "此际人间天上，是两个、广寒阙。"]'),
('song-ci-893','糖多令・唐多令','陈允平','宋','宋词','song-ci','糖多令・唐多令','[]','明月可中庭。',74,'宋词/ci.song.16000.json','["明月可中庭。", "萧萧络纬声。", "画阑秋、千树吹香。", "玉宇无尘凉似水，销不尽、许多清。", "欲醉醉还醒。", "欲吟吟未成。", "拈金英、三嗅微馨。", "应有乘鸾天上女，随风露、下青冥。"]'),
('song-ci-894','柳梢青','陈允平','宋','宋词','song-ci','柳梢青','[]','藓迹苔痕。',61,'宋词/ci.song.16000.json','["藓迹苔痕。", "香浮砚席，影蘸吟尊。", "雪正商量，同云淡淡，微月昏昏。", "孤山往事谁论。", "但招得、逋仙断魂。", "客里相逢，数枝驿路，千树江村。"]'),
('song-ci-895','柳梢青','陈允平','宋','宋词','song-ci','柳梢青','[]','沁月凝霜。',61,'宋词/ci.song.16000.json','["沁月凝霜。", "精神好处，曾悟花光。", "带雪煎茶，和冰酿酒，聊润枯肠。", "看花小立疏廊。", "道是雪、如何恁香。", "几度巡檐，一枝清瘦，疑在蓬窗。"]'),
('song-ci-896','柳梢青','陈允平','宋','宋词','song-ci','柳梢青','[]','菊谢东篱。',61,'宋词/ci.song.16000.json','["菊谢东篱。", "问梅开未，先问南枝。", "两蕊三花，松边傍石，竹外临溪。", "尊前暗忆年时。", "算笛里、关情是伊。", "何逊风流，林逋标致，一二联诗。"]'),
('song-ci-897','柳梢青','陈允平','宋','宋词','song-ci','柳梢青','[]','片片花飞。',61,'宋词/ci.song.16000.json','["片片花飞。", "风前疏树，雪后残枝。", "剗地多情，带将明月，来伴书帏。", "岁寒心事谁知。", "向篱落、微斜半敧。", "添得闲愁，酒将阑处，吟未成时。"]'),
('song-ci-898','思佳客','陈允平','宋','宋词','song-ci','思佳客','[]','簇簇红云冷欲凝。',64,'宋词/ci.song.16000.json','["簇簇红云冷欲凝。", "东风特地唤花醒。", "数枝夜色当银烛，一段春娇入画屏。", "如有恨，似多情。", "柳边莺语十分明。", "柳边莺语如何说，莫笑梅花太瘦生。"]'),
('song-ci-899','糖多令・唐多令','陈允平','宋','宋词','song-ci','糖多令・唐多令','[]','休去采芙蓉。',73,'宋词/ci.song.16000.json','["休去采芙蓉。", "秋江烟水空。", "带斜阳、一片征鸿。", "欲顿闲愁无顿处，都著在两眉峰。", "心事寄题红。", "画桥流水东。", "断肠人、无奈秋浓。", "回首层楼归去懒，早新月、挂梧桐。"]'),
('song-ci-900','瑞龙吟','陈允平','宋','宋词','song-ci','瑞龙吟','[]','双溪墅。',163,'宋词/ci.song.16000.json','["双溪墅。", "重见种玉锄云，采花研露。", "遥知绿野芳浓，锦堂燕子，迎门共舞。", "近前语。", "还问去年山馆，旧经行处。", "西风鸿水边上，惊千里苑，梅英乍吐。", "几度月昏霜晓，望驰天北，驿传湘渚。", "冷艳暗香春寒，剗地清苦。", "看看翠幄，青子江头路。", "才收尽、蛮烟瘴雨，初回轻暑。", "便忆南园趣。", "唤人况有，多情杜宇。", "此计非迟暮。", "都付与、和羹功成归去。", "海榴院落，长逢重午。"]'),
('song-ci-901','渡江云','陈允平','宋','宋词','song-ci','渡江云','[]','桐花寒食近，青门紫陌，不禁绿杨烟。',124,'宋词/ci.song.16000.json','["桐花寒食近，青门紫陌，不禁绿杨烟。", "正长眉仙客，来向人间，听鹤语溪泉。", "清和天气，为栽培、种玉心田。", "莺昼长，一尊芳酒，容与看芝山。", "庭闲。", "东风榆荚，夜雨苔痕，满地欲流钱。", "爱墙阴、成蹊桃李，春自无言。", "殷勤晓鹊凭檐喜，丹凤下、红药阶前。", "兰砌晓，香飘舞袖斓斒。"]'),
('song-ci-902','八声甘州','陈允平','宋','宋词','song-ci','八声甘州','["\u897f\u6e56"]','两台帘对卷，燕芹香、风花近清明。',119,'宋词/ci.song.16000.json','["两台帘对卷，燕芹香、风花近清明。", "望春弥柳际，流红水布，暖縠天晴。", "谁信闲襟似水，时忆语溪耕。", "襟抱番江阔，云远波平。", "静昼轻挥玉尘，见春扉草绿，暮冶烟青。", "问清华姓字，几度录虬屏。", "看西湖、一汀鸳鹭，正晓风、残月两三星。", "早归来，赴花鱼宴，宫树闻莺。"]'),
('song-ci-903','三犯渡江云・渡江云','陈允平','宋','宋词','song-ci','三犯渡江云・渡江云','[]','风流三径远，此君淡薄，谁与伴清足。',124,'宋词/ci.song.16000.json','["风流三径远，此君淡薄，谁与伴清足。", "岁寒人自得，傍石锄云，闲里种苍玉。", "琅玕翠立，爱细雨、疏烟初沐。", "春昼长，秋声不断，洗红尘凡俗。", "高独。", "虚心共许，淡节相期，几人闲棋局。", "堪爱处，月明琴院，雪晴书屋。", "心盟更许青松结，笑四时、梅矾兰菊。", "庭砌晓，东风旋添新绿。"]'),
('song-ci-904','过秦楼','陈允平','宋','宋词','song-ci','过秦楼','[]','谷雨收寒，茶烟扬晓，又是牡丹时候。',136,'宋词/ci.song.16000.json','["谷雨收寒，茶烟扬晓，又是牡丹时候。", "浮龟碧水，听鹤丹山，彩屋幔亭依旧。", "和气缥缈人间，满谷红云，德星呈秀。", "向东风种就，一亭兰茁，玉香初茂。", "遥想曲度娇莺，舞低轻燕，二十四帘芳昼。", "清溪九曲，上已风光，觞咏似山阴否。", "翠阁凝清，正宜瀹茗银罂，熨香金斗。", "看双鸾飞下，长生殿里，赐蔷薇酒。"]'),
('song-ci-905','醉蓬莱','陈允平','宋','宋词','song-ci','醉蓬莱','[]','正槐龙欲老，影动朱门，薰风帘卷。',120,'宋词/ci.song.16000.json','["正槐龙欲老，影动朱门，薰风帘卷。", "竹外人清，听秋声将转。", "梦草池塘，种兰庭砌，爽气生葵扇。", "香染黄扉，律调翠简，赏音清宴。", "因念南阳，碧幢烟静，纶玉宣频，辔丝催遣。", "带锡犀虹，宠下甘泉殿。", "笑指蓬莱，画舸东去，向五云葱茜。", "骑竹欢迎，贺家湖上，绿香红茜。"]'),
('song-ci-906','法曲献仙音','陈允平','宋','宋词','song-ci','法曲献仙音','["\u897f\u6e56"]','风箨晴暄，昼桐阴早，燕阁新香时度。',113,'宋词/ci.song.16000.json','["风箨晴暄，昼桐阴早，燕阁新香时度。", "沁月楼台，带山城郭，西湖翠娇红妩。", "甚爱此闲中趣，寻盟旧鸥鹭。", "共容与。", "倚阑干、静看飞絮。", "吟啸里，帘卷暖烟霁雨。", "向一碧波璃，几东风、呼棹来去。", "秀玉芳兰，伴丝簧、庭院笑语。", "渐梅霖清润，喜近槐扉初暑。"]'),
('song-ci-907','八声甘州','陈允平','宋','宋词','song-ci','八声甘州','["\u94b1\u5858\u6c5f"]','帘垂鸱尾阁，桂花风、天香满黄扉。',119,'宋词/ci.song.16000.json','["帘垂鸱尾阁，桂花风、天香满黄扉。", "向郁罗霄汉，朝回金阙，心运璇玑。", "一点元台初度，八表共清辉。", "紫塞烟尘静，捷羽东飞。", "此际钱塘江上，爱月仍夜色，潮正秋期。", "想波仙冰妹，同日宴瑶池。", "报龙楼、玉音宣劝，赐紫金、杯泛日中葵。", "庆千秋，醉长生酒，歌太平诗。"]'),
('song-ci-908','兰陵王','陈允平','宋','宋词','song-ci','兰陵王','[]','楚天碧。',158,'宋词/ci.song.16000.json','["楚天碧。", "秋晚尘清禁陌。", "朝鸡静，班退晓墀，回马金门漏犹滴。", "千官佩如织。", "来作黄扉寿客。", "黑头相，玉虹紫貂，亲奉春慈拜南极。", "丛萱燕堂北。", "正霭护犀帷，香泛鲛额。", "瑶池女伴驻鸾翼。", "拥歌袖笼翠，舞鞯铺锦，屏开家庆怎画得。", "想人在仙宅。", "今夕。", "是何夕。", "正月满槐厅，凉透杶席。", "黄花满地弄寒色。", "喜蛩雨初霁，雁风又息。", "龙楼宣劝，万岁里、宴太液。"]'),
('song-ci-909','木兰花慢','陈允平','宋','宋词','song-ci','木兰花慢','[]','江南春信早，问谁是、百花魁。',123,'宋词/ci.song.16000.json','["江南春信早，问谁是、百花魁。", "过揽桂褰蓉，纫兰采菊，独许寒梅。", "阳和渐回涧底，向水西、先放一枝开。", "潇洒纤琼瘦玉，化工月翦云裁。", "诗催。", "付与雪襟怀。", "消得暗香来。", "算知心惟有，青松瘦竹，白石苍苔。", "年年上林胜赏，拈清芳、蘸入紫金杯。", "须信和羹未晚，岁寒聊自徘徊。"]'),
('song-ci-910','摸鱼儿','陈允平','宋','宋词','song-ci','摸鱼儿','[]','过重阳、晚香犹耐，江城风露初峭。',140,'宋词/ci.song.16000.json','["过重阳、晚香犹耐，江城风露初峭。", "梅花已索巡檐笑，春入数枝红小。", "寒恁早。", "正帘卷苍云，和气生芝草。", "金虬篆袅。", "喜人乐丰年，波澄瀚海，星斗焕牙纛。", "家山近，游宴十洲三岛。", "石桥诗思频绕。", "朱颜白发神仙样，谁信玉关人老。", "春渐好。", "望阊阖天低，咫尺瞻黄道。", "祥云缥缈。", "看柳色沙堤，莺声禁辇，鸣佩凤池晓。"]'),
('song-ci-911','汉宫春','陈允平','宋','宋词','song-ci','汉宫春','[]','帘卷苍云，爱初翔凤尾，忽驾虬枝。',118,'宋词/ci.song.16000.json','["帘卷苍云，爱初翔凤尾，忽驾虬枝。", "青青岁寒自保，越样清奇。", "参天溜雨，带疏苔、密藓芳蕤。", "天赋与，凌霜傲雪，臞然山泽风姿。", "他年楝梁共许，记雪山巫峡，曾赋新诗。", "庭前可人翠幄，葱蒨烟霏。", "高标劲节，有青松、绿竹心知。", "来试倚，摩挲黛色，一尊相祝齐眉。"]'),
('song-ci-912','汉宫春','陈允平','宋','宋词','song-ci','汉宫春','[]','春满芝田，正鹤飞空霭，龟引清涟。',118,'宋词/ci.song.16000.json','["春满芝田，正鹤飞空霭，龟引清涟。", "祥云满谷缥缈，非雾非烟。", "莺花燕柳，占年年、三月长安。", "天气好，新声暖响，东风十二雕阑。", "葱蒨兽炉香袅，映金貂玉佩，绿鬓朱颜。", "何妨买花载酒，日日湖边。", "烟光万顷，恁清闲、才是神仙。", "芳昼永，珠帘静卷，悠然相对南山。"]'),
('song-ci-913','风入松','陈允平','宋','宋词','song-ci','风入松','["\u897f\u6e56"]','西清人住水云乡。',90,'宋词/ci.song.16000.json','["西清人住水云乡。", "心静日偏长。", "闲中自乐壶天趣，笑红尘、谁是羲皇。", "叠嶂双溪争似，西湖雨色晴光。", "碧龟巢处藕花香。", "波影浸书床。", "庭前一种红兰树，薰风又、吹长瑶芳。", "竹外椿前舞彩，柳边槐底鸣珰。"]'),
('song-ci-914','西湖明月引・江城梅花引','陈允平','宋','宋词','song-ci','西湖明月引・江城梅花引','[]','朝回花底晓星明。',108,'宋词/ci.song.16000.json','["朝回花底晓星明。", "瑞烟凝。", "暖风轻。", "修禊湔裙，时节又闻莺。", "绰约岸桃堤柳近，波万顷，碧琉璃，镜样平。", "仙翁佩襟秋水清。", "渺莲舟，浮翠瀛。", "御楼香近，东风里、吹下青冥。", "鲛撷围红，春在牡丹屏。", "日正迟迟人正酒，画帘外，一声声，卖放生。"]'),
('song-ci-915','临江仙','陈允平','宋','宋词','song-ci','临江仙','[]','门外湖光清似玉，雨桐烟柳扶疏。',70,'宋词/ci.song.16000.json','["门外湖光清似玉，雨桐烟柳扶疏。", "爱闲吾亦爱吾庐。", "炉香心在在，杯酒乐如如。", "有子专城才四十，诸孙颗颗明珠。", "传家衣钵只诗书。", "一坡存菊意，千岁学松臞。"]'),
('song-ci-916','少年游','陈允平','宋','宋词','song-ci','少年游','[]','光风怀抱玉精神。',60,'宋词/ci.song.16000.json','["光风怀抱玉精神。", "不染世间尘。", "香暖衣篝，歌题彩扇，清似晋时人。", "柳边小驻朝天马，一笑领佳宾。", "帘卷湖山，花围尊俎，同醉碧桃春。"]'),
('song-ci-917','鹧鸪天','陈允平','宋','宋词','song-ci','鹧鸪天','[]','四壁图书静不哗。',64,'宋词/ci.song.16000.json','["四壁图书静不哗。", "里湖深处隐人家。", "斑衣自斗百家彩，乌帽亲裁一幅纱。", "新酿酒，旋烹茶。", "半溪霜月正梅花。", "前庭手种红兰树，看到春风第二芽。"]'),
('song-ci-918','霜天晓角','陈允平','宋','宋词','song-ci','霜天晓角','[]','月树风枝。',53,'宋词/ci.song.16000.json','["月树风枝。", "孤山两字诗。", "来到十洲三岛，香得更、十分奇。", "阳和迟自迟。", "冰霜欺怎欺。", "且伴岁寒人醉，有移种、玉堂时。"]'),
('song-ci-919','瑞鹤仙','陈允平','宋','宋词','song-ci','瑞鹤仙','[]','燕归帘半卷。',127,'宋词/ci.song.16000.json','["燕归帘半卷。", "正漏约琼签，笙调玉琯。", "蛾眉画来浅。", "甚春衫懒试，夜灯慵翦。", "香温梦暖。", "诉芳心、芭蕉未展。", "渺双波、望极江空，二十四桥凭遍。", "葱茜。", "银屏彩凤，雾帐金蝉，旧家坊院。", "烟花弄晚。", "芳草恨，断魂远。", "对东风无语，绿阴深处，时见飞红数片。", "算多情、尚有黄鹂，向人睍睆。"]'),
('song-ci-920','垂杨','陈允平','宋','宋词','song-ci','垂杨','[]','银屏梦觉。',122,'宋词/ci.song.16000.json','["银屏梦觉。", "渐浅黄嫩绿，一声莺小。", "细雨轻尘，建章初闭东风悄。", "依然千树长安道。", "翠云锁、玉窗深窈。", "断桥人、空倚斜阳，带旧愁多少。", "还是清明过了。", "任烟缕露条，碧纤青袅。", "恨隔天涯，几回惆怅苏堤晓。", "飞花满地谁为扫。", "甚薄幸、随波缥缈。", "纵啼鹃、不唤春归，人自老。"]'),
('song-ci-921','瑞龙吟','陈允平','宋','宋词','song-ci','瑞龙吟','[]','长安路。',163,'宋词/ci.song.16000.json','["长安路。", "还是燕乳莺娇，度帘迁树。", "层楼十二阑干，绣帘半卷，相思处处。", "漫凭伫。", "因念彩云初到，琐窗琼户。", "梨花犹却春寒，翠羞粉怨，尊前解语。", "空有章台烟柳，瘦纤仍似，宫腰飞舞。", "憔悴暗觉文园，双鬓非故。", "闲拈断叶，重托殷勤句。", "频回首、河桥素约，津亭归步。", "恨逐芳尘去。", "眩醉眼尽，游丝乱绪。", "肠结愁千缕。", "深院静，东风落红如雨。", "画屏梦绕，一篝香絮。"]'),
('song-ci-922','风流子','陈允平','宋','宋词','song-ci','风流子','[]','阑干休去倚，长亭外、烟草带愁归。',135,'宋词/ci.song.16000.json','["阑干休去倚，长亭外、烟草带愁归。", "正晓阴帘幕，绮罗清润，西风环佩，金玉参差。", "深院悄，乱蝉嘶夏木，双燕别春泥。", "满地残花，蝶圆凉梦，半亭落叶，蛩感秋悲。", "兰屏馀香在，销魂处、憔悴瘦不胜衣。", "谁念凤楼当日，星约云期。", "怅倦理鸾筝，朱弦空暗，强临鸳镜，锦带闲垂。", "别后两峰眉恨，千里心知。"]'),
('song-ci-923','风流子','陈允平','宋','宋词','song-ci','风流子','[]','残梦绕林塘。',133,'宋词/ci.song.16000.json','["残梦绕林塘。", "诗添瘦、瘦不似东阳。", "正流水荡红，暗通幽径，嫩篁翻翠，斜映回墙。", "对握宝筝低度曲，销蜡靓新簧。", "莺懒昼长，燕闲人倦，乍亲花簟，慵引壶觞。", "帘栊深深地，歌尘静、芳草自碧空厢。", "十二画桥，一堤烟树成行。", "向杜鹃声里，绿杨庭院，共寻红豆，同结丁香。", "春已无多，祗愁风雨相妨。"]'),
('song-ci-924','华胥引','陈允平','宋','宋词','song-ci','华胥引','[]','涵空斜照，掠水轻岚，满天红叶。',104,'宋词/ci.song.16000.json','["涵空斜照，掠水轻岚，满天红叶。", "雁泊平芜，凫依乱荻声唼唼。", "寂寞金井梧桐，渐辘轳伊轧。", "明月纱窗，夜寒孤枕应怯。", "吟老西风，笑衰髯、顿疏如镊。", "锦笺勤重，频剔兰灯自阅。", "多谢征衫初寄，尚宝香熏箧。", "愁忆家山，梦魂飞度千叠。"]'),
('song-ci-925','意难忘','陈允平','宋','宋词','song-ci','意难忘','[]','额粉宫黄。',114,'宋词/ci.song.16000.json','["额粉宫黄。", "衬桃花扇底，歌送瑶觞。", "裙拖金缕细，衫唾碧花香。", "琼佩冷，玉肌凉。", "罗袜步沧浪。", "漫共伊，心盟意约，眼觑眉相。", "连环未结双双。", "似桃源误入，初嫁刘郎。", "珑璁仙子髻，绰约道家妆。", "千种恨、九回肠。", "云雨梦犹妨。", "误少年，红销翠减，虚度风光。"]'),
('song-ci-926','宴清都','陈允平','宋','宋词','song-ci','宴清都','[]','听彻南楼鼓。',126,'宋词/ci.song.16000.json','["听彻南楼鼓。", "寒宵迥、玉壶冰漏迟度。", "重温锦幄，低护青毡，曲通朱户。", "巡檐细嚼寒梅，叹寂寞、孤山伴侣。", "更信有、铁石心肠，广平几度曾赋。", "寒深试拥羊裘，松醪自酌，谁伴吟苦。", "摩挲醉眼，阑干笑拍，白鸥惊去。", "梁园胜赏重约，渐玉树、琼花处处。", "怕柳条、未觉春风，青青在否。"]'),
('song-ci-927','兰陵王','陈允平','宋','宋词','song-ci','兰陵王','[]','古堤直。',158,'宋词/ci.song.16000.json','["古堤直。", "隔水轻阴扬碧。", "东风路，还是舞烟眠露，年年自春色。", "红尘遍京国。", "留滞高阳醉客。", "斜阳外，千缕翠条，彷佛流莺度金尺。", "长亭半陈迹。", "记曾系征鞍，频护歌席。", "匆匆江上又寒食。", "回首处应念，旧曾攀折，依然离恨遍四驿。", "倦游尚南北。", "恻恻。", "怨怀积。", "渐楚榭寒收，隋苑春寂。", "眉颦不尽相思极。", "想人在何处，倚楼横笛。", "闲情似絮，更那听，夜雨滴。"]'),
('song-ci-928','琐窗寒','陈允平','宋','宋词','song-ci','琐窗寒','["\u897f\u6e56"]','禁烛飞烟，东风插柳，万家千户。',122,'宋词/ci.song.16000.json','["禁烛飞烟，东风插柳，万家千户。", "梨花院落，数点弄晴纤雨。", "傍秋千、红云半湿，画帘燕子商春语。", "数十年南北，西湖倦客，曲江行旅。", "日暮。", "花深处。", "对修竹弹棋，戏评格五。", "携尊共约，诗酒云朋月侣。", "念旧游、九陌香尘，倡条冶叶还在否。", "踏青归，醉宿兰舟，枕藉黄金俎。"]'),
('song-ci-929','隔浦莲近拍','陈允平','宋','宋词','song-ci','隔浦莲近拍','[]','铅霜初褪凤葆。',90,'宋词/ci.song.16000.json','["铅霜初褪凤葆。", "碧旆侵云窈。", "万绿伤春远，林幽乐、多禽鸟。", "斜阳堤畔草。", "游鱼闹。", "暗水流萍沼。", "翠钿小。", "凉亭醉倚，接罗巾、任敧倒。", "月明庭树，夜半鹊飞惊晓。", "隔岸苹乡梦渐到。", "吹觉。", "一襟风露尘表。"]'),
('song-ci-930','早梅芳・喜迁莺','陈允平','宋','宋词','song-ci','早梅芳・喜迁莺','[]','柳初妍，花渐好。',99,'宋词/ci.song.16000.json','["柳初妍，花渐好。", "可恨行期到。", "落梅香尽，澹月朦胧微照。", "风帘银烛暗，露幕金花小。", "纵离歌缓唱，残角又霜晓。", "琐窗前，秦吉了。", "促上长安道。", "扬鞭西去，几点稀星尚云表。", "去程疑是梦，宿酒昏情抱。", "凤楼空，琼箫声渐杳。"]'),
('song-ci-931','早梅芳・喜迁莺','陈允平','宋','宋词','song-ci','早梅芳・喜迁莺','[]','凤钗横，鸾带绕。',101,'宋词/ci.song.16000.json','["凤钗横，鸾带绕。", "独步鸳鸯沼。", "阑干斜倚，自打精神对花笑。", "贴衣琼佩冷，衬袜金莲小。", "卷香茵缥缈，舞袖称纤妙。", "梦初成，欢未了。", "明日青门道。", "离云别雨，脉脉无情画堂晓。", "柳边国骄马去，翠阁空凝眺。", "渐春风、绿愁江上草。"]'),
('song-ci-932','四园竹','陈允平','宋','宋词','song-ci','四园竹','[]','昏昏瞑色，乱叶拥云扉。',93,'宋词/ci.song.16000.json','["昏昏瞑色，乱叶拥云扉。", "渚兰风润，庭桂露凉，香动秋帏。", "独向闲亭步月，阑干瘦倚，此情惟有天知。", "纵如其。", "黄花时节归来，因循已误心期。", "欲写相思寄与，愁拂鸾笺。", "粉泪盈盈先满纸。", "正寂寞，楼南雁过稀。"]'),
('song-ci-933','侧犯','陈允平','宋','宋词','song-ci','侧犯','[]','晚凉倦浴，素妆薄试铅华靓。',95,'宋词/ci.song.16000.json','["晚凉倦浴，素妆薄试铅华靓。", "凝定。", "似一朵芙蓉泛清镜。", "轻纨笑自拈，扑蝶鸳鸯径。", "娇懒。", "金凤亸、斜敧翠蝉影。", "冰肌玉骨，衬体红绡莹。", "还暗省。", "记青青、双鬓旧潘令。", "梦想鸾筝，后堂深静。", "何日西风，碧梧金井。"]'),
('song-ci-934','齐天乐','陈允平','宋','宋词','song-ci','齐天乐','[]','客愁都在斜阳外，凭阑桂香吹晚。',123,'宋词/ci.song.16000.json','["客愁都在斜阳外，凭阑桂香吹晚。", "乱叶蝉哀，寒汀鹭泊，离绪并刀难翦。", "牙屏半掩。", "渐尘扑冰纨，浪收云簟。", "露入征衣，满襟秋思付诗卷。", "远思前度问酒，凤楼人共倚，归兴无限。", "雁影亭皋，蛩声院落，双阙明河光转。", "田园梦远。", "叹篱菊初黄，涧莼堪荐。", "拄笏西风，四山烟翠敛。"]'),
('song-ci-935','荔枝香近・荔枝香','陈允平','宋','宋词','song-ci','荔枝香近・荔枝香','[]','杜宇声声频唤，春渐去。',91,'宋词/ci.song.16000.json','["杜宇声声频唤，春渐去。", "暗碧柳色依依，湖上迷青雾。", "残香净冼红兰，昨夜朱铅雨。", "金泥帐底，双虬自沈乳。", "天际，渐迤逦片帆南浦。", "一笑蔷薇，别后酒杯慵举。", "江上琵琶，莫遣东风误鹦鹉。", "泪拥通宵蜡炬。"]'),
('song-ci-936','荔枝香近・荔枝香','陈允平','宋','宋词','song-ci','荔枝香近・荔枝香','[]','脸霞香销粉薄，泪偷泫。',88,'宋词/ci.song.16000.json','["脸霞香销粉薄，泪偷泫。", "叆叆金兽，沈水微薰，人帘绿树春阴，糁径红英风卷。", "芳草怨碧，王孙渐远。", "锦屏梦回，恍觉云雨散。", "玉瑟无心理，懒醉琼花宴。", "宝钗翠滑，一缕青丝为君翦。", "别情谁更排遣。"]'),
('song-ci-937','水龙吟','陈允平','宋','宋词','song-ci','水龙吟','[]','晓莺啼醒春愁，粉香独步千红地。',127,'宋词/ci.song.16000.json','["晓莺啼醒春愁，粉香独步千红地。", "庭闲散缟，林空翦雪，鸥惊鹤避。", "妒月魂凄，行云梦冷，温柔乡闭。", "渐黄昏院落，清明时候，东风里、无情泪。", "织翠玲珑叶底。", "倚阑人、玉龙休吹。", "残妆微洗，芳心微露，昭阳睡起。", "恨结连环，舞停双佩，水晶如意。", "倩蜂媒、聘取琼花，细与向、尊前比。"]'),
('song-ci-938','六丑','陈允平','宋','宋词','song-ci','六丑','[]','自清明过了，渐柳底、莺梭慵掷。',172,'宋词/ci.song.16000.json','["自清明过了，渐柳底、莺梭慵掷。", "万红御风，飘飘如附翼。", "锦绣陈迹。", "障地香尘暗，乱蜂似雨，漫冶游南国。", "兰襟缥缈辞湘泽。", "马迹郊原，燕泥巷陌。", "伤春为花深惜。", "叹芳菲薄幸，容易疏隔。", "庭闲人寂。", "空除芳草碧。", "梦里惊春去，如瞬息。", "长安市上狂客。", "为桃源解佩，醉浓欢极。", "无心整、雾襟烟帻。", "惊回处，断雨残云倦倚，画阑干侧。", "相思恨、暗度流汐。", "更杜鹃、院落黄昏近，谁禁受得。"]'),
('song-ci-939','塞垣春','陈允平','宋','宋词','song-ci','塞垣春','[]','草碧铺横野。',118,'宋词/ci.song.16000.json','["草碧铺横野。", "带暝色、归鞍卸。", "烟葭露苇，满汀鸥鹭，人在图画。", "渐一声雁过南楼也。", "更细雨、时飘洒。", "念徽容、都销瘦，漫将纨素描写。", "临镜理残妆，依然是、京兆柔雅。", "落叶感秋声，啼浆叹凉夜。", "对黄花共说憔悴，相思梦、顿醒西窗下。", "两腕玉挑脱，素纤悭半把。"]'),
('song-ci-940','扫花游・扫地游','陈允平','宋','宋词','song-ci','扫花游・扫地游','[]','蕙风扬暖，渐草色分吴，柳阴迷楚。',117,'宋词/ci.song.16000.json','["蕙风扬暖，渐草色分吴，柳阴迷楚。", "寸心似缕。", "看窥帘燕妥，妒花蝶舞。", "翦翦愁红，万点轻飘泪雨。", "怕春去。", "问杜宇唤春，归去何处。", "后期重细许。", "倩落絮飞烟，障春归路。", "长亭别俎。", "对歌尘舞地，暗伤蛮素。", "算得相思，比著伤春又苦。", "正凭伫。", "听斜阳、断桥箫鼓。"]'),
('song-ci-941','夜飞鹊・夜飞鹊慢','陈允平','宋','宋词','song-ci','夜飞鹊・夜飞鹊慢','[]','秋江际天阔，风雨凄其。',128,'宋词/ci.song.16000.json','["秋江际天阔，风雨凄其。", "云阴未放晴晖。", "归鸦乱叶更萧索，砧声几处寒衣。", "沙头酒初熟，尽篱边朱槿，竹外青旗。", "潮期尚晚，怕轻离、故故迟迟。", "何以醉中先别，容易为分襟，独抱琴归。", "回首征帆缥缈，津亭寂寞，衰草烟迷。", "虹收霁色，渐落霞孤鹜飞齐。", "更何时，重与论文渭北，翦烛窗西。"]'),
('song-ci-942','满庭芳','陈允平','宋','宋词','song-ci','满庭芳','[]','槐影连阴，竹光抟露，小荷新绿浮园。',118,'宋词/ci.song.16000.json','["槐影连阴，竹光抟露，小荷新绿浮园。", "簟纹如浪，绡帐碧笼烟。", "回合溪桥一曲，初雨过、流水溅溅。", "阑干外，沙鸥野鸟，飞过钓鱼船。", "浮生，同幻境，眼空四海，迹寄三椽。", "但随天、休问我后谁前。", "要识渊明琴趣，真真意、都在无弦。", "薰风里，纶巾羽扇，一枕北窗眠。"]'),
('song-ci-943','花犯','陈允平','宋','宋词','song-ci','花犯','[]','报南枝、东风试暖，萧萧甚情味。',126,'宋词/ci.song.16000.json','["报南枝、东风试暖，萧萧甚情味。", "乱琼雕缀。", "幻姑射精神，玉蕊佳丽。", "寿阳宴罢妆台倚。", "眉颦羞鹊喜。", "念误却、何郎归去，清香空翠被。", "溪松径竹素知心，青青岁寒友，甘同憔悴。", "渐画角，严城上、雁霜惊坠。", "烟江暮、佩环未解，愁不到、独醒人梦里。", "但恨绕、六桥明月，孤山云畔水。"]'),
('song-ci-944','大酺','陈允平','宋','宋词','song-ci','大酺','[]','雾幕西山，珠帘卷，浓霭凄迷华屋。',163,'宋词/ci.song.16000.json','["雾幕西山，珠帘卷，浓霭凄迷华屋。", "蒲萄新绿涨，正桃花烟浪，乱红翻触。", "绣阁留寒，罗衣怯润，慵理凤楼丝竹。", "东风垂杨恨，锁朱门深静，粉香初熟。", "念缓酌灯前，醉吟孤枕，顿成清独。", "伤心春去速。", "叹美景虚掷如飞毂。", "漫孤负、秋千台榭，拾翠心期，误芳菲、怨眉愁目。", "冷透金篝湿，空展转、画屏山曲。", "梦不到、华胥国。", "闲倚雕槛，试采青青梅菽。", "海棠尚堪对烛。"]'),
('song-ci-945','霜叶飞','陈允平','宋','宋词','song-ci','霜叶飞','[]','碧天如水，新蟾挂、修眉初画云表。',134,'宋词/ci.song.16000.json','["碧天如水，新蟾挂、修眉初画云表。", "半江枫叶自黄昏，深院砧声悄。", "渐凉蝶、残花梦晓。", "西风篱落寒螀小。", "背画阑依依，有数点、流萤乱扑，扇底微照。", "凝望渺漠平芜，蒹葭烟远，过雁远带愁到。", "拼教日日醉斜阳，但素琴横抱。", "记旧谱、归耕未了。", "金徽谁度凄凉调。", "算多少悲秋恨，恨比秋多，比秋犹少。"]'),
('song-ci-946','法曲献仙音','陈允平','宋','宋词','song-ci','法曲献仙音','[]','油幕收尘。',113,'宋词/ci.song.16000.json','["油幕收尘。", "素纨招月，一枕苹香微度。", "枕玉牙床，浣冰金斛，薰风夜凉窗户。", "渐睡醒、明河暗，芭蕉几声雨。", "对谁语。", "念徽容已成憔悴，心期误。", "归计欲成又阻。", "寂寞燕楼空，想弓弯、眉黛慵妩。", "泪墨愁笺，纵回文，难写情素。", "便山遥水邈，几度梦魂飞去。"]'),
('song-ci-947','渡江云','陈允平','宋','宋词','song-ci','渡江云','[]','青青江上草，片帆浪暖，初泊渡头沙。',124,'宋词/ci.song.16000.json','["青青江上草，片帆浪暖，初泊渡头沙。", "翠筇便瘦倚，问酒垂杨，影里那人家。", "东风未许，漫媚妩、轻试铅华。", "飘佩环、玉波秋莹，双髻绿堆鸦。", "空嗟。", "赤阑桥畔，暗约琴心，傍秋千影下。", "夜渐分、西窗愁对，烟月笼纱。", "离情暗逐春潮去，南浦恨、风苇烟葭。", "肠断处，门前一树桃花。"]'),
('song-ci-948','应天长','陈允平','宋','宋词','song-ci','应天长','[]','流莺唤梦，芳草带愁，东风料峭寒色。',120,'宋词/ci.song.16000.json','["流莺唤梦，芳草带愁，东风料峭寒色。", "又见杏浆饧粥，家家禁烟食。", "江湖几年倦客。", "曾惯识、凄凉岑寂。", "苦吟瘦，萧索诗肠，空愧郊籍。", "春事正溪山，柳雾花尘，深映翠萝壁。", "更谢多情双燕，归来旧庭宅。", "情丝乱游巷陌。", "怅容易、万红陈迹。", "酒旗直，绿水桥边，犹记曾识。"]'),
('song-ci-949','玉楼春','陈允平','宋','宋词','song-ci','玉楼春','[]','东风跃马长安道。',64,'宋词/ci.song.16000.json','["东风跃马长安道。", "一树樱桃花谢了。", "别来千里梦频归，醉里五更愁不到。", "江南两岸无名草。", "雨遍莓苔生嫩葆。", "玉楼人远绿腰闲，帘幕深沈双燕老。"]'),
('song-ci-950','玉楼春','陈允平','宋','宋词','song-ci','玉楼春','[]','粉销香减红兰泪。',64,'宋词/ci.song.16000.json','["粉销香减红兰泪。", "总是文君初别意。", "春风织就闷情怀，夜月砌成愁况未。", "迢迢归梦频东里。", "堪恨洛阳花渐已。", "斜阳日日自相思，三十六陂芳草地。"]'),
('song-ci-951','玉楼春','陈允平','宋','宋词','song-ci','玉楼春','[]','万花丛底曾抬目。',64,'宋词/ci.song.16000.json','["万花丛底曾抬目。", "澹雅梳妆娇已足。", "夜来鹦鹉梦中人，春去琵琶江上曲。", "双鸾碧重钗头玉。", "裙曳湘罗浮浅绿。", "东风一醉买蛾眉，为拚明珠三万斛。"]'),
('song-ci-952','玉楼春','陈允平','宋','宋词','song-ci','玉楼春','[]','西园斗结秋千了。',64,'宋词/ci.song.16000.json','["西园斗结秋千了。", "日漾游丝烟外袅。", "小桥杨柳色初浓，别院海棠花正好。", "粉墙低度莺声巧。", "薄薄轻衫宜短帽。", "便拚日日醉芳菲，未必春风留玉貌。"]'),
('song-ci-953','玉楼春','陈允平','宋','宋词','song-ci','玉楼春','[]','柳丝挽得秋光住。',64,'宋词/ci.song.16000.json','["柳丝挽得秋光住。", "肠断驿亭离别处。", "斜阳一片水边楼，红叶满天江上路。", "来鸿去雁知何数。", "欲问归期朝复暮。", "晚风亭院倚阑干，两岸芦花飞雪絮。"]'),
('song-ci-954','伤情怨・清商怨','陈允平','宋','宋词','song-ci','伤情怨・清商怨','[]','南枝春意正小。',51,'宋词/ci.song.16000.json','["南枝春意正小。", "篱菊都荒了。", "帐底孤灯，夜来还独照。", "沙洲烟翠渺渺。", "谢塞鸿、频带书到。", "笑拈梅花，今年开较早。"]'),
('song-ci-955','品令','陈允平','宋','宋词','song-ci','品令','[]','玉壶尘静。',66,'宋词/ci.song.16000.json','["玉壶尘静。", "蟾光透、一帘疏影。", "偏爱水月楼台近。", "画阑独倚，风度寒香阵。", "犹记曲江烟水恨。", "叹凄凉谁问。", "夜深沙觜霜痕印。", "嚼花拚醉，枝上春无尽。"]'),
('song-ci-956','木兰花・玉楼春','陈允平','宋','宋词','song-ci','木兰花・玉楼春','["\u957f\u6c5f"]','长江浩渺山明秀。',64,'宋词/ci.song.16000.json','["长江浩渺山明秀。", "宛转西风惊客袖。", "相逢才系柳边舟，相别又倾花下酒。", "怪得新来诗骨瘦。", "都在秋娘相识后。", "一天明月照相思，芦荻汀洲霜满首。"]'),
('song-ci-957','秋蕊香','陈允平','宋','宋词','song-ci','秋蕊香','[]','晚酌宜城酒暖。',56,'宋词/ci.song.16000.json','["晚酌宜城酒暖。", "玉软嫩红潮面。", "醉中窈窕度娇眼。", "不识愁深恨浅。", "绣窗一缕香绒线。", "击双燕。", "海棠满地夕阳远。", "明月笙歌别院。"]'),
('song-ci-958','菩萨蛮','陈允平','宋','宋词','song-ci','菩萨蛮','[]','银城远枕清江曲。',52,'宋词/ci.song.16000.json','["银城远枕清江曲。", "汀洲尽画蒹葭绿。", "君上木兰舟。", "妾愁双凤楼。", "角声何处发。", "月浸溪桥雪。", "独自倚阑看。", "风飘襟袖寒。"]'),
('song-ci-959','丑奴儿・采桑子','陈允平','宋','宋词','song-ci','丑奴儿・采桑子','["\u897f\u6e56"]','岁寒时节千林表，独耐风霜。',52,'宋词/ci.song.16000.json','["岁寒时节千林表，独耐风霜。", "妒粉欺黄。", "澹澹衣裳薄薄妆。", "西湖十二阑干曲，倚遍寒香。", "白鹭横塘。", "一片孤山几夕阳。"]'),
('song-ci-960','感皇恩','陈允平','宋','宋词','song-ci','感皇恩','[]','体态玉精神，惺憁言语。',81,'宋词/ci.song.16000.json','["体态玉精神，惺憁言语。", "一点灵犀动人处。", "绣香罗帕，为待别时亲付。", "要人长记得，相思苦。", "彩鸾独跨，蓝桥归路。", "憔悴东风自蛮素。", "桃叶杨花，又向空江欲度。", "任洛阳城里，春无数。"]'),
('song-ci-961','宴桃源・如梦令','陈允平','宋','宋词','song-ci','宴桃源・如梦令','[]','闲倚琐窗工绣。',40,'宋词/ci.song.16000.json','["闲倚琐窗工绣。", "春困两眉频皱。", "独自下香街，攀折画桥烟柳。", "晴昼。", "晴昼。", "偏称玉楼歌酒。"]'),
('song-ci-962','宴桃源・如梦令','陈允平','宋','宋词','song-ci','宴桃源・如梦令','[]','何处春风归路。',40,'宋词/ci.song.16000.json','["何处春风归路。", "金屋空藏樊素。", "零乱海棠花，愁梦欲随春去。", "情绪。", "情绪。", "粉溅两行冰箸。"]'),
('song-ci-963','月中行・月宫春','陈允平','宋','宋词','song-ci','月中行・月宫春','[]','鬓云斜插映山红。',59,'宋词/ci.song.16000.json','["鬓云斜插映山红。", "春里澹香融。", "自携纨扇出帘栊。", "意欲扑飞虫。", "蔷薇架下偏宜酒，纤纤手、自引金锺。", "倦歌佯醉倚东风。", "愁在落花中。"]'),
('song-ci-964','渔家傲','陈允平','宋','宋词','song-ci','渔家傲','[]','日转花梢春已昼。',72,'宋词/ci.song.16000.json','["日转花梢春已昼。", "双蛾曲理遥山秀。", "百草偏输羞不斗。", "随人后。", "无情自折金丝柳。", "秋水盈盈娇欲溜。", "六么倦舞弓弯袖。", "偷摘青梅推病酒。", "俳徊久。", "一双燕子归时候。"]'),
('song-ci-965','渔家傲','陈允平','宋','宋词','song-ci','渔家傲','[]','自别春风情意恻。',72,'宋词/ci.song.16000.json','["自别春风情意恻。", "秦筝不理香尘积。", "去跃青骢游上国。", "归未得。", "何如莫向尊前识。", "薄幸高阳花酒客。", "迷云恋雨青楼侧。", "金屋空闲双凤席。", "离怀适。", "银台烛泪成行滴。"]'),
('song-ci-966','定风波','陈允平','宋','宋词','song-ci','定风波','[]','慵拂妆台懒画眉。',70,'宋词/ci.song.16000.json','["慵拂妆台懒画眉。", "此情惟有落花知。", "流水悠悠春脉脉，闲倚绣屏，犹自立多时。", "有约莫教莺解语，多愁却妒燕于飞。", "一笑蔷薇孤旧约，载酒寻欢，因甚懒支持。"]'),
('song-ci-967','蝶恋花','陈允平','宋','宋词','song-ci','蝶恋花','[]','谢了梨花寒食后。',70,'宋词/ci.song.16000.json','["谢了梨花寒食后。", "翦翦轻寒，晓色侵书牖。", "寂寞幽斋惟酌酒。", "柔条恨结东风手。", "浅黛娇黄春色透。", "薄雾轻烟，远映苏堤秀。", "目断章台愁举首。", "故人应似青青旧。"]'),
('song-ci-968','蝶恋花','陈允平','宋','宋词','song-ci','蝶恋花','[]','墙外秋千花影后。',70,'宋词/ci.song.16000.json','["墙外秋千花影后。", "环兽金悬，暗绿笼朱牖。", "为怯轻寒犹殢酒。", "同心共结怀纤手。", "粉袖盈盈香泪透。", "蹙损双眉，懒画遥山秀。", "柔弱风条低拂首。", "渭城歌舞春如旧。"]'),
('song-ci-969','蝶恋花','陈允平','宋','宋词','song-ci','蝶恋花','[]','寂寞长亭人别后。',70,'宋词/ci.song.16000.json','["寂寞长亭人别后。", "一把垂丝，乱拂闲轩牖。", "三月春光浓似酒。", "传怀莫放纤纤手。", "金缕依依红日透。", "舞彻东风，不减蛮腰秀。", "扑鬓杨花如白首。", "少年张绪心如旧。"]'),
('song-ci-970','蝶恋花','陈允平','宋','宋词','song-ci','蝶恋花','["\u897f\u6e56"]','落尽樱桃春去后。',70,'宋词/ci.song.16000.json','["落尽樱桃春去后。", "舞絮飞绵，扑簌穿帘牖。", "异别情怀愁对酒。", "翠条折赠劳亲手。", "绣幕深沉寒尚透。", "雨雨晴晴，妆点西湖秀。", "怅望章台愁转首。", "画阑十二东风旧。"]'),
('song-ci-971','蝶恋花','陈允平','宋','宋词','song-ci','蝶恋花','[]','楼上钟残人渐定。',70,'宋词/ci.song.16000.json','["楼上钟残人渐定。", "庭户沉沉，月落梧桐井。", "闷倚琐窗灯炯炯。", "兽香闲伴银屏冷。", "淅沥西风吹雁影。", "一曲胡笳，别后谁堪听。", "誓海盟山虚话柄。", "凭书问著无言应。"]');
